# Custom function for files with too many lines of code
from typing import Dict, List
def check_files_avoid_having_too_many_lines(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects files with more than 1000 lines of code, excluding generated and test files.
    """
    findings = []
    # Exclude generated files only
    if any(s in filename for s in [".Designer.cs", ".g.cs", ".Generated.cs"]):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    # Exclude <auto-generated> marker
    if '<auto-generated>' in source:
        return findings
    # Exclude files with [Test], [Fact], [Theory]
    if any(attr in source for attr in ["[Test", "[Fact", "[Theory"]):
        return findings
    line_count = source.count('\n') + 1
    if line_count > 1000:
        findings.append({
            'rule_id': 'files_avoid_having_too',
            'message': f'File has {line_count} lines of code, which exceeds the recommended maximum (1000).',
            'file': filename,
            'line': 1,
            'severity': 'Major',
            'node': 'CompilationUnit',
            'property_path': ['source'],
            'value': f'{line_count} lines',
            'status': 'violation',
        })
    return findings

# Custom function for files that should have a newline at the end
def check_files_newline(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects files that do not end with a newline character.
    Some tools work better when files end with an empty line.
    """
    findings = []
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Exclude generated files
    if any(s in filename for s in [".Designer.cs", ".g.cs", ".Generated.cs"]):
        return findings
    
    # Exclude <auto-generated> marker
    if '<auto-generated>' in source:
        return findings
    
    # Check if file ends with newline
    # A file should end with \n (newline character)
    if not source.endswith('\n'):
        findings.append({
            'rule_id': 'files_newline',
            'message': 'File should end with a newline character.',
            'file': filename,
            'line': len(source.splitlines()) if source else 1,
            'severity': 'Major',
            'node': 'CompilationUnit',
            'property_path': ['source'],
            'value': 'Missing newline at end of file',
            'status': 'violation',
        })
    return findings
