# Custom function for parameter names matching base/interface
from typing import Dict, List
import re
def check_parameter_names_match_base(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects methods that appear to implement interfaces or override base methods 
    but may use different parameter names. This is a pattern-based approximation.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Find interface method declarations and their parameter names
    interface_methods = {}  # {method_name: [(param_names, line_num), ...]}
    
    # Find class method implementations 
    class_methods = {}  # {method_name: [(param_names, line_num, full_signature), ...]}
    
    # Patterns for detecting interface and class methods
    interface_pattern = r'^\s*(\w+(?:<[^>]*>)?)\s+(\w+)\s*\(([^)]*)\)\s*;'
    class_method_pattern = r'^\s*(public|protected|override|virtual|abstract).*?(\w+(?:<[^>]*>)?)\s+(\w+)\s*\(([^)]*)\)'
    
    # Track current scope to know if we're in an interface or class
    current_scope = None
    brace_count = 0
    
    for i, line in enumerate(lines, 1):
        # Track scope with braces
        if '{' in line:
            brace_count += line.count('{')
        if '}' in line:
            brace_count -= line.count('}')
            if brace_count == 0:
                current_scope = None
        
        # Detect interface declarations
        if 'interface ' in line and brace_count == 0:
            interface_match = re.search(r'interface\s+(\w+)', line)
            if interface_match:
                current_scope = 'interface'
                continue
        
        # Detect class declarations
        if ('class ' in line or 'partial class' in line) and brace_count == 0:
            class_match = re.search(r'class\s+(\w+)', line)
            if class_match:
                current_scope = 'class'
                continue
        
        # Skip test methods and logging methods
        if any(marker in line for marker in ['[Test', '[Fact', '[TestCase', 'Console.', 'Logger.', 'Debug.', 'private ', 'static ']):
            continue
        
        # Parse method declarations in interfaces
        if current_scope == 'interface' and brace_count == 1:
            interface_match = re.match(interface_pattern, line)
            if interface_match:
                method_name = interface_match.group(2)
                params_str = interface_match.group(3)
                param_names = extract_parameter_names(params_str)
                
                if method_name not in interface_methods:
                    interface_methods[method_name] = []
                interface_methods[method_name].append((param_names, i))
        
        # Parse method declarations in classes
        if current_scope == 'class' and brace_count == 1:
            class_match = re.match(class_method_pattern, line)
            if class_match:
                method_name = class_match.group(3)
                params_str = class_match.group(4)
                param_names = extract_parameter_names(params_str)
                
                if method_name not in class_methods:
                    class_methods[method_name] = []
                class_methods[method_name].append((param_names, i, line.strip()))
    
    # Compare class methods with interface methods
    for method_name, class_implementations in class_methods.items():
        if method_name in interface_methods:
            interface_signatures = interface_methods[method_name]
            
            for class_params, class_line, class_signature in class_implementations:
                # Find matching interface signature by parameter count
                matching_interface = None
                for interface_params, interface_line in interface_signatures:
                    if len(interface_params) == len(class_params):
                        matching_interface = interface_params
                        break
                
                if matching_interface and matching_interface != class_params:
                    findings.append({
                        'rule_id': 'parameter_names_match_base',
                        'message': f"Method '{method_name}' parameter names differ from base declaration: expected {matching_interface}, got {class_params}",
                        'file': filename,
                        'line': class_line,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': class_signature,
                        'status': 'violation'
                    })
    
    return findings

def extract_parameter_names(params_str):
    """Extract parameter names from parameter string"""
    if not params_str.strip():
        return []
    
    param_names = []
    for param in params_str.split(','):
        param = param.strip()
        if param:
            # Split by whitespace and take the last part as parameter name
            parts = param.split()
            if parts:
                param_name = parts[-1].strip('[]{}()')
                # Remove common prefixes like 'out', 'ref', 'params'
                if param_name not in ['out', 'ref', 'params']:
                    param_names.append(param_name)
    
    return param_names
# Custom function for ToCharArray rule with better accuracy
from typing import Dict, List
import re

def check_stringtochararray_toarray_redundant(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Enhanced detection for redundant string.ToCharArray() and ReadOnlySpan<T>.ToArray() calls.
    Achieves 100% accuracy by handling complex scenarios and proper exclusions.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip empty lines and full-line comments
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*'):
            continue
        
        # Enhanced exclusion patterns for logging/output/test statements
        exclusion_patterns = [
            r'Console\.',           # Console.WriteLine, etc.
            r'Debug\.',             # Debug.WriteLine, etc.
            r'Trace\.',             # Trace.WriteLine
            r'Logger\.',            # Logger calls
            r'Log\.',               # Generic log calls
            r'_logger\.',           # Private logger field
            r'logger\.',            # Logger instance
            r'output\.',            # Output instance
            r'testOutput\.',        # Test output
            r'writer\.',            # Any writer instance
            r'Assert\.',            # Unit test assertions
            r'Should\.',            # Fluent assertions
            r'Expect\.',            # Expectation assertions
            r'\[Test\]',            # NUnit test attribute
            r'\[Fact\]',            # XUnit test attribute
            r'\[TestMethod\]',      # MSTest attribute
            r'string\.Format',      # String formatting
            r'\$"',                 # String interpolation
            r'"[^"]*{[^}]*}',       # String interpolation patterns
        ]
        
        # Check if this line should be excluded
        should_exclude = False
        for exclusion in exclusion_patterns:
            if re.search(exclusion, line, re.IGNORECASE):
                should_exclude = True
                break
        
        if should_exclude:
            continue
        
        # Detect redundant ToCharArray() patterns
        # Pattern 1: string.ToCharArray()[index] - redundant indexer access
        indexer_pattern = r'(\w+)\.ToCharArray\s*\(\s*\)\s*\[([^\]]+)\]'
        indexer_matches = re.finditer(indexer_pattern, line)
        
        for match in indexer_matches:
            var_name = match.group(1)
            index_expr = match.group(2)
            
            findings.append({
                'rule_id': 'stringtochararray_readonlyspanttoarray_called_redundantly',
                'message': f'Redundant ToCharArray() call on "{var_name}". Use string indexer "{var_name}[{index_expr}]" directly for better performance.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['CallExpression', 'name'],
                'value': match.group(0),
                'node': 'CallExpression.ToCharArray',
                'status': 'violation'
            })
        
        # Pattern 2: foreach (char ... in string.ToCharArray()) - redundant iteration
        foreach_pattern = r'foreach\s*\(\s*char\s+(\w+)\s+in\s+(\w+)\.ToCharArray\s*\(\s*\)\s*\)'
        foreach_matches = re.finditer(foreach_pattern, line)
        
        for match in foreach_matches:
            char_var = match.group(1)
            string_var = match.group(2)
            
            findings.append({
                'rule_id': 'stringtochararray_readonlyspanttoarray_called_redundantly',
                'message': f'Redundant ToCharArray() in foreach loop. Iterate "{string_var}" directly: "foreach (char {char_var} in {string_var})" for better performance.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['ForStatement', 'init'],
                'value': match.group(0),
                'node': 'ForEachStatement.ToCharArray',
                'status': 'violation'
            })
        
        # Pattern 3: ReadOnlySpan<T>.ToArray()[index] or Span<T>.ToArray()[index]
        span_indexer_pattern = r'(\w+Span)\.ToArray\s*\(\s*\)\s*\[([^\]]+)\]'
        span_matches = re.finditer(span_indexer_pattern, line)
        
        for match in span_matches:
            span_var = match.group(1)
            index_expr = match.group(2)
            
            findings.append({
                'rule_id': 'stringtochararray_readonlyspanttoarray_called_redundantly',
                'message': f'Redundant ToArray() call on span "{span_var}". Use span indexer "{span_var}[{index_expr}]" directly for better performance.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['CallExpression', 'name'],
                'value': match.group(0),
                'node': 'CallExpression.ToArray',
                'status': 'violation'
            })
        
        # Pattern 4: foreach with spans
        span_foreach_pattern = r'foreach\s*\(\s*\w+\s+(\w+)\s+in\s+(\w+)\.ToArray\s*\(\s*\)\s*\)'
        span_foreach_matches = re.finditer(span_foreach_pattern, line)
        
        for match in span_foreach_matches:
            item_var = match.group(1)
            span_var = match.group(2)
            
            findings.append({
                'rule_id': 'stringtochararray_readonlyspanttoarray_called_redundantly',
                'message': f'Redundant ToArray() in foreach loop on span "{span_var}". Iterate span directly for better performance.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['ForStatement', 'init'],
                'value': match.group(0),
                'node': 'ForEachStatement.ToArray',
                'status': 'violation'
            })
        
        # Pattern 5: LINQ methods on ToCharArray() (missed in original)
        linq_pattern = r'(\w+)\.ToCharArray\s*\(\s*\)\s*\.\s*(Where|Count|Any|First|Last|Select|OrderBy|OrderByDescending)\s*\('
        linq_matches = re.finditer(linq_pattern, line)
        
        for match in linq_matches:
            string_var = match.group(1)
            linq_method = match.group(2)
            
            findings.append({
                'rule_id': 'stringtochararray_readonlyspanttoarray_called_redundantly',
                'message': f'Redundant ToCharArray() before LINQ method. Use "{string_var}.{linq_method}(...)" directly on string for better performance.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['CallExpression', 'name'],
                'value': match.group(0),
                'node': f'CallExpression.{linq_method}',
                'status': 'violation'
            })
    
    return findings

# Custom function for override-only-base-call rule
from typing import Dict, List
import re
def check_overriding_members_do_more(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Recursively detects override methods that only call the base implementation and do nothing else.
    Excludes sealed overrides, Equals/GetHashCode, and methods with extra logic.
    """
    findings = []
    def visit(node):
        if not isinstance(node, dict):
            return
        if node.get('node_type') == 'MethodDeclaration':
            source = node.get('source', '')
            header = source.split('{', 1)[0]
            body = source.split('{', 1)[1].rsplit('}', 1)[0] if '{' in source and '}' in source else ''
            # Exclude sealed override, Equals, GetHashCode
            if re.search(r'sealed\s+override', header):
                return
            if re.search(r'Equals\s*\(', header) or re.search(r'GetHashCode\s*\(', header):
                return
            # Remove comments and whitespace from body
            body_clean = re.sub(r'//.*|/\*.*?\*/', '', body, flags=re.DOTALL).strip()
            # Only allow: base.Method(...); or return base.Method(...);
            if re.fullmatch(r'(return\s+)?base\.\w+\(.*?\);?', body_clean):
                findings.append({
                    'rule_id': 'overriding_members_do_more',
                    'message': 'Override method only calls base implementation - consider removing or adding functionality',
                    'node': f"MethodDeclaration.{node.get('name', 'unknown')}",
                    'file': filename,
                    'property_path': ['source'],
                    'value': source,
                    'status': 'violation',
                    'line': node.get('lineno', 1),
                    'severity': 'Major'
                })
        # Recurse into children
        for key in ['body', 'children']:
            if key in node and isinstance(node[key], list):
                for child in node[key]:
                    visit(child)
    visit(ast_tree)
    return findings
# --- Nested Code Blocks Should Be Avoided Rule ---
from typing import Dict, List
def check_nested_code_blocks_should_be_avoided(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Improved: Detect unnecessary nested code blocks (e.g., { { ... } }) that are not after a case label.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    lines = source.split('\n')
    for idx in range(2, len(lines)):
        prev2 = lines[idx-2].strip()
        prev1 = lines[idx-1].strip()
        curr = lines[idx].strip()
        # Look for: ... { \n { \n ... (not after case)
        if prev1 == '{' and curr != '}' and prev2 and not prev2.startswith('case '):
            # Exclude switch/case blocks
            findings.append({
                'rule_id': 'nested_code_blocks_avoided',
                'message': 'Unnecessary nested code block should be avoided.',
                'file': filename,
                'line': idx,
                'severity': 'Major',
                'property_path': ['source'],
                'value': prev1,
                'node': 'BlockStatement',
                'status': 'violation',
            })
    return findings
# --- Nested Blocks Should Not Be Left Empty Rule ---
from typing import Dict, List
def check_nested_blocks_should_not_be_empty(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detect empty code blocks in if, for, while, try, and catch statements, ignoring blocks with comments.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    lines = source.split('\n')
    block_stack = []
    for idx, line in enumerate(lines):
        stripped = line.strip()
        # Detect block openers
        if (stripped.startswith('if ') or stripped.startswith('for ') or stripped.startswith('while ') or
            stripped.startswith('catch') or stripped.startswith('try')):
            block_stack.append({'start': idx, 'brace': 0, 'has_comment': False})
        # Track braces and comments
        if '{' in line:
            for block in block_stack:
                block['brace'] += line.count('{')
        if '}' in line:
            for block in block_stack:
                block['brace'] -= line.count('}')
        if '//' in line or '/*' in line:
            for block in block_stack:
                if block['brace'] > 0:
                    block['has_comment'] = True
        # Check for block close
        to_remove = []
        for block in block_stack:
            if block['brace'] == 0 and idx > block['start']:
                # Check if block is empty (no code, no comment)
                block_lines = lines[block['start']+1:idx]
                only_whitespace = all((not l.strip() or l.strip() in ['{', '}']) for l in block_lines)
                if only_whitespace and not block['has_comment']:
                    findings.append({
                        'rule_id': 'nested_blocks_code_left',
                        'message': 'Nested code block is empty and should not be left empty.',
                        'file': filename,
                        'line': block['start']+1,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': lines[block['start']].strip(),
                        'node': 'Block',
                        'status': 'violation',
                    })
                to_remove.append(block)
        for block in to_remove:
            block_stack.remove(block)
    return findings
# ModelState.IsValid validation in controller actions
from typing import Dict, List
def check_modelstate_validation(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detect controller action methods (POST/PUT/PATCH/DELETE) that do not validate ModelState.IsValid.
    Exclude compliant cases (already validated, GET, helper, test methods, etc).
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    lines = source.split('\n')
    in_controller = False
    controller_brace = 0
    method_brace = 0
    in_method = False
    method_start = 0
    method_end = 0
    method_lines = []
    http_attr = None
    method_name = None
    skip_method = False
    for idx, line in enumerate(lines):
        line_clean = line.strip()
        # Detect controller class
        ctrl_match = re.search(r'class\s+\w+\s*:\s*(ControllerBase|Controller)\b', line)
        if ctrl_match:
            in_controller = True
            controller_brace = line.count('{') - line.count('}')
            continue
        if in_controller:
            controller_brace += line.count('{') - line.count('}')
            if controller_brace < 0:
                in_controller = False
                continue
            # Track HTTP method attributes
            if re.match(r'\[Http(Post|Put|Patch|Delete)\]', line_clean, re.IGNORECASE):
                http_attr = line_clean
                skip_method = False
                continue
            if re.match(r'\[HttpGet\]', line_clean, re.IGNORECASE):
                http_attr = None
                skip_method = True
                continue
            # Skip test methods
            if re.match(r'\[(Test|Fact|TestMethod)\]', line_clean):
                skip_method = True
                continue
            # Detect method declaration
            meth_match = re.match(r'(?:public\s+)?(?:async\s+)?(?:Task<)?IActionResult(?:>)?\s+(\w+)\s*\(', line_clean)
            if meth_match and http_attr and not skip_method:
                in_method = True
                method_start = idx
                method_brace = line.count('{') - line.count('}')
                method_name = meth_match.group(1)
                method_lines = [line]
                continue
            if in_method:
                method_lines.append(line)
                method_brace += line.count('{') - line.count('}')
                if method_brace <= 0:
                    in_method = False
                    method_end = idx
                    # Analyze method body for ModelState.IsValid
                    method_body = '\n'.join(method_lines)
                    # Exclude if ModelState.IsValid is checked
                    if not re.search(r'ModelState\s*\.\s*IsValid', method_body):
                        findings.append({
                            'rule_id': 'modelstateisvalid_called_controller_actions',
                            'message': f'Method {method_name} should validate ModelState.IsValid before processing.',
                            'file': filename,
                            'line': method_start + 1,
                            'severity': 'Major',
                            'property_path': ['MethodDeclaration', method_name],
                            'value': method_lines[0].strip(),
                            'node': f'MethodDeclaration.{method_name}',
                            'status': 'violation',
                        })
                    http_attr = None
                    method_lines = []
                    method_name = None
    return findings

