import re
from typing import List, Dict, Any

# --- Native Methods Should Be Wrapped Rule ---
def check_native_methods_should_be_wrapped(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detect public static extern methods with [DllImport] attribute (native methods) that are not private.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    lines = source.split('\n')
    for idx, line in enumerate(lines):
        # Look for [DllImport(...)]
        if '[DllImport' in line:
            # Look ahead for the method declaration (could be next line)
            for offset in range(1, 3):
                if idx + offset < len(lines):
                    method_line = lines[idx + offset].strip()
                    # Match public static extern ...
                    m = re.match(r'public\s+static\s+extern\s+\w+', method_line)
                    if m:
                        findings.append({
                            'rule_id': 'native_methods_wrapped',
                            'message': 'Public native method with DllImport should be private and wrapped.',
                            'file': filename,
                            'line': idx + offset + 1,
                            'severity': 'Major',
                            'property_path': ['MethodDeclaration'],
                            'value': method_line,
                            'node': 'MethodDeclaration',
                            'status': 'violation',
                        })
    return findings

