def check_methods_should_not_return_values_that_are_never_used(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detect private methods that return a value, but whose return value is never used by any caller.
    Flags cases where a private method is called and its result is ignored (not assigned, not used in an expression).
    """
    findings = []
    source = ast_tree.get('source', '')
    if not source:
        return findings
    lines = source.split('\n')
    # Find all private methods with non-void return type
    private_methods = []
    method_pattern = re.compile(r'\bprivate\s+([\w<>\[\]]+)\s+(\w+)\s*\(([^)]*)\)')
    for idx, line in enumerate(lines):
        m = method_pattern.search(line)
        if m:
            return_type, method_name, params = m.groups()
            if return_type != 'void':
                private_methods.append({
                    'name': method_name,
                    'line': idx + 1,
                    'return_type': return_type
                })
    # For each private method, search for calls where the result is ignored
    for method in private_methods:
        call_pattern = re.compile(r'\b' + re.escape(method['name']) + r'\s*\(')
        for idx, line in enumerate(lines):
            # Ignore the method declaration itself
            if idx + 1 == method['line']:
                continue
            # Look for method call
            call_match = call_pattern.search(line)
            if call_match:
                # Check if the call is part of an assignment or used in an expression
                before = line[:call_match.start()].strip()
                after = line[call_match.end():].strip()
                # If not assigned, not returned, not used in expression, flag as violation
                if not (before.endswith('=') or before.endswith('return') or before.endswith('(') or before.endswith(',') or before.endswith('?:')):
                    findings.append({
                        'rule_id': 'methods_return_values_that',
                        'message': f'Private method "{method["name"]}" returns a value that is never used by the caller.',
                        'file': filename,
                        'line': idx + 1,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': line.strip(),
                        'node': f'MethodCall.{method["name"]}',
                        'status': 'violation'
                    })
    return findings
