import re

from typing import List, Dict, Any

def check_close_curly_brace_placement(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for close_curly_brace_placed rule.
    Checks that closing curly braces are placed at the beginning of a line
    (meaning on their own line with only whitespace before them),
    except for simple inline blocks like properties and collection initializers.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code if available
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, 1):
        # Skip empty lines 
        if not line.strip():
            continue
            
        # Look for closing braces
        if '}' in line:
            # Find positions of all closing braces
            brace_positions = [i for i, char in enumerate(line) if char == '}']
            
            for pos in brace_positions:
                # Get everything before this brace position
                before_brace = line[:pos]
                
                # Check for simple inline cases that should be allowed
                if '{' in before_brace:
                    # This might be an inline block
                    open_count = before_brace.count('{')
                    close_count = before_brace.count('}')
                    
                    if open_count > close_count:  # This closing brace matches an opening brace on same line
                        # Get the content between the last opening brace and this closing brace
                        last_open_pos = before_brace.rfind('{')
                        between_braces = before_brace[last_open_pos+1:]
                        
                        # Allow several types of inline cases:
                        # 1. Properties: { get; set; }
                        # 2. Empty blocks: { }
                        # 3. Simple collection initializers: {1, 2, 3}
                        # 4. Simple object initializers: {"key", value}
                        
                        # Pattern matching for allowed cases
                        simple_patterns = [
                            r'^\s*get\s*;\s*set\s*;?\s*$',           # { get; set; }
                            r'^\s*set\s*;\s*get\s*;?\s*$',           # { set; get; }
                            r'^\s*get\s*;\s*$',                      # { get; }
                            r'^\s*set\s*;\s*$',                      # { set; }
                            r'^\s*$',                                # { }
                            r'^\s*[\d\s,]+\s*$',                     # {1, 2, 3}
                            r'^\s*["\w\s,{}]+\s*$'                   # {"key", value} simple cases
                        ]
                        
                        # Also check for simple collection/array initializers
                        is_simple_initializer = (
                            # Simple numeric or string literals with commas
                            re.match(r'^\s*[\d\s,."\']+\s*$', between_braces) or
                            # Property patterns
                            any(re.match(pattern, between_braces, re.IGNORECASE) 
                                for pattern in simple_patterns) or
                            # Very short content (likely simple)
                            (len(between_braces.strip()) < 30 and 
                             '(' not in between_braces and 
                             ')' not in between_braces and
                             not 'Console' in between_braces)
                        )
                        
                        if is_simple_initializer:
                            continue  # Skip this - it's an allowed inline case
                
                # Now check if there's non-whitespace content before the brace
                non_whitespace_before = before_brace.strip()
                
                if non_whitespace_before:  # There's actual code before the brace
                    # This is a violation - brace is not at beginning of line
                    clean_line = ' '.join(line.split())
                    findings.append({
                        'rule_id': 'close_curly_brace_placed',
                        'message': 'Closing curly brace should be placed at the beginning of the line',
                        'file': filename,
                        'line': line_num,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': clean_line,
                        'node': f'Line {line_num}',
                        'status': 'violation'
                    })
                    break  # Only report one violation per line
    
    return findings

def check_cls_compliant_assembly(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check if assembly should be marked with [assembly:CLSCompliant(true)] when it contains public types.
    
    Logic:
    1. Check if file already contains [assembly:CLSCompliant(true)] - if yes, return no violations
    2. If not present, check for public classes/interfaces/structs/delegates
    3. Flag violations only for actual public type declarations, exclude comments and strings
    """
    import re
    
    findings = []
    
    source_code = ast_tree.get('source', '')
    if not source_code:
        return findings
    
    # Check if assembly already has CLSCompliant attribute (must be actual attribute, not comment)
    cls_compliant_patterns = [
        r'^\s*\[assembly\s*:\s*CLSCompliant\s*\(\s*true\s*\)\s*\]',
        r'^\s*\[assembly\s*:\s*System\.CLSCompliant\s*\(\s*true\s*\)\s*\]'
    ]
    
    lines = source_code.split('\n')
    for line in lines:
        line = line.strip()
        if line.startswith('//') or line.startswith('/*'):
            continue  # Skip comments
            
        for pattern in cls_compliant_patterns:
            if re.search(pattern, line, re.IGNORECASE):
                # Assembly is already marked as CLS compliant, no violations
                return findings
    
    # Assembly is not marked as CLS compliant, check for public types
    # Parse from source lines to find public types, excluding comments and strings
    for line_num, line in enumerate(lines, 1):
        original_line = line
        line_clean = line.strip()
        
        # Skip comments and empty lines
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*'):
            continue
        
        # Advanced string literal detection - skip lines inside string literals
        if '"' in original_line:
            # More robust string detection: check if entire line is inside a string
            in_string = False
            escaped = False
            for char in original_line:
                if char == '\\' and not escaped:
                    escaped = True
                    continue
                elif char == '"' and not escaped:
                    in_string = not in_string
                escaped = False
            
            # If we end up in a string state, or if 'public class' appears within quotes, skip
            if in_string:
                continue
                
            # Additional check: if 'public class' pattern appears between quotes on same line
            string_content_matches = re.findall(r'"([^"]*public[^"]*class[^"]*)"', original_line, re.IGNORECASE)
            if string_content_matches:
                continue
                
        # Check for public type declarations with stricter validation
        type_declaration_pattern = r'\bpublic\s+(?:static\s+)?(?:partial\s+)?(?:abstract\s+)?(class|interface|struct|delegate)\s+(\w+)'
        match = re.search(type_declaration_pattern, line_clean, re.IGNORECASE)
        
        if match:
            # Verify this is a real type declaration by checking for proper syntax
            # Must be at start of line (after whitespace) or after namespace/accessibility
            line_before_public = line_clean[:match.start()].strip()
            if line_before_public and not re.match(r'^(?:namespace\s+\w+\s*{)?$', line_before_public):
                # There's non-namespace content before 'public', likely not a type declaration
                continue
            
            # For C# class declarations, the opening brace may be on the next line
            has_opening_brace = False
            if '{' in original_line or original_line.strip().endswith(';'):
                has_opening_brace = True
            else:
                # Look ahead up to 3 lines for the opening brace
                for lookahead in range(1, min(4, len(lines) - line_num + 1)):
                    next_line_idx = line_num - 1 + lookahead
                    if next_line_idx < len(lines):
                        next_line = lines[next_line_idx].strip()
                        if next_line == '{' or next_line.startswith('{'):
                            has_opening_brace = True
                            break
                        elif next_line and not next_line.startswith('//'):
                            # If we hit non-comment, non-brace content, stop looking
                            break
            
            if has_opening_brace:
                type_kind = match.group(1)
                type_name = match.group(2)
                
                findings.append({
                    'rule_id': 'assemblies_marked_as_cls',
                    'message': 'Assembly should be marked with [assembly:CLSCompliant(true)] when it contains public types.',
                    'line': line_num,
                    'severity': 'Major',
                    'node': f'{type_kind.title()}Declaration.{type_name}',
                    'status': 'violation'
                })
    
    return findings


