def check_flags_enum_explicitly_initialize(ast_tree: dict, filename: str) -> list:
    """
    Custom logic for flags_enumerations_should_explicitly_initialize.
    Checks if a [Flags] enum has members after the first three that are not explicitly initialized.
    The first three members (0, 1, 2) naturally match powers of two, so they're allowed.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    import re
    # Find [Flags] enums
    flags_enum_pattern = r'\[Flags\]\s*enum\s+(\w+)'
    for match in re.finditer(flags_enum_pattern, source):
        enum_name = match.group(1)
        # Find enum block
        enum_block_pattern = rf'enum\s+{enum_name}\s*{{([^}}]*)}}'
        block_match = re.search(enum_block_pattern, source, re.DOTALL)
        if not block_match:
            continue
        members = block_match.group(1)
        # Split members by comma, but handle multi-line members
        member_lines = []
        current_member = ''
        for char in members:
            current_member += char
            if char == ',':
                member_lines.append(current_member.strip())
                current_member = ''
        if current_member.strip():
            member_lines.append(current_member.strip())
        
        # Check members after the first three
        for i, member in enumerate(member_lines):
            if i < 3:
                continue  # First three are OK
            # Check if member has explicit value assignment
            if '=' not in member:
                # Member doesn't have explicit value - violation
                member_name_match = re.search(r'(\w+)', member)
                if member_name_match:
                    member_name = member_name_match.group(1)
                    findings.append({
                        'rule_id': 'flags_enumerations_explicitly_initialize',
                        'message': f"[Flags] enum '{enum_name}' member '{member_name}' (4th+ member) should be explicitly initialized to a power of 2",
                        'file': filename,
                        'severity': 'Major',
                        'node': f'EnumDeclaration.{enum_name}',
                        'status': 'violation',
                        'property_path': ['EnumDeclaration', enum_name, member_name],
                        'value': member.strip(),
                    })
    return findings

def check_flags_enum_zero_value_member_named_none(ast_tree: dict, filename: str) -> list:
    """
    Custom logic for flags_enumerations_zero_value_members_should_be_na.
    Checks if a [Flags] enum has a zero-value member named 'None' (case-insensitive).
    Returns a finding if not present.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    import re
    # Find [Flags] enums
    flags_enum_pattern = r'\[Flags\]\s*enum\s+(\w+)'
    for match in re.finditer(flags_enum_pattern, source):
        enum_name = match.group(1)
        # Find enum block
        enum_block_pattern = rf'enum\s+{enum_name}\s*{{([^}}]*)}}'
        block_match = re.search(enum_block_pattern, source, re.DOTALL)
        if not block_match:
            continue
        members = block_match.group(1)
        # Look for zero-value member named 'None'
        zero_member_pattern = r'(\w+)\s*=\s*0'
        found_none = False
        for member_match in re.finditer(zero_member_pattern, members):
            member_name = member_match.group(1)
            if member_name.strip().lower() == 'none':
                found_none = True
                break
        if not found_none:
            findings.append({
                'rule_id': 'flags_enumerations_zero_value_members_should_be_na',
                'message': f"[Flags] enum '{enum_name}' does not have a zero-value member named 'None' (case-insensitive)",
                'file': filename,
                'severity': 'Major',
                'node': f'EnumDeclaration.{enum_name}',
                'status': 'violation',
                'property_path': ['EnumDeclaration', enum_name],
                'value': members.strip(),
            })
    return findings

def check_fieldlike_events_virtual(ast_tree, filename):
    """
    Custom logic for field-like events should not be virtual rule.
    
    Field-like events are events without explicit add/remove accessors.
    When virtual, they create separate delegate instances in derived classes.
    
    Should detect: public virtual event EventHandler MyEvent;
    Should NOT detect: 
    - Events with explicit add/remove accessors
    - Comments containing "virtual event"
    - String literals containing "virtual event"
    - Non-virtual events
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, 1):
        original_line = line
        line_clean = line.strip()
        
        # Skip empty lines
        if not line_clean:
            continue
            
        # Skip comment lines
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
            
        # Skip lines that are entirely within string literals
        if is_line_in_string_literal(original_line):
            continue
        
        # Look for virtual event declarations
        import re
        # Enhanced pattern to match:
        # - virtual event with simple types: virtual event EventHandler MyEvent;
        # - virtual event with generic types: virtual event Action<string> MyEvent;
        # - virtual event with complex generic types: virtual event EventHandler<CustomArgs> MyEvent;
        # - override event (also creates separate delegate): override event EventHandler MyEvent;
        virtual_event_pattern = r'\b(?:virtual|override)\s+event\s+([\w<>.,\s]+)\s+(\w+)\s*;'
        match = re.search(virtual_event_pattern, line)
        
        if match:
            # Verify this is not within a comment on the line
            comment_pos = line.find('//')
            if comment_pos != -1 and match.start() >= comment_pos:
                continue  # Match is in a comment
            
            # Verify this is not within a string literal
            if is_match_in_string_literal(line, match.start(), match.end()):
                continue
                
            # Verify this is not an event with explicit add/remove accessors
            # Check if this line or subsequent lines contain { add remove }
            has_explicit_accessors = False
            
            # Check current line for accessors
            if '{' in line[match.end():]:
                remaining_line = line[match.end():]
                if 'add' in remaining_line and 'remove' in remaining_line:
                    has_explicit_accessors = True
            
            # Check next few lines for accessors if opening brace is found
            if '{' in line[match.end():] and not has_explicit_accessors:
                for next_line_idx in range(line_num, min(line_num + 10, len(lines))):
                    next_line = lines[next_line_idx].strip()
                    if 'add' in next_line and 'remove' in next_line:
                        has_explicit_accessors = True
                        break
                    if '}' in next_line:
                        break  # End of event declaration
                        
            if not has_explicit_accessors:
                findings.append({
                    'rule_id': 'fieldlike_events_virtual',
                    'message': 'Field-like events should not be virtual. Virtual field-like events create separate delegate instances in derived classes.',
                    'line': line_num,
                    'severity': 'Major',
                    'node': 'EventDeclaration',
                    'status': 'violation',
                    'file': filename,
                    'property_path': ['source'],
                    'value': line_clean
                })
    
    return findings


def is_line_in_string_literal(line):
    """
    Check if the entire line is within a string literal.
    Simple heuristic: count quotes and check if we end up inside a string.
    """
    in_string = False
    escape_next = False
    
    for char in line:
        if escape_next:
            escape_next = False
            continue
            
        if char == '\\':
            escape_next = True
            continue
            
        if char == '"' and not escape_next:
            in_string = not in_string
            
    return in_string


def is_match_in_string_literal(line, start_pos, end_pos):
    """
    Check if a regex match position is within a string literal.
    """
    # Count quotes before the match
    before_match = line[:start_pos]
    quote_count = 0
    escape_next = False
    
    for char in before_match:
        if escape_next:
            escape_next = False
            continue
            
        if char == '\\':
            escape_next = True
            continue
            
        if char == '"' and not escape_next:
            quote_count += 1
    
    # If odd number of quotes, we're inside a string
    return quote_count % 2 == 1


def check_fields_private(ast_tree_or_node, filename=None):
    """
    Detect non-private fields (public, protected, internal) that break encapsulation.
    Excludes properties, const fields, readonly fields, and events.
    
    This function supports two calling conventions:
    1. check_fields_private(ast_tree, filename) - full tree analysis
    2. check_fields_private(node) - single node analysis (fallback)
    """
    import re  # Ensure re module is available
    
    # Handle single-node calling convention (fallback mode)
    if filename is None and isinstance(ast_tree_or_node, dict) and 'source' in ast_tree_or_node:
        # This is a single node, analyze just this node
        node = ast_tree_or_node
        source = node.get('source', '')
        if not source:
            return False
            
        # Check for non-private field patterns
        pattern = r'\b(public|protected|internal)\s+(?:(static)\s+)?(\w+|\w+<[^>]+>|\w+\[\])\s+(\w+)\s*(?:=([^;]+))?\s*;'
        matches = re.finditer(pattern, source, re.MULTILINE | re.DOTALL)
        
        for match in matches:
            # Skip if it's a property, const, readonly, event, etc.
            if ('{' in match.group(0) or '=>' in match.group(0) or
                re.search(r'\b(const|readonly|event|class|interface|struct|enum)\b', match.group(0))):
                continue
            return True  # Found a violation
        
        return False  # No violations in this node
    
    # Handle full tree analysis (main mode)
    ast_tree = ast_tree_or_node
    if filename is None:
        filename = 'unknown'
    
    findings = []
    
    def extract_line_number(source_code, start_line_num):
        """Extract line number from source code context"""
        if not source_code or not isinstance(source_code, str):
            return start_line_num
        
        lines = source_code.split('\n')
        for i, line in enumerate(lines, start=start_line_num):
            if line.strip():
                return i
        return start_line_num

    def is_in_comment_or_string(source, target_text):
        """Check if target text is within comments or string literals"""
        lines = source.split('\n')
        for line in lines:
            if target_text in line:
                stripped = line.strip()
                # Skip comment lines
                if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*') or stripped.startswith('///'):
                    continue
                # Skip if target is within string literals
                if ('"' in line and target_text in line):
                    # Check if target is within quotes
                    parts = line.split('"')
                    for i in range(1, len(parts), 2):  # Check odd indices (inside quotes)
                        if target_text in parts[i]:
                            return True
                return False
        return False

    # Enhanced pattern to handle complex C# types including generics
    pattern = r'\b(public|protected|internal)\s+(?:(static)\s+)?(\w+|\w+<[^>]+>|\w+\[\])\s+(\w+)\s*(?:=([^;]+))?\s*;'
    
    for node_type, nodes in ast_tree.items():
        if node_type in ["ClassDeclaration", "StructDeclaration"]:
            for node in nodes:
                source = node.get('source', '')
                if not source:
                    continue
                
                # Skip if this is within comments or strings
                if is_in_comment_or_string(source, 'public ') or is_in_comment_or_string(source, 'protected ') or is_in_comment_or_string(source, 'internal '):
                    continue
                
                start_line = node.get('start_line', 1)
                
                matches = re.finditer(pattern, source, re.MULTILINE | re.DOTALL)
                
                for match in matches:
                    accessibility, static_modifier, field_type, field_name, initializer = match.groups()
                    
                    # Skip if it's a property (contains { or =>)
                    if '{' in match.group(0) or '=>' in match.group(0):
                        continue
                    
                    # Skip const and readonly fields
                    if re.search(r'\b(const|readonly)\b', match.group(0)):
                        continue
                    
                    # Skip events
                    if re.search(r'\bevent\b', match.group(0)):
                        continue
                    
                    # Skip class/interface/struct/enum declarations
                    if re.search(r'\b(class|interface|struct|enum)\b', match.group(0)):
                        continue
                    
                    # Calculate line number
                    text_before_match = source[:match.start()]
                    line_offset = text_before_match.count('\n')
                    line_num = start_line + line_offset
                    
                    # Clean up the field type
                    field_type_clean = re.sub(r'\s+', ' ', field_type.strip())
                    
                    findings.append({
                        'rule_id': 'fields_private',
                        'message': f'Fields should be private. Consider making this field private and exposing it through a property instead.',
                        'file': filename,
                        'line': line_num,
                        'severity': 'Major',
                        'node': 'FieldDeclaration',
                        'status': 'violation',
                        'property_path': ['source'],
                        'value': match.group(0).strip(),
                        'context': {
                            'field_name': field_name,
                            'field_type': field_type_clean,
                            'accessibility': accessibility,
                            'is_static': bool(static_modifier),
                            'has_initializer': bool(initializer and initializer.strip())
                        }
                    })
    
    return findings

    """
    Custom logic for fields should avoid having public accessibility rule.
    
    Detects public fields (not properties, not const, not readonly) that break encapsulation.
    
    Should detect:
    - public int Data = 42;
    - public string Name;
    - public List<T> Items;
    
    Should NOT detect:
    - public int Data { get; set; } (properties)
    - public const int MaxValue = 100; (const fields)
    - public readonly string Id; (readonly fields)
    - private/protected/internal fields
    - comments containing public fields
    - string literals containing public fields
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip empty lines
        if not line_clean:
            continue
            
        # Skip comment lines
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
            
        # Skip lines that are entirely within string literals
        if is_line_in_string_literal(line):
            continue
        
        # Look for public field declarations
        # Pattern: public [static] type fieldName [= value];
        import re
        
        # Enhanced pattern to handle generic types and various modifiers
        public_field_pattern = r'\bpublic\s+(?:(static)\s+)?([\w<>.,\[\]\s]+)\s+(\w+)\s*(?:=([^;]+))?\s*;'
        match = re.search(public_field_pattern, line)
        
        if match:
            # Verify this is not within a comment on the line
            comment_pos = line.find('//')
            if comment_pos != -1 and match.start() >= comment_pos:
                continue  # Match is in a comment
            
            # Verify this is not within a string literal
            if is_match_in_string_literal(line, match.start(), match.end()):
                continue
            
            is_static = match.group(1) is not None
            type_part = match.group(2).strip()
            field_name = match.group(3)
            initializer = match.group(4)
            
            # Skip if it contains const or readonly keywords
            if 'const' in line or 'readonly' in line:
                continue
                
            # Skip if it's a property (contains { get/set })
            if '{' in line and ('get' in line or 'set' in line):
                continue
                
            # Skip if it's an expression-bodied property (contains =>)
            if '=>' in line:
                continue
                
            # Skip if it's a class, interface, enum, or struct declaration
            if any(keyword in line for keyword in ['class ', 'interface ', 'enum ', 'struct ']):
                continue
            
            # This is a public field violation
            findings.append({
                'rule_id': 'fields_avoid_having_public',
                'message': 'Public fields break encapsulation. Use properties with proper get/set accessors instead.',
                'line': line_num,
                'severity': 'Major',
                'node': 'FieldDeclaration',
                'status': 'violation',
                'file': filename,
                'property_path': ['source'],
                'value': line_clean,
                'context': {
                    'field_name': field_name,
                    'field_type': type_part,
                    'is_static': is_static,
                    'has_initializer': initializer is not None
                }
            })
    
    return findings

def check_context_aware_lock_mismatches(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Context-aware logic for write_lock_released_when rule.
    Tracks lock acquisition and release patterns to detect actual mismatches
    while avoiding false positives from correct usage.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Define lock patterns
    acquisition_patterns = {
        'write_lock': [
            r'\.AcquireWriterLock\s*\(',
            r'\.UpgradeToWriterLock\s*\(',
            r'\.EnterWriteLock\s*\(',
            r'\.TryEnterWriteLock\s*\('
        ],
        'read_lock': [
            r'\.AcquireReaderLock\s*\(',
            r'\.DowngradeFromWriterLock\s*\(',
            r'\.EnterReadLock\s*\(',
            r'\.TryEnterReadLock\s*\(',
            r'\.EnterUpgradeableReadLock\s*\(',
            r'\.TryEnterUpgradeableReadLock\s*\('
        ]
    }
    
    release_patterns = {
        'write_lock': [
            r'\.ReleaseWriterLock\s*\(',
            r'\.ExitWriteLock\s*\('
        ],
        'read_lock': [
            r'\.ReleaseReaderLock\s*\(',
            r'\.ExitReadLock\s*\('
        ]
    }
    
    # Track lock state per object within method scope
    lock_state = {}  # {object_name: {lock_type: str, line: int}}
    current_method_depth = 0
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments and empty lines
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Track method boundaries
        if re.search(r'\b(public|private|protected|internal)\s+.*\(.*\)\s*$', line_clean):
            current_method_depth += 1
            # Clear lock state on new method (simple scope tracking)
            lock_state.clear()
        
        # Extract object name from lock operations
        def extract_object_name(line_text):
            # Look for pattern: objectName.LockMethod
            match = re.search(r'(\w+)\.(?:Acquire|Enter|Release|Exit|Upgrade|Downgrade)', line_text)
            return match.group(1) if match else 'unknown'
        
        # Check for lock acquisitions
        for lock_type, patterns in acquisition_patterns.items():
            for pattern in patterns:
                if re.search(pattern, line):
                    obj_name = extract_object_name(line)
                    
                    # Skip method name patterns (like LogReleaseReaderLock)
                    if re.search(r'(Log|Process|Handle|Check).*Lock', line):
                        continue
                        
                    # Skip string literals
                    if '"' in line and re.search(pattern, line.split('"')[1] if '"' in line else ''):
                        continue
                    
                    # Store the lock state for this object
                    lock_state[obj_name] = {
                        'lock_type': lock_type,
                        'line': line_num,
                        'operation': 'acquire'
                    }
                    break
        
        # Check for lock releases
        for lock_type, patterns in release_patterns.items():
            for pattern in patterns:
                if re.search(pattern, line):
                    obj_name = extract_object_name(line)
                    
                    # Skip method name patterns
                    if re.search(r'(Log|Process|Handle|Check).*Lock', line):
                        continue
                    
                    # Skip string literals
                    if '"' in line and re.search(pattern, line.split('"')[1] if '"' in line else ''):
                        continue
                    
                    # Check if we have acquisition state for this object
                    if obj_name in lock_state:
                        acquired_type = lock_state[obj_name]['lock_type']
                        acquired_line = lock_state[obj_name]['line']
                        
                        # Check for mismatch
                        if acquired_type != lock_type:
                            violation_msg = f"{acquired_type.replace('_', ' ').title()} acquired at line {acquired_line} but {lock_type.replace('_', ' ')} released - lock type mismatch"
                            
                            findings.append({
                                'rule_id': 'write_lock_released_when',
                                'message': violation_msg,
                                'file': filename,
                                'line': line_num,
                                'severity': 'Major',
                                'property_path': ['CallExpression', 'name'],
                                'value': line_clean,
                                'node': f'CallExpression.{obj_name}',
                                'status': 'violation',
                                'context': {
                                    'acquired_line': acquired_line,
                                    'acquired_type': acquired_type,
                                    'released_type': lock_type,
                                    'object_name': obj_name
                                }
                            })
                        
                        # Clear state after release (simple tracking)
                        del lock_state[obj_name]
                    break
    
    return findings
def check_abstract_class_public_constructors(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Context-aware logic for abstract_classes_avoid_having rule.
    Identifies public constructors within abstract class scope while avoiding
    false positives from regular classes, comments, and string literals.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code from various possible keys
    source = ast_tree.get('source_code', '') or ast_tree.get('source', '') or ast_tree.get('content', '')
    if not source:
        # Try to reconstruct from lines if available
        lines_data = ast_tree.get('lines', [])
        if lines_data:
            source = '\n'.join(lines_data)
        else:
            return findings
    
    lines = source.split('\n')
    
    # Track abstract classes and their constructors
    abstract_classes = {}  # {class_name: {'line': int, 'start_brace': int, 'end_brace': int}}
    current_abstract_class = None
    brace_level = 0
    
    # First pass: identify abstract class declarations and their scope
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments and empty lines
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Count braces to track scope
        brace_level += line.count('{') - line.count('}')
        
        # Look for abstract class declarations
        abstract_match = re.search(r'public\s+abstract\s+class\s+(\w+)', line)
        if not abstract_match:
            abstract_match = re.search(r'abstract\s+class\s+(\w+)', line)
        
        if abstract_match:
            class_name = abstract_match.group(1)
            abstract_classes[class_name] = {
                'line': line_num,
                'start_brace_level': brace_level,
                'class_name': class_name
            }
            current_abstract_class = class_name
        
        # Track when we exit a class (simplified scope tracking)
        if current_abstract_class and brace_level == abstract_classes[current_abstract_class]['start_brace_level'] - 1:
            current_abstract_class = None
    
    # Second pass: find public constructors within abstract classes
    current_abstract_class = None
    brace_level = 0
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments, empty lines, and string literals
        if (not line_clean or 
            line_clean.startswith('//') or 
            line_clean.startswith('/*') or 
            line_clean.startswith('*') or
            '"' in line_clean):
            continue
        
        # Update brace level
        brace_level += line.count('{') - line.count('}')
        
        # Check if we're entering an abstract class scope
        for class_name, class_info in abstract_classes.items():
            if line_num == class_info['line']:
                current_abstract_class = class_name
                break
        
        # Check if we're exiting the current abstract class
        if current_abstract_class and current_abstract_class in abstract_classes:
            if brace_level < abstract_classes[current_abstract_class]['start_brace_level']:
                current_abstract_class = None
        
        # Look for public constructors only within abstract class scope
        if current_abstract_class:
            # Enhanced pattern matching for all public constructor types
            constructor_patterns = [
                rf'public\s+{re.escape(current_abstract_class)}\s*\(',  # Default: public ClassName()
                rf'public\s+{re.escape(current_abstract_class)}\s*\([^)]+\)',  # Parameterized: public ClassName(params)
                r'public\s+\w+\s*\([^)]*\)\s*(?::\s*\w+\([^)]*\))?\s*\{'  # Generic pattern with optional base call
            ]
            
            for pattern in constructor_patterns:
                if re.search(pattern, line):
                    # Extract constructor name to verify it matches current abstract class
                    constructor_match = re.search(r'public\s+(\w+)\s*\(', line)
                    if constructor_match:
                        constructor_name = constructor_match.group(1)
                        
                        # Verify it matches the current abstract class name
                        if constructor_name == current_abstract_class:
                            # Verify this is actually a constructor, not a method
                            # Check for method return types BEFORE the constructor name, not in parameters
                            method_pattern = rf'\b(void|string|int|bool|object|double|float|decimal)\s+{re.escape(constructor_name)}\s*\('
                            is_method = re.search(method_pattern, line)
                            
                            if not is_method:
                                # Check if we already flagged this exact line to avoid duplicates
                                already_flagged = any(f['line'] == line_num for f in findings)
                                if not already_flagged:
                                    findings.append({
                                        'rule_id': 'abstract_classes_avoid_having',
                                        'message': f'Public constructor in abstract class {current_abstract_class} - consider using protected or private visibility',
                                        'file': filename,
                                        'line': line_num,
                                        'severity': 'Major',
                                        'property_path': ['ClassDeclaration', 'constructor'],
                                        'value': line_clean,
                                        'node': f'Constructor.{current_abstract_class}',
                                        'status': 'violation',
                                        'context': {
                                            'class_name': current_abstract_class,
                                            'class_line': abstract_classes[current_abstract_class]['line'],
                                            'constructor_visibility': 'public',
                                            'recommendation': 'Change to protected or private'
                                        }
                                    })
                                break  # Found a match, move to next line
    
    return findings


def check_context_aware_action_result_methods(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Context-aware check for controller methods returning IActionResult/IResult without ProducesResponseType.
    
    This function:
    1. Identifies controller classes (inherit from ControllerBase or Controller)
    2. Finds HTTP method attributes ([HttpGet], [HttpPost], etc.)
    3. Checks if methods return IActionResult or IResult
    4. Verifies ProducesResponseType attribute is missing
    5. Excludes abstract methods, interfaces, and non-controller classes
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Track controller classes and their scopes
    controller_classes = {}
    in_controller_class = None
    brace_depth = 0
    class_start_depth = 0
    
    # Identify controller classes
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Track brace depth for scope
        brace_depth += line.count('{') - line.count('}')
        
        # Check for controller class declarations (including generic controllers)
        controller_match = re.search(r'class\s+(\w+)(?:<[^>]*>)?\s*:\s*(ControllerBase|Controller)\b', line)
        if controller_match:
            class_name = controller_match.group(1)
            controller_classes[class_name] = {
                'line': line_num,
                'start_depth': brace_depth,
                'name': class_name
            }
            in_controller_class = class_name
            class_start_depth = brace_depth
            continue
            
        # Check if we've left the current controller class
        if in_controller_class and brace_depth < class_start_depth:
            in_controller_class = None
    
    # Now scan for problematic methods within controller classes
    in_controller_class = None
    brace_depth = 0
    class_start_depth = 0
    pending_http_attribute = None
    pending_attributes = []
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Track brace depth
        brace_depth += line.count('{') - line.count('}')
        
        # Determine current controller context (including generic controllers)
        controller_match = re.search(r'class\s+(\w+)(?:<[^>]*>)?\s*:\s*(ControllerBase|Controller)\b', line)
        if controller_match:
            class_name = controller_match.group(1)
            if class_name in controller_classes:
                in_controller_class = class_name
                class_start_depth = brace_depth
                pending_http_attribute = None
                pending_attributes = []
            continue
            
        # Check if we've left the current controller class
        if in_controller_class and brace_depth < class_start_depth:
            in_controller_class = None
            pending_http_attribute = None
            pending_attributes = []
            continue
        
        # Skip if not in a controller class
        if not in_controller_class:
            continue
            
        # Skip abstract classes, interfaces, and comments
        if re.search(r'(abstract\s+class|interface\s+\w+|^\s*/[/*])', line):
            continue
            
        # Track HTTP method attributes
        http_attr_match = re.search(r'\[Http(Get|Post|Put|Delete|Patch|Head|Options)', line, re.IGNORECASE)
        if http_attr_match:
            pending_http_attribute = line_num
            pending_attributes = [line_clean]
            continue
            
        # Track other attributes (including ProducesResponseType)
        if line_clean.startswith('[') and pending_http_attribute:
            pending_attributes.append(line_clean)
            continue
            
        # Look for method declarations with IActionResult or IResult
        action_result_pattern = r'(?:public\s+)?(?:async\s+)?(?:Task<)?(IActionResult|IResult)(?:>)?\s+(\w+)\s*\('
        method_match = re.search(action_result_pattern, line)
        
        if method_match and pending_http_attribute:
            return_type = method_match.group(1)
            method_name = method_match.group(2)
            
            # Check if this is an abstract method (skip if so)
            if re.search(r'abstract\s+', line):
                pending_http_attribute = None
                pending_attributes = []
                continue
                
            # Check for ProducesResponseType attribute in pending attributes
            has_produces_response_type = any(
                'ProducesResponseType' in attr for attr in pending_attributes
            )
            
            if not has_produces_response_type:
                findings.append({
                    'rule_id': 'actions_that_return_value',
                    'message': f'Method {method_name} returns {return_type} but lacks ProducesResponseType attribute',
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['MethodDeclaration', method_name],
                    'value': line_clean,
                    'node': f'MethodDeclaration.{in_controller_class}.{method_name}',
                    'status': 'violation',
                    'context': {
                        'class_name': in_controller_class,
                        'method_name': method_name,
                        'return_type': return_type,
                        'http_attribute_line': pending_http_attribute,
                        'attributes': pending_attributes
                    }
                })
            
            # Reset for next method
            pending_http_attribute = None
            pending_attributes = []
            
        # Also check for Task<IActionResult> and Task<IResult> patterns more explicitly
        elif pending_http_attribute and re.search(r'Task<(IActionResult|IResult)>\s+(\w+)\s*\(', line):
            task_match = re.search(r'Task<(IActionResult|IResult)>\s+(\w+)\s*\(', line)
            if task_match:
                return_type = f"Task<{task_match.group(1)}>"
                method_name = task_match.group(2)
                
                # Check if this is an abstract method (skip if so)
                if re.search(r'abstract\s+', line):
                    pending_http_attribute = None
                    pending_attributes = []
                    continue
                    
                # Check for ProducesResponseType attribute in pending attributes
                has_produces_response_type = any(
                    'ProducesResponseType' in attr for attr in pending_attributes
                )
                
                if not has_produces_response_type:
                    findings.append({
                        'rule_id': 'actions_that_return_value',
                        'message': f'Method {method_name} returns {return_type} but lacks ProducesResponseType attribute',
                        'file': filename,
                        'line': line_num,
                        'severity': 'Major',
                        'property_path': ['MethodDeclaration', method_name],
                        'value': line_clean,
                        'node': f'MethodDeclaration.{in_controller_class}.{method_name}',
                        'status': 'violation',
                        'context': {
                            'class_name': in_controller_class,
                            'method_name': method_name,
                            'return_type': return_type,
                            'http_attribute_line': pending_http_attribute,
                            'attributes': pending_attributes
                        }
                    })
                
                # Reset for next method
                pending_http_attribute = None
                pending_attributes = []
            
        elif not re.search(r'^\s*\[', line) and line_clean and pending_http_attribute:
            # Non-attribute line found, reset pending attributes if it's not a method
            if not re.search(action_result_pattern, line) and not re.search(r'Task<(IActionResult|IResult)>\s+(\w+)\s*\(', line):
                pending_http_attribute = None
                pending_attributes = []
    
    return findings


def check_all_branches_conditional_structure(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for all_branches_conditional_structure rule.
    Detects when all branches in a conditional structure have identical implementations.
    Handles if-else, switch statements, and ternary operators.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code if available
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Check if-else structures
    findings.extend(_check_if_else_identical(source, lines))
    
    # Check switch statements
    findings.extend(_check_switch_identical(source, lines))
    
    # Check ternary operators
    findings.extend(_check_ternary_identical(source, lines))
    
    return findings


def _check_if_else_identical(source: str, lines: List[str]) -> List[Dict]:
    """Check if-else structures for identical implementations"""
    findings = []
    
    # Pattern to match if-else blocks
    if_else_pattern = r'if\s*\([^)]+\)\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\}\s*else\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\}'
    
    for match in re.finditer(if_else_pattern, source, re.DOTALL):
        if_content = match.group(1).strip()
        else_content = match.group(2).strip()
        
        # Normalize whitespace for comparison
        if_normalized = re.sub(r'\s+', ' ', if_content).strip()
        else_normalized = re.sub(r'\s+', ' ', else_content).strip()
        
        # Check if contents are identical (ignoring whitespace differences)
        if if_normalized and else_normalized and if_normalized == else_normalized:
            line_num = source[:match.start()].count('\n') + 1
            
            findings.append({
                'rule_id': 'all_branches_conditional_structure',
                'message': 'All branches in conditional structure have identical implementation',
                'line': line_num,
                'severity': 'Major',
                'node': 'IfElseStatement',
                'status': 'violation'
            })
    
    # Check else-if chains
    findings.extend(_check_else_if_chains(source, lines))
    
    return findings


def _check_else_if_chains(source: str, lines: List[str]) -> List[Dict]:
    """Check else-if chains for identical implementations"""
    findings = []
    
    # Pattern to match else-if chains
    else_if_pattern = r'if\s*\([^)]+\)\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\}(?:\s*else\s+if\s*\([^)]+\)\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\})+(?:\s*else\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\})?'
    
    for match in re.finditer(else_if_pattern, source, re.DOTALL):
        # Extract all branch contents
        full_match = match.group(0)
        
        # Find all individual branches
        branch_pattern = r'(?:if|else\s+if|else)\s*(?:\([^)]+\))?\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\}'
        branches = []
        
        for branch_match in re.finditer(branch_pattern, full_match):
            content = branch_match.group(1).strip()
            normalized = re.sub(r'\s+', ' ', content).strip()
            if normalized:  # Only consider non-empty branches
                branches.append(normalized)
        
        # Check if all branches are identical
        if len(branches) >= 2 and len(set(branches)) == 1:  # All branches are the same
            line_num = source[:match.start()].count('\n') + 1
            
            findings.append({
                'rule_id': 'all_branches_conditional_structure',
                'message': f'All {len(branches)} branches in conditional chain have identical implementation',
                'line': line_num,
                'severity': 'Major',
                'node': 'ElseIfChain',
                'status': 'violation'
            })
    
    return findings


def _check_switch_identical(source: str, lines: List[str]) -> List[Dict]:
    """Check switch statements for identical implementations"""
    findings = []
    
    # Pattern to match switch statements
    switch_pattern = r'switch\s*\([^)]+\)\s*\{(.*?)\}'
    
    for match in re.finditer(switch_pattern, source, re.DOTALL):
        switch_body = match.group(1)
        
        # Extract case contents
        case_pattern = r'case\s+[^:]+:|default\s*:'
        case_splits = re.split(case_pattern, switch_body)[1:]  # Skip the part before first case
        
        case_contents = []
        for case_content in case_splits:
            # Remove break statements and normalize
            content = re.sub(r'\s*break\s*;?\s*', '', case_content.strip())
            normalized = re.sub(r'\s+', ' ', content).strip()
            if normalized:  # Only consider non-empty cases
                case_contents.append(normalized)
        
        # Check if all cases are identical
        if len(case_contents) >= 2 and len(set(case_contents)) == 1:
            line_num = source[:match.start()].count('\n') + 1
            
            findings.append({
                'rule_id': 'all_branches_conditional_structure',
                'message': f'All {len(case_contents)} cases in switch statement have identical implementation',
                'line': line_num,
                'severity': 'Major',
                'node': 'SwitchStatement',
                'status': 'violation'
            })
    
    return findings


def _check_ternary_identical(source: str, lines: List[str]) -> List[Dict]:
    """Check ternary operators for identical results"""
    findings = []
    
    # Pattern to match ternary operators
    ternary_pattern = r'([^?]+)\?\s*([^:]+)\s*:\s*([^;,\)\}]+)'
    
    for match in re.finditer(ternary_pattern, source):
        true_result = match.group(2).strip()
        false_result = match.group(3).strip()
        
        # Normalize for comparison
        true_normalized = re.sub(r'\s+', ' ', true_result).strip()
        false_normalized = re.sub(r'\s+', ' ', false_result).strip()
        
        # Check if results are identical
        if true_normalized and false_normalized and true_normalized == false_normalized:
            line_num = source[:match.start()].count('\n') + 1
            
            findings.append({
                'rule_id': 'all_branches_conditional_structure', 
                'message': 'Ternary operator has identical results for both conditions',
                'line': line_num,
                'severity': 'Major',
                'node': 'TernaryOperator',
                'status': 'violation'
            })
    
    return findings


def check_datetime_kind_specification(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for always_set_datetimekind_when rule.
    Checks that DateTime constructors specify DateTimeKind parameter
    and DateTime.Parse methods use DateTimeStyles parameter.
    
    This function properly handles:
    - Excluding DateTime constructors that already specify DateTimeKind
    - Excluding DateTime.Now/UtcNow/Today (they have implicit DateTimeKind)  
    - Excluding string literals and comments
    - Excluding DateTime.ParseExact with proper DateTimeStyles
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Pattern for DateTime constructor without DateTimeKind
    datetime_constructor_pattern = r'(?:^|[^"\'].*?)(?:^|[^a-zA-Z0-9_\.])new\s+DateTime\s*\('
    
    # Pattern for DateTime.Parse/TryParse without DateTimeStyles
    datetime_parse_pattern = r'(?:^|[^"\'].*?)(?:^|[^a-zA-Z0-9_])DateTime\s*\.\s*(Parse|TryParse)\s*\('
    
    for line_num, line in enumerate(lines, 1):
        original_line = line
        
        # Skip comments and string literals
        if _is_comment_or_string_literal(line):
            continue
            
        # Skip lines with DateTime.Now/UtcNow/Today (they have implicit DateTimeKind)
        if re.search(r'DateTime\s*\.\s*(Now|UtcNow|Today)', line):
            continue
            
        # Check DateTime constructors
        constructor_matches = re.finditer(datetime_constructor_pattern, line)
        for match in constructor_matches:
            # Get the full constructor call to check parameters
            constructor_start = match.end() - 1  # Position of opening parenthesis
            constructor_call = _extract_balanced_parentheses(line, constructor_start)
            
            if constructor_call:
                # Check if DateTimeKind is specified in the constructor
                if 'DateTimeKind' not in constructor_call and 'DateTimeKind' not in line:
                    findings.append({
                        'rule_id': 'always_set_datetimekind_when',
                        'message': 'DateTime constructor should specify DateTimeKind',
                        'line': line_num,
                        'severity': 'Major', 
                        'node': 'Assignment.unknown',
                        'status': 'violation'
                    })
        
        # Check DateTime.Parse/TryParse methods
        parse_matches = re.finditer(datetime_parse_pattern, line)
        for match in parse_matches:
            # Get the full method call to check parameters
            method_start = line.find('(', match.start())
            if method_start != -1:
                method_call = _extract_balanced_parentheses(line, method_start)
                
                if method_call:
                    # Check if DateTimeStyles is specified
                    # Also check if it's ParseExact with proper DateTimeStyles
                    if ('DateTimeStyles' not in method_call and 'DateTimeStyles' not in line and
                        'ParseExact' not in line):
                        findings.append({
                            'rule_id': 'always_set_datetimekind_when',
                            'message': 'DateTime constructor should specify DateTimeKind',
                            'line': line_num,
                            'severity': 'Major',
                            'node': 'Assignment.unknown', 
                            'status': 'violation'
                        })
    
    return findings


def _is_comment_or_string_literal(line: str) -> bool:
    """Check if line is a comment or contains only string literals with DateTime patterns."""
    stripped = line.strip()
    
    # Single line comment
    if stripped.startswith('//'):
        return True
        
    # Multi-line comment (simple check)
    if '/*' in stripped and '*/' in stripped:
        return True
        
    # Check if DateTime pattern is inside string literals
    in_string = False
    escape_next = False
    quote_char = None
    
    for i, char in enumerate(line):
        if escape_next:
            escape_next = False
            continue
            
        if char == '\\':
            escape_next = True
            continue
            
        if char in ['"', "'"] and not in_string:
            in_string = True
            quote_char = char
        elif char == quote_char and in_string:
            in_string = False
            quote_char = None
            
    # If we find DateTime patterns and they appear to be in strings, skip
    if ('"new DateTime' in line or "'new DateTime" in line or 
        (in_string and ('new DateTime' in line or 'DateTime.Parse' in line))):
        return True
        
    return False


def _extract_balanced_parentheses(text: str, start_pos: int) -> str:
    """Extract text within balanced parentheses starting from start_pos."""
    if start_pos >= len(text) or text[start_pos] != '(':
        return ""
    
    paren_count = 0
    result = ""
    
    for i in range(start_pos, len(text)):
        char = text[i]
        result += char
        
        if char == '(':
            paren_count += 1
        elif char == ')':
            paren_count -= 1
            if paren_count == 0:
                return result
                
    return result  # Unbalanced parentheses


def check_abstract_class_composition(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Enhanced logic for abstract_class_include_both rule.
    
    Only flags abstract classes that have design issues:
    1. Pure abstract classes (only abstract methods/properties) - should use interface instead
    2. Pure concrete classes marked as abstract (only concrete methods) - should not be abstract
    
    Does NOT flag well-designed abstract classes with both abstract and concrete members.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Find all abstract class definitions in the source code
    def find_abstract_classes(node):
        found = []
        if isinstance(node, dict):
            source = node.get('source', '')
            # Look for abstract class declarations that are actual class definitions
            if re.search(r'\babstract\s+class\s+\w+', source) and '{' in source:
                found.append(node)
            
            # Recursively search children
            for value in node.values():
                found.extend(find_abstract_classes(value))
        elif isinstance(node, list):
            for item in node:
                found.extend(find_abstract_classes(item))
        return found
    
    abstract_classes = find_abstract_classes(ast_tree)
    
    # Deduplicate based on class name and position
    unique_classes = {}
    for class_node in abstract_classes:
        source = class_node.get('source', '')
        
        # Extract class name
        name_match = re.search(r'abstract\s+class\s+(\w+)', source)
        if not name_match:
            continue
        
        class_name = name_match.group(1)
        
        # Use class name + approximate line as key for deduplication
        line_num = class_node.get('lineno', class_node.get('line', 1))
        key = f"{class_name}_{line_num}"
        
        if key not in unique_classes or len(source) > len(unique_classes[key].get('source', '')):
            unique_classes[key] = class_node
    
    # Analyze each unique abstract class
    for class_node in unique_classes.values():
        source = class_node.get('source', '')
        
        # Extract class name
        name_match = re.search(r'abstract\s+class\s+(\w+)', source)
        if not name_match:
            continue
        
        class_name = name_match.group(1)
        
        # Extract class body (everything between the first { and last })
        class_body_match = re.search(r'\{(.*)\}', source, re.DOTALL)
        if not class_body_match:
            continue
        
        class_body = class_body_match.group(1)
        
        # Count different types of members in the class body
        abstract_members = 0
        concrete_members = 0
        static_members = 0
        
        # Abstract method patterns
        abstract_patterns = [
            r'public\s+abstract\s+\w+\s+\w+\s*\(',  # abstract methods
            r'protected\s+abstract\s+\w+\s+\w+\s*\(',  # protected abstract methods
            r'internal\s+abstract\s+\w+\s+\w+\s*\(',  # internal abstract methods
            r'public\s+abstract\s+\w+\s+\w+\s*\{[^}]*get;[^}]*set;[^}]*\}',  # abstract properties
            r'public\s+abstract\s+\w+\s+\w+\s*\{[^}]*get;[^}]*\}',  # abstract readonly properties
        ]
        
        # Concrete method patterns (excluding constructors and static)
        concrete_patterns = [
            r'public\s+(?!abstract|static)\w+\s+\w+\s*\([^)]*\)\s*\{',  # public concrete methods
            r'protected\s+(?!abstract|static)\w+\s+\w+\s*\([^)]*\)\s*\{',  # protected concrete methods
            r'internal\s+(?!abstract|static)\w+\s+\w+\s*\([^)]*\)\s*\{',  # internal concrete methods
            r'public\s+virtual\s+\w+\s+\w+\s*\([^)]*\)\s*\{',  # virtual methods
            r'protected\s+virtual\s+\w+\s+\w+\s*\([^)]*\)\s*\{',  # protected virtual methods
            r'public\s+\w+\s+\w+\s*\{\s*(get\s*\{[^}]+\}|set\s*\{[^}]+\})',  # properties with implementation
        ]
        
        # Static member patterns
        static_patterns = [
            r'public\s+static\s+\w+\s+\w+\s*[\({]',  # static methods/properties
            r'private\s+static\s+\w+\s+\w+\s*[\({]',  # private static methods/properties
            r'internal\s+static\s+\w+\s+\w+\s*[\({]',  # internal static methods/properties
        ]
        
        # Count abstract members
        for pattern in abstract_patterns:
            abstract_members += len(re.findall(pattern, class_body, re.MULTILINE))
        
        # Count concrete members (excluding constructors)
        for pattern in concrete_patterns:
            matches = re.findall(pattern, class_body, re.MULTILINE)
            # Filter out constructors (method name matches class name)
            concrete_members += len([m for m in matches if class_name.lower() not in str(m).lower()])
        
        # Count static members
        for pattern in static_patterns:
            static_members += len(re.findall(pattern, class_body, re.MULTILINE))
        
        # Determine if this is a violation based on method composition
        violation_type = None
        message = None
        
        if abstract_members > 0 and concrete_members == 0:
            # Pure abstract class - should be interface
            violation_type = "pure_abstract"
            message = f"Abstract class '{class_name}' contains only abstract methods ({abstract_members}) and should be an interface instead"
        elif abstract_members == 0 and concrete_members > 0:
            # Pure concrete class marked as abstract - should not be abstract
            violation_type = "pure_concrete"
            message = f"Abstract class '{class_name}' contains only concrete methods ({concrete_members}) and should not be marked as abstract"
        elif abstract_members == 0 and concrete_members == 0 and static_members > 0:
            # Only static members - should not be abstract
            violation_type = "static_only"
            message = f"Abstract class '{class_name}' contains only static members ({static_members}) and should not be marked as abstract"
        # If abstract_members > 0 and concrete_members > 0, it's a well-designed abstract class - NO violation
        
        # Only report violations, not well-designed abstract classes
        if violation_type and message:
            line_number = class_node.get('lineno', class_node.get('line', 1))
            
            finding = {
                'rule_id': 'abstract_class_include_both',
                'message': message,
                'file': filename,
                'line': line_number,
                'severity': 'Major',
                'node': f"ClassDeclaration.{class_name}",
                'property_path': ['source'],
                'value': source[:100] + "..." if len(source) > 100 else source,
                'status': 'violation',
                'violation_type': violation_type,
                'composition': {
                    'abstract_members': abstract_members,
                    'concrete_members': concrete_members,
                    'static_members': static_members
                }
            }
            findings.append(finding)
    
    return findings


def _find_nodes_by_type_recursive(node: Dict, target_types: List[str]) -> List[Dict]:
    """Helper function to recursively find nodes of specific types."""
    found_nodes = []
    
    if not isinstance(node, dict):
        return found_nodes
    
    # Check if current node matches target types
    node_type = node.get('type', '')
    if node_type in target_types:
        found_nodes.append(node)
    
    # Recursively search in all child nodes
    for key, value in node.items():
        if isinstance(value, dict):
            found_nodes.extend(_find_nodes_by_type_recursive(value, target_types))
        elif isinstance(value, list):
            for item in value:
                if isinstance(item, dict):
                    found_nodes.extend(_find_nodes_by_type_recursive(item, target_types))
    
    return found_nodes


def check_neutral_resources_language_attribute(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for assemblies_marked_neutralresourceslanguageattribute rule.
    This rule should flag assemblies that contain resource management code 
    (like ResourceManager) but lack the NeutralResourcesLanguageAttribute.
    
    Steps:
    1. Check if assembly has NeutralResourcesLanguageAttribute
    2. Check if code uses ResourceManager or resource-related functionality
    3. Flag violation only if both conditions are met: uses resources AND missing attribute
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Step 1: Check if NeutralResourcesLanguageAttribute is present
    has_neutral_resources_attribute = False
    for line_num, line in enumerate(lines, 1):
        if re.search(r'\[\s*assembly\s*:\s*NeutralResourcesLanguage\s*\(', line, re.IGNORECASE):
            has_neutral_resources_attribute = True
            break
    
    # Step 2: Check for ResourceManager usage or resource-related code
    uses_resources = False
    resource_usage_lines = []
    
    for line_num, line in enumerate(lines, 1):
        # Skip comment lines to avoid false positives
        stripped_line = line.strip()
        if stripped_line.startswith('//') or stripped_line.startswith('/*'):
            continue
        
        # Check for ResourceManager instantiation or usage
        if re.search(r'new\s+ResourceManager\s*\(|ResourceManager\s+\w+\s*=|\.ResourceManager', line):
            uses_resources = True
            resource_usage_lines.append(line_num)
        
        # Check for resource access patterns that indicate ResourceManager usage
        elif re.search(r'\.GetString\s*\(', line) and 'resourceManager' in line.lower():
            uses_resources = True
            resource_usage_lines.append(line_num)
            
        # Check for ResourceManager type declarations (but not in using statements)
        elif re.search(r'ResourceManager\s+\w+', line) and 'using' not in line.lower():
            uses_resources = True
            resource_usage_lines.append(line_num)
    
    # Step 3: Flag violation if uses resources but missing attribute
    if uses_resources and not has_neutral_resources_attribute:
        for line_num in resource_usage_lines:
            findings.append({
                'rule_id': 'assemblies_marked_neutralresourceslanguageattribute',
                'message': 'Assembly uses ResourceManager but lacks NeutralResourcesLanguageAttribute. Add [assembly: NeutralResourcesLanguage("culture")] to improve resource lookup performance.',
                'line': line_num,
                'severity': 'Major',
                'node': f'ResourceUsage.line{line_num}',
                'status': 'violation',
                'file': filename,
                'property_path': ['source'],
                'value': lines[line_num - 1].strip() if line_num <= len(lines) else ''
            })
    
    return findings


def check_com_visible_attribute(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for assemblies_explicitly_specify_com rule.
    Checks that assembly explicitly specifies COM visibility using ComVisible attribute.
    Only triggers once per file if the attribute is missing.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Check if the file contains [assembly: ComVisible] attribute
    com_visible_pattern = r'\[assembly:\s*System\.Runtime\.InteropServices\.ComVisible\s*\('
    
    if not re.search(com_visible_pattern, source, re.IGNORECASE):
        # ComVisible attribute is missing - add one finding for the entire file
        findings.append({
            'rule_id': 'assemblies_explicitly_specify_com',
            'message': 'Assembly should explicitly specify COM visibility using [assembly: ComVisible(true/false)].',
            'line': 1,  # Report at line 1
            'severity': 'Major',
            'node': 'CompilationUnit.unknown',
            'status': 'violation',
            'file': filename,
            'property_path': ['source'],
            'value': ''
        })
    
    return findings

def check_assembly_version_present(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for assemblies_include_version_information rule.
    Checks if the file contains [assembly: AssemblyVersion(...)] attribute.
    Reports violation only if the AssemblyVersion attribute is missing.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code if available
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Pattern to detect AssemblyVersion attribute
    assembly_version_pattern = r'\[assembly:\s*AssemblyVersion\s*\([^)]*\)\s*\]'
    
    # Check if the source contains AssemblyVersion attribute
    has_assembly_version = bool(re.search(assembly_version_pattern, source, re.MULTILINE | re.IGNORECASE))
    
    # Only report violation if AssemblyVersion is missing
    if not has_assembly_version:
        findings.append({
            'rule_id': 'assemblies_include_version_information_fixed',
            'message': 'Assembly should include version information using [assembly: AssemblyVersion(...)].',
            'node': 'CompilationUnit.unknown',
            'file': filename,
            'property_path': ['source'],
            'value': source[:100] + '...' if len(source) > 100 else source,  # Truncate for display
            'status': 'violation',
            'line': 1,  # Report at line 1 since it's a file-level issue
            'severity': 'Major'
        })
    
    return findings


def check_azure_functions_stateless(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for azure_functions_stateless rule.
    Azure Functions should be stateless - avoid modifying static fields or variables
    within Azure Function methods.
    
    This function checks for:
    1. Classes with Azure Function attributes ([FunctionName])
    2. Static fields or variables that are modified within function methods
    3. Assignment operations (=, +=, -=, etc.) to static members
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Step 1: Find Azure Function methods by looking for FunctionName attribute
    function_methods = {}  # method_name -> line_number
    
    i = 0
    while i < len(lines):
        line = lines[i]
        
        # Look for FunctionName attribute
        if re.search(r'\[\s*FunctionName\s*\(', line, re.IGNORECASE):
            # Look for the method declaration in the next few lines
            for j in range(i + 1, min(i + 10, len(lines))):
                next_line = lines[j].strip()
                
                # Look for method declaration pattern - this handles async methods too
                method_match = re.search(r'(public|private|protected|internal)\s+(static\s+)?.*?(\w+)\s*\(', next_line)
                if method_match:
                    method_name = method_match.group(3)
                    function_methods[method_name] = j + 1  # Convert to 1-based line numbers
                    break
        i += 1
    
    # Step 2: Find static field declarations (excluding readonly)
    static_fields = set()
    for line_num, line in enumerate(lines, 1):
        # Skip readonly fields as they can't be modified anyway
        if 'readonly' in line.lower():
            continue
            
        # Look for static field declarations
        static_field_match = re.search(r'(private|public|protected|internal)?\s*static\s+\w+\s+(\w+)\s*(=|;)', line)
        if static_field_match:
            field_name = static_field_match.group(2)
            static_fields.add(field_name)
    
    # Step 3: For each Azure Function method, check for static field modifications
    for method_name, method_start_line in function_methods.items():
        # Find the method boundaries by tracking braces
        method_end_line = find_method_end(lines, method_start_line - 1)  # Convert back to 0-based
        
        if method_end_line == -1:
            continue
            
        # Look for static field modifications within this method
        for line_num in range(method_start_line, method_end_line + 1):
            if line_num > len(lines):
                break
                
            line = lines[line_num - 1]  # Convert to 0-based for array access
            stripped_line = line.strip()
            
            # Skip comment lines
            if stripped_line.startswith('//') or stripped_line.startswith('/*'):
                continue
                
            # Look for modifications to static fields
            for field_name in static_fields:
                # Check for various assignment operators
                assignment_patterns = [
                    rf'\b{field_name}\s*=(?!=)',     # field = value (but not ==)
                    rf'\b{field_name}\s*\+=',        # field += value  
                    rf'\b{field_name}\s*-=',         # field -= value
                    rf'\b{field_name}\s*\*=',        # field *= value
                    rf'\b{field_name}\s*/=',         # field /= value
                    rf'\b{field_name}\s*%=',         # field %= value
                    rf'\b{field_name}\s*\+\+',       # field++
                    rf'\b{field_name}\s*--',         # field--
                    rf'\+\+\s*{field_name}\b',       # ++field
                    rf'--\s*{field_name}\b',         # --field
                ]
                
                for pattern in assignment_patterns:
                    if re.search(pattern, line):
                        findings.append({
                            'rule_id': 'azure_functions_stateless',
                            'message': f'Azure Function "{method_name}" modifies static field "{field_name}". Functions should be stateless.',
                            'node': 'Assignment',
                            'file': filename,
                            'property_path': ['static_field_modification'],
                            'value': stripped_line,
                            'status': 'violation', 
                            'line': line_num,
                            'severity': 'Major'
                        })
    
    return findings


def find_method_end(lines, method_start_index):
    """
    Find the end line of a method by tracking opening and closing braces.
    Returns the line number (1-based) where the method ends, or -1 if not found.
    """
    brace_count = 0
    method_started = False
    
    for i in range(method_start_index, len(lines)):
        line = lines[i]
        
        # Start counting braces when we see the first opening brace
        if '{' in line and not method_started:
            method_started = True
            
        if method_started:
            brace_count += line.count('{') - line.count('}')
            
            # Method ends when braces are balanced
            if brace_count <= 0:
                return i + 1  # Return 1-based line number
    
    return -1


def check_azure_functions_log_all_failures(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for azure_functions_log_all failures rule.
    Azure Functions should log all failures - every catch block in Azure Function methods
    should log exceptions, and not at Debug or Trace level.
    
    This function checks for:
    1. Methods with Azure Function attributes ([FunctionName])
    2. Try-catch blocks within those methods
    3. Catch blocks without proper logging or with Debug/Trace logging
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Step 1: Find Azure Function methods by looking for FunctionName attribute
    function_methods = {}  # method_name -> (line_number, method_end_line)
    
    i = 0
    while i < len(lines):
        line = lines[i]
        
        # Look for FunctionName attribute
        if re.search(r'\[\s*FunctionName\s*\(', line, re.IGNORECASE):
            # Look for the method declaration in the next few lines
            for j in range(i + 1, min(i + 10, len(lines))):
                next_line = lines[j].strip()
                
                # Look for method declaration pattern - this handles async methods too
                method_match = re.search(r'(public|private|protected|internal)\s+(static\s+)?.*?(\w+)\s*\(', next_line)
                if method_match:
                    method_name = method_match.group(3)
                    method_start = j + 1  # Convert to 1-based line numbers
                    method_end = find_method_end(lines, j)  # Find method boundaries
                    function_methods[method_name] = (method_start, method_end)
                    break
        i += 1
    
    # Step 2: For each Azure Function method, check for try-catch blocks and their logging
    for method_name, (method_start_line, method_end_line) in function_methods.items():
        if method_end_line == -1:
            continue
        
        # Find try-catch blocks within this method
        method_lines = lines[method_start_line-1:method_end_line]
        catch_blocks = find_catch_blocks_in_method(method_lines, method_start_line)
        
        for catch_info in catch_blocks:
            catch_start = catch_info['start_line']
            catch_end = catch_info['end_line']
            exception_var = catch_info['exception_var']
            
            # Check if the catch block has proper logging
            has_proper_logging = check_catch_block_logging(
                lines[catch_start-1:catch_end], 
                exception_var,
                catch_start
            )
            
            if not has_proper_logging:
                # Find the exact catch line for reporting
                catch_line = catch_start
                for line_idx in range(catch_start-1, min(catch_end, len(lines))):
                    if 'catch' in lines[line_idx].lower():
                        catch_line = line_idx + 1
                        break
                
                findings.append({
                    'rule_id': 'azure_functions_log_all',
                    'message': f'Azure Function "{method_name}" has a catch block without proper error logging. All exceptions should be logged at Warning, Error, or Critical level.',
                    'node': 'CatchBlock',
                    'file': filename,
                    'property_path': ['exception_handling'],
                    'value': lines[catch_line-1].strip(),
                    'status': 'violation',
                    'line': catch_line,
                    'severity': 'Major'
                })
    
    return findings


def find_catch_blocks_in_method(method_lines: List[str], method_start_line: int) -> List[Dict]:
    """
    Find all catch blocks within a method and return their details.
    Returns list of dicts with start_line, end_line, and exception_var.
    """
    catch_blocks = []
    
    for i, line in enumerate(method_lines):
        # Look for catch blocks
        catch_match = re.search(r'catch\s*\(\s*(\w+)?\s*(\w+)?\s*(\w+)?\s*\)', line, re.IGNORECASE)
        if catch_match:
            # Extract exception variable name (last captured group that's not None)
            exception_var = None
            for group in reversed(catch_match.groups()):
                if group and group not in ['Exception', 'exception', 'ex']:
                    exception_var = group
                    break
            if not exception_var:
                exception_var = catch_match.groups()[-1] if catch_match.groups()[-1] else 'ex'
            
            # Find the end of this catch block
            catch_start = method_start_line + i
            catch_end = find_catch_block_end(method_lines, i)
            
            if catch_end != -1:
                catch_blocks.append({
                    'start_line': catch_start,
                    'end_line': method_start_line + catch_end,
                    'exception_var': exception_var
                })
    
    return catch_blocks


def find_catch_block_end(method_lines: List[str], catch_start_idx: int) -> int:
    """
    Find the end of a catch block by tracking braces.
    Returns the relative index within method_lines, or -1 if not found.
    """
    brace_count = 0
    block_started = False
    
    for i in range(catch_start_idx, len(method_lines)):
        line = method_lines[i]
        
        # Start counting braces when we see the first opening brace
        if '{' in line and not block_started:
            block_started = True
            
        if block_started:
            brace_count += line.count('{') - line.count('}')
            
            # Block ends when braces are balanced
            if brace_count <= 0:
                return i
    
    return -1


def check_catch_block_logging(catch_lines: List[str], exception_var: str, catch_start_line: int) -> bool:
    """
    Check if a catch block has proper logging.
    Returns True if proper logging is found, False otherwise.
    """
    
    # Join all catch block lines for easier pattern matching
    catch_block_text = ' '.join(line.strip() for line in catch_lines)
    
    # Check for logging calls - look for log.LogError, log.LogWarning, log.LogCritical, etc.
    # But NOT log.LogDebug or log.LogTrace
    proper_logging_patterns = [
        rf'\blog\.Log(Error|Warning|Critical|Information)\s*\(',
        rf'\blogger\.Log(Error|Warning|Critical|Information)\s*\(',
        rf'\b_log\.Log(Error|Warning|Critical|Information)\s*\(',
        rf'\b_logger\.Log(Error|Warning|Critical|Information)\s*\(',
        # Also check for the exception variable being used in the logging
        rf'\blog\.Log(Error|Warning|Critical|Information)\s*\([^)]*{exception_var}[^)]*\)',
        rf'\blogger\.Log(Error|Warning|Critical|Information)\s*\([^)]*{exception_var}[^)]*\)',
    ]
    
    # Check for improper logging (Debug/Trace levels)
    improper_logging_patterns = [
        rf'\blog\.Log(Debug|Trace)\s*\(',
        rf'\blogger\.Log(Debug|Trace)\s*\(',
        rf'\b_log\.Log(Debug|Trace)\s*\(',
        rf'\b_logger\.Log(Debug|Trace)\s*\(',
    ]
    
    # If we find improper logging, it's a violation
    for pattern in improper_logging_patterns:
        if re.search(pattern, catch_block_text, re.IGNORECASE):
            return False
    
    # Check for proper logging
    for pattern in proper_logging_patterns:
        if re.search(pattern, catch_block_text, re.IGNORECASE):
            return True
    
    # If no logging found at all, it's a violation
    return False


def check_azure_function_structured_error_handling(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for azure_functions_use_structured rule.
    Azure Functions should use structured error handling - the top-most level of an Azure Function
    should include a try/catch block to capture and log all errors.
    
    This function checks for:
    1. Methods with Azure Function attributes ([FunctionName])
    2. Whether the method body is wrapped in a top-level try/catch block
    3. Reports violations for Azure Function methods without structured error handling
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Step 1: Find Azure Function methods by looking for FunctionName attribute
    function_methods = {}  # method_name -> (line_number, method_end_line)
    
    i = 0
    while i < len(lines):
        line = lines[i]
        
        # Look for FunctionName attribute
        if re.search(r'\[\s*FunctionName\s*\(', line, re.IGNORECASE):
            # Look for the method declaration in the next few lines
            for j in range(i + 1, min(i + 10, len(lines))):
                next_line = lines[j].strip()
                
                # Look for method declaration pattern - this handles async methods too
                method_match = re.search(r'(public|private|protected|internal)\s+(static\s+)?.*?(\w+)\s*\(', next_line)
                if method_match:
                    method_name = method_match.group(3)
                    method_start = j + 1  # Convert to 1-based line numbers
                    method_end = find_method_end(lines, j)  # Find method boundaries
                    function_methods[method_name] = (method_start, method_end)
                    break
        i += 1
    
    # Step 2: For each Azure Function method, check if it has top-level try/catch structure
    for method_name, (method_start_line, method_end_line) in function_methods.items():
        if method_end_line == -1:
            continue
            
        # Get method body lines (excluding method signature)
        method_body_start = method_start_line
        
        # Find the opening brace of the method
        for line_idx in range(method_start_line-1, method_end_line):
            if '{' in lines[line_idx]:
                method_body_start = line_idx + 2  # Start after the opening brace
                break
        
        method_body_lines = lines[method_body_start-1:method_end_line-1]  # Convert to 0-based for slicing
        
        # Check if the method has top-level try/catch structure
        has_top_level_try_catch = check_top_level_try_catch_structure(method_body_lines)
        
        if not has_top_level_try_catch:
            # Find the method declaration line for reporting
            method_declaration_line = method_start_line - 1
            for line_idx in range(method_start_line-2, max(0, method_start_line-10), -1):
                if re.search(r'(public|private|protected|internal)\s+(static\s+)?.*?\w+\s*\(', lines[line_idx]):
                    method_declaration_line = line_idx + 1
                    break
            
            findings.append({
                'rule_id': 'azure_functions_use_structured',
                'message': f'Azure Function "{method_name}" should use structured error handling. Wrap the entire method body in a try/catch block.',
                'node': 'MethodDeclaration',
                'file': filename,
                'property_path': ['structured_error_handling'],
                'value': lines[method_declaration_line-1].strip(),
                'status': 'violation',
                'line': method_declaration_line,
                'severity': 'Major'
            })
    
    return findings


def check_top_level_try_catch_structure(method_body_lines: List[str]) -> bool:
    """
    Check if a method body has top-level try/catch structure.
    Returns True if the method body is properly wrapped in try/catch, False otherwise.
    """
    if not method_body_lines:
        return False
    
    # Remove empty lines and comments from the beginning
    significant_lines = []
    for line in method_body_lines:
        stripped = line.strip()
        if stripped and not stripped.startswith('//') and not stripped.startswith('/*'):
            significant_lines.append(stripped)
    
    if not significant_lines:
        return False
    
    # Check if the first significant line starts with 'try'
    first_significant_line = significant_lines[0]
    if not re.match(r'^try\s*{?\s*$', first_significant_line, re.IGNORECASE):
        return False
    
    # Look for corresponding catch blocks
    method_body_text = ' '.join(significant_lines)
    
    # Check if there's at least one catch block
    if not re.search(r'\bcatch\s*\(', method_body_text, re.IGNORECASE):
        return False
    
    # Additional check: ensure the try block encompasses most of the method
    # by checking that we have both try and catch, and they form the main structure
    try_count = len(re.findall(r'\btry\s*{', method_body_text, re.IGNORECASE))
    catch_count = len(re.findall(r'\bcatch\s*\(', method_body_text, re.IGNORECASE))
    
    # Should have at least one try and one catch
    return try_count >= 1 and catch_count >= 1


def check_backslash_route_templates(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for backslash_avoided_route_templates rule.
    Checks that route templates don't use backslashes instead of forward slashes.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code if available
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Pattern to match route attributes with backslashes
    # Matches [Route("api\products")], [HttpGet("users\{id}")], etc.
    pattern = r'\[(Route|Http(?:Get|Post|Put|Delete|Patch|Head|Options))\s*\([^)]*"[^"]*\\[^"]*"[^)]*\)\]'
    
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, 1):
        matches = re.finditer(pattern, line, re.IGNORECASE)
        
        for match in matches:
            finding = {
                'rule_id': 'backslash_avoided_route_templates',
                'message': 'Backslash should be avoided in route templates. Use forward slashes instead.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'found_value': match.group()
            }
            findings.append(finding)
    
    return findings


def check_base_class_methods_hidden(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for base_class_methods_hidden rule.
    Detects when a method in a derived class has the same name as a method in the base class
    but with parameter types that are ancestors (less specific) than the base class method parameters.
    This causes the base method to be hidden rather than properly overridden.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code
    source = ast_tree.get('source_code', '') or ast_tree.get('source', '') or ast_tree.get('content', '')
    if not source:
        lines_data = ast_tree.get('lines', [])
        if lines_data:
            source = '\n'.join(lines_data)
        else:
            return findings
    
    lines = source.split('\n')
    
    # Track class definitions and their methods
    classes = {}  # {class_name: {'base_class': str, 'methods': [{'name': str, 'params': [str], 'line': int}], 'start_line': int}}
    current_class = None
    brace_level = 0
    
    # First pass: identify class declarations and inheritance
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments and empty lines
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Update brace level
        brace_level += line.count('{') - line.count('}')
        
        # Look for class declarations with inheritance
        class_match = re.search(r'class\s+(\w+)\s*:\s*(\w+)', line)
        if class_match:
            class_name = class_match.group(1)
            base_class = class_match.group(2)
            classes[class_name] = {
                'base_class': base_class,
                'methods': [],
                'start_line': line_num,
                'start_brace_level': brace_level
            }
            current_class = class_name
            continue
        
        # Look for class declarations without inheritance
        class_match_no_inherit = re.search(r'class\s+(\w+)', line)
        if class_match_no_inherit and ':' not in line:
            class_name = class_match_no_inherit.group(1)
            classes[class_name] = {
                'base_class': None,
                'methods': [],
                'start_line': line_num,
                'start_brace_level': brace_level
            }
            current_class = class_name
            continue
        
        # Track when we exit a class
        if current_class and current_class in classes:
            if brace_level < classes[current_class]['start_brace_level']:
                current_class = None
    
    # Second pass: find method declarations within classes
    current_class = None
    brace_level = 0
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments, empty lines
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Update brace level
        brace_level += line.count('{') - line.count('}')
        
        # Determine current class context
        for class_name, class_info in classes.items():
            if line_num >= class_info['start_line'] and brace_level >= class_info['start_brace_level']:
                if not current_class or line_num > classes.get(current_class, {}).get('start_line', 0):
                    current_class = class_name
        
        # Check if we're exiting the current class
        if current_class and current_class in classes:
            if brace_level < classes[current_class]['start_brace_level']:
                current_class = None
                continue
        
        # Look for method declarations
        if current_class:
            # Match method declarations: [access_modifier] [virtual/override/new] [return_type] MethodName(parameters)
            method_match = re.search(r'(public|protected|internal|private)?\s*(virtual|override|new)?\s*\w+\s+(\w+)\s*\(([^)]*)\)', line)
            if method_match:
                access_modifier = method_match.group(1) or 'private'
                override_keyword = method_match.group(2)
                method_name = method_match.group(3)
                params_str = method_match.group(4).strip()
                
                # Parse parameters to extract types
                param_types = []
                if params_str:
                    params = [p.strip() for p in params_str.split(',') if p.strip()]
                    for param in params:
                        # Extract parameter type (handle 'type name' format)
                        param_parts = param.split()
                        if len(param_parts) >= 2:
                            param_types.append(param_parts[0])  # First part is the type
                
                method_info = {
                    'name': method_name,
                    'param_types': param_types,
                    'line': line_num,
                    'access_modifier': access_modifier,
                    'override_keyword': override_keyword,
                    'original_line': line.strip()
                }
                
                classes[current_class]['methods'].append(method_info)
    
    # Third pass: detect method hiding
    for class_name, class_info in classes.items():
        if not class_info['base_class']:
            continue  # Skip classes without inheritance
        
        base_class_name = class_info['base_class']
        if base_class_name not in classes:
            continue  # Base class not found in current file
        
        base_class_methods = classes[base_class_name]['methods']
        derived_class_methods = class_info['methods']
        
        for derived_method in derived_class_methods:
            # Skip if method explicitly uses override or new keywords
            if derived_method['override_keyword'] in ['override', 'new']:
                continue
            
            # Look for base class methods with the same name
            for base_method in base_class_methods:
                if base_method['name'] == derived_method['name']:
                    # Check if parameter types indicate hiding
                    if len(base_method['param_types']) == len(derived_method['param_types']):
                        hiding_detected = False
                        
                        for base_param, derived_param in zip(base_method['param_types'], derived_method['param_types']):
                            # Check for common type hierarchy issues
                            if _is_base_type_of(derived_param, base_param):
                                hiding_detected = True
                                break
                        
                        if hiding_detected:
                            finding = {
                                'rule_id': 'base_class_methods_hidden',
                                'message': f"Method '{derived_method['name']}' in class '{class_name}' hides base class method. Use 'override' or 'new' keyword explicitly.",
                                'filename': filename,
                                'line': derived_method['line'],
                                'severity': 'Major',
                                'property_path': ['methods', derived_method['name']],
                                'found_value': derived_method['original_line'],
                                'base_class': base_class_name,
                                'method_name': derived_method['name']
                            }
                            findings.append(finding)
    
    return findings


def _is_base_type_of(derived_type: str, base_type: str) -> bool:
    """
    Check if derived_type is a base type of base_type (i.e., less specific).
    This is a simplified check for common C# type hierarchies.
    """
    # Normalize types by removing generic brackets and namespaces for simpler comparison
    derived_clean = derived_type.split('<')[0].split('.')[-1].strip()
    base_clean = base_type.split('<')[0].split('.')[-1].strip()
    
    # If types are the same, no hiding
    if derived_clean == base_clean:
        return False
    
    # Common type hierarchy mappings
    type_hierarchies = {
        'object': ['string', 'int', 'bool', 'double', 'float', 'long', 'DateTime', 'List', 'Array', 'Exception', 'ArgumentException', 'InvalidOperationException', 'NullReferenceException'],
        'Exception': ['ArgumentException', 'InvalidOperationException', 'NullReferenceException', 'SystemException'],
        'IEnumerable': ['List', 'Array', 'Collection', 'IList', 'ICollection'],
        'ICollection': ['List', 'Array', 'Collection'],
        'IList': ['List', 'Array'],
        'ValueType': ['int', 'bool', 'double', 'float', 'long', 'DateTime', 'decimal'],
        'Stream': ['FileStream', 'MemoryStream', 'NetworkStream']
    }
    
    # Check if derived_type is a base of base_type
    base_types = type_hierarchies.get(derived_clean, [])
    return base_clean in base_types


def check_blazor_query_parameter_type(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for blazor_query_parameter_type rule.
    
    Checks that Blazor query parameters with [SupplyParameterFromQuery] attribute
    use supported types only. Supported types are:
    - bool, DateTime, decimal, double, float, Guid, int, long, string
    - Nullable variants of the preceding types
    - Arrays of the preceding types (nullable or not nullable)
    
    Non-compliant examples include: TimeSpan, DateTimeOffset, Dictionary, custom objects
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Supported types for Blazor query parameters
    supported_base_types = {
        'bool', 'DateTime', 'decimal', 'double', 'float', 'Guid', 'int', 'long', 'string'
    }
    
    # Non-compliant types explicitly mentioned in the rule
    non_compliant_types = {
        'TimeSpan', 'DateTimeOffset', 'Dictionary', 'IDictionary', 'List', 'IList',
        'Collection', 'ICollection', 'Hashtable', 'ArrayList', 'Queue', 'Stack'
    }
    
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        
        # State tracking for attribute detection
        has_parameter = False
        has_supply_parameter = False
        attribute_end_line = i
        
        # Check if current line starts an attribute block that contains both attributes
        if line.startswith('['):
            # Scan forward from current position to collect all attributes
            j = i
            while j < len(lines):
                attr_line = lines[j].strip()
                
                # Stop when we reach a non-attribute line that's not empty
                if not attr_line.startswith('[') and attr_line and not attr_line.startswith('//'):
                    attribute_end_line = j
                    break
                
                # Check for our specific attributes
                if '[Parameter]' in attr_line or attr_line == '[Parameter]':
                    has_parameter = True
                if '[SupplyParameterFromQuery]' in attr_line or 'SupplyParameterFromQuery' in attr_line:
                    has_supply_parameter = True
                
                j += 1
            
            # Only proceed if we found both required attributes
            if has_parameter and has_supply_parameter:
                # Look for the property declaration that follows
                for k in range(attribute_end_line, min(len(lines), attribute_end_line + 5)):
                    prop_line = lines[k].strip()
                    
                    # Skip empty lines and comments
                    if not prop_line or prop_line.startswith('//'):
                        continue
                    
                    # Look for property declaration pattern: public Type PropertyName { get; set; }
                    property_match = re.search(r'public\s+([^{]+?)\s+(\w+)\s*\{', prop_line)
                    if property_match:
                        type_part = property_match.group(1).strip()
                        property_name = property_match.group(2).strip()
                        
                        # Clean up type - remove nullable markers and array indicators
                        type_clean = type_part
                        is_nullable = False
                        is_array = False
                        
                        # Check for nullable types (Type? or Nullable<Type>)
                        if type_clean.endswith('?'):
                            is_nullable = True
                            type_clean = type_clean[:-1].strip()
                        elif type_clean.startswith('Nullable<') and type_clean.endswith('>'):
                            is_nullable = True
                            type_clean = type_clean[9:-1].strip()
                        
                        # Check for array types (Type[] or Type[])
                        if type_clean.endswith('[]'):
                            is_array = True
                            type_clean = type_clean[:-2].strip()
                            # Handle nullable arrays like int?[]
                            if type_clean.endswith('?'):
                                is_nullable = True
                                type_clean = type_clean[:-1].strip()
                        
                        # Now check if the base type is supported
                        is_compliant = False
                        
                        # First check if it's a supported base type
                        if type_clean in supported_base_types:
                            is_compliant = True
                        
                        # Check for explicitly non-compliant types
                        elif any(non_compliant in type_clean for non_compliant in non_compliant_types):
                            is_compliant = False
                        
                        # Check for generic types that are not supported
                        elif '<' in type_clean and '>' in type_clean:
                            # Generic types like Dictionary<string, string>, List<int> etc are not supported
                            is_compliant = False
                        
                        # If not explicitly supported, assume it's a custom type (not supported)
                        else:
                            is_compliant = False
                        
                        if not is_compliant:
                            finding = {
                                "rule_id": "blazor_query_parameter_type",
                                "message": f"Blazor query parameter '{property_name}' uses unsupported type '{type_part}'. Supported types are: bool, DateTime, decimal, double, float, Guid, int, long, string, their nullable variants, and arrays of these types.",
                                "line": k + 1,
                                "severity": "Major",
                                "node": f"PropertyDeclaration:{property_name}",
                                "status": "violation"
                            }
                            findings.append(finding)
                        
                        # Break after finding the first property for this attribute set
                        break
        
        i += 1
    
    return findings

def check_blocks_synchronized_readonly_fields(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check that blocks are synchronized on readonly fields only.
    Detects lock statements using non-readonly fields.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # First, find all field declarations and track which are readonly
    readonly_fields = set()
    non_readonly_fields = set()
    
    for i, line in enumerate(lines):
        line_clean = line.strip()
        
        # Skip empty lines and comments
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*'):
            continue
            
        # Check for field declarations
        # Match patterns like: [visibility] [static] [readonly] type fieldName [= value];
        field_pattern = r'(private|protected|public|internal)?\s*(static)?\s*(readonly)?\s+\w+(?:<[^>]+>)?\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*[=;]'
        field_match = re.search(field_pattern, line_clean)
        
        if field_match:
            visibility = field_match.group(1) or ''
            is_static = field_match.group(2) is not None
            is_readonly = field_match.group(3) is not None
            field_name = field_match.group(4)
            
            if is_readonly:
                readonly_fields.add(field_name)
            else:
                non_readonly_fields.add(field_name)
    
    # Now check for lock statements and see if they use non-readonly fields
    for i, line in enumerate(lines):
        line_clean = line.strip()
        
        # Look for lock statements
        lock_pattern = r'lock\s*\(\s*(?:this\.)?([a-zA-Z_][a-zA-Z0-9_]*)\s*\)'
        lock_match = re.search(lock_pattern, line_clean)
        
        if lock_match:
            locked_field = lock_match.group(1)
            
            # Check if this field is in our non-readonly fields list
            if locked_field in non_readonly_fields:
                finding = {
                    "rule_id": "blocks_synchronized_readonly_fields",
                    "message": f"Lock statement uses non-readonly field '{locked_field}'. Use 'readonly' modifier for fields used in lock statements.",
                    "line": i + 1,
                    "severity": "Major",
                    "node": "LockStatement",
                    "status": "violation",
                    "file": filename
                }
                findings.append(finding)
    
    return findings


def check_blocks_synchronized_local_variables(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for blocks_synchronized_local_variables rule.
    Detects lock statements that synchronize on local variables or parameters.
    Local variables should not be used for synchronization as they create
    different instances for each thread, defeating the purpose of synchronization.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # First pass: identify class-level fields
    class_fields = set()
    for line in lines:
        line_clean = line.strip()
        # Look for field declarations (private, public, protected, etc.) at class level
        if re.search(r'\b(?:private|public|protected|internal|static)\s+(?:readonly\s+)?\w+\s+\w+\s*[=;]', line_clean):
            field_match = re.search(r'\b(?:private|public|protected|internal|static)\s+(?:readonly\s+)?\w+\s+(\w+)\s*[=;]', line_clean)
            if field_match:
                field_name = field_match.group(1)
                class_fields.add(field_name)
    
    # Track local variables and parameters for current method scope
    current_method_locals = set()
    current_method_params = set()
    in_method = False
    brace_depth = 0
    
    for i, line in enumerate(lines):
        line_clean = line.strip()
        line_num = i + 1
        
        # Skip comments and empty lines
        if line_clean.startswith('//') or not line_clean:
            continue
        
        # Track brace depth
        brace_depth += line_clean.count('{')
        brace_depth -= line_clean.count('}')
        
        # Detect method start
        if re.search(r'\b(?:public|private|protected|internal|static)?\s*\w+\s+\w+\s*\([^)]*\)', line_clean):
            in_method = True
            current_method_locals.clear()
            current_method_params.clear()
            
            # Extract method parameters
            param_match = re.search(r'\(([^)]*)\)', line_clean)
            if param_match:
                params_str = param_match.group(1)
                if params_str.strip():
                    # Parse parameters like "object param", "int value", "Type param"
                    param_patterns = re.findall(r'\b\w+\s+(\w+)', params_str)
                    for param_name in param_patterns:
                        current_method_params.add(param_name)
        
        # Reset when leaving method (simplified)
        if in_method and brace_depth == 0 and '}' in line_clean:
            in_method = False
        
        # Track local variable declarations within methods
        if in_method:
            # Look for variable declarations with various patterns
            var_declaration_patterns = [
                r'\b(?:var|object|string|int|bool|float|double|decimal|long|short|byte|char|DateTime|StringBuilder|List<\w+>|Dictionary<\w+,\s*\w+>)\s+(\w+)\s*[=;]',
                r'\bobject\s+(\w+)\s*=',
                r'\bvar\s+(\w+)\s*=',
            ]
            
            for pattern in var_declaration_patterns:
                matches = re.finditer(pattern, line_clean)
                for match in matches:
                    var_name = match.group(1)
                    current_method_locals.add(var_name)
            
            # Also look for Type varName = new pattern separately
            type_new_pattern = r'\b(\w+)\s+(\w+)\s*=\s*new\s+'
            type_new_matches = re.finditer(type_new_pattern, line_clean)
            for match in type_new_matches:
                var_type, var_name = match.groups()
                # Skip if it's an access modifier or keyword
                if var_type not in ['public', 'private', 'protected', 'internal', 'static', 'readonly', 'const', 'class', 'interface', 'enum', 'struct']:
                    current_method_locals.add(var_name)
        
        # Look for lock statements
        lock_match = re.search(r'lock\s*\(\s*(?:this\.)?(\w+)\s*\)', line_clean)
        
        if lock_match:
            locked_var = lock_match.group(1)
            
            # Check for this.field pattern
            if re.search(r'lock\s*\(\s*this\.\w+\s*\)', line_clean):
                continue  # this.field is compliant
                
            # Skip if it's a known class field
            if locked_var in class_fields:
                continue
                
            # Skip common framework identifiers that are safe
            if locked_var in ['this', 'typeof']:
                continue
            
            # print(f"Line {line_num}: Checking '{locked_var}' - locals: {current_method_locals}, params: {current_method_params}")
            
            # Check if locked variable is a local variable
            if locked_var in current_method_locals:
                finding = {
                    "rule_id": "blocks_synchronized_local_variables",
                    "message": f"Blocks should not be synchronized on local variables. Variable '{locked_var}' is a local variable. Use a field or static object for synchronization.",
                    "line": line_num,
                    "severity": "Major",
                    "node": "LockStatement",
                    "status": "violation",
                    "file": filename
                }
                findings.append(finding)
            # Check if locked variable is a method parameter
            elif locked_var in current_method_params:
                finding = {
                    "rule_id": "blocks_synchronized_local_variables",
                    "message": f"Blocks should not be synchronized on local variables. Variable '{locked_var}' is a method parameter. Use a field or static object for synchronization.",
                    "line": line_num,
                    "severity": "Major",
                    "node": "LockStatement",
                    "status": "violation",
                    "file": filename
                }
                findings.append(finding)
    
    return findings


def check_catch_clauses_do_more(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for catch_clauses_do_more rule.
    Detects catch clauses that only rethrow the exception without performing any additional work.
    
    Exception: catch blocks are allowed to only rethrow if they are followed by another
    catch block for a more general exception type (this allows for exception filtering).
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Improved regex pattern to match catch blocks that only contain throw;
    # Allows whitespace, newlines, and comments between braces
    catch_pattern = re.compile(
        r'catch\s*\(([^)]+)\)\s*(?://[^\n]*)?\s*\{([^}]*)\}',
        re.MULTILINE | re.DOTALL
    )
    
    # Find all catch blocks
    matches = list(catch_pattern.finditer(source))
    
    for i, match in enumerate(matches):
        exception_decl = match.group(1).strip()  # e.g., "Exception e" or "IOException ex"
        catch_body = match.group(2).strip()      # Content between braces
        
        # Check if the body only contains 'throw;' (possibly with whitespace/comments)
        # Remove all whitespace and comments
        body_cleaned = re.sub(r'//[^\n]*', '', catch_body)  # Remove single-line comments
        body_cleaned = re.sub(r'/\*.*?\*/', '', body_cleaned, flags=re.DOTALL)  # Remove multi-line comments
        body_cleaned = body_cleaned.strip()
        
        # Check if only 'throw;' remains
        if body_cleaned == 'throw;':
            # This catch block only rethrows
            # Now check if there's a following catch block (exception to the rule)
            is_followed_by_catch = False
            
            # Check if there's another catch block immediately following
            if i + 1 < len(matches):
                # Get the position right after this catch block
                current_catch_end = match.end()
                next_catch_start = matches[i + 1].start()
                
                # Get the text between this catch and the next
                between_catches = source[current_catch_end:next_catch_start].strip()
                
                # If the next catch starts right after (only whitespace/newlines between),
                # it's a sequential catch block
                if not between_catches or between_catches.startswith('catch'):
                    # Check if the next catch has a more general exception type
                    # For simplicity, we consider 'Exception' as the most general
                    # A more robust check would parse the exception hierarchy
                    next_exception = matches[i + 1].group(1).strip()
                    
                    # Extract exception type (first word before space or variable name)
                    current_type = exception_decl.split()[0] if exception_decl else ''
                    next_type = next_exception.split()[0] if next_exception else ''
                    
                    # If current is more specific and next is 'Exception', allow it
                    if next_type == 'Exception' and current_type != 'Exception':
                        is_followed_by_catch = True
            
            # If not followed by a more general catch, it's a violation
            if not is_followed_by_catch:
                # Calculate line number
                lines_before_match = source[:match.start()].count('\n')
                line_num = lines_before_match + 1
                
                finding = {
                    "rule_id": "catch_clauses_do_more",
                    "message": "Remove the problematic code and refactor as needed.",
                    "line": line_num,
                    "severity": "Major",
                    "node": "ClassDeclaration",
                    "status": "violation",
                    "file": filename
                }
                findings.append(finding)
    
    return findings


def check_child_class_fields_differ(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for child_class_fields_differ rule.
    Detects child class fields that differ from parent class fields only by capitalization.
    
    This is a common source of confusion and bugs in object-oriented code.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Dictionary to store class information: {class_name: {'fields': set(), 'parent': str, 'line': int}}
    classes = {}
    
    # Regex to find class declarations with optional inheritance
    class_pattern = re.compile(
        r'(?:public|internal|private|protected)?\s*class\s+(\w+)(?:\s*:\s*(\w+))?',
        re.MULTILINE
    )
    
    # Regex to find field declarations (private, protected, public, or no modifier)
    field_pattern = re.compile(
        r'^\s*(?:private|protected|public|internal)?\s+(?:static\s+)?(?:readonly\s+)?(\w+(?:<[^>]+>)?)\s+(\w+)\s*(?:;|=)',
        re.MULTILINE
    )
    
    lines = source.split('\n')
    
    # First pass: Find all classes and their inheritance
    for match in class_pattern.finditer(source):
        class_name = match.group(1)
        parent_name = match.group(2) if match.group(2) else None
        line_num = source[:match.start()].count('\n') + 1
        
        classes[class_name] = {
            'fields': {},  # {field_name_lower: (actual_name, line_number)}
            'parent': parent_name,
            'line': line_num,
            'start_pos': match.start(),
            'end_pos': None
        }
    
    # Determine end positions for each class (start of next class or end of file)
    class_list = sorted(classes.items(), key=lambda x: x[1]['start_pos'])
    for i, (class_name, class_info) in enumerate(class_list):
        if i + 1 < len(class_list):
            class_info['end_pos'] = class_list[i + 1][1]['start_pos']
        else:
            class_info['end_pos'] = len(source)
    
    # Second pass: Find all fields within each class
    for class_name, class_info in classes.items():
        start_pos = class_info['start_pos']
        end_pos = class_info['end_pos']
        class_source = source[start_pos:end_pos]
        
        for field_match in field_pattern.finditer(class_source):
            field_type = field_match.group(1)
            field_name = field_match.group(2)
            
            # Skip if it looks like a property (contains { get/set })
            # Check a bit ahead in the source
            check_end = min(field_match.end() + 50, len(class_source))
            following_text = class_source[field_match.end():check_end]
            if '{' in following_text and ('get' in following_text or 'set' in following_text):
                continue
            
            # Calculate actual line number in the original source
            field_line = source[:start_pos + field_match.start()].count('\n') + 1
            
            # Store field with lowercase version as key for comparison
            field_name_lower = field_name.lower()
            class_info['fields'][field_name_lower] = (field_name, field_line)
    
    # Third pass: Check for capitalization conflicts with parent classes
    for class_name, class_info in classes.items():
        parent_name = class_info['parent']
        
        if not parent_name or parent_name not in classes:
            continue
        
        # Collect all parent fields (including grandparents, etc.)
        parent_fields = {}  # {field_name_lower: (actual_name, class_name, line_number)}
        
        current_parent = parent_name
        while current_parent and current_parent in classes:
            parent_class = classes[current_parent]
            for field_lower, (field_name, field_line) in parent_class['fields'].items():
                if field_lower not in parent_fields:
                    parent_fields[field_lower] = (field_name, current_parent, field_line)
            current_parent = parent_class['parent']
        
        # Check child class fields against parent fields
        for field_lower, (child_field_name, child_line) in class_info['fields'].items():
            if field_lower in parent_fields:
                parent_field_name, parent_class, parent_line = parent_fields[field_lower]
                
                # Only flag if the names differ in capitalization (not exact match)
                if child_field_name != parent_field_name:
                    finding = {
                        "rule_id": "child_class_fields_differ",
                        "message": f"Field '{child_field_name}' in class '{class_name}' differs from parent class '{parent_class}' field '{parent_field_name}' only by capitalization.",
                        "line": child_line,
                        "severity": "Major",
                        "node": f"ClassDeclaration.{class_name}",
                        "status": "violation",
                        "file": filename
                    }
                    findings.append(finding)
    
    return findings


def check_child_class_fields_shadow(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for child_class_fields_shadow rule.
    Detects child class fields that shadow (hide) parent class fields by having the same name.
    
    This can cause confusion and bugs, especially when the shadowing is unintentional.
    Exception: Fields declared with the 'new' keyword are intentional and not flagged.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Dictionary to store class information
    classes = {}
    
    # Regex to find class declarations with optional inheritance
    class_pattern = re.compile(
        r'(?:public|internal|private|protected)?\s*class\s+(\w+)(?:\s*:\s*(\w+))?',
        re.MULTILINE
    )
    
    # Regex to find field declarations (not properties)
    # This pattern looks for fields but excludes properties with { get/set }
    field_pattern = re.compile(
        r'^\s*(?:private|protected|public|internal)?\s+(?:static\s+)?(?:readonly\s+)?(?:const\s+)?(\w+(?:<[^>]+>)?)\s+(\w+)\s*(?:;|=)',
        re.MULTILINE
    )
    
    # Regex to detect 'new' keyword for intentional hiding
    new_keyword_pattern = re.compile(
        r'^\s*(?:private|protected|public|internal)?\s+new\s+',
        re.MULTILINE
    )
    
    # First pass: Find all classes and their inheritance
    for match in class_pattern.finditer(source):
        class_name = match.group(1)
        parent_name = match.group(2) if match.group(2) else None
        line_num = source[:match.start()].count('\n') + 1
        
        classes[class_name] = {
            'fields': {},  # {field_name: (line_number, has_new_keyword)}
            'parent': parent_name,
            'line': line_num,
            'start_pos': match.start(),
            'end_pos': None
        }
    
    # Determine end positions for each class
    class_list = sorted(classes.items(), key=lambda x: x[1]['start_pos'])
    for i, (class_name, class_info) in enumerate(class_list):
        if i + 1 < len(class_list):
            class_info['end_pos'] = class_list[i + 1][1]['start_pos']
        else:
            class_info['end_pos'] = len(source)
    
    # Second pass: Find all fields within each class
    for class_name, class_info in classes.items():
        start_pos = class_info['start_pos']
        end_pos = class_info['end_pos']
        class_source = source[start_pos:end_pos]
        
        for field_match in field_pattern.finditer(class_source):
            field_type = field_match.group(1)
            field_name = field_match.group(2)
            
            # Calculate position in original source
            field_start_in_class = field_match.start()
            field_abs_start = start_pos + field_start_in_class
            
            # Check if this is a property by looking ahead
            check_end = min(field_match.end() + 100, len(class_source))
            following_text = class_source[field_match.end():check_end]
            
            # Skip if it's a property (has { followed by get/set})
            if '{' in following_text:
                brace_pos = following_text.index('{')
                after_brace = following_text[brace_pos:brace_pos+30] if brace_pos+30 < len(following_text) else following_text[brace_pos:]
                if 'get' in after_brace.lower() or 'set' in after_brace.lower():
                    continue
            
            # Check for 'new' keyword in the field declaration
            field_line_start = class_source.rfind('\n', 0, field_start_in_class) + 1
            field_line_text = class_source[field_line_start:field_match.end()]
            has_new_keyword = bool(re.search(r'\bnew\s+', field_line_text))
            
            # Calculate actual line number
            field_line = source[:field_abs_start].count('\n') + 1
            
            # Store field
            classes[class_name]['fields'][field_name] = (field_line, has_new_keyword)
    
    # Third pass: Check for shadowing
    for class_name, class_info in classes.items():
        parent_name = class_info['parent']
        
        if not parent_name or parent_name not in classes:
            continue
        
        # Collect all parent fields (including grandparents)
        parent_fields = {}  # {field_name: (parent_class, line_number)}
        
        current_parent = parent_name
        while current_parent and current_parent in classes:
            parent_class = classes[current_parent]
            for field_name, (field_line, has_new) in parent_class['fields'].items():
                if field_name not in parent_fields:
                    parent_fields[field_name] = (current_parent, field_line)
            current_parent = parent_class['parent']
        
        # Check child class fields against parent fields
        for field_name, (child_line, has_new_keyword) in class_info['fields'].items():
            if field_name in parent_fields:
                parent_class, parent_line = parent_fields[field_name]
                
                # Skip if the field uses 'new' keyword (intentional hiding)
                if has_new_keyword:
                    continue
                
                finding = {
                    "rule_id": "child_class_fields_shadow",
                    "message": f"Field '{field_name}' in class '{class_name}' shadows parent class '{parent_class}' field with the same name. Consider renaming or using 'new' keyword for intentional hiding.",
                    "line": child_line,
                    "severity": "Major",
                    "node": f"ClassDeclaration.{class_name}",
                    "status": "violation",
                    "file": filename
                }
                findings.append(finding)
    
    return findings


def check_classes_directly_extending_object(ast_tree, filename):
    """
    Custom logic for classes_directly_extending_object rule.
    Checks that classes directly extending object should not call base.Equals() or base.GetHashCode().
    Classes with explicit base classes (other than object) are allowed to call these methods.
    """
    import re
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Find all class declarations
    classes = []
    
    def collect_classes(node):
        if isinstance(node, dict):
            if node.get('node_type') == 'ClassDeclaration':
                classes.append(node)
            # Recursively check children
            if 'children' in node:
                for child in node.get('children', []):
                    collect_classes(child)
    
    collect_classes(ast_tree)
    
    # Check each class
    for class_node in classes:
        source = class_node.get('source', '')
        class_name = class_node.get('name', 'Unknown')
        
        # Check if class has an explicit base class (other than object)
        # Pattern matches: class MyClass : BaseClass
        # Should not match: class MyClass or class MyClass : object
        has_explicit_base = bool(re.search(r'^\s*(?:public|internal|private|protected)?\s*class\s+\w+\s*:\s*(?!object\b)[A-Z]\w+', source, re.MULTILINE))
        
        # If class has explicit base class other than object, skip it
        if has_explicit_base:
            continue
        
        # Check for base.Equals() or base.GetHashCode() calls
        base_equals_matches = list(re.finditer(r'base\.Equals\s*\(', source))
        base_gethashcode_matches = list(re.finditer(r'base\.GetHashCode\s*\(', source))
        
        all_matches = base_equals_matches + base_gethashcode_matches
        
        for match in all_matches:
            # Find line number
            lines_before = source[:match.start()].count('\n')
            line_num = class_node.get('lineno', 1) + lines_before
            
            finding = {
                "rule_id": "classes_directly_extending_object",
                "message": "Classes directly extending object should not call base in GetHashCode or Equals. Remove the base call and implement using field values instead.",
                "line": line_num,
                "severity": "Major",
                "node": f"ClassDeclaration.{class_name}",
                "status": "violation",
                "file": filename
            }
            findings.append(finding)
    
    return findings


def check_classes_named_like_exception(ast_tree, filename):
    """
    Custom logic for classes_named_like_exception rule.
    Checks that classes with "Exception" in their name properly extend Exception or its subclasses.
    Classes named like exceptions (ending with "Exception") should extend Exception or a subclass.
    """
    import re
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Find all class declarations
    classes = []
    
    def collect_classes(node):
        if isinstance(node, dict):
            if node.get('node_type') == 'ClassDeclaration':
                classes.append(node)
            # Recursively check children
            if 'children' in node:
                for child in node.get('children', []):
                    collect_classes(child)
    
    collect_classes(ast_tree)
    
    # Check each class
    for class_node in classes:
        source = class_node.get('source', '')
        class_name = class_node.get('name', 'Unknown')
        
        # Check if class name ends with "Exception"
        if not class_name.endswith('Exception'):
            continue
        
        # Check if class has explicit base that is Exception or Exception subclass
        # Pattern matches inheritance like:
        # : Exception, : System.Exception, : ArgumentException, : InvalidOperationException, etc.
        # Also handles generic exceptions and qualified names
        
        # Look for class declaration with inheritance
        class_decl_pattern = r'class\s+' + re.escape(class_name) + r'\s*(?:<[^>]+>)?\s*:\s*([A-Za-z_][\w.]*(?:<[^>]+>)?)'
        match = re.search(class_decl_pattern, source)
        
        if match:
            base_class = match.group(1).strip()
            
            # Check if base class is Exception or ends with Exception (indicating it's an exception subclass)
            # Common exception base classes: Exception, SystemException, ApplicationException, etc.
            if base_class == 'Exception' or base_class.endswith('Exception') or base_class == 'System.Exception':
                # This is compliant - class properly extends an exception
                continue
        
        # If we get here, class name ends with "Exception" but doesn't extend Exception or subclass
        line_num = class_node.get('lineno', 1)
        
        finding = {
            "rule_id": "classes_named_like_exception",
            "message": "Classes named like Exception should extend Exception or a subclass. Either extend Exception or rename the class to avoid confusion.",
            "line": line_num,
            "severity": "Major",
            "node": f"ClassDeclaration.{class_name}",
            "status": "violation",
            "file": filename
        }
        findings.append(finding)
    
    return findings


def check_classes_avoid_having_only_private_constructors(ast_tree, filename):
    """
    Custom logic for classes_avoid_having_only rule.
    Checks that classes should not have only private constructors.
    
    Exceptions:
    - Singleton pattern (class instantiates itself with private constructor)
    - Static utility classes (only static members)
    - Factory pattern (static factory method creates instances)
    - Smart enums (static readonly instances)
    - Classes derived from SafeHandle
    - Classes with internal, protected, or public constructors
    - Abstract classes
    - Static classes
    """
    import re
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Find all class declarations
    classes = []
    
    def collect_classes(node):
        if isinstance(node, dict):
            if node.get('node_type') == 'ClassDeclaration':
                classes.append(node)
            # Recursively check children
            if 'children' in node:
                for child in node.get('children', []):
                    collect_classes(child)
    
    collect_classes(ast_tree)
    
    # Check each class
    for class_node in classes:
        source = class_node.get('source', '')
        class_name = class_node.get('name', 'Unknown')
        
        # Skip static classes
        if re.search(r'\bstatic\s+class\s+' + re.escape(class_name), source):
            continue
        
        # Skip abstract classes
        if re.search(r'\babstract\s+class\s+' + re.escape(class_name), source):
            continue
        
        # Skip classes that derive from SafeHandle
        if re.search(r'class\s+' + re.escape(class_name) + r'[^{]*:\s*[^{]*SafeHandle', source):
            continue
        
        # Find all constructors
        # Match: private ClassName(
        private_constructor_pattern = r'private\s+' + re.escape(class_name) + r'\s*\('
        private_constructors = list(re.finditer(private_constructor_pattern, source))
        
        # Find public, internal, or protected constructors
        non_private_constructor_pattern = r'(?:public|internal|protected)\s+' + re.escape(class_name) + r'\s*\('
        non_private_constructors = list(re.finditer(non_private_constructor_pattern, source))
        
        # If there are no private constructors or there are non-private constructors, skip
        if not private_constructors or non_private_constructors:
            continue
        
        # Check if class only has private constructors
        # Now check for exceptions:
        
        # Exception 1: Check if class instantiates itself (Singleton, Factory, Smart Enum)
        # Look for: new ClassName( inside the class
        self_instantiation_pattern = r'new\s+' + re.escape(class_name) + r'\s*\('
        if re.search(self_instantiation_pattern, source):
            continue  # Singleton or Factory pattern
        
        # Exception 2: Check if class has only static members (utility class)
        # This is a simplified check - look for instance members
        # If we find instance fields or instance methods, it's not a pure utility class
        instance_field_pattern = r'(?:public|private|protected|internal)\s+(?!static|const)\w+[\w\.<>]*\s+\w+\s*[;=]'
        instance_method_pattern = r'(?:public|private|protected|internal)\s+(?!static)\w+[\w\.<>]*\s+\w+\s*\([^)]*\)\s*(?:=>|{)'
        
        has_instance_members = bool(re.search(instance_field_pattern, source) or 
                                   re.search(instance_method_pattern, source))
        
        # If no instance members, it's likely a utility class
        if not has_instance_members:
            continue
        
        # Exception 3: Check if this is a nested private class
        # Nested private classes are likely helper classes for the outer class
        if re.search(r'private\s+class\s+' + re.escape(class_name), source):
            continue  # Nested private class is acceptable
        
        # If we get here, class has only private constructors and isn't an exception
        line_num = class_node.get('lineno', 1)
        
        finding = {
            "rule_id": "classes_avoid_having_only",
            "message": "Classes should not have only private constructors. Add a public constructor, make the class static, or use the singleton pattern.",
            "line": line_num,
            "severity": "Major",
            "node": f"ClassDeclaration.{class_name}",
            "status": "violation",
            "file": filename
        }
        findings.append(finding)
    
    return findings

def check_classes_dispose_of_members(ast_tree, filename):
    """
    Custom logic for classes_dispose_members_from rule.
    Checks that classes implementing IDisposable dispose of their IDisposable members
    in the Dispose method, not in other methods.
    
    This rule detects when:
    - A class implements IDisposable
    - Has disposable member fields (FileStream, StreamReader, etc.)
    - Calls Dispose() on those members in methods other than Dispose/Dispose(bool)
    """
    import re
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Find all class declarations
    classes = []
    
    def collect_classes(node):
        if isinstance(node, dict):
            if node.get('node_type') == 'ClassDeclaration':
                classes.append(node)
            # Recursively check children
            if 'children' in node:
                for child in node.get('children', []):
                    collect_classes(child)
    
    collect_classes(ast_tree)
    
    # Common IDisposable types to look for
    disposable_types = [
        'FileStream', 'StreamReader', 'StreamWriter', 'MemoryStream',
        'BinaryReader', 'BinaryWriter', 'TextReader', 'TextWriter',
        'SqlConnection', 'SqlCommand', 'SqlDataReader', 'SqlDataAdapter',
        'HttpClient', 'HttpResponseMessage', 'WebClient',
        'Process', 'Timer', 'Mutex', 'Semaphore',
        'CancellationTokenSource', 'ManualResetEvent', 'AutoResetEvent'
    ]
    
    # Check each class
    for class_node in classes:
        source = class_node.get('source', '')
        class_name = class_node.get('name', 'Unknown')
        
        # Check if class implements IDisposable or IAsyncDisposable
        if not re.search(r':\s*[^{]*\bI(?:Async)?Disposable\b', source):
            continue  # Class doesn't implement IDisposable
        
        # Find disposable member fields
        disposable_fields = []
        for disp_type in disposable_types:
            # Pattern: private/protected/public Type fieldName;
            field_pattern = rf'(?:private|protected|public|internal)\s+{disp_type}\s+(\w+)\s*[;=]'
            matches = re.finditer(field_pattern, source)
            for match in matches:
                field_name = match.group(1)
                disposable_fields.append(field_name)
        
        if not disposable_fields:
            continue  # No disposable fields to check
        
        # Find all Dispose method calls on these fields
        # We need to check if they're called outside of Dispose methods
        
        # First, identify Dispose method boundaries
        # Look for: public void Dispose() or protected virtual void Dispose(bool disposing)
        # Also include DisposeAsync, DisposeAsyncCore methods
        dispose_method_pattern = r'(?:public|protected)\s+(?:virtual\s+)?(?:async\s+)?(?:void|ValueTask)\s+(?:Dispose(?:Async)?(?:Core)?)\s*\([^)]*\)\s*(?:=>|{)'
        dispose_methods = list(re.finditer(dispose_method_pattern, source))
        
        if not dispose_methods:
            continue  # No Dispose method found
        
        # For each disposable field, check if it's disposed outside Dispose methods
        for field_name in disposable_fields:
            # Look for: fieldName?.Dispose() or fieldName.Dispose()
            dispose_call_pattern = rf'\b{re.escape(field_name)}\??\.Dispose(?:Async)?\s*\('
            dispose_calls = list(re.finditer(dispose_call_pattern, source))
            
            for dispose_call in dispose_calls:
                call_pos = dispose_call.start()
                
                # Check if this call is within a Dispose method
                in_dispose_method = False
                
                for dispose_method in dispose_methods:
                    # Find the end of the Dispose method
                    # Simple approach: find matching closing brace
                    method_start = dispose_method.end()
                    
                    # Count braces to find method end
                    brace_count = 1
                    method_end = method_start
                    for i in range(method_start, len(source)):
                        if source[i] == '{':
                            brace_count += 1
                        elif source[i] == '}':
                            brace_count -= 1
                            if brace_count == 0:
                                method_end = i
                                break
                    
                    # Check if dispose call is within this method's range
                    if dispose_method.start() <= call_pos <= method_end:
                        in_dispose_method = True
                        break
                
                # If not in Dispose method, it's a violation
                if not in_dispose_method:
                    # Find line number
                    lines_before = source[:call_pos].count('\n')
                    line_num = class_node.get('lineno', 1) + lines_before
                    
                    finding = {
                        "rule_id": "classes_dispose_members_from",
                        "message": f"Dispose member '{field_name}' in the class's Dispose method, not in other methods. This prevents resource leaks.",
                        "line": line_num,
                        "severity": "Major",
                        "node": f"ClassDeclaration.{class_name}",
                        "status": "violation",
                        "file": filename
                    }
                    findings.append(finding)
                    break  # Only report once per field per class
    
    return findings


def check_classes_implement_their_exportattribute(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for classes_implement_their_exportattribute rule.
    Checks that classes with [Export(typeof(Interface))] attribute actually implement the exported interface.
    
    This function:
    1. Identifies classes with [Export(typeof(...))] attributes
    2. Extracts the interface type from the Export attribute
    3. Checks if the class implements that interface (directly, via base class, or inheritance)
    4. Reports violations when a class exports an interface but doesn't implement it
    5. Handles multiple Export attributes on same class
    6. Distinguishes between interface exports and self-exports (exporting the class itself)
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # First pass: build a map of class inheritance to track all interfaces
    class_inheritance = {}  # class_name -> set of implemented interfaces and base classes
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Check for class declaration - improved pattern to handle comments
        class_match = re.search(r'\b(?:public\s+|private\s+|internal\s+|protected\s+)?class\s+(\w+)', line)
        if class_match:
            class_name = class_match.group(1)
            
            # Extract inheritance part more carefully
            inheritance_part = None
            if ':' in line:
                # Find the part after the class name and colon
                after_class = line[line.find(class_name) + len(class_name):]
                if ':' in after_class:
                    inheritance_part = after_class[after_class.find(':') + 1:]
                    # Remove comments and opening brace
                    inheritance_part = re.sub(r'//.*$', '', inheritance_part).strip()
                    inheritance_part = re.sub(r'\{.*$', '', inheritance_part).strip()
            
            implemented_types = set()
            if inheritance_part:
                # Split by comma and clean up
                parts = [part.strip() for part in inheritance_part.split(',')]
                for part in parts:
                    # Remove generic type parameters and whitespace
                    type_name = part.split('<')[0].strip()
                    if type_name:
                        implemented_types.add(type_name)
            
            class_inheritance[class_name] = implemented_types
    
    # Helper function to check if a class implements an interface (directly or via inheritance)
    def implements_interface(class_name: str, interface_name: str, visited=None) -> bool:
        if visited is None:
            visited = set()
        
        if class_name in visited:
            return False  # Prevent infinite loops
        visited.add(class_name)
        
        if class_name not in class_inheritance:
            return False
        
        # Direct implementation
        if interface_name in class_inheritance[class_name]:
            return True
        
        # Check via base classes
        for base_type in class_inheritance[class_name]:
            if implements_interface(base_type, interface_name, visited):
                return True
        
        return False
    
    # Second pass: check Export attributes
    pending_exports = []  # List of (interface_name, line_num) tuples
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip empty lines and full-line comments
        if not line_clean or line_clean.startswith('//'):
            continue
        
        # Check for Export attribute with typeof
        export_match = re.search(r'\[Export\s*\(\s*typeof\s*\(\s*(\w+)\s*\)\s*\)\s*\]', line, re.IGNORECASE)
        if export_match:
            exported_type = export_match.group(1)
            pending_exports.append((exported_type, line_num))
            continue
        
        # Check for class declaration - improved pattern to handle comments
        class_match = re.search(r'\b(?:public\s+|private\s+|internal\s+|protected\s+)?class\s+(\w+)', line)
        if class_match:
            class_name = class_match.group(1)
            
            # Only process if we have pending exports for this class
            if pending_exports:
                # Check each pending export
                for exported_type, export_line_num in pending_exports:
                    # If the exported type is the class itself, it's a self-export (compliant)
                    if exported_type == class_name:
                        continue
                    
                    # Check if it starts with 'I' and is followed by an uppercase letter (interface naming convention)
                    is_likely_interface = (exported_type.startswith('I') and 
                                         len(exported_type) > 1 and 
                                         exported_type[1].isupper())
                    
                    # If it's likely an interface, check if the class implements it
                    if is_likely_interface:
                        if not implements_interface(class_name, exported_type):
                            # Get implemented types for context
                            implemented = class_inheritance.get(class_name, set())
                            
                            # Violation: class exports an interface but doesn't implement it
                            findings.append({
                                'rule_id': 'classes_implement_their_exportattribute',
                                'message': f"Class '{class_name}' exports '{exported_type}' but does not implement it. Classes should implement their ExportAttribute interfaces.",
                                'line': line_num,
                                'severity': 'Major',
                                'node': f'ClassDeclaration.{class_name}',
                                'status': 'violation',
                                'file': filename,
                                'context': {
                                    'class_name': class_name,
                                    'exported_type': exported_type,
                                    'export_line': export_line_num,
                                    'implemented_types': list(implemented)
                                }
                            })
            
            # Always clear pending exports after processing ANY class declaration
            pending_exports = []
    
    return findings


def check_classes_coupled_to_too_many(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for classes_coupled_too_many rule.
    Checks if a class is coupled to too many other classes (threshold: 20).
    
    Counts unique type dependencies from:
    - Field declarations
    - Property declarations  
    - Method parameters
    - Method return types
    - Local variables (new keyword)
    
    Does NOT count:
    - Primitive types (int, string, bool, etc.)
    - System types (List, Dictionary, etc.)
    - Nested class dependencies (per rule description)
    - Duplicate types (same type used multiple times counts as 1)
    - Base classes and interfaces (per rule: "Nested classes dependencies are not counted")
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Primitive and common system types to exclude
    excluded_types = {
        'int', 'string', 'bool', 'double', 'float', 'decimal', 'long', 'short', 'byte',
        'char', 'void', 'object', 'DateTime', 'TimeSpan', 'Guid', 'var',
        'List', 'Dictionary', 'HashSet', 'IEnumerable', 'IList', 'ICollection',
        'Task', 'Action', 'Func', 'Lazy', 'Nullable', 'Array',
        'StringBuilder', 'Exception', 'ArgumentException', 'InvalidOperationException',
        'IDisposable', 'IComparable', 'IEquatable', 'Console', 'Math', 'Convert',
        # Keywords that might appear
        'public', 'private', 'protected', 'internal', 'static', 'readonly', 'const',
        'virtual', 'override', 'abstract', 'sealed', 'partial', 'async', 'await',
        'get', 'set', 'value', 'class', 'namespace', 'using', 'new', 'return', 'if',
        'else', 'for', 'foreach', 'while', 'throw', 'try', 'catch', 'finally', 'in'
    }
    
    COUPLING_THRESHOLD = 20
    
    # Parse classes and their dependencies
    class_dependencies = {}
    class_line_numbers = {}
    
    current_class = None
    class_start_depth = 0
    brace_depth = 0
    in_namespace = False
    namespace_depth = 0
    just_entered_class = False  # Track if we just entered a class this iteration
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip empty lines and comments
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Track namespace
        if 'namespace' in line and not line_clean.startswith('//'):
            in_namespace = True
            namespace_depth = brace_depth + 1
        
        # Count braces
        open_braces = line.count('{')
        close_braces = line.count('}')
        
        # Detect class declaration (only top-level, not nested)
        if not current_class:
            class_match = re.search(r'\b(?:public\s+|private\s+|internal\s+|protected\s+)?class\s+(\w+)', line)
            if class_match and 'interface' not in line:
                class_name = class_match.group(1)
                
                # Only track top-level classes (under namespace)
                if in_namespace and brace_depth == namespace_depth:
                    current_class = class_name
                    class_dependencies[class_name] = set()
                    class_line_numbers[class_name] = line_num
                    # Class body will be one level deeper than class declaration
                    class_start_depth = brace_depth + 1
                    just_entered_class = True
        
        # If we're inside a class, extract type dependencies
        elif current_class:
            # 1. Field declarations: private/public Type fieldName;
            field_match = re.search(r'\b(?:private|public|protected|internal|readonly|static)\s+(\w+)\s+(\w+)\s*[;=]', line)
            if field_match:
                type_name = field_match.group(1)
                if type_name not in excluded_types and type_name != current_class:
                    class_dependencies[current_class].add(type_name)
            
            # 2. Property declarations: public Type PropName { get; set; }
            prop_match = re.search(r'\b(?:public|private|protected|internal)\s+(\w+)\s+(\w+)\s*\{', line)
            if prop_match and not re.search(r'\bclass\s+', line):  # Not a class declaration
                type_name = prop_match.group(1)
                if type_name not in excluded_types and type_name != current_class:
                    class_dependencies[current_class].add(type_name)
            
            # 3. Method declarations: public Type MethodName(...
            method_match = re.search(r'\b(?:public|private|protected|internal)\s+(\w+)\s+(\w+)\s*\(', line)
            if method_match:
                return_type = method_match.group(1)
                if return_type not in excluded_types and return_type != current_class:
                    class_dependencies[current_class].add(return_type)
                
                # Extract parameter types
                param_section = re.search(r'\(([^)]+)\)', line)
                if param_section:
                    params = param_section.group(1)
                    # Match Type paramName patterns
                    param_matches = re.findall(r'\b(\w+)\s+\w+(?:\s*,|\s*$)', params)
                    for param_type in param_matches:
                        if param_type not in excluded_types and param_type != current_class:
                            class_dependencies[current_class].add(param_type)
            
            # 4. Local variables: Type varName = new
            local_var_match = re.search(r'\b(\w+)\s+(\w+)\s*=\s*new', line)
            if local_var_match:
                type_name = local_var_match.group(1)
                if type_name not in excluded_types and type_name != current_class:
                    class_dependencies[current_class].add(type_name)
            
            # 5. Generic type parameters: List<Type>
            generic_matches = re.findall(r'<(\w+)>', line)
            for gen_type in generic_matches:
                if gen_type not in excluded_types and gen_type != current_class:
                    class_dependencies[current_class].add(gen_type)
        
        # Update brace depth
        brace_depth += open_braces - close_braces
        
        # Check if we exited the current class (but not on the same line we entered)
        if current_class and not just_entered_class and brace_depth < class_start_depth:
            current_class = None
        
        # Reset the flag for next iteration
        just_entered_class = False
    
    # Check each class against the threshold
    for class_name, dependencies in class_dependencies.items():
        dependency_count = len(dependencies)
        
        if dependency_count > COUPLING_THRESHOLD:
            line_num = class_line_numbers.get(class_name, 1)
            
            findings.append({
                'rule_id': 'classes_coupled_too_many',
                'message': f"Class '{class_name}' is coupled to {dependency_count} types (threshold: {COUPLING_THRESHOLD}). Consider splitting into smaller, more focused classes with single responsibilities.",
                'line': line_num,
                'severity': 'Major',
                'node': f'ClassDeclaration.{class_name}',
                'status': 'violation',
                'file': filename,
                'context': {
                    'class_name': class_name,
                    'dependency_count': dependency_count,
                    'threshold': COUPLING_THRESHOLD,
                    'dependencies': sorted(list(dependencies))[:10]  # Show first 10 for context
                }
            })
    
    return findings


def check_classes_empty(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for empty classes that have no members.
    
    Empty classes violate good design principles. They should either:
    - Be replaced with interfaces if serving as extension points
    - Be fleshed out with actual implementation
    - Be removed if not needed
    
    Args:
        ast_tree: The AST tree to analyze
        filename: The source file being analyzed
        
    Returns:
        List of findings for empty classes
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    def is_class_empty(class_source):
        """
        Check if a class is empty by analyzing its source code.
        A class is considered empty if its body contains no members.
        """
        if not class_source:
            return False
        
        # First, verify this is actually a class declaration
        # Should start with class keyword (with optional modifiers)
        if not re.search(r'\b(public|private|protected|internal|abstract|sealed|static)?\s*(public|private|protected|internal|abstract|sealed|static)?\s*class\s+\w+', class_source):
            return False
        
        # Remove comments and strings
        source_clean = re.sub(r'//.*?$', '', class_source, flags=re.MULTILINE)
        source_clean = re.sub(r'/\*.*?\*/', '', source_clean, flags=re.DOTALL)
        source_clean = re.sub(r'"[^"]*"', '', source_clean)
        source_clean = re.sub(r"'[^']*'", '', source_clean)
        
        # Extract the class body (content between the first { and last })
        # Find the class header first
        class_header_match = re.search(r'class\s+\w+[^{]*\{', source_clean, re.DOTALL)
        if not class_header_match:
            return False
        
        # Get everything after the opening brace
        start_pos = class_header_match.end() - 1  # Position of {
        body_start = start_pos + 1
        
        # Find matching closing brace
        brace_count = 1
        body_end = body_start
        for i in range(body_start, len(source_clean)):
            if source_clean[i] == '{':
                brace_count += 1
            elif source_clean[i] == '}':
                brace_count -= 1
                if brace_count == 0:
                    body_end = i
                    break
        
        # Extract body content
        body = source_clean[body_start:body_end].strip()
        
        # If body is empty or only whitespace, class is empty
        if not body or re.match(r'^\s*$', body):
            return True
        
        # Check for member declarations that would make the class non-empty
        member_patterns = [
            # Constructors (ClassName followed by parentheses)
            r'\b\w+\s*\([^)]*\)\s*\{',
            # Methods (return type + name + parameters)
            r'\b(void|int|string|bool|double|float|long|short|byte|char|object|\w+)\s+\w+\s*\([^)]*\)\s*[{;]',
            # Properties with get/set
            r'\b(public|private|protected|internal)\s+\w+\s+\w+\s*\{.*?(get|set)',
            # Auto-properties
            r'\b\w+\s+\w+\s*\{\s*(get|set)\s*;',
            # Fields with assignment or semicolon
            r'\b(public|private|protected|internal|static|readonly|const)\s+\w+\s+\w+\s*[;=]',
            # Events
            r'\bevent\s+\w+',
            # Nested types
            r'\b(class|struct|enum|interface)\s+\w+',
        ]
        
        for pattern in member_patterns:
            if re.search(pattern, body, re.DOTALL):
                return False
        
        # If we found no members, the class is empty
        return True
    
    # Collect class nodes from the AST
    nodes = ast_tree.get('nodes', ast_tree.get('children', []))
    if not nodes and 'node_type' in ast_tree:
        # Sometimes the AST structure is different
        nodes = [ast_tree]
    
    for node in nodes:
        if isinstance(node, dict):
            node_type = node.get('node_type', '')
            
            if node_type == 'ClassDeclaration':
                class_name = node.get('name', 'Unknown')
                class_source = node.get('source', '')
                line_num = node.get('lineno', node.get('line', 1))
                
                # Skip invalid class names (likely from parser errors with comments)
                # Valid C# class names start with uppercase letter or underscore
                if not re.match(r'^[A-Z_]', class_name):
                    continue
                
                if is_class_empty(class_source):
                    findings.append({
                        'rule_id': 'classes_empty',
                        'message': f"Class '{class_name}' is empty. Replace with an interface if it's an extension point, or add implementation if needed.",
                        'line': line_num,
                        'severity': 'Major',
                        'node': f'ClassDeclaration.{class_name}',
                        'status': 'violation',
                        'file': filename,
                        'property_path': ['source'],
                        'value': class_name
                    })
    
    return findings


def check_classes_that_provide_equalst(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for classes that provide Equals(T) but don't implement IEquatable<T>.
    
    A class that implements Equals(T) should also implement IEquatable<T> interface
    to expand the utility of the class and allow it to be used where an IEquatable is called for.
    
    Args:
        ast_tree: The AST representation of the C# file
        filename: The name of the file being checked
        
    Returns:
        List of findings for classes violating this rule
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Find all class declarations
    classes = []
    
    def collect_classes(node):
        if isinstance(node, dict):
            if node.get('node_type') == 'ClassDeclaration':
                classes.append(node)
            # Recursively check children
            if 'children' in node:
                for child in node.get('children', []):
                    collect_classes(child)
    
    collect_classes(ast_tree)
    
    # Check each class
    for class_node in classes:
        source = class_node.get('source', '')
        class_name = class_node.get('name', 'Unknown')
        line_num = class_node.get('lineno', 1)
        
        # Skip if class name is invalid (parser errors)
        if not re.match(r'^[A-Z_]', class_name):
            continue
        
        # Check if the class has an Equals(T) method where T is the class type
        # Pattern: public bool Equals(ClassName other) or bool Equals(ClassName other)
        equals_method_pattern = r'\bbool\s+Equals\s*\(\s*' + re.escape(class_name) + r'\s+\w+\s*\)'
        has_equals_method = re.search(equals_method_pattern, source)
        
        if not has_equals_method:
            # No Equals(T) method, so this rule doesn't apply
            continue
        
        # Check if the class implements IEquatable<T> in the class declaration
        # Look for it specifically in the class declaration line, not in comments
        # Pattern: class ClassName : ... IEquatable<ClassName>
        class_decl_pattern = r'class\s+' + re.escape(class_name) + r'[^{]*:\s*([^{]+)'
        class_decl_match = re.search(class_decl_pattern, source)
        
        implements_iequatable = False
        if class_decl_match:
            # Check if IEquatable<T> is in the inheritance/interface list
            inheritance_list = class_decl_match.group(1)
            iequatable_pattern = r'\bIEquatable\s*<\s*' + re.escape(class_name) + r'\s*>'
            if re.search(iequatable_pattern, inheritance_list):
                implements_iequatable = True
        
        if not implements_iequatable:
            # Class has Equals(T) but doesn't implement IEquatable<T>
            finding = {
                "rule_id": "classes_that_provide_equalst",
                "message": f"Class '{class_name}' provides Equals({class_name}) but doesn't implement IEquatable<{class_name}>. Explicitly implement IEquatable<T> to expand utility.",
                "line": line_num,
                "severity": "Major",
                "node": f"ClassDeclaration.{class_name}",
                "status": "violation",
                "file": filename,
                "property_path": ["source"],
                "value": class_name
            }
            findings.append(finding)
    
    return findings


def check_classes_idisposable_members_implement(ast_tree, filename):
    """
    Custom logic for classes_idisposable_members_implement rule.
    Checks that classes with IDisposable members implement IDisposable themselves.
    
    This rule detects when:
    - A class owns IDisposable field members (created via 'new' in field initializer or constructor)
    - The class does NOT implement IDisposable interface
    
    Classes that merely observe IDisposable members (receive them via constructor parameter
    without creating them) should NOT be flagged.
    """
    import re
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Find all class declarations
    classes = []
    
    def collect_classes(node):
        if isinstance(node, dict):
            if node.get('node_type') == 'ClassDeclaration':
                classes.append(node)
            # Recursively check children
            if 'children' in node:
                for child in node.get('children', []):
                    collect_classes(child)
    
    collect_classes(ast_tree)
    
    # Common IDisposable types to look for
    disposable_types = [
        'FileStream', 'StreamReader', 'StreamWriter', 'MemoryStream', 'BufferedStream',
        'BinaryReader', 'BinaryWriter', 'TextReader', 'TextWriter', 'StringReader', 'StringWriter',
        'SqlConnection', 'SqlCommand', 'SqlDataReader', 'SqlDataAdapter', 'SqlTransaction',
        'DbConnection', 'DbCommand', 'DbDataReader', 'DbDataAdapter', 'DbTransaction',
        'HttpClient', 'HttpResponseMessage', 'WebClient', 'HttpRequestMessage',
        'Process', 'Timer', 'Mutex', 'Semaphore', 'SemaphoreSlim', 'EventWaitHandle',
        'CancellationTokenSource', 'ManualResetEvent', 'AutoResetEvent', 'ManualResetEventSlim',
        'NetworkStream', 'TcpClient', 'TcpListener', 'UdpClient', 'Socket',
        'CryptoStream', 'GZipStream', 'DeflateStream',
        'IsolatedStorageFile', 'IsolatedStorageFileStream',
        'UnmanagedMemoryStream', 'FileSystemWatcher'
    ]
    
    # Check each class
    for class_node in classes:
        source = class_node.get('source', '')
        class_name = class_node.get('name', 'Unknown')
        
        # Skip classes that already implement IDisposable
        if re.search(r':\s*[^{]*\bI(?:Async)?Disposable\b', source):
            continue  # Class already implements IDisposable - compliant
        
        # Find class declaration line for accurate reporting
        class_decl_pattern = rf'class\s+{re.escape(class_name)}\s*[:<{{]'
        class_decl_match = re.search(class_decl_pattern, source)
        
        # Calculate line number
        line_num = 1
        if class_decl_match:
            lines_before = source[:class_decl_match.start()].count('\n')
            line_num = lines_before + 1
        
        # Find disposable member fields that are owned (created with 'new')
        # Look for field declarations with initializers using 'new'
        owned_fields = []
        
        for disp_type in disposable_types:
            # Pattern 1: private Type fieldName = new Type(...)
            field_init_pattern = rf'(?:private|protected|public|internal)\s+{disp_type}(?:<[^>]+>)?\s+(\w+)\s*=\s*new\s+{disp_type}'
            matches = re.finditer(field_init_pattern, source, re.IGNORECASE)
            for match in matches:
                field_name = match.group(1)
                owned_fields.append((disp_type, field_name))
        
        # Also check for fields assigned with 'new' in constructors or methods
        # Pattern 2: this.fieldName = new Type(...) or fieldName = new Type(...)
        for disp_type in disposable_types:
            # First find all field declarations
            field_decl_pattern = rf'(?:private|protected|public|internal)\s+{disp_type}(?:<[^>]+>)?\s+(\w+)\s*;'
            field_matches = re.finditer(field_decl_pattern, source, re.IGNORECASE)
            
            for field_match in field_matches:
                field_name = field_match.group(1)
                
                # Check if this field is assigned with 'new' anywhere in the class
                # Look for: this.fieldName = new Type or fieldName = new Type
                assign_pattern = rf'(?:this\.)?{field_name}\s*=\s*new\s+{disp_type}'
                if re.search(assign_pattern, source, re.IGNORECASE):
                    owned_fields.append((disp_type, field_name))
        
        # If there are owned disposable fields, this is a violation
        if owned_fields:
            field_list = ', '.join([f"{ftype} {fname}" for ftype, fname in owned_fields[:3]])
            if len(owned_fields) > 3:
                field_list += f" (and {len(owned_fields) - 3} more)"
            
            finding = {
                "rule_id": "classes_idisposable_members_implement",
                "message": f"Class '{class_name}' owns IDisposable member(s) ({field_list}) but doesn't implement IDisposable. Classes that own disposable resources should implement IDisposable to properly clean up resources.",
                "line": line_num,
                "severity": "Major",
                "node": f"ClassDeclaration.{class_name}",
                "status": "violation",
                "file": filename,
                "property_path": ["source"],
                "value": class_name
            }
            findings.append(finding)
    
    return findings


def check_collection_properties_readonly(ast_tree: Dict, filename: str) -> List[Dict]:
    '''
    Check that collection properties are readonly (not publicly writable).
    Collection properties should not have public setters to prevent replacement of the entire collection.
    
    Noncompliant: public List<T> Items { get; set; }
    Compliant: public List<T> Items { get; } = new List<T>();
    Compliant: public List<T> Items { get; private set; }
    Compliant: public IReadOnlyList<T> Items => items;
    '''
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Collection types that implement ICollection or ICollection<T>
    collection_types = [
        'List', 'ICollection', 'Collection', 'ArrayList', 'HashSet', 'ISet', 
        'Dictionary', 'IDictionary', 'SortedDictionary', 'SortedList',
        'Queue', 'Stack', 'LinkedList', 'ObservableCollection',
        'ConcurrentBag', 'ConcurrentQueue', 'ConcurrentStack',
        'BlockingCollection', 'SortedSet'
    ]
    
    # Track class visibility
    current_class_visibility = 'public'
    in_class = False
    class_name = 'Unknown'
    
    for i, line in enumerate(lines):
        line_clean = line.strip()
        
        # Skip empty lines and comments
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Track class declarations to determine visibility
        class_match = re.match(r'(public|internal|private|protected)?\s*(class|struct|record)\s+(\w+)', line_clean)
        if class_match:
            current_class_visibility = class_match.group(1) or 'internal'
            class_name = class_match.group(3)
            in_class = True
            continue
        
        # Only check properties in public/protected classes (externally visible)
        if not in_class or current_class_visibility not in ['public', 'protected']:
            continue
        
        # Look for property declarations with collection types
        has_collection_type = False
        matched_collection_type = None
        for coll_type in collection_types:
            if coll_type in line_clean:
                has_collection_type = True
                matched_collection_type = coll_type
                break
        
        if not has_collection_type:
            continue
        
        # Check for property with { get; set; } pattern (public setter)
        property_pattern = r'public\s+\w+(?:<[^>]+>)?\s+(\w+)\s*\{\s*get\s*;\s*set\s*;?\s*\}'
        property_match = re.search(property_pattern, line_clean)
        
        if property_match:
            property_name = property_match.group(1)
            
            # Verify this is actually a collection type property
            type_pattern = r'public\s+(\w+(?:<[^>]+>)?)\s+\w+\s*\{'
            type_match = re.search(type_pattern, line_clean)
            
            if type_match:
                full_type = type_match.group(1)
                
                # Check if the type is a collection type
                is_collection = any(coll_type in full_type for coll_type in collection_types)
                
                # Exclude IEnumerable (it's read-only interface, not ICollection)
                is_enumerable_only = 'IEnumerable' in full_type and 'ICollection' not in full_type
                
                # Exclude readonly collection types
                is_readonly_type = any(readonly in full_type for readonly in ['IReadOnlyList', 'IReadOnlyCollection', 'IReadOnlyDictionary', 'ImmutableList', 'ImmutableArray', 'ImmutableDictionary', 'ImmutableHashSet', 'ImmutableQueue', 'ImmutableStack'])
                
                if is_collection and not is_enumerable_only and not is_readonly_type:
                    finding = {
                        'rule_id': 'collection_properties_readonly',
                        'message': f"Collection property '{property_name}' of type '{full_type}' should be readonly. Remove the public setter and make the property readonly to prevent replacement of the entire collection.",
                        'line': i + 1,
                        'severity': 'Major',
                        'node': f"PropertyDeclaration:{property_name}",
                        'status': 'violation',
                        'file': filename,
                        'class': class_name
                    }
                    findings.append(finding)
        
        # Also check for properties with initializer
        property_with_init_pattern = r'public\s+\w+(?:<[^>]+>)?\s+(\w+)\s*\{\s*get\s*;\s*set\s*;?\s*\}\s*='
        property_init_match = re.search(property_with_init_pattern, line_clean)
        
        if property_init_match:
            property_name = property_init_match.group(1)
            
            # Verify this is actually a collection type property
            type_pattern = r'public\s+(\w+(?:<[^>]+>)?)\s+\w+\s*\{'
            type_match = re.search(type_pattern, line_clean)
            
            if type_match:
                full_type = type_match.group(1)
                
                # Check if the type is a collection type
                is_collection = any(coll_type in full_type for coll_type in collection_types)
                
                # Exclude IEnumerable (it's read-only interface)
                is_enumerable_only = 'IEnumerable' in full_type and 'ICollection' not in full_type
                
                # Exclude readonly collection types
                is_readonly_type = any(readonly in full_type for readonly in ['IReadOnlyList', 'IReadOnlyCollection', 'IReadOnlyDictionary', 'ImmutableList', 'ImmutableArray', 'ImmutableDictionary'])
                
                if is_collection and not is_enumerable_only and not is_readonly_type:
                    finding = {
                        'rule_id': 'collection_properties_readonly',
                        'message': f"Collection property '{property_name}' of type '{full_type}' should be readonly. Even with initializer, the public setter allows replacement of the entire collection.",
                        'line': i + 1,
                        'severity': 'Major',
                        'node': f"PropertyDeclaration:{property_name}",
                        'status': 'violation',
                        'file': filename,
                        'class': class_name
                    }
                    findings.append(finding)
    
    return findings


def check_non_generic_collections(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for collections_implement_generic_interface rule.
    Detects public classes using non-generic IEnumerable instead of IEnumerable<T>.
    Also detects classes inheriting from non-generic collection base classes.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Pattern 1: Find public class declarations with IEnumerable (non-generic)
    class_pattern = r'public\s+class\s+(\w+)\s*:.*?\bIEnumerable\b(?!\s*<)'
    
    for match in re.finditer(class_pattern, source, re.MULTILINE):
        class_name = match.group(1)
        line_num = source[:match.start()].count("\n") + 1
        findings.append({
            "rule_id": "collections_implement_generic_interface",
            "message": f"Class '{class_name}' implements non-generic IEnumerable instead of IEnumerable<T>.",
            "line": line_num,
            "severity": "Major",
            "node": f"ClassDeclaration.{class_name}",
            "status": "violation",
            "file": filename
        })
    
    # Pattern 2: Find public classes inheriting from non-generic collection base classes
    non_generic_bases = [
        'CollectionBase', 'DictionaryBase', 'ArrayList', 
        'Stack', 'Queue', 'Hashtable', 'SortedList'
    ]
    
    for base_class in non_generic_bases:
        # Pattern to match: public class ClassName : BaseClass
        base_pattern = rf'public\s+class\s+(\w+)\s*:\s*{base_class}\b'
        
        for match in re.finditer(base_pattern, source, re.MULTILINE):
            class_name = match.group(1)
            line_num = source[:match.start()].count("\n") + 1
            findings.append({
                "rule_id": "collections_implement_generic_interface",
                "message": f"Class '{class_name}' inherits from non-generic '{base_class}'. Use generic collections like List<T>, Dictionary<TKey, TValue>, etc.",
                "line": line_num,
                "severity": "Major",
                "node": f"ClassDeclaration.{class_name}",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_collection_self_reference(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for collections_passed_as_arguments rule.
    Detects when a collection is passed as argument to its own method.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Problematic methods
    problematic_methods = [
        'AddRange', 'Concat', 'Union', 'Intersect', 'Except', 'SequenceEqual',
        'UnionWith', 'IntersectWith', 'ExceptWith', 'SymmetricExceptWith',
        'IsProperSubsetOf', 'IsProperSupersetOf', 'IsSubsetOf', 'IsSupersetOf',
        'Overlaps', 'SetEquals'
    ]
    
    methods_regex = '|'.join(problematic_methods)
    pattern = rf'\b(\w+)\.({methods_regex})\s*\(\s*\1\s*\)'
    
    for match in re.finditer(pattern, source):
        var_name = match.group(1)
        method_name = match.group(2)
        line_num = source[:match.start()].count("\n") + 1
        
        # Exclude logging contexts
        line_start = source.rfind('\n', 0, match.start()) + 1
        line_end = source.find('\n', match.end())
        if line_end == -1:
            line_end = len(source)
        line_text = source[line_start:line_end]
        
        if any(keyword in line_text for keyword in ['Console.', 'Logger.', 'Debug.', '$"', 'string.Format']):
            continue
        
        findings.append({
            "rule_id": "collections_passed_as_arguments",
            "message": f"Collection '{var_name}' is passed as argument to its own method '{method_name}'.",
            "line": line_num,
            "severity": "Major",
            "node": f"CallExpression.{method_name}",
            "status": "violation",
            "file": filename
        })
    
    return findings


def check_list_any_instead_of_exists(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for collectionspecific_exists_method_preferred rule.
    Detects List<T>.Any() usage instead of List<T>.Exists().
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Find List<T> variable declarations
    list_vars = set()
    list_decl_pattern = r'\b(?:var|List<[^>]+>)\s+(\w+)\s*=\s*new\s+List<'
    for match in re.finditer(list_decl_pattern, source):
        list_vars.add(match.group(1))
    
    # Check for .Any() calls on List variables
    for var_name in list_vars:
        any_pattern = rf'\b{var_name}\.Any\s*\('
        for match in re.finditer(any_pattern, source):
            line_num = source[:match.start()].count("\n") + 1
            
            # Exclude logging/formatting contexts
            line_start = source.rfind('\n', 0, match.start()) + 1
            line_end = source.find('\n', match.end())
            if line_end == -1:
                line_end = len(source)
            line_text = source[line_start:line_end]
            
            if any(keyword in line_text for keyword in ['Console.', 'Logger.', 'Debug.', '$"', 'string.Format']):
                continue
            
            findings.append({
                "rule_id": "collectionspecific_exists_method_preferred",
                "message": f"Use List.Exists() instead of Any() for better performance on '{var_name}'.",
                "line": line_num,
                "severity": "Major",
                "node": "CallExpression.Any",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_empty_comments(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for comments_empty rule.
    Detects empty comment markers (//, /* */, ///).
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Pattern for single-line comments that are empty
    single_line_pattern = r'^(\s*)//(/)?(\s*)$'
    
    # Pattern for multi-line comments that are empty
    multi_line_pattern = r'/\*\s*\*/'
    
    lines = source.split('\n')
    for i, line in enumerate(lines, 1):
        # Check single-line empty comments
        if re.match(single_line_pattern, line):
            findings.append({
                "rule_id": "comments_empty",
                "message": "Empty comment should be removed or filled with meaningful text.",
                "line": i,
                "severity": "Major",
                "node": "Comment",
                "status": "violation",
                "file": filename
            })
    
    # Check multi-line empty comments
    for match in re.finditer(multi_line_pattern, source):
        line_num = source[:match.start()].count("\n") + 1
        findings.append({
            "rule_id": "comments_empty",
            "message": "Empty comment should be removed or filled with meaningful text.",
            "line": line_num,
            "severity": "Major",
            "node": "Comment",
            "status": "violation",
            "file": filename
        })
    
    return findings


def check_blazor_route_parameter_type_mismatch(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for component_parameter_type_match rule.
    Detects Blazor route parameter type mismatches.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Extract @page route parameters with constraints
    route_params = {}
    page_pattern = r'@page\s+"[^"]*\{(\w+):(\w+)\}[^"]*"'
    for match in re.finditer(page_pattern, source):
        param_name = match.group(1).lower()
        constraint_type = match.group(2).lower()
        
        # Map constraints to C# types
        type_map = {
            'int': 'int',
            'long': 'long',
            'bool': 'bool',
            'datetime': 'DateTime',
            'decimal': 'decimal',
            'double': 'double',
            'float': 'float',
            'guid': 'Guid'
        }
        
        if constraint_type in type_map:
            route_params[param_name] = type_map[constraint_type]
    
    # Find [Parameter] properties and check types
    param_pattern = r'\[Parameter\]\s+public\s+(\w+)\s+(\w+)\s*\{'
    for match in re.finditer(param_pattern, source, re.DOTALL):
        prop_type = match.group(1)
        prop_name = match.group(2).lower()
        
        if prop_name in route_params:
            expected_type = route_params[prop_name]
            if prop_type != expected_type:
                line_num = source[:match.start()].count("\n") + 1
                findings.append({
                    "rule_id": "component_parameter_type_match",
                    "message": f"Parameter '{match.group(2)}' type '{prop_type}' does not match route constraint type '{expected_type}'.",
                    "line": line_num,
                    "severity": "Major",
                    "node": "PropertyDeclaration",
                    "status": "violation",
                    "file": filename
                })
    
    return findings


def check_composite_format_string_arguments(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for composite_format_strings_preferred rule.
    Detects String.Format calls with mismatched placeholder/argument counts.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Match String.Format("format", args...)
    format_pattern = r'String\.Format\s*\(\s*"([^"]+)"((?:\s*,\s*[^,)]+)*)\s*\)'
    
    for match in re.finditer(format_pattern, source):
        format_string = match.group(1)
        args_part = match.group(2)
        
        # Count placeholders {0}, {1}, etc. including format specifiers and alignment
        # Matches {0}, {0:F2}, {0,10}, {0,-10:F2}, etc.
        placeholder_pattern = r'\{(\d+)(?:[,:-][^}]*)?\}'
        placeholders = re.findall(placeholder_pattern, format_string)
        
        # Find max placeholder index
        max_placeholder = max([int(p) for p in placeholders]) if placeholders else -1
        expected_arg_count = max_placeholder + 1 if max_placeholder >= 0 else 0
        
        # Count actual arguments
        actual_arg_count = len([a for a in args_part.split(",") if a.strip()]) if args_part.strip() else 0
        
        if expected_arg_count != actual_arg_count:
            line_num = source[:match.start()].count("\n") + 1
            findings.append({
                "rule_id": "composite_format_strings_preferred",
                "message": f"String.Format has {expected_arg_count} placeholders but {actual_arg_count} arguments.",
                "line": line_num,
                "severity": "Major",
                "node": "CallExpression.Format",
                "status": "violation",
                "file": filename
            })
    
    return findings


