def check_conditionally_executed_unreachable_code(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for conditionally_executed_code_reachable rule.
    Detects if statements with literal true/false that make code unreachable.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Detect if (true) ... else { unreachable }
    if_true_pattern = r'if\s*\(\s*true\s*\)\s*\{[^}]*\}\s*else\s*\{'
    for match in re.finditer(if_true_pattern, source, re.DOTALL):
        line_num = source[:match.start()].count("\n") + 1
        
        # Find the else line
        else_pos = match.group().rfind('else')
        else_line = source[:match.start() + else_pos].count("\n") + 1
        
        findings.append({
            "rule_id": "conditionally_executed_code_reachable",
            "message": "Else block is unreachable because condition is always true.",
            "line": else_line,
            "severity": "Major",
            "node": "IfStatement",
            "status": "violation",
            "file": filename
        })
    
    # Detect if (false) { unreachable }
    if_false_pattern = r'if\s*\(\s*false\s*\)\s*\{'
    for match in re.finditer(if_false_pattern, source):
        line_num = source[:match.start()].count("\n") + 1
        findings.append({
            "rule_id": "conditionally_executed_code_reachable",
            "message": "If block is unreachable because condition is always false.",
            "line": line_num,
            "severity": "Major",
            "node": "IfStatement",
            "status": "violation",
            "file": filename
        })
    
    # Detect var a = false; if (a) - but exclude const bool and check for reassignments
    # Only match literal false, not expressions
    var_false_pattern = r'(?:var|bool)\s+(\w+)\s*=\s*(false)\s*;'
    var_declarations = []  # List of (var_name, position) tuples
    for match in re.finditer(var_false_pattern, source):
        var_name = match.group(1)
        var_declarations.append((var_name, match.start()))
    
    for var_name, decl_pos in var_declarations:
        # Check if this variable is used in if condition
        if_pattern = rf'if\s*\(\s*{re.escape(var_name)}\s*\)'
        for if_match in re.finditer(if_pattern, source):
            # Make sure if is after the declaration and find the closest declaration before this if
            if if_match.start() > decl_pos:
                # Find the closest declaration of this variable before the if statement
                closest_decl = None
                for vn, dp in var_declarations:
                    if vn == var_name and dp < if_match.start():
                        if closest_decl is None or dp > closest_decl:
                            closest_decl = dp
                
                # Skip if this isn't the closest declaration
                if closest_decl != decl_pos:
                    continue
                
                # Check it's not a const bool (excluded case)
                decl_line_start = source.rfind('\n', 0, decl_pos) + 1
                decl_text = source[decl_line_start:decl_pos + 100]
                
                # Skip if const bool (excluded pattern)
                if 'const' in decl_text:
                    continue
                
                # Check for reassignments between declaration and if statement
                # Skip past the initial declaration by finding the semicolon
                decl_end = source.find(';', decl_pos)
                if decl_end > 0 and decl_end < if_match.start():
                    between_code = source[decl_end + 1:if_match.start()]
                    reassignment_pattern = rf'\b{re.escape(var_name)}\s*='
                    if re.search(reassignment_pattern, between_code):
                        # Variable is reassigned, skip
                        continue
                
                line_num = source[:if_match.start()].count("\n") + 1
                findings.append({
                    "rule_id": "conditionally_executed_code_reachable",
                    "message": f"Condition '{var_name}' is always false, making if block unreachable.",
                    "line": line_num,
                    "severity": "Major",
                    "node": "IfStatement",
                    "status": "violation",
                    "file": filename
                })
    
    # Detect var b = true; if (b) { ... } else { unreachable }
    var_true_pattern = r'(?:var|bool)\s+(\w+)\s*=\s*(true)\s*;'
    var_true_declarations = []  # List of (var_name, position) tuples
    for match in re.finditer(var_true_pattern, source):
        var_name = match.group(1)
        var_true_declarations.append((var_name, match.start()))
    
    for var_name, decl_pos in var_true_declarations:
        # Look for if (var) ... else pattern
        if_else_pattern = rf'if\s*\(\s*{re.escape(var_name)}\s*\)\s*\{{[^}}]*\}}\s*else\s*\{{'
        for if_match in re.finditer(if_else_pattern, source, re.DOTALL):
            # Make sure if is after the declaration and find the closest declaration before this if
            if if_match.start() > decl_pos:
                # Find the closest declaration of this variable before the if statement
                closest_decl = None
                for vn, dp in var_true_declarations:
                    if vn == var_name and dp < if_match.start():
                        if closest_decl is None or dp > closest_decl:
                            closest_decl = dp
                
                # Skip if this isn't the closest declaration
                if closest_decl != decl_pos:
                    continue
                
                # Check it's not a const bool (excluded case)
                decl_line_start = source.rfind('\n', 0, decl_pos) + 1
                decl_text = source[decl_line_start:decl_pos + 100]
                
                # Skip if const bool (excluded pattern)
                if 'const' in decl_text:
                    continue
                
                # Check for reassignments between declaration and if statement
                # Skip past the initial declaration by finding the semicolon
                decl_end = source.find(';', decl_pos)
                if decl_end > 0 and decl_end < if_match.start():
                    between_code = source[decl_end + 1:if_match.start()]
                    reassignment_pattern = rf'\b{re.escape(var_name)}\s*='
                    if re.search(reassignment_pattern, between_code):
                        # Variable is reassigned, skip
                        continue
                
                # Find the else line
                else_pos = if_match.group().rfind('else')
                else_line = source[:if_match.start() + else_pos].count("\n") + 1
                
                findings.append({
                    "rule_id": "conditionally_executed_code_reachable",
                    "message": f"Else block is unreachable because condition '{var_name}' is always true.",
                    "line": else_line,
                    "severity": "Major",
                    "node": "IfStatement",
                    "status": "violation",
                    "file": filename
                })
    
    return findings


def check_conditionals_on_same_line(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for conditionals_start_new_lines rule.
    Detects if statements starting on same line as closing brace.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Pattern: } if (condition) on SAME line
    # But NOT: } else if (condition)
    # Split into lines to check same-line condition
    lines = source.split('\n')
    
    for line_idx, line in enumerate(lines):
        # Check if line contains } followed by if (not else if)
        # Pattern: } ... if( where ... contains no newline and no 'else'
        if re.search(r'\}[^\n]*\bif\s*\(', line):
            # Make sure it's not "} else if"
            # Check if 'else' appears between } and if on this line
            match = re.search(r'\}([^\n]*\bif\s*\()', line)
            if match:
                between_text = match.group(1)
                # If 'else' is not in the text between } and if, it's a violation
                if 'else' not in between_text:
                    line_num = line_idx + 1  # Line numbers are 1-indexed
                    findings.append({
                        "rule_id": "conditionals_start_new_lines",
                        "message": "If statement should start on a new line after closing brace.",
                        "line": line_num,
                        "severity": "Major",
                        "node": "IfStatement",
                        "status": "violation",
                        "file": filename
                    })
    
    return findings


def check_missing_configure_await(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for configureawaitfalse_preferred rule.
    Detects await calls without ConfigureAwait(false) in library code.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Process line by line to avoid matching across lines and in comments
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, 1):
        # Skip comment lines
        stripped_line = line.strip()
        if stripped_line.startswith('//') or stripped_line.startswith('/*') or stripped_line.startswith('*'):
            continue
        
        # Remove inline comments to avoid false matches
        code_part = line.split('//')[0] if '//' in line else line
        
        # Find await expressions on this line
        await_pattern = r'await\s+([^;]+);'
        
        for match in re.finditer(await_pattern, code_part):
            await_expr = match.group(1).strip()
            
            # Check if it already has ConfigureAwait
            if 'ConfigureAwait' in await_expr:
                continue
            
            # Exclude certain patterns that don't need ConfigureAwait
            # (e.g., in UI code, but we're checking library code)
            
            findings.append({
                "rule_id": "configureawaitfalse_preferred",
                "message": "Await should use ConfigureAwait(false) in library code to avoid deadlocks.",
                "line": line_num,
                "severity": "Major",
                "node": "AwaitExpression",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_custom_attributes_have_attributeusage(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for custom_attributes_marked_systemattributeusageattribute rule.
    Checks that custom attributes (classes inheriting from Attribute) have [AttributeUsage] attribute.
    
    Exclusions:
    - Abstract attribute classes (base classes for inheritance)
    - Classes in System.* namespace (built-in attributes)
    - Classes that inherit from already-attributed base classes
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    children = ast_tree.get('children', [])
    if not children:
        return findings
    
    # Collect all Attribute nodes and their line numbers
    attribute_usage_lines = set()
    for node in children:
        if isinstance(node, dict) and node.get('node_type') == 'Attribute':
            source = node.get('source', '')
            if 'AttributeUsage' in source:
                attribute_usage_lines.add(node.get('lineno'))
    
    # Collect all namespace declarations
    system_namespace_ranges = []
    for node in children:
        if isinstance(node, dict) and node.get('node_type') == 'NamespaceDeclaration':
            namespace_name = node.get('name', '')
            if namespace_name.startswith('System'):
                # This is a System namespace - remember the line number
                system_namespace_ranges.append(node.get('lineno'))
    
    # Check all ClassDeclaration nodes
    for node in children:
        if not isinstance(node, dict) or node.get('node_type') != 'ClassDeclaration':
            continue
        
        source = node.get('source', '')
        lineno = node.get('lineno', 0)
        class_name = node.get('name', 'unknown')
        
        # Check if class inherits from Attribute
        if not re.search(r':\s*Attribute\b', source):
            continue
        
        # Exclude abstract classes (base classes for inheritance)
        if re.search(r'\babstract\s+class\b', source):
            continue
        
        # Exclude classes in System namespace
        # Check if this class is after a System namespace declaration
        in_system_namespace = False
        for ns_line in system_namespace_ranges:
            if lineno > ns_line:
                in_system_namespace = True
                break
        if in_system_namespace:
            continue
        
        # Check if AttributeUsage is on the line immediately before the class
        # AttributeUsage can be 1-3 lines before the class (accounting for multi-line attributes)
        has_attribute_usage = False
        for offset in range(1, 4):
            if (lineno - offset) in attribute_usage_lines:
                has_attribute_usage = True
                break
        
        if not has_attribute_usage:
            findings.append({
                "rule_id": "custom_attributes_marked_systemattributeusageattribute",
                "message": f"Custom attribute '{class_name}' should be marked with [AttributeUsage] to indicate where it can be applied",
                "line": lineno,
                "severity": "Major",
                "property_path": ["ClassDeclaration", class_name],
                "value": class_name,
                "node": f"ClassDeclaration.{class_name}",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_control_structures_use_curly_braces(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for control_structures_should_use_curly_braces rule.
    Detects control structures (if, for, while, foreach) without curly braces.
    
    This function checks method source code for control structures that don't use
    braces, even for single-statement bodies.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    lines = source.split('\n')
    
    # Patterns for control structures
    # Look for if/for/while/foreach NOT followed by { on same or next line
    control_keywords = ['if', 'for', 'while', 'foreach', 'else']
    
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        
        # Skip comments and empty lines
        if not line or line.startswith('//') or line.startswith('/*') or line.startswith('*'):
            i += 1
            continue
        
        # Special handling for 'else' keyword (can be standalone)
        if line.startswith('else') and 'if' not in line:
            # Check if else is followed by {
            # Pattern: else NOT followed by {
            rest_of_line = line[4:].strip()  # After 'else'
            
            has_brace = rest_of_line.startswith('{')
            
            # If no brace on same line, check next line
            if not has_brace and i + 1 < len(lines):
                next_line = lines[i + 1].strip()
                if next_line and not next_line.startswith('{'):
                    findings.append({
                        "rule_id": "control_structures_should_use_curly_braces",
                        "message": "Else statement should use curly braces even for single statements.",
                        "line": i + 1,
                        "severity": "Major",
                        "node": "ElseStatement",
                        "status": "violation",
                        "file": filename
                    })
            elif not has_brace and not rest_of_line:
                # Empty after else, check next line
                if i + 1 < len(lines):
                    next_line = lines[i + 1].strip()
                    if next_line and not next_line.startswith('{'):
                        findings.append({
                            "rule_id": "control_structures_should_use_curly_braces",
                            "message": "Else statement should use curly braces even for single statements.",
                            "line": i + 1,
                            "severity": "Major",
                            "node": "ElseStatement",
                            "status": "violation",
                            "file": filename
                        })
            i += 1
            continue
        
        # Check for control keywords with conditions
        for keyword in ['if', 'for', 'while', 'foreach']:
            # Pattern: keyword (condition)
            pattern = rf'\b{keyword}\s*\('
            
            if re.search(pattern, line):
                # Skip 'else if' for the 'if' keyword (else if is different pattern)
                if keyword == 'if' and 'else' in line[:line.find(keyword)]:
                    continue
                
                # Find the closing parenthesis
                # Count parentheses to find the matching close
                paren_count = 0
                found_open = False
                close_paren_idx = -1
                
                for idx, char in enumerate(line):
                    if char == '(' and not found_open:
                        found_open = True
                        paren_count = 1
                    elif found_open:
                        if char == '(':
                            paren_count += 1
                        elif char == ')':
                            paren_count -= 1
                            if paren_count == 0:
                                close_paren_idx = idx
                                break
                
                if close_paren_idx == -1:
                    # Condition spans multiple lines, skip for now
                    i += 1
                    continue
                
                # Check what comes after the closing parenthesis
                after_condition = line[close_paren_idx + 1:].strip()
                
                has_brace = after_condition.startswith('{')
                
                # If no brace on same line, check next line
                if not has_brace and i + 1 < len(lines):
                    next_line = lines[i + 1].strip()
                    if next_line and not next_line.startswith('{'):
                        findings.append({
                            "rule_id": "control_structures_should_use_curly_braces",
                            "message": f"{keyword.capitalize()} statement should use curly braces even for single statements.",
                            "line": i + 1,
                            "severity": "Major",
                            "node": f"{keyword.capitalize()}Statement",
                            "status": "violation",
                            "file": filename
                        })
                elif not has_brace and not after_condition:
                    # Empty after condition, check next line
                    if i + 1 < len(lines):
                        next_line = lines[i + 1].strip()
                        if next_line and not next_line.startswith('{'):
                            findings.append({
                                "rule_id": "control_structures_should_use_curly_braces",
                                "message": f"{keyword.capitalize()} statement should use curly braces even for single statements.",
                                "line": i + 1,
                                "severity": "Major",
                                "node": f"{keyword.capitalize()}Statement",
                                "status": "violation",
                                "file": filename
                            })
        
        i += 1
    
    return findings


def check_control_flow_nesting_depth(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for control_flow_statements_if rule.
    Detects control flow statements nested too deeply (max depth: 3).
    
    Counts nesting levels of if, switch, for, foreach, while, do, and try statements.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    MAX_DEPTH = 3
    lines = source.split('\n')
    
    # Track nesting depth
    nesting_depth = 0
    depth_stack = []  # Stack of (line_num, keyword) to track what increased depth
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments and empty lines
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Check for control flow keywords that increase nesting
        keywords = ['if', 'switch', 'for', 'foreach', 'while', 'do', 'try']
        
        for keyword in keywords:
            # Pattern: keyword followed by ( or { (for do/try)
            if keyword in ['do', 'try']:
                pattern = rf'\b{keyword}\s*\{{'
            else:
                pattern = rf'\b{keyword}\s*\('
            
            if re.search(pattern, line_clean):
                # Skip 'else if' (doesn't add extra nesting)
                if keyword == 'if' and 'else' in line_clean[:line_clean.find(keyword)]:
                    continue
                
                # Increase nesting depth
                nesting_depth += 1
                depth_stack.append((line_num, keyword))
                
                # Check if depth exceeds threshold
                if nesting_depth > MAX_DEPTH:
                    findings.append({
                        "rule_id": "control_flow_statements_if",
                        "message": f"Control flow statements should not be nested too deeply (max depth: {MAX_DEPTH}, current: {nesting_depth})",
                        "line": line_num,
                        "severity": "Major",
                        "node": f"{keyword.capitalize()}Statement",
                        "status": "violation",
                        "file": filename
                    })
        
        # Check for closing braces that decrease nesting
        # Count braces on this line
        open_braces = line_clean.count('{')
        close_braces = line_clean.count('}')
        
        # Decrease depth for closing braces (but not below 0)
        for _ in range(close_braces):
            if depth_stack:
                depth_stack.pop()
                nesting_depth = max(0, nesting_depth - 1)
    
    return findings


def check_controllers_mixed_responsibilities(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for controllers_avoid_having_mixed rule.
    Detects controllers with mixed responsibilities (handling multiple resources).
    
    Identifies controllers with HTTP methods targeting different route prefixes/resources.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    lines = source.split('\n')
    
    # Track controller classes and their routes
    current_controller = None
    controller_routes = {}  # {controller_name: set of route prefixes}
    controller_line = {}  # {controller_name: line_number}
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments and empty lines
        if not line_clean or line_clean.startswith('//'):
            continue
        
        # Detect controller class declaration
        controller_match = re.search(r'class\s+(\w+Controller)\s*:\s*ControllerBase', line_clean)
        if controller_match:
            current_controller = controller_match.group(1)
            controller_routes[current_controller] = set()
            controller_line[current_controller] = line_num
            continue
        
        # Detect HTTP method attributes with routes
        if current_controller:
            # Match [HttpGet("route")], [HttpPost("route")], etc.
            http_attr_match = re.search(r'\[Http(?:Get|Post|Put|Delete|Patch)\("([^"]+)"\)\]', line_clean)
            if http_attr_match:
                route = http_attr_match.group(1)
                
                # Extract the resource prefix (first segment)
                # Split by / and take first non-empty part
                parts = [p for p in route.split('/') if p and not p.startswith('{')]
                if parts:
                    resource = parts[0]
                    controller_routes[current_controller].add(resource)
    
    # Check each controller for mixed responsibilities
    for controller_name, route_prefixes in controller_routes.items():
        # If controller handles more than one distinct resource, it's a violation
        if len(route_prefixes) > 1:
            line_num = controller_line[controller_name]
            resources_str = ', '.join(sorted(route_prefixes))
            
            findings.append({
                "rule_id": "controllers_avoid_having_mixed",
                "message": f"Controller '{controller_name}' handles mixed responsibilities ({resources_str}). Split into focused controllers.",
                "line": line_num,
                "severity": "Major",
                "node": f"ClassDeclaration.{controller_name}",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_exception_should_not_be_caught(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for catch blocks that catch generic Exception types.
    This rule detects when catch blocks catch Exception or SystemException instead of specific exceptions.
    
    Args:
        ast_tree: The AST representation of the C# file
        filename: The name of the file being checked
        
    Returns:
        List of findings for violations of this rule
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Pattern for catch blocks with generic exceptions
    generic_exception_patterns = [
        r'catch\s*\(\s*Exception\s+\w*\s*\)',  # catch (Exception e)
        r'catch\s*\(\s*Exception\s*\)',         # catch (Exception)
        r'catch\s*\(\s*SystemException\s+\w*\s*\)',  # catch (SystemException ex)
        r'catch\s*\(\s*SystemException\s*\)',  # catch (SystemException)
        r'catch\s*\(\s*System\.Exception\s+\w*\s*\)',  # catch (System.Exception e)
        r'catch\s*\(\s*System\.Exception\s*\)',  # catch (System.Exception)
    ]
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip empty lines and comments
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        for pattern in generic_exception_patterns:
            if re.search(pattern, line_clean):
                # Check if this is inside a test method (common exception for testing)
                is_test_method = False
                
                # Look backwards to see if we're in a test method
                for prev_line_idx in range(max(0, line_num - 20), line_num):
                    prev_line = lines[prev_line_idx - 1] if prev_line_idx > 0 else ""
                    if re.search(r'\[Test\]|\[TestMethod\]|\[Fact\]', prev_line):
                        is_test_method = True
                        break
                    # If we hit another method, stop looking
                    if re.search(r'(public|private|protected|internal)\s+.*\w+\s*\(', prev_line):
                        break
                
                # Skip if inside test methods (common pattern for testing exceptions)
                if is_test_method:
                    continue
                
                # Also check for proper exception handling patterns that should not be flagged:
                # 1. Catch and rethrow pattern: catch (Exception) { /* log */ throw; }
                # 2. Catch at application boundary with logging
                
                # Look ahead to see what's in the catch block
                catch_block_content = []
                brace_count = 0
                found_opening_brace = False
                
                for check_line_idx in range(line_num - 1, min(len(lines), line_num + 10)):
                    check_line = lines[check_line_idx]
                    
                    if '{' in check_line:
                        found_opening_brace = True
                        brace_count += check_line.count('{')
                    
                    if found_opening_brace:
                        brace_count -= check_line.count('}')
                        catch_block_content.append(check_line.strip())
                        
                        if brace_count <= 0:
                            break
                
                catch_content = ' '.join(catch_block_content).lower()
                
                # Allow if catch block only contains throw; (rethrow pattern)
                if 'throw;' in catch_content and len(catch_content.split()) <= 3:
                    continue
                
                # Allow if catch block contains logging AND rethrow
                has_logging = any(log_word in catch_content for log_word in ['log', 'logger', 'console.write', 'debug.', 'trace.'])
                has_rethrow = 'throw;' in catch_content
                
                if has_logging and has_rethrow:
                    continue
                
                findings.append({
                    'rule_id': 'exception_should_not_be_caught',
                    'message': 'Catch blocks should not catch generic Exception types. Use specific exception types instead.',
                    'line': line_num,
                    'severity': 'Major',
                    'node': 'CatchClause',
                    'status': 'violation',
                    'file': filename,
                    'property_path': ['source'],
                    'value': line_clean
                })
                break  # Only report one violation per line
    
    return findings
    
    return findings


def check_composite_format_string_arguments(ast_tree, filename):
    """
    Custom logic for composite_format_strings_preferred rule.
    Detects String.Format calls with mismatched placeholder/argument counts.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Match String.Format("format", args...)
    format_pattern = r'String\.Format\s*\(\s*"([^"]+)"((?:\s*,\s*[^,)]+)*)\s*\)'
    
    for match in re.finditer(format_pattern, source):
        format_string = match.group(1)
        args_part = match.group(2)
        
        # Count placeholders {0}, {1}, etc.
        placeholder_pattern = r'\{(\d+)\}'
        placeholders = re.findall(placeholder_pattern, format_string)
        
        # Find max placeholder index
        max_placeholder = max([int(p) for p in placeholders]) if placeholders else -1
        expected_arg_count = max_placeholder + 1 if max_placeholder >= 0 else 0
        
        # Count actual arguments
        actual_arg_count = len([a for a in args_part.split(",") if a.strip()]) if args_part.strip() else 0
        
        if expected_arg_count != actual_arg_count:
            line_num = source[:match.start()].count("\n") + 1
            findings.append({
                "rule_id": "composite_format_strings_preferred",
                "message": f"String.Format has {expected_arg_count} placeholders but {actual_arg_count} arguments.",
                "line": line_num,
                "severity": "Major",
                "node": "CallExpression.Format",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_extension_methods_extend_object(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for extension_methods_should_not_extend_object rule.
    Checks that extension methods should not extend object type.
    
    Extension methods that extend object apply to all types, which can clutter IntelliSense
    and increase the chance of naming conflicts. Prefer extending specific types instead.
    
    This function checks for:
    1. Method parameters with 'this object' pattern
    2. Excluding comments and string literals
    3. Supporting both regular and generic extension methods
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Process line by line to get accurate line numbers
    for line_num, line in enumerate(lines, 1):
        original_line = line
        line_clean = line.strip()
        
        # Skip comment lines to avoid false positives
        if (not line_clean or 
            line_clean.startswith('//') or 
            line_clean.startswith('/*') or 
            line_clean.startswith('*') or 
            line_clean.startswith('///')):
            continue
        
        # Skip lines that are primarily comments (comments not at start but dominant)
        if '//' in line:
            # Check if the 'this object' part is in a comment
            comment_start = line.find('//')
            code_part = line[:comment_start]
            comment_part = line[comment_start:]
            
            # If 'this object' appears only in the comment part, skip
            if 'this object' not in code_part and 'this object' in comment_part:
                continue
        
        # Check for multi-line comment blocks /* ... */
        if '/*' in line and '*/' in line:
            # Simple inline comment check
            start = line.find('/*')
            end = line.find('*/')
            if start < end and 'this object' in line[start:end+2]:
                # Check if 'this object' is ONLY in the comment
                before_comment = line[:start]
                after_comment = line[end+2:]
                if 'this object' not in before_comment and 'this object' not in after_comment:
                    continue
        
        # Pattern to match extension method parameters: this object
        # This covers both simple and generic cases:
        # - public static void Method(this object obj)
        # - public static T CastTo<T>(this object obj)
        # - public static TResult Transform<TResult>(this object source, ...)
        
        if re.search(r'\bthis\s+object\b', line):
            # Additional validation to ensure this is in a method parameter context
            # Look for method signature pattern before the 'this object'
            
            # Check if this line contains a method signature pattern
            method_pattern = r'\b(?:public|private|protected|internal)?\s*static\s+\w+\s+\w+\s*\([^)]*this\s+object\b'
            if re.search(method_pattern, line):
                findings.append({
                    'rule_id': 'extension_methods_should_not_extend_object',
                    'message': 'Extension methods should not extend object. Extend a specific type instead to avoid cluttering IntelliSense and naming conflicts.',
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['MethodDeclaration', 'parameter'],
                    'value': line_clean,
                    'node': 'MethodDeclaration',
                    'status': 'violation'
                })
            # Also check if 'this object' appears in parameter list (for multi-line methods)
            elif '(' in line and 'this object' in line:
                # This could be a multi-line method parameter
                findings.append({
                    'rule_id': 'extension_methods_should_not_extend_object',
                    'message': 'Extension methods should not extend object. Extend a specific type instead to avoid cluttering IntelliSense and naming conflicts.',
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['MethodDeclaration', 'parameter'],
                    'value': line_clean,
                    'node': 'MethodDeclaration',
                    'status': 'violation'
                })
    
    return findings


def check_extensions_in_separate_namespaces(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for extensions_separate_namespaces rule.
    Checks that extension classes are not in the same namespace as the classes they extend.
    
    This function:
    1. Identifies all namespaces and the classes within them
    2. Finds extension classes (static classes with methods having 'this' parameters)
    3. Determines what types the extension methods extend
    4. Flags violations when extension classes are in the same namespace as extended classes
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Track namespaces and classes
    namespaces = {}  # {namespace_name: {'classes': [], 'extension_classes': []}}
    current_namespace = None
    namespace_stack = []
    brace_depth = 0
    
    # First pass: identify namespaces and classes
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments and empty lines
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Track brace depth
        brace_depth += line.count('{') - line.count('}')
        
        # Detect namespace declarations
        namespace_match = re.search(r'namespace\s+([\w\.]+)', line)
        if namespace_match:
            namespace_name = namespace_match.group(1)
            namespace_stack.append((namespace_name, brace_depth))
            current_namespace = namespace_name
            if namespace_name not in namespaces:
                namespaces[namespace_name] = {'classes': [], 'extension_classes': []}
            continue
        
        # Update current namespace based on brace depth
        while namespace_stack and brace_depth < namespace_stack[-1][1]:
            namespace_stack.pop()
        current_namespace = namespace_stack[-1][0] if namespace_stack else None
        
        # Detect class declarations
        class_match = re.search(r'\bclass\s+(\w+)', line)
        if class_match and current_namespace:
            class_name = class_match.group(1)
            
            # Check if it's a static class (potential extension class)
            if 'static' in line:
                namespaces[current_namespace]['extension_classes'].append({
                    'name': class_name,
                    'line': line_num,
                    'extends': []  # Will be populated in second pass
                })
            else:
                namespaces[current_namespace]['classes'].append({
                    'name': class_name,
                    'line': line_num
                })
    
    # Second pass: identify what types extension methods extend
    for namespace_name, namespace_info in namespaces.items():
        for ext_class in namespace_info['extension_classes']:
            ext_class_name = ext_class['name']
            ext_class_line = ext_class['line']
            
            # Find the class body and look for extension methods
            in_extension_class = False
            class_brace_depth = 0
            
            for line_num, line in enumerate(lines, 1):
                line_clean = line.strip()
                
                # Skip comments
                if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*'):
                    continue
                
                # Check if we're entering the extension class
                if line_num == ext_class_line and f'class {ext_class_name}' in line:
                    in_extension_class = True
                    class_brace_depth = 0
                    continue
                
                if in_extension_class:
                    class_brace_depth += line.count('{') - line.count('}')
                    
                    # Exit the class when brace depth returns to 0 or below
                    if class_brace_depth <= 0 and '}' in line:
                        break
                    
                    # Look for extension method parameters: this TypeName
                    this_match = re.search(r'\bthis\s+(\w+(?:\.\w+)*)', line)
                    if this_match:
                        extended_type = this_match.group(1)
                        # Remove generic type parameters if any
                        extended_type = re.sub(r'<[^>]*>', '', extended_type)
                        # Get the simple class name (remove namespace prefix)
                        simple_type = extended_type.split('.')[-1]
                        
                        if simple_type not in ext_class['extends']:
                            ext_class['extends'].append(simple_type)
    
    # Third pass: check for violations
    for namespace_name, namespace_info in namespaces.items():
        # Get all class names in this namespace
        class_names = [cls['name'] for cls in namespace_info['classes']]
        
        # Check each extension class
        for ext_class in namespace_info['extension_classes']:
            extended_types = ext_class['extends']
            
            # Check if any extended type is in the same namespace
            for extended_type in extended_types:
                if extended_type in class_names:
                    # Found a violation: extension class extends a class in the same namespace
                    findings.append({
                        'rule_id': 'extensions_separate_namespaces',
                        'message': f"Extension class '{ext_class['name']}' is in the same namespace '{namespace_name}' as the class it extends ('{extended_type}'). Move the extension class to a separate namespace.",
                        'file': filename,
                        'line': ext_class['line'],
                        'severity': 'Major',
                        'property_path': ['ClassDeclaration', ext_class['name']],
                        'value': ext_class['name'],
                        'node': f"ClassDeclaration.{ext_class['name']}",
                        'status': 'violation',
                        'context': {
                            'extension_class': ext_class['name'],
                            'extended_class': extended_type,
                            'namespace': namespace_name
                        }
                    })
                    break  # Only report once per extension class
    
    return findings


def check_extracting_archives_lead_zip_slip(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for extracting_archives_lead_zip rule.
    Detects zip slip vulnerabilities when extracting archives without proper path validation.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Look for ExtractToFile calls
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*'):
            continue
        
        # Look for ExtractToFile method calls
        if 'ExtractToFile(' in line:
            # Check if this line uses entry.FullName or entry.Name
            uses_entry_path = False
            
            # Direct usage patterns
            if re.search(r'entry\.(FullName|Name)', line):
                uses_entry_path = True
            
            # Check for variables that might contain entry paths
            elif any(var in line for var in ['path', 'filePath', 'destinationPath', 'targetPath', 'outputPath', 'fullPath']):
                # Look backwards in the method to see if these variables use entry paths
                method_start = max(0, line_num - 20)
                method_lines = lines[method_start:line_num]
                for prev_line in method_lines:
                    # Check for direct entry usage or variable assignments from entry
                    if (re.search(r'entry\.(FullName|Name)', prev_line) or 
                        re.search(r'entryName\s*=.*entry\.', prev_line) or
                        re.search(r'fileName\s*=.*entry\.', prev_line)):
                        uses_entry_path = True
                        break
            
            if uses_entry_path:
                # Check if there's proper validation in the surrounding context
                has_validation = False
                context_start = max(0, line_num - 15)
                context_end = min(len(lines), line_num + 5)
                context_lines = lines[context_start:context_end]
                context_text = '\n'.join(context_lines)
                
                # Check for validation patterns
                validation_patterns = [
                    r'\.StartsWith\s*\(',
                    r'Path\.GetFullPath\s*\(',
                    r'Path\.IsPathRooted\s*\(',
                    r'ZipFile\.ExtractToDirectory',
                    r'throw.*[Ss]ecurity',
                    r'throw.*[Uu]nauthorized',
                    r'throw.*[Ii]nvalid'
                ]
                
                for pattern in validation_patterns:
                    if re.search(pattern, context_text):
                        has_validation = True
                        break
                
                # If no validation found, it's a vulnerability
                if not has_validation:
                    findings.append({
                        'rule_id': 'extracting_archives_lead_zip',
                        'message': 'Zip slip vulnerability: ExtractToFile called without proper path validation',
                        'file': filename,
                        'line': line_num,
                        'severity': 'Major',
                        'property_path': ['CallExpression', 'ExtractToFile'],
                        'value': line_clean,
                        'node': 'CallExpression.ExtractToFile',
                        'status': 'violation'
                    })
    
    return findings


def check_deserialization_methods_for_optionalfield(ast_tree, filename):
    """
    Check for OptionalField members without deserialization event handlers.
    
    Rule: Classes with [Serializable] and [OptionalField] must have
    [OnDeserializing] or [OnDeserialized] handlers.
    """
    import re
    findings = []
    
    # Get full source to check for attributes before class declarations
    full_source = ast_tree.get('source', '')
    lines = full_source.splitlines() if full_source else []
    
    children = ast_tree.get('children', [])
    
    # Find all class declarations
    for node in children:
        if node.get('node_type') != 'ClassDeclaration':
            continue
        
        source = node.get('source', '')
        class_name = node.get('name', 'unknown')
        line_num = node.get('lineno', 0)
        
        # Get context: look for attributes immediately before the class
        # Scan backwards from class line to find [Serializable]
        has_serializable = False
        check_line_idx = line_num - 2  # Start 1 line before class (0-indexed)
        
        while check_line_idx >= 0 and check_line_idx >= line_num - 10:
            check_line = lines[check_line_idx].strip()
            
            # Stop if we hit another class declaration or namespace/using
            if re.match(r'(public|private|internal|protected)?\s*(class|interface|struct|enum)', check_line):
                break
            if check_line.startswith('namespace ') or check_line.startswith('using '):
                break
            
            # If we hit non-empty, non-comment, non-attribute line, stop
            if check_line and not check_line.startswith('[') and not check_line.startswith('//'):
                break
            
            # Check for [Serializable] attribute (only in non-comment lines)
            if check_line.startswith('[') and '[Serializable]' in check_line:
                has_serializable = True
                break
                
            check_line_idx -= 1
        
        # Skip if no [Serializable] attribute found for this specific class
        if not has_serializable:
            continue
        
        # Skip test classes
        if re.search(r'\[Test\]|\[Fact\]|Assert\.', source):
            continue
        
        # Check if class has OptionalField attributes (in class body)
        if not re.search(r'\[OptionalField\]', source):
            continue
        
        # Check if class has OnDeserializing or OnDeserialized handlers (in class body)
        has_on_deserializing = bool(re.search(r'\[OnDeserializing\]', source))
        has_on_deserialized = bool(re.search(r'\[OnDeserialized\]', source))
        
        if not has_on_deserializing and not has_on_deserialized:
            # Violation: Has OptionalField but no handlers
            findings.append({
                "rule_id": "deserialization_methods_provided_optionalfield",
                "message": f"Class '{class_name}' has [OptionalField] members but lacks [OnDeserializing] or [OnDeserialized] event handlers",
                "line": line_num,
                "severity": "Major",
                "node": f"ClassDeclaration.{class_name}",
                "status": "violation",
                "file": filename,
                "context": {
                    "class_name": class_name,
                    "has_optional_field": True,
                    "has_deserializing_handler": has_on_deserializing,
                    "has_deserialized_handler": has_on_deserialized
                }
            })
    
    return findings


def check_deserialization_vulnerable_to_injection(ast_tree, filename):
    """
    Detect unsafe deserialization methods vulnerable to injection attacks.
    
    Rule: BinaryFormatter, NetDataContractSerializer, and JavaScriptSerializer
    are vulnerable to deserialization attacks and should not be used.
    """
    import re
    findings = []
    
    # Get full source
    full_source = ast_tree.get('source', '')
    lines = full_source.splitlines() if full_source else []
    
    # Dangerous deserialization patterns
    dangerous_patterns = [
        (r'BinaryFormatter\s*\(\s*\)[\s\S]{0,200}\.Deserialize\s*\(', 
         'BinaryFormatter.Deserialize is vulnerable to injection attacks'),
        (r'NetDataContractSerializer\s*\(\s*\)[\s\S]{0,200}\.Deserialize\s*\(', 
         'NetDataContractSerializer.Deserialize allows arbitrary type instantiation'),
        (r'JavaScriptSerializer\s*\(\s*\)[\s\S]{0,200}\.Deserialize\s*(<[^>]+>)?\s*\(',
         'JavaScriptSerializer.Deserialize is vulnerable to injection attacks')
    ]
    
    for pattern, message in dangerous_patterns:
        for match in re.finditer(pattern, full_source):
            match_text = match.group(0)
            
            # Skip if in comments
            if '//' in match_text or '/*' in match_text:
                continue
            
            # Skip test classes
            if re.search(r'\[Test\]|\[Fact\]|Assert\.', match_text):
                continue
            
            # Calculate line number
            line_num = full_source[:match.start()].count('\n') + 1
            
            findings.append({
                "rule_id": "deserialization_vulnerable_injection_attacks",
                "message": message,
                "line": line_num,
                "severity": "Critical",
                "node": "CallExpression.Deserialize",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_deserializing_without_validation(ast_tree, filename):
    """
    Detect Serializable classes with validation in constructors but no deserialization validation.
    
    Rule: [Serializable] classes that validate in constructors should also validate during
    deserialization via IDeserializationCallback or property setters.
    """
    import re
    findings = []
    
    full_source = ast_tree.get('source', '')
    lines = full_source.splitlines() if full_source else []
    children = ast_tree.get('children', [])
    
    for node in children:
        if node.get('node_type') != 'ClassDeclaration':
            continue
        
        source = node.get('source', '')
        class_name = node.get('name', 'unknown')
        line_num = node.get('lineno', 0)
        
        # Get context for [Serializable] attribute
        start_line = max(0, line_num - 11)
        context = '\n'.join(lines[start_line:line_num]) + '\n' + source
        
        # Skip test classes
        if re.search(r'\[Test\]|\[Fact\]', context):
            continue
        
        # Check if class is Serializable
        if not re.search(r'\[Serializable\]', context):
            continue
        
        # Check for validation in constructor (if/throw pattern)
        has_constructor_validation = bool(re.search(r'if\s*\([^)]+\)\s*throw\s+new\s+\w*Exception', source))
        
        # Skip if no constructor validation (not a security concern)
        if not has_constructor_validation:
            continue
        
        # Check for deserialization validation
        has_ideserializationcallback = bool(re.search(r':\s*IDeserializationCallback', context))
        has_ondeserialization = bool(re.search(r'void\s+OnDeserialization\s*\(', source))
        has_property_validation = bool(re.search(r'set\s*\{[^}]*if\s*\([^)]+\)\s*throw', source))
        
        if not (has_ideserializationcallback or has_ondeserialization or has_property_validation):
            findings.append({
                "rule_id": "deserializing_objects_without_performing",
                "message": f"Serializable class '{class_name}' validates in constructor but lacks deserialization validation (IDeserializationCallback or property validation)",
                "line": line_num,
                "severity": "Major",
                "node": f"ClassDeclaration.{class_name}",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_disabling_aspnet_request_validation(ast_tree, filename):
    """Detect [ValidateInput(false)] attribute."""
    import re
    findings = []
    full_source = ast_tree.get('source', '')
    
    for match in re.finditer(r'\[ValidateInput\s*\(\s*false\s*\)\]', full_source):
        line_num = full_source[:match.start()].count('\n') + 1
        findings.append({
            "rule_id": "disabling_aspnet_request_validation",
            "message": "Disabling ASP.NET request validation ([ValidateInput(false)]) is security-sensitive",
            "line": line_num,
            "severity": "Major",
            "node": "Attribute.ValidateInput",
            "status": "violation",
            "file": filename
        })
    
    return findings


def check_disabling_csrf_protections(ast_tree, filename):
    """Detect missing or disabled CSRF protection on state-changing actions."""
    import re
    findings = []
    full_source = ast_tree.get('source', '')
    children = ast_tree.get('children', [])
    
    # Check for ValidateAntiForgeryToken(false) - explicit disabling
    for match in re.finditer(r'\[ValidateAntiForgeryToken\s*\(\s*false\s*\)\]', full_source):
        line_num = full_source[:match.start()].count('\n') + 1
        findings.append({
            "rule_id": "disabling_csrf_protections_is",
            "message": "Disabling CSRF protection ([ValidateAntiForgeryToken(false)]) is security-sensitive",
            "line": line_num,
            "severity": "Critical",
            "node": "Attribute.ValidateAntiForgeryToken",
            "status": "violation",
            "file": filename
        })
    
    # Check for IgnoreAntiforgeryToken attribute - at class or method level
    for match in re.finditer(r'\[IgnoreAntiforgeryToken\]', full_source):
        line_num = full_source[:match.start()].count('\n') + 1
        findings.append({
            "rule_id": "disabling_csrf_protections_is",
            "message": "Disabling CSRF protection ([IgnoreAntiforgeryToken]) is security-sensitive",
            "line": line_num,
            "severity": "Critical",
            "node": "Attribute.IgnoreAntiforgeryToken",
            "status": "violation",
            "file": filename
        })
    
    # Now check for HTTP methods missing CSRF protection
    lines = full_source.split('\n')
    http_method_patterns = [
        (r'\[HttpPost\]', 'POST'),
        (r'\[HttpPut\]', 'PUT'),
        (r'\[HttpDelete\]', 'DELETE'),
        (r'\[HttpPatch\]', 'PATCH')
    ]
    
    for pattern, method_type in http_method_patterns:
        for match in re.finditer(pattern, full_source, re.IGNORECASE):
            http_line_num = full_source[:match.start()].count('\n') + 1
            
            # Look for the method declaration following this HTTP attribute
            method_found = False
            method_name = "unknown"
            method_line = http_line_num
            
            for line_offset in range(10):  # Look ahead up to 10 lines
                check_line_num = http_line_num + line_offset
                if check_line_num <= len(lines):
                    line_content = lines[check_line_num - 1] if check_line_num > 0 else ""
                    
                    # Look for method declaration
                    method_match = re.search(r'public\s+\w+\s+(\w+)\s*\([^)]*\)', line_content)
                    if method_match:
                        method_name = method_match.group(1)
                        method_line = check_line_num
                        method_found = True
                        break
            
            if method_found:
                # Extract broader context to check for CSRF attributes
                # Look back for controller-level attributes and forward for method attributes
                context_start = max(0, http_line_num - 10)
                context_end = min(len(lines), method_line + 5)
                context_lines = lines[context_start:context_end]
                context_text = '\n'.join(context_lines)
                
                # Check if this method or its controller has CSRF protection/disabling
                has_validate_antiforgery = re.search(r'\[ValidateAntiForgeryToken\]', context_text) is not None
                has_ignore_antiforgery = re.search(r'\[IgnoreAntiforgeryToken\]', context_text) is not None
                has_disabled_antiforgery = re.search(r'\[ValidateAntiForgeryToken\s*\(\s*false\s*\)\]', context_text) is not None
                
                # Special case: if this HTTP method is immediately preceded by IgnoreAntiforgeryToken
                # on the line directly before, don't flag as missing protection
                immediate_context_start = max(0, http_line_num - 2)
                immediate_context_end = min(len(lines), http_line_num + 3)
                immediate_context_lines = lines[immediate_context_start:immediate_context_end]
                immediate_context = '\n'.join(immediate_context_lines)
                
                has_immediate_ignore = re.search(r'\[IgnoreAntiforgeryToken\]\s*\[Http', immediate_context) is not None
                
                # If method has explicit disabling or is immediately preceded by ignore, skip
                if has_ignore_antiforgery or has_disabled_antiforgery or has_immediate_ignore:
                    continue
                
                # Also check if we're inside a controller that has class-level IgnoreAntiforgeryToken
                # Look for IgnoreAntiforgeryToken followed by class declaration (possibly on different lines)
                class_ignore_pattern = r'\[IgnoreAntiforgeryToken\].*?public\s+class'
                controller_has_ignore = re.search(class_ignore_pattern, context_text, re.DOTALL) is not None
                
                # For methods in controllers with class-level ignore, we still want to flag them
                # as they represent the same security issue
                if controller_has_ignore:
                    # Flag this as a method in a controller with disabled CSRF
                    findings.append({
                        "rule_id": "disabling_csrf_protections_is",
                        "message": f"{method_type} action in controller with disabled CSRF protection is security-sensitive",
                        "line": http_line_num,
                        "severity": "Critical",
                        "node": f"MethodDeclaration.{method_name}",
                        "status": "violation",
                        "file": filename
                    })
                    continue
                
                # Check if method is missing CSRF protection
                if not has_validate_antiforgery:
                    findings.append({
                        "rule_id": "disabling_csrf_protections_is",
                        "message": f"{method_type} action missing [ValidateAntiForgeryToken] attribute is security-sensitive",
                        "line": http_line_num,
                        "severity": "Critical",
                        "node": f"MethodDeclaration.{method_name}",
                        "status": "violation",
                        "file": filename
                    })
    
    return findings


def check_doubled_prefix_operators(ast_tree, filename):
    """Detect doubled prefix operators !! and ~~."""
    import re
    findings = []
    full_source = ast_tree.get('source', '')
    
    patterns = [
        (r'!!', 'Doubled !! operator is redundant'),
        (r'~~', 'Doubled ~~ operator cancels out')
    ]
    
    for pattern, message in patterns:
        for match in re.finditer(pattern, full_source):
            # Skip if in string or comment
            line_start = full_source.rfind('\n', 0, match.start()) + 1
            line_end = full_source.find('\n', match.start())
            if line_end == -1:
                line_end = len(full_source)
            line_text = full_source[line_start:line_end]
            
            # Check if operators are in a comment (before //)
            comment_pos = line_text.find('//')
            operator_pos = match.start() - line_start
            if comment_pos != -1 and operator_pos > comment_pos:
                continue
                
            # Check if operators are inside string literals
            is_in_string = False
            quote_count = 0
            for i, char in enumerate(line_text):
                if char == '"' and (i == 0 or line_text[i-1] != '\\'):
                    quote_count += 1
                if i == operator_pos:
                    is_in_string = (quote_count % 2 == 1)
                    break
                    
            if is_in_string:
                continue
            
            line_num = full_source[:match.start()].count('\n') + 1
            findings.append({
                "rule_id": "doubled_prefix_operators_avoided",
                "message": message,
                "line": line_num,
                "severity": "Major",
                "node": "Expression",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_duplicate_casts(ast_tree, filename):
    """Detect duplicate type casts like (string)(string)obj and is-cast patterns."""
    import re
    findings = []
    full_source = ast_tree.get('source', '')
    
    # Pattern 1: Direct duplicate casts like (Type)(Type)obj
    # Enhanced pattern to support complex types including generics
    direct_pattern = r'\(([^)]+)\)\s*\(\1\)'
    
    for match in re.finditer(direct_pattern, full_source):
        line_num = full_source[:match.start()].count('\n') + 1
        type_name = match.group(1).strip()
        findings.append({
            "rule_id": "duplicate_casts_made",
            "message": f"Duplicate cast to '{type_name}' is redundant",
            "line": line_num,
            "severity": "Major",
            "node": "CastExpression",
            "status": "violation",
            "file": filename
        })
    
    # Pattern 2: is-cast pattern like "if (obj is Type) { var x = (Type)obj; }"
    is_cast_pattern = r'if\s*\([^)]*\s+is\s+([^)]+?)\s*\)\s*\{[^}]*?=\s*\(\1\)'
    
    for match in re.finditer(is_cast_pattern, full_source, re.DOTALL):
        line_num = full_source[:match.start()].count('\n') + 1
        type_name = match.group(1).strip()
        findings.append({
            "rule_id": "duplicate_casts_made",
            "message": f"Cast after 'is {type_name}' check is redundant - use pattern matching instead",
            "line": line_num,
            "severity": "Major",
            "node": "CastExpression",
            "status": "violation",
            "file": filename
        })
    
    return findings


def check_dynamic_code_execution_vulnerable(ast_tree, filename):
    """Detect unsafe dynamic code execution (Assembly.Load, CompileAssemblyFromSource, etc.)."""
    import re
    findings = []
    full_source = ast_tree.get('source', '')
    
    dangerous_patterns = [
        (r'Assembly\.Load\s*\([^)]*\)', 'Assembly.Load with user input is vulnerable to code injection'),
        (r'Assembly\.LoadFrom\s*\([^)]*\)', 'Assembly.LoadFrom with user input is vulnerable'),
        (r'Assembly\.LoadFile\s*\([^)]*\)', 'Assembly.LoadFile with user input is vulnerable'),
        (r'CompileAssemblyFromSource\s*\(', 'Dynamic code compilation is vulnerable to code injection')
    ]
    
    for pattern, message in dangerous_patterns:
        for match in re.finditer(pattern, full_source):
            match_text = match.group(0)
            
            # Skip if loading constant/known assembly
            if re.search(r'"[^"]*"', match_text):
                continue
                
            line_num = full_source[:match.start()].count('\n') + 1
            findings.append({
                "rule_id": "dynamic_code_execution_vulnerable",
                "message": message,
                "line": line_num,
                "severity": "Critical",
                "node": "CallExpression",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_dont_hardcode_format_when(ast_tree, filename):
    """Detect hardcoded date/time format strings in ToString()."""
    import re
    findings = []
    full_source = ast_tree.get('source', '')
    
    # Match DateTime.ToString("format") or date.ToString("format")
    pattern = r'\.ToString\s*\(\s*"([^"]*[dDmMyYhHsS][^"]*)"\s*\)'
    
    for match in re.finditer(pattern, full_source):
        format_string = match.group(1)
        
        # Skip if standard format (single char) or if CultureInfo is mentioned
        if len(format_string) == 1 or 'CultureInfo' in match.group(0):
            continue
        
        # Skip if format contains date/time specifiers
        if not re.search(r'[dDmMyYhHsS]', format_string):
            continue
            
        line_num = full_source[:match.start()].count('\n') + 1
        findings.append({
            "rule_id": "dont_hardcode_format_when",
            "message": f"Hardcoded date/time format string '{format_string}' should use standard format or CultureInfo",
            "line": line_num,
            "severity": "Major",
            "node": "CallExpression.ToString",
            "status": "violation",
            "file": filename
        })
    
    return findings


def check_disposable_types_declare_finalizers(ast_tree, filename):
    """Detect IDisposable types with unmanaged resources but no finalizer."""
    import re
    findings = []
    full_source = ast_tree.get('source', '')
    children = ast_tree.get('children', [])
    
    for node in children:
        if node.get('node_type') != 'ClassDeclaration':
            continue
        
        class_name = node.get('name', '').strip()
        line_num = node.get('lineno', 0)
        
        # Skip if class name is invalid or contains parsing artifacts
        if not class_name or class_name in ['unknown', 'should'] or len(class_name) < 3:
            continue
        
        # Extract broader context around the class declaration for analysis
        lines = full_source.split('\n')
        if line_num <= 0 or line_num > len(lines):
            continue
            
        # Get context from several lines before the class to several lines after
        start_idx = max(0, line_num - 5)
        end_idx = min(len(lines), line_num + 50)  # Look further ahead to capture full class
        class_context_lines = lines[start_idx:end_idx]
        class_context = '\n'.join(class_context_lines)
        
        # More precise IDisposable detection - look for inheritance declaration
        implements_idisposable = False
        
        # Find the line with the class declaration
        class_declaration_pattern = rf'public\s+(abstract\s+)?class\s+{re.escape(class_name)}\s*:'
        class_match = re.search(class_declaration_pattern, class_context, re.IGNORECASE)
        
        if class_match:
            # Get the inheritance part after the colon
            colon_pos = class_match.end()
            remaining_text = class_context[colon_pos:]
            # Look for IDisposable in the inheritance list (before any opening brace)
            brace_pos = remaining_text.find('{')
            if brace_pos != -1:
                inheritance_part = remaining_text[:brace_pos]
            else:
                inheritance_part = remaining_text[:200]  # Fallback limit
            
            # Check for direct IDisposable implementation or inheritance from IDisposable class
            if (re.search(r'\bIDisposable\b', inheritance_part, re.IGNORECASE) or
                re.search(r'\bAbstractDisposable\b', inheritance_part, re.IGNORECASE)):
                implements_idisposable = True
        
        if not implements_idisposable:
            continue
        
        # Skip abstract classes
        if re.search(rf'abstract\s+class\s+{re.escape(class_name)}', class_context, re.IGNORECASE):
            continue
        
        # Check for unmanaged resource fields within this class context
        # Be more specific - look for exact field declarations
        has_unmanaged = False
        
        # Extract just this class's content (between its opening and closing braces)
        class_start = class_context.find(f'class {class_name}')
        if class_start == -1:
            continue
            
        brace_count = 0
        in_class_body = False
        class_body_start = -1
        class_body_end = -1
        
        for i, char in enumerate(class_context[class_start:], class_start):
            if char == '{':
                if not in_class_body:
                    in_class_body = True
                    class_body_start = i + 1
                    brace_count = 1
                else:
                    brace_count += 1
            elif char == '}' and in_class_body:
                brace_count -= 1
                if brace_count == 0:
                    class_body_end = i
                    break
        
        if class_body_start != -1 and class_body_end != -1:
            class_body = class_context[class_body_start:class_body_end]
        else:
            class_body = class_context  # Fallback
        
        # Look for unmanaged field declarations specifically
        unmanaged_field_patterns = [
            r'private\s+IntPtr\s+\w+\s*;',
            r'protected\s+IntPtr\s+\w+\s*;',
            r'public\s+IntPtr\s+\w+\s*;',
            r'private\s+UIntPtr\s+\w+\s*;',
            r'protected\s+UIntPtr\s+\w+\s*;',
            r'public\s+UIntPtr\s+\w+\s*;',
            r'private\s+HandleRef\s+\w+\s*;',
            r'protected\s+HandleRef\s+\w+\s*;',
            r'public\s+HandleRef\s+\w+\s*;'
        ]
        
        for pattern in unmanaged_field_patterns:
            if re.search(pattern, class_body, re.IGNORECASE):
                has_unmanaged = True
                break
        
        if not has_unmanaged:
            continue
        
        # Check for finalizer (destructor) - look for ~ClassName() pattern
        finalizer_pattern = rf'~{re.escape(class_name)}\s*\('
        has_finalizer = bool(re.search(finalizer_pattern, class_context, re.IGNORECASE))
        
        if not has_finalizer:
            findings.append({
                "rule_id": "disposable_types_declare_finalizers",
                "message": f"Class '{class_name}' implements IDisposable and uses unmanaged resources but lacks a finalizer",
                "line": line_num,
                "severity": "Major",
                "node": f"ClassDeclaration.{class_name}",
                "status": "violation",
                "file": filename
            })
    
    return findings


def check_debugger_display_references_exist(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for debuggerdisplayattribute_strings_reference_existing rule.
    Checks that DebuggerDisplay attribute strings reference existing members.
    
    The DebuggerDisplayAttribute is used to determine how an object is displayed in the debugger window.
    Any text within curly braces is evaluated as the name of a field or property, or any complex 
    expression containing method calls and operators. Naming a non-existent member between curly 
    braces will result in a CS0103 error in the debug window when debugging objects.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Find all classes, structs, and records with DebuggerDisplay attribute
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        
        # Look for DebuggerDisplay attribute
        debugger_display_match = re.match(r'\[DebuggerDisplay\s*\(\s*["\'](.+?)["\']\s*\)\]', line)
        
        if debugger_display_match:
            display_string = debugger_display_match.group(1)
            attribute_line = i + 1
            
            # Look for the class/struct/record declaration on the next non-empty line
            j = i + 1
            while j < len(lines) and not lines[j].strip():
                j += 1
            
            if j < len(lines):
                declaration_line = lines[j].strip()
                class_match = re.search(r'\b(class|struct|record)\s+(\w+)', declaration_line)
                
                if class_match:
                    type_kind = class_match.group(1)
                    type_name = class_match.group(2)
                    
                    # Extract all member references from the display string
                    # Members are in curly braces: {MemberName} or {Method()} or {Property.SubProperty}
                    member_refs = re.findall(r'\{([^}]+)\}', display_string)
                    
                    if member_refs:
                        # Extract the body of the class/struct/record
                        type_body = ""
                        brace_count = 0
                        start_found = False
                        for k in range(j, len(lines)):
                            current_line = lines[k]
                            type_body += current_line + "\n"
                            for char in current_line:
                                if char == '{':
                                    brace_count += 1
                                    start_found = True
                                elif char == '}':
                                    brace_count -= 1
                            if start_found and brace_count == 0:
                                break
                        
                        # Extract actual members from the class/struct/record body
                        actual_members = set()
                        
                        # Properties: public Type PropertyName { get; set; } or public Type<GenericType> PropertyName { get; set; }
                        property_matches = re.finditer(r'\b(public|private|protected|internal)\s+[\w<>.,\s]+\s+(\w+)\s*\{', type_body)
                        for match in property_matches:
                            actual_members.add(match.group(2))
                        
                        # Fields: public Type fieldName; or public Type fieldName = value;
                        field_matches = re.finditer(r'\b(public|private|protected|internal)\s+[\w<>.,\s]+\s+(\w+)\s*[;=]', type_body)
                        for match in field_matches:
                            # Make sure we don't capture the type name
                            field_name = match.group(2)
                            if field_name not in ['get', 'set', 'init']:
                                actual_members.add(field_name)
                        
                        # Methods: public Type MethodName(...) - handle generic return types
                        method_matches = re.finditer(r'\b(public|private|protected|internal|static|virtual|override|abstract)\s+[\w<>.,\s]+\s+(\w+)\s*\(', type_body)
                        for match in method_matches:
                            actual_members.add(match.group(2))
                        
                        # Record parameters (primary constructor)
                        if type_kind == 'record':
                            record_params = re.search(r'record\s+\w+\s*\(([^)]+)\)', declaration_line)
                            if record_params:
                                params = record_params.group(1).split(',')
                                for param in params:
                                    param_match = re.search(r'\w+\s+(\w+)', param.strip())
                                    if param_match:
                                        actual_members.add(param_match.group(1))
                        
                        # Check each member reference
                        for member_ref in member_refs:
                            # Clean up the reference
                            base_member = member_ref.strip()
                            
                            # Remove this. prefix if present
                            base_member = re.sub(r'this\.', '', base_member)
                            
                            # For property access (Customer.Name), only validate the first part
                            # For expressions (Quantity * Price), validate all identifiers
                            if '.' in base_member and not any(op in base_member for op in ['*', '+', '-', '/', '%', '(', ')']):
                                # Simple property access - only check the first identifier
                                first_part = base_member.split('.')[0].strip()
                                identifiers_to_check = [first_part] if re.match(r'^[A-Za-z_]\w*$', first_part) else []
                            else:
                                # Expression or simple member - extract all identifiers
                                identifiers_to_check = re.findall(r'\b([A-Za-z_]\w*)\b', base_member)
                            
                            # Skip common keywords and special cases
                            skip_identifiers = {'null', 'true', 'false', 'this', 'base', 'ToString', 'GetHashCode', 'Equals', 'GetType', 'Count', 'Length'}
                            
                            for identifier in identifiers_to_check:
                                if identifier not in skip_identifiers and identifier not in actual_members:
                                    findings.append({
                                        "rule_id": "debuggerdisplayattribute_strings_reference_existing",
                                        "message": f"DebuggerDisplay attribute references non-existent member '{identifier}' in {type_kind} '{type_name}'",
                                        "line": attribute_line,
                                        "severity": "Major",
                                        "node": f"{type_kind.capitalize()}Declaration.{type_name}",
                                        "status": "violation",
                                        "file": filename
                                    })
        
        i += 1
    
    return findings


def check_default_parameter_values_passed(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for method calls that pass default parameter values explicitly.
    This requires matching method calls to their declarations to know default values.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Step 1: Extract method declarations with default parameters
    # Format: method_name -> {'params': [(name, has_default, default_value)], 'total': count}
    method_signatures = {}
    
    for i, line in enumerate(lines):
        # Match method declarations with parameters
        # Pattern: access_modifier return_type method_name(params)
        method_decl = re.search(r'\b(?:public|private|protected|internal)?\s*(?:static)?\s*[\w<>.,\[\]]+\s+(\w+)\s*\(([^)]+)\)', line)
        if method_decl:
            method_name = method_decl.group(1)
            params_str = method_decl.group(2).strip()
            
            # Skip constructors and common non-method patterns
            if method_name in ['if', 'while', 'for', 'switch', 'catch']:
                continue
            
            # Parse all parameters
            all_params = []
            has_defaults = False
            if params_str:
                # Split by comma, but be careful with nested generics
                params = []
                current_param = ""
                depth = 0
                for char in params_str:
                    if char == '<':
                        depth += 1
                    elif char == '>':
                        depth -= 1
                    elif char == ',' and depth == 0:
                        params.append(current_param.strip())
                        current_param = ""
                        continue
                    current_param += char
                if current_param.strip():
                    params.append(current_param.strip())
                
                # Extract parameter info: name, has_default, default_value
                for param in params:
                    # Pattern: type param_name = default_value
                    default_match = re.search(r'\b(\w+)\s*=\s*(.+)$', param)
                    if default_match:
                        param_name = default_match.group(1)
                        default_value = default_match.group(2).strip()
                        all_params.append((param_name, True, default_value))
                        has_defaults = True
                    else:
                        # Required parameter - extract just the name
                        param_name_match = re.search(r'\b(\w+)\s*$', param)
                        if param_name_match:
                            param_name = param_name_match.group(1)
                            all_params.append((param_name, False, None))
            
            if has_defaults:
                method_signatures[method_name] = {
                    'params': all_params,
                    'total': len(all_params)
                }
    
    # Step 2: Find method calls and check if they pass default values
    for i, line in enumerate(lines, 1):
        # Skip method declarations
        if re.search(r'\b(?:public|private|protected|internal)?\s*(?:static)?\s*[\w<>.,\[\]]+\s+\w+\s*\([^)]*\)\s*{', line):
            continue
        
        # Find method calls
        # Pattern: method_name(args) or obj.method_name(args)
        for method_name, signature in method_signatures.items():
            all_params = signature['params']
            
            # Look for calls to this method
            call_pattern = rf'\b{method_name}\s*\(([^)]*)\)'
            calls = re.finditer(call_pattern, line)
            
            for call_match in calls:
                args_str = call_match.group(1).strip()
                if not args_str:
                    continue
                
                # Parse arguments (positional and named)
                args = []
                current_arg = ""
                depth = 0
                paren_depth = 0
                for char in args_str:
                    if char == '<':
                        depth += 1
                    elif char == '>':
                        depth -= 1
                    elif char == '(':
                        paren_depth += 1
                    elif char == ')':
                        paren_depth -= 1
                    elif char == ',' and depth == 0 and paren_depth == 0:
                        args.append(current_arg.strip())
                        current_arg = ""
                        continue
                    current_arg += char
                if current_arg.strip():
                    args.append(current_arg.strip())
                
                # Check each argument
                for arg_index, arg in enumerate(args):
                    # Check for named argument: param_name: value
                    named_match = re.match(r'(\w+)\s*:\s*(.+)', arg)
                    
                    if named_match:
                        # Named argument
                        param_name = named_match.group(1)
                        arg_value = named_match.group(2).strip()
                        
                        # Find this parameter in signature
                        for p_name, has_default, default_value in all_params:
                            if p_name == param_name and has_default:
                                # Normalize values for comparison
                                normalized_arg = arg_value.strip().strip('"').strip("'")
                                normalized_default = default_value.strip().strip('"').strip("'")
                                
                                if normalized_arg == normalized_default:
                                    findings.append({
                                        "rule_id": "default_parameter_values_passed",
                                        "message": f"Remove redundant argument '{param_name}' with default value '{default_value}'",
                                        "line": i,
                                        "severity": "Major",
                                        "node": f"CallExpression.{method_name}",
                                        "status": "violation",
                                        "file": filename
                                    })
                                break
                    else:
                        # Positional argument - map to parameter at this position
                        if arg_index < len(all_params):
                            param_name, has_default, default_value = all_params[arg_index]
                            if has_default:
                                arg_value = arg.strip()
                                
                                # Normalize values for comparison
                                normalized_arg = arg_value.strip().strip('"').strip("'")
                                normalized_default = default_value.strip().strip('"').strip("'")
                                
                                if normalized_arg == normalized_default:
                                    # Check if all subsequent arguments (if any) also match their defaults
                                    # If any subsequent arg doesn't match its default, this default is needed
                                    all_subsequent_are_defaults = True
                                    for subsequent_idx in range(arg_index + 1, len(args)):
                                        if subsequent_idx < len(all_params):
                                            _, sub_has_default, sub_default_value = all_params[subsequent_idx]
                                            subsequent_arg = args[subsequent_idx].strip()
                                            
                                            # Check if it's a named argument
                                            if ':' in subsequent_arg and not any(c in subsequent_arg.split(':')[0] for c in ['<', '>', '(', ')']):
                                                # It's a named argument, doesn't affect our check
                                                continue
                                            
                                            if sub_has_default:
                                                normalized_sub_arg = subsequent_arg.strip().strip('"').strip("'")
                                                normalized_sub_default = sub_default_value.strip().strip('"').strip("'")
                                                if normalized_sub_arg != normalized_sub_default:
                                                    all_subsequent_are_defaults = False
                                                    break
                                            else:
                                                # Subsequent param has no default, so current default is needed
                                                all_subsequent_are_defaults = False
                                                break
                                    
                                    if all_subsequent_are_defaults:
                                        findings.append({
                                            "rule_id": "default_parameter_values_passed",
                                            "message": f"Remove redundant argument at position {arg_index + 1} with default value '{default_value}'",
                                            "line": i,
                                            "severity": "Major",
                                            "node": f"CallExpression.{method_name}",
                                            "status": "violation",
                                            "file": filename
                                        })
    
    return findings


def check_deprecated_code(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for deprecated_code_removed rule.
    Detects [Obsolete] attributes on any code declaration.
    Handles cases where the attribute is on a preceding line.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Pattern to match [Obsolete] attribute in various forms
    obsolete_pattern = re.compile(r'\[(?:System\.)?Obsolete(?:Attribute)?[^\]]*\]')
    
    # Track lines with [Obsolete] attributes
    obsolete_lines = {}
    for line_num, line in enumerate(lines, 1):
        line_strip = line.strip()
        if obsolete_pattern.search(line_strip):
            obsolete_lines[line_num] = line_strip
    
    # For each [Obsolete] attribute found, check if it's followed by a declaration
    for attr_line_num, attr_text in obsolete_lines.items():
        # Extract the attribute match for the violation report
        match = obsolete_pattern.search(attr_text)
        if not match:
            continue
        
        obsolete_value = match.group(0)
        
        # Check if this line itself has a declaration (attribute on same line)
        same_line = lines[attr_line_num - 1] if attr_line_num <= len(lines) else ""
        if re.search(r'\b(class|interface|struct|enum|delegate|void|int|string|bool|public|private|protected|internal|static|virtual|override|abstract|event|get|set)\s+', same_line):
            findings.append({
                "rule_id": "deprecated_code_removed",
                "message": "Remove deprecated code marked with [Obsolete] attribute",
                "line": attr_line_num,
                "severity": "Major",
                "node": "Declaration",
                "status": "violation",
                "file": filename
            })
            continue
        
        # Check following lines for a declaration (attribute on preceding line)
        for offset in range(1, 5):  # Check up to 4 lines ahead
            check_line_num = attr_line_num + offset
            if check_line_num > len(lines):
                break
            
            check_line = lines[check_line_num - 1].strip()
            
            # Skip empty lines and comments
            if not check_line or check_line.startswith('//'):
                continue
            
            # Skip additional attributes
            if check_line.startswith('['):
                continue
            
            # Check if this is a declaration line with enhanced patterns
            declaration_patterns = [
                r'\b(public|private|protected|internal)\s+(static\s+)?(sealed\s+)?(abstract\s+)?(partial\s+)?(class|interface|struct|enum)\s+\w+',
                r'\b(public|private|protected|internal)\s+delegate\s+',
                r'\b(public|private|protected|internal)\s+(static\s+)?(virtual\s+)?(override\s+)?(abstract\s+)?[\w<>]+\s+\w+\s*[\(\{;]',
                r'\b(public|private|protected|internal)\s+(static\s+)?(readonly\s+)?(event\s+)?[\w<>]+\s+\w+\s*[;={]',  # Fields, events, properties
                r'\b(public|private|protected|internal)\s+\w+\s*\(',  # Constructors (ClassName followed by parenthesis)
                r'\boperator\s+[\+\-\*/!=%<>&\|\^~]',  # Operators
                r'\bthis\s*\[',  # Indexers
                r'^\s*\w+\s*[,]?\s*$',  # Enum member (simple name)
                r'\b(get|set)\s*[\{;]',  # Property accessors
            ]
            
            is_declaration = any(re.search(pattern, check_line) for pattern in declaration_patterns)
            
            if is_declaration:
                findings.append({
                    "rule_id": "deprecated_code_removed",
                    "message": "Remove deprecated code marked with [Obsolete] attribute",
                    "line": attr_line_num,
                    "severity": "Major",
                    "node": "Declaration",
                    "status": "violation",
                    "file": filename
                })
                break
    
    return findings

def check_line_length(node: Dict, max_length: int = 120) -> bool:
    """
    Check if any line in the node's source exceeds the maximum length.
    
    Args:
        node: AST node containing 'source' property
        max_length: Maximum allowed line length (default: 120)
        
    Returns:
        True if violation found (line too long), False otherwise
    """
    source = node.get('source', '')
    if not source:
        return False
    
    lines = source.split('\n')
    for line in lines:
        # Skip empty lines and comment lines
        stripped = line.strip()
        if not stripped or stripped.startswith('//') or stripped.startswith('/*'):
            continue
        
        # Check if line exceeds max length
        if len(line) > max_length:
            return True
    
    return False

def check_variable_shadowing(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for local variables that shadow class-level fields or properties.
    
    Args:
        ast_tree: Full AST tree with source code
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    
    if not ast_tree or 'source' not in ast_tree:
        return findings
    
    source = ast_tree['source']
    lines = source.split('\n')
    
    # Find all classes and their members (fields and properties only)
    class_members = {}  # class_name -> set of member names
    
    # Pattern to match class declarations
    class_pattern = r'^\s*(?:public\s+|private\s+|protected\s+|internal\s+)?(?:static\s+)?(?:partial\s+)?class\s+(\w+)'
    
    # Patterns to match field and property declarations (NOT in methods)
    field_pattern = r'^\s*(?:public\s+|private\s+|protected\s+|internal\s+)?(?:static\s+)?(?:readonly\s+)?(?:const\s+)?\w+(?:<[^>]*>)?\s+(\w+)(?:\s*[=;,])'
    property_pattern = r'^\s*(?:public\s+|private\s+|protected\s+|internal\s+)?(?:static\s+)?\w+(?:<[^>]*>)?\s+(\w+)\s*{\s*(?:get|set)'
    method_pattern = r'^\s*(?:public\s+|private\s+|protected\s+|internal\s+)?(?:static\s+)?(?:virtual\s+|override\s+|abstract\s+)?(?:\w+(?:<[^>]*>)?\s+)?(\w+)\s*\([^)]*\)\s*(?:{\s*)?$'
    
    current_class = None
    brace_count = 0
    in_method = False
    
    # First pass: Collect only actual class members (fields and properties)
    for i, line in enumerate(lines, 1):
        # Track brace count for scope
        if '{' in line:
            brace_count += line.count('{')
        if '}' in line:
            brace_count -= line.count('}')
            if brace_count <= 1:
                in_method = False
            if brace_count == 0:
                current_class = None
        
        # Find class declarations
        class_match = re.match(class_pattern, line)
        if class_match:
            current_class = class_match.group(1)
            class_members[current_class] = set()
            brace_count = 0
            in_method = False
            continue
        
        if current_class and brace_count == 1 and not in_method:
            # Check for method declarations at class level
            method_match = re.match(method_pattern, line)
            if method_match:
                in_method = True
                continue
            
            # Only collect fields and properties at class level (not in methods)
            field_match = re.match(field_pattern, line)
            if field_match:
                class_members[current_class].add(field_match.group(1))
            
            property_match = re.match(property_pattern, line)
            if property_match:
                class_members[current_class].add(property_match.group(1))
    
    # Second pass: Check for local variable shadowing in methods
    current_class = None
    current_method = None
    brace_count = 0
    local_var_pattern = r'^\s*(?:var|\w+(?:<[^>]*>)?)\s+(\w+)(?:\s*,\s*(\w+))*\s*[=;]'
    
    for i, line in enumerate(lines, 1):
        # Track scope
        if '{' in line:
            brace_count += line.count('{')
        if '}' in line:
            brace_count -= line.count('}')
            if brace_count <= 1:
                current_method = None
            if brace_count == 0:
                current_class = None
        
        # Find class
        class_match = re.match(class_pattern, line)
        if class_match:
            current_class = class_match.group(1)
            brace_count = 0
            continue
        
        # Find method
        if current_class and brace_count == 1:
            method_match = re.match(method_pattern, line)
            if method_match:
                current_method = method_match.group(1)
                continue
        
        # Check local variables in methods (brace_count > 1 means inside method)
        if current_class and current_method and brace_count > 1:
            # Skip lines with 'this.' qualifier - these are valid
            if 'this.' in line:
                continue
                
            var_match = re.match(local_var_pattern, line)
            if var_match:
                var_names = [var_match.group(1)]
                # Handle multiple variable declarations (int x, y, z;)
                if var_match.group(2):
                    remaining = line[var_match.end(1):]
                    additional_vars = re.findall(r',\s*(\w+)', remaining)
                    var_names.extend(additional_vars)
                
                # Check if any variable name shadows class member
                if current_class in class_members:
                    for var_name in var_names:
                        if var_name in class_members[current_class]:
                            findings.append({
                                'rule_id': 'local_variables_shadow_class',
                                'message': f"Local variable '{var_name}' shadows class member with the same name",
                                'file': filename,
                                'line': i,
                                'severity': 'Major',
                                'node': 'VariableDeclaration',
                                'property_path': ['source'],
                                'value': line.strip(),
                                'status': 'violation',
                            })
    
    return findings

def check_jwt_hardcoded_secrets(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for hardcoded secrets used in JWT token operations.
    Detects string literals passed to GetBytes() method that are used in JWT context.
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    seen_secrets = set()  # Track unique secrets to avoid duplicates
    
    def collect_nodes(node, node_list):
        """Recursively collect all nodes"""
        node_list.append(node)
        if 'children' in node and node['children']:
            for child in node['children']:
                collect_nodes(child, node_list)
    
    all_nodes = []
    collect_nodes(ast_tree, all_nodes)
    
    # Look for GetBytes calls with string literals
    getbytes_pattern = r'Encoding\.(UTF8|ASCII|Unicode)\.GetBytes\s*\(\s*"([^"]+)"\s*\)'
    
    # JWT-related keywords that indicate security context
    jwt_keywords = ['SymmetricSecurityKey', 'SigningCredentials', 'JwtSecurityToken', 
                   'SecurityKey', 'TokenDescriptor', 'ValidateToken']
    
    # Excluded contexts (tests, configuration, environment variables)
    excluded_contexts = ['[Test]', '[Fact]', '[TestMethod]', '[TestFixture]',
                        'Configuration[', 'ConfigurationManager', 'AppSettings',
                        'Environment.GetEnvironmentVariable', 'GetEnvironmentVariable',
                        'GetSecret', 'KeyVault']
    
    for node in all_nodes:
        source = node.get('source', '')
        if not source:
            continue
        
        # Only check MethodDeclaration nodes for more precise context
        if node.get('node_type') != 'MethodDeclaration':
            continue
        
        # Check if this method has any excluded context (test attributes, etc.)
        has_excluded_context = any(ctx in source for ctx in excluded_contexts)
        if has_excluded_context:
            continue
        
        # Find all GetBytes calls with string literals in this method
        for match in re.finditer(getbytes_pattern, source):
            secret_value = match.group(2)  # Group 2 is the string literal
            
            # Skip if we've already reported this exact secret
            if secret_value in seen_secrets:
                continue
            
            # Get context around the GetBytes call - look for JWT keywords nearby
            # This ensures GetBytes is actually used in JWT context, not just anywhere in the method
            match_start = match.start()
            match_end = match.end()
            
            # Check 200 characters before and after the match for JWT keywords
            context_start = max(0, match_start - 200)
            context_end = min(len(source), match_end + 200)
            context = source[context_start:context_end]
            
            has_jwt_context = any(keyword in context for keyword in jwt_keywords)
            
            if has_jwt_context:
                seen_secrets.add(secret_value)
                # Calculate line number
                lines_before = source[:match_start].count('\n')
                base_line = node.get('lineno', 1)
                match_line = base_line + lines_before
                
                findings.append({
                    'rule_id': 'jwt_secret_keys_disclosed',
                    'message': f'Hardcoded secret key should not be used in JWT operations: "{secret_value}"',
                    'file': filename,
                    'line': match_line,
                    'severity': 'Critical',
                    'property_path': ['source'],
                    'value': source.strip()[:100],
                    'node': f"{node.get('node_type', 'Unknown')}.{node.get('name', 'Unknown')}",
                    'status': 'violation'
                })
    
    return findings

def check_logging_in_catch_clause(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for logging_catch_clause_pass rule.
    Detects logging calls in catch blocks that don't pass the caught exception as a parameter.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    
    lines = source.split('\n')
    
    # Pattern to find catch blocks with logging calls (simplified)
    catch_pattern = r'catch\s*\(([^)]+)\s+(\w+)\s*\)\s*\{([^}]+)\}'
    
    matches = list(re.finditer(catch_pattern, source, re.MULTILINE | re.DOTALL))
    
    for match in re.finditer(catch_pattern, source, re.MULTILINE | re.DOTALL):
        exception_type = match.group(1).strip()
        exception_var = match.group(2).strip()
        catch_body = match.group(3)
        
        
        # Find logging calls in catch body
        log_pattern = r'\.(Log(Error|Warning|Information|Debug|Critical|Trace))\s*\('
        
        log_matches = list(re.finditer(log_pattern, catch_body))
        
        for log_match in re.finditer(log_pattern, catch_body):
            # Get the full logging call
            log_start = log_match.start()
            # Find the end of the logging call
            paren_count = 1
            i = log_match.end()
            while i < len(catch_body) and paren_count > 0:
                if catch_body[i] == '(':
                    paren_count += 1
                elif catch_body[i] == ')':
                    paren_count -= 1
                i += 1
            
            log_call = catch_body[log_start:i]
            
            
            # Check if exception variable is passed as first parameter (after opening paren)
            # Pattern: .LogError(ex, ...  or  .LogError( ex, ...
            exception_passed_pattern = rf'\.(Log\w+)\s*\(\s*{exception_var}\s*,'
            
            has_exception = re.search(exception_passed_pattern, log_call)
            
            if not has_exception:
                # Exception not passed as first parameter - this is a violation
                
                
                # Skip if THIS SPECIFIC catch block is in test code
                # Check the class/method containing this catch block
                catch_context = source[max(0, match.start() - 500):match.end()]
                if re.search(r'\[Test\]|\[Fact\]|\[Theory\]', catch_context):
                    continue
                
                # Skip if in ToString override
                if re.search(r'override\s+string\s+ToString\s*\(', catch_context):
                    continue
                
                # Find line number
                line_num = source[:match.start()].count('\n') + 1
                
                
                findings.append({
                    'rule_id': 'logging_catch_clause_pass',
                    'message': f'Logging in catch clause should pass the caught exception "{exception_var}" as a parameter',
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': log_call.strip()[:100],
                    'status': 'violation'
                })
    
    return findings


def check_locales_set_data_types(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for locales_set_data_types rule.
    Detects DataTable/DataSet creation without explicit Locale property setting.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Find all DataTable and DataSet instantiations
    # Pattern: new DataTable(...) or new DataSet(...)
    instantiation_pattern = r'(new\s+(DataTable|DataSet)\s*\([^)]*\))'
    
    for match in re.finditer(instantiation_pattern, source, re.MULTILINE):
        instantiation = match.group(1)
        type_name = match.group(2)
        var_name = None
        
        # Try to find the variable name this is assigned to
        # Look backward from match position to find variable name
        before_match = source[:match.start()].rstrip()
        
        # Pattern: var varName = new DataTable() or DataTable varName = new DataTable()
        var_pattern = r'(\w+)\s*=\s*$'
        var_match = re.search(var_pattern, before_match)
        if var_match:
            var_name = var_match.group(1)
        
        # Now check if Locale is set shortly after this instantiation
        # Look ahead to see if there's a .Locale assignment
        # Check within the next 500 characters for locale assignment
        after_instantiation = source[match.end():match.end() + 500]
        
        # Check for: varName.Locale = or { Locale = ... }
        locale_set = False
        
        if var_name:
            # Pattern: varName.Locale = 
            locale_assignment_pattern = rf'{var_name}\s*\.\s*Locale\s*='
            if re.search(locale_assignment_pattern, after_instantiation):
                locale_set = True
        
        # Also check for inline object initializer: new DataTable() { Locale = ... }
        inline_locale_pattern = r'\{\s*Locale\s*='
        remaining_line = source[match.end():match.end() + 200]
        if re.search(inline_locale_pattern, remaining_line):
            locale_set = True
        
        if not locale_set:
            # Violation found - no locale assignment
            line_num = source[:match.start()].count('\n') + 1
            
            findings.append({
                'rule_id': 'locales_set_data_types',
                'message': f'{type_name} instance created without setting Locale property',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': instantiation[:100],
                'status': 'violation'
            })
    
    return findings


def check_locks_released_all_paths(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for locks_released_all_paths rule.
    Detects lock acquisitions (Monitor.Enter, Mutex, ReaderWriterLock, etc.) 
    that are not released on all code paths.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Lock acquire patterns to detect
    acquire_patterns = [
        (r'Monitor\.Enter\s*\(', 'Monitor.Enter', 'Monitor.Exit'),
        (r'(\w+)\.AcquireReaderLock\s*\(', 'AcquireReaderLock', 'ReleaseReaderLock'),
        (r'(\w+)\.AcquireWriterLock\s*\(', 'AcquireWriterLock', 'ReleaseWriterLock'),
        (r'(\w+)\.EnterReadLock\s*\(', 'EnterReadLock', 'ExitReadLock'),
        (r'(\w+)\.EnterWriteLock\s*\(', 'EnterWriteLock', 'ExitWriteLock'),
        (r'(\w+)\.Enter\s*\(.*ref', 'SpinLock.Enter', 'Exit'),
    ]
    
    for acquire_pattern, acquire_name, release_name in acquire_patterns:
        for match in re.finditer(acquire_pattern, source):
            # Find the method containing this lock acquisition
            # Look backward to find the method declaration
            before_match = source[:match.start()]
            method_pattern = r'(public|private|protected|internal).*?\s+\w+\s*\([^)]*\)\s*\{[^}]*$'
            method_match = re.search(method_pattern, before_match, re.MULTILINE | re.DOTALL)
            
            if not method_match:
                continue
            
            # Find the end of the method
            method_start = method_match.start()
            brace_count = 0
            start_found = False
            method_end = method_start
            
            for i in range(method_start, len(source)):
                if source[i] == '{':
                    brace_count += 1
                    start_found = True
                elif source[i] == '}':
                    brace_count -= 1
                    if start_found and brace_count == 0:
                        method_end = i + 1
                        break
            
            method_body = source[method_start:method_end]
            
            # Check if lock is released in all paths
            # Look for try-finally pattern or lock statement
            has_try_finally = re.search(r'try\s*\{.*?finally\s*\{.*?' + release_name, method_body, re.DOTALL)
            has_lock_statement = 'lock(' in method_body or 'lock (' in method_body
            
            # Count acquire vs release calls
            acquire_count = len(re.findall(acquire_pattern, method_body))
            release_count = len(re.findall(release_name, method_body))
            
            # Violation if:
            # 1. Not using try-finally (which guarantees release on all paths)
            # 2. Not using lock statement (which guarantees release)
            # 3. AND (acquire > release OR has early returns with conditional releases)
            has_early_return = 'return;' in method_body or 'return ' in method_body
            has_conditional = 'if (' in method_body or 'if(' in method_body
            
            if not has_try_finally and not has_lock_statement:
                # If there are early returns or conditionals with same acquire/release count,
                # it's likely not all paths release the lock
                if acquire_count > release_count or (has_early_return and has_conditional and acquire_count == release_count):
                    # Potential violation - lock not released on all paths
                    line_num = source[:match.start()].count('\n') + 1
                    
                    findings.append({
                        'rule_id': 'locks_released_all_paths',
                        'message': f'Lock acquired with {acquire_name} but may not be released on all paths. Use try-finally or lock statement.',
                        'file': filename,
                        'line': line_num,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': match.group()[:100],
                        'status': 'violation'
                    })
    
    return findings


def check_locks_released_within_same(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for locks_released_within_same rule.
    Detects lock acquisitions that are not released within the same method.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Patterns for locks that should be released in same method
    lock_pairs = [
        (r'\.AcquireReaderLock\s*\(', r'\.ReleaseReaderLock\s*\(', 'AcquireReaderLock', 'ReleaseReaderLock'),
        (r'\.AcquireWriterLock\s*\(', r'\.ReleaseWriterLock\s*\(', 'AcquireWriterLock', 'ReleaseWriterLock'),
        (r'\.EnterReadLock\s*\(', r'\.ExitReadLock\s*\(', 'EnterReadLock', 'ExitReadLock'),
        (r'\.EnterUpgradeableReadLock\s*\(', r'\.ExitUpgradeableReadLock\s*\(', 'EnterUpgradeableReadLock', 'ExitUpgradeableReadLock'),
        (r'\.EnterWriteLock\s*\(', r'\.ExitWriteLock\s*\(', 'EnterWriteLock', 'ExitWriteLock'),
    ]
    
    for acquire_pattern, release_pattern, acquire_name, release_name in lock_pairs:
        for match in re.finditer(acquire_pattern, source):
            # Find the method containing this acquire call
            before_match = source[:match.start()]
            method_pattern = r'(public|private|protected|internal).*?\s+\w+\s*\([^)]*\)\s*\{?[^}]*$'
            method_match = re.search(method_pattern, before_match, re.MULTILINE | re.DOTALL)
            
            if not method_match:
                continue
            
            # Find method end
            method_start = method_match.start()
            brace_count = 0
            started = False
            method_end = method_start
            
            for i in range(method_start, len(source)):
                if source[i] == '{':
                    brace_count += 1
                    started = True
                elif source[i] == '}':
                    brace_count -= 1
                    if started and brace_count == 0:
                        method_end = i + 1
                        break
            
            method_body = source[method_start:method_end]
            
            # Check if corresponding release exists in same method
            has_release = re.search(release_pattern, method_body)
            
            if not has_release:
                # Violation - lock acquired but not released in same method
                line_num = source[:match.start()].count('\n') + 1
                
                findings.append({
                    'rule_id': 'locks_released_within_same',
                    'message': f'{acquire_name} should be released within the same method using {release_name}',
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': match.group()[:100],
                    'status': 'violation'
                })
    
    return findings

def check_loggers_named_their_enclosing(ast_tree, filename):
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    re = __import__('re')
    
    # Find all class declarations with their positions
    class_pattern = r'(?:\[(?:TestClass|Test|Fact|Theory)\][^\{]*)?class\s+(\w+)'
    class_matches = list(re.finditer(class_pattern, source))
    
    def get_enclosing_class(pos):
        """Find the enclosing class name for a given position"""
        for i, cm in enumerate(class_matches):
            if cm.start() > pos:
                if i > 0:
                    return class_matches[i-1].group(1), class_matches[i-1].group(0)
                return None, None
        if class_matches:
            return class_matches[-1].group(1), class_matches[-1].group(0)
        return None, None
    
    def is_test_class(class_context):
        """Check if the class has test attributes"""
        if class_context:
            return bool(re.search(r'\[(?:TestClass|Test|Fact|Theory)\]', class_context))
        return False
    
    # Pattern 1: CreateLogger<T>()
    for match in re.finditer(r'CreateLogger<(\w+)>\s*\(', source):
        logger_type = match.group(1)
        class_name, class_context = get_enclosing_class(match.start())
        
        if class_name and logger_type != class_name:
            # Skip test classes
            if is_test_class(class_context):
                continue
            line_num = source[:match.start()].count('\n') + 1
            findings.append({
                'rule_id': 'loggers_named_their_enclosing',
                'message': f'Logger should be named for enclosing type {class_name}, not {logger_type}',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'status': 'violation'
            })
    
    # Pattern 2: LogManager.GetLogger("string") or GetLogger(typeof(Type)) or GetLogger(nameof(Type))
    for match in re.finditer(r'GetLogger\s*\(\s*(?:"(\w+)"|typeof\s*\(\s*(\w+)\s*\)|nameof\s*\(\s*(\w+)\s*\))\s*\)', source):
        logger_name = match.group(1) or match.group(2) or match.group(3)
        class_name, class_context = get_enclosing_class(match.start())
        
        if class_name and logger_name != class_name:
            # Skip test classes
            if is_test_class(class_context):
                continue
            line_num = source[:match.start()].count('\n') + 1
            findings.append({
                'rule_id': 'loggers_named_their_enclosing',
                'message': f'Logger should be named for enclosing type {class_name}, not {logger_name}',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'status': 'violation'
            })
    
    return findings

def check_logger_fields_private_static(ast_tree, filename):
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    re = __import__('re')
    
    # Pattern for logger fields - handles ILogger, ILogger<T>, Logger, Serilog.ILogger, NLog.Logger
    pattern = r'(public|protected|internal|private)?\s*(static)?\s*(readonly)?\s*(?:\w+\.)?(?:ILogger|Logger)[<\w>]*\s+(\w+)\s*[;=]'
    
    for match in re.finditer(pattern, source):
        field_decl = match.group()
        field_name = match.group(4)
        
        # Get context to check for exclusions
        match_start = match.start()
        context_before = source[max(0, match_start - 500):match_start]
        
        # Skip test classes
        if re.search(r'\[(?:TestClass|Test|Fact|Theory)\]', context_before):
            continue
        
        # Check if this is a DI-injected logger (has constructor that receives the logger)
        # Look for constructor pattern that assigns to this field
        class_context = source[max(0, match_start - 1000):min(len(source), match_start + 2000)]
        di_pattern = rf'public\s+\w+\s*\([^)]*(?:ILogger|Logger)[<\w>]*\s+\w+[^)]*\)\s*\{{\s*[^}}]*{re.escape(field_name)}\s*='
        if re.search(di_pattern, class_context, re.DOTALL):
            # This is a DI-injected logger - it should be readonly but not static
            is_private = 'private' in field_decl or (not any(m in field_decl for m in ['public', 'protected', 'internal']))
            is_readonly = 'readonly' in field_decl
            if is_private and is_readonly:
                continue  # DI pattern is compliant if private and readonly
        
        is_private = 'private' in field_decl or (not any(m in field_decl for m in ['public', 'protected', 'internal']))
        is_static = 'static' in field_decl
        is_readonly = 'readonly' in field_decl
        
        if not (is_private and is_static and is_readonly):
            line_num = source[:match.start()].count('\n') + 1
            issues = []
            if not is_private: issues.append('should be private')
            if not is_static: issues.append('should be static')
            if not is_readonly: issues.append('should be readonly')
            findings.append({
                'rule_id': 'logger_fields_private_static',
                'message': f'Logger field {", ".join(issues)}',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'status': 'violation'
            })
    
    return findings

def check_logger_field_property_name(ast_tree, filename):
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    re = __import__('re')
    
    # Pattern for logger fields - handles ILogger, ILogger<T>, Logger
    pattern = r'(?:\w+\.)?(?:ILogger|Logger)[<\w>]*\s+(\w+)\s*[;=]'
    
    for match in re.finditer(pattern, source):
        logger_name = match.group(1)
        
        # Skip if name is correct
        if logger_name in ['logger', '_logger', 'LOG']:
            continue
        
        # Get context to check for exclusions
        match_start = match.start()
        context_before = source[max(0, match_start - 500):match_start]
        
        # Skip test classes
        if re.search(r'\[(?:TestClass|Test|Fact|Theory)\]', context_before):
            continue
        
        line_num = source[:match.start()].count('\n') + 1
        findings.append({
            'rule_id': 'logger_field_property_name',
            'message': f'Logger name "{logger_name}" should follow naming convention (logger, _logger, or LOG)',
            'file': filename,
            'line': line_num,
            'severity': 'Major',
            'status': 'violation'
        })
    
    return findings

def check_logging_arguments_passed_correct(ast_tree, filename):
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    re = __import__('re')
    
    # Pattern: _logger.Log*("template", args) or logger.Log*("template", args)
    # Match the last argument part after the template string
    log_pattern = r'_?logger\.(Log(?:Error|Warning|Information|Debug|Critical|Trace)?)\s*\([^"]*"[^"]*"\s*,\s*([^;]+)\);'
    
    for match in re.finditer(log_pattern, source, re.MULTILINE | re.DOTALL):
        method = match.group(1)
        args = match.group(2).strip()
        
        # Get context to check for test/ToString exclusions
        match_start = match.start()
        context_before = source[max(0, match_start - 500):match_start]
        
        # Skip test methods
        if re.search(r'\[(?:Test|Fact|Theory)\]', context_before):
            continue
        
        # Skip ToString overrides
        if re.search(r'override\s+string\s+ToString\s*\(', context_before):
            continue
        
        line_num = source[:match.start()].count('\n') + 1
        
        # Check if exception variable is in args (standalone, not .Message or .ToString())
        # Match: ex, ioEx, exception, e (but not as part of other words)
        # Exclude: ex.Message, ex.ToString(), etc.
        exception_pattern = r'\b(ex|ioEx|exception)\s*(?:[,)]|$)'
        if re.search(exception_pattern, args, re.IGNORECASE):
            # Make sure it's not ex.Message, ex.ToString(), etc.
            if not re.search(r'\b(ex|ioEx|exception)\s*\.', args, re.IGNORECASE):
                findings.append({
                    'rule_id': 'logging_arguments_passed_correct',
                    'message': 'Exception should be passed as separate parameter, not in message arguments',
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'status': 'violation'
                })
                continue
        
        # Check if LogLevel variable is in args
        if re.search(r'\b(level|logLevel)\s*(?:[,)]|$)', args, re.IGNORECASE):
            findings.append({
                'rule_id': 'logging_arguments_passed_correct',
                'message': 'LogLevel should be passed as method parameter, not in message arguments',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'status': 'violation'
            })
    
    return findings

def check_log_message_template_placeholders(ast_tree, filename):
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    re = __import__('re')
    # Pattern: logger.Log*("template {Name}", args)
    log_pattern = r'logger\.Log\w*\("([^"]+)",\s*([^)]+)\)'
    for match in re.finditer(log_pattern, source):
        template = match.group(1)
        args_str = match.group(2)
        # Extract placeholder names from template
        placeholders = re.findall(r'\{(\w+)\}', template)
        # Extract argument names (simple variable names)
        args = [arg.strip() for arg in args_str.split(',')]
        # Check if placeholder names match argument names (case-insensitive)
        if len(placeholders) == len(args):
            for i, (placeholder, arg) in enumerate(zip(placeholders, args)):
                if placeholder.lower() != arg.lower():
                    line_num = source[:match.start()].count('\n') + 1
                    findings.append({'rule_id': 'log_message_template_placeholders', 'message': f'Argument order mismatch: placeholder {{{placeholder}}} does not match argument {arg}', 'file': filename, 'line': line_num, 'severity': 'Major', 'status': 'violation'})
                    break
    return findings

def check_log_message_template_syntactically(ast_tree, filename):
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    re = __import__('re')
    # Pattern: logger.Log*("template")
    log_pattern = r'logger\.Log\w*\("([^"]+)"'
    for match in re.finditer(log_pattern, source):
        template = match.group(1)
        # Check for empty placeholders {}
        if '{}' in template:
            line_num = source[:match.start()].count('\n') + 1
            findings.append({'rule_id': 'log_message_template_syntactically', 'message': 'Empty placeholder {} is not allowed', 'file': filename, 'line': line_num, 'severity': 'Major', 'status': 'violation'})
        # Check for unmatched braces
        open_count = template.count('{')
        close_count = template.count('}')
        if open_count != close_count:
            line_num = source[:match.start()].count('\n') + 1
            findings.append({'rule_id': 'log_message_template_syntactically', 'message': 'Unmatched braces in message template', 'file': filename, 'line': line_num, 'severity': 'Major', 'status': 'violation'})
        # Check for invalid characters in placeholders
        invalid_placeholders = re.findall(r'\{[^}]*[-\s][^}]*\}', template)
        if invalid_placeholders:
            line_num = source[:match.start()].count('\n') + 1
            findings.append({'rule_id': 'log_message_template_syntactically', 'message': f'Invalid characters in placeholder: {invalid_placeholders[0]}', 'file': filename, 'line': line_num, 'severity': 'Major', 'status': 'violation'})
    return findings

def check_exception_standard_constructors(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for exceptions_provide_standard_constructors rule.
    Checks that exception classes provide the three standard constructors:
    - public ExceptionName()
    - public ExceptionName(string message)
    - public ExceptionName(string message, Exception innerException)
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code if available
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    import re
    
    # Remove comments to avoid false matches
    source_no_comments = re.sub(r'//.*$', '', source, flags=re.MULTILINE)
    source_no_comments = re.sub(r'/\*.*?\*/', '', source_no_comments, flags=re.DOTALL)
    
    # Find all exception classes with a more comprehensive approach
    class_pattern = r'(?:public|internal|protected)(?:\s+(?:sealed|abstract))?\s+class\s+(\w+)\s*:\s*Exception\s*\{'
    
    for class_match in re.finditer(class_pattern, source_no_comments, re.IGNORECASE):
        class_name = class_match.group(1)
        
        # Check if this is in a test context (should be excluded)
        class_start = class_match.start()
        text_before_class = source_no_comments[:class_start]
        if re.search(r'\[(?:Test|Fact|TestMethod)\]', text_before_class[-200:], re.IGNORECASE):
            continue
        
        # Use a simpler approach: search for constructors in the entire remaining source
        # after the class declaration (this is more robust than brace matching)
        remaining_source = source_no_comments[class_match.end():]
        
        # Find the next class declaration to limit our search scope
        next_class_match = re.search(r'(?:public|internal|protected)(?:\s+(?:sealed|abstract))?\s+class\s+\w+', remaining_source, re.IGNORECASE)
        if next_class_match:
            class_body = remaining_source[:next_class_match.start()]
        else:
            class_body = remaining_source
        
        # Check for the three standard constructors within this class scope
        # More flexible patterns that account for various formatting
        parameterless_pattern = rf'(?:public|protected)\s+{re.escape(class_name)}\s*\(\s*\)'
        string_pattern = rf'(?:public|protected)\s+{re.escape(class_name)}\s*\(\s*string\s+\w+\s*\)'
        string_exception_pattern = rf'(?:public|protected)\s+{re.escape(class_name)}\s*\(\s*string\s+\w+\s*,\s*Exception\s+\w+\s*\)'
        
        has_parameterless = bool(re.search(parameterless_pattern, class_body, re.IGNORECASE))
        has_string = bool(re.search(string_pattern, class_body, re.IGNORECASE))
        has_string_exception = bool(re.search(string_exception_pattern, class_body, re.IGNORECASE))
        
        # If any standard constructor is missing, report violation
        if not (has_parameterless and has_string and has_string_exception):
            missing = []
            if not has_parameterless:
                missing.append("()")
            if not has_string:
                missing.append("(string)")
            if not has_string_exception:
                missing.append("(string, Exception)")
            
            message = f"Exception class '{class_name}' is missing standard constructors: {', '.join(missing)}"
            
            # Calculate line number
            line_number = source[:class_match.start()].count('\n') + 1
            
            findings.append({
                'rule_id': 'exceptions_provide_standard_constructors',
                'message': message,
                'node': f"ClassDeclaration.{class_name}",
                'file': filename,
                'property_path': ['source'],
                'value': class_match.group(0),
                'status': 'violation',
                'line': line_number,
                'severity': 'Major'
            })
    
    return findings


def check_exceptions_thrown_from_unexpected(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for exceptions_thrown_from_unexpected rule.
    Detects exceptions thrown from methods that should not throw:
    - ToString() overrides
    - Equals() overrides and IEquatable<T>.Equals implementations
    - GetHashCode() overrides
    - Dispose() implementations
    - Static constructors
    - Event accessors (add/remove)
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Find all methods that are flagged types and contain throw statements
    method_patterns = [
        # ToString override - using DOTALL to handle multiline
        (r'public\s+override\s+string\s+ToString\s*\([^)]*\)\s*\{.*?throw\s+new', 'ToString'),
        # Equals override
        (r'public\s+override\s+bool\s+Equals\s*\([^)]*\)\s*\{.*?throw\s+new', 'Equals'),
        # GetHashCode override
        (r'public\s+override\s+int\s+GetHashCode\s*\([^)]*\)\s*\{.*?throw\s+new', 'GetHashCode'),
        # IEquatable<T>.Equals implementation
        (r'public\s+bool\s+Equals\s*\([^)]+\s+\w+\)\s*\{.*?throw\s+new', 'IEquatable.Equals'),
        # Dispose implementation
        (r'public\s+void\s+Dispose\s*\([^)]*\)\s*\{.*?throw\s+new', 'Dispose'),
        # Static constructor
        (r'static\s+[A-Za-z_][A-Za-z0-9_]*\s*\([^)]*\)\s*\{.*?throw\s+new', 'static constructor'),
    ]
    
    for pattern, method_type in method_patterns:
        for match in re.finditer(pattern, source, re.DOTALL | re.IGNORECASE):
            # Check if this method has test attributes - look backwards for attributes
            method_start = match.start()
            preceding_text = source[:method_start]
            
            # Find the last few lines before this method to check for test attributes
            lines_before = preceding_text.split('\n')[-10:]  # Check last 10 lines
            has_test_attribute = any(re.search(r'\[\s*(?:Test|Fact)\s*\]', line) for line in lines_before)
            
            if has_test_attribute:
                continue  # Skip test methods
            
            # Calculate line number
            line_number = source[:match.start()].count('\n') + 1
            
            # Extract a reasonable portion for display
            match_text = match.group(0)
            if len(match_text) > 100:
                # Find the throw statement for better display
                throw_match = re.search(r'throw\s+new[^;]*', match_text)
                if throw_match:
                    display_value = throw_match.group(0)
                else:
                    display_value = match_text[:100] + '...'
            else:
                display_value = match_text
            
            findings.append({
                'rule_id': 'exceptions_thrown_from_unexpected',
                'message': f'Exceptions should not be thrown from {method_type} methods',
                'node': f"MethodDeclaration.{method_type}",
                'file': filename,
                'property_path': ['source'],
                'value': display_value,
                'status': 'violation',
                'line': line_number,
                'severity': 'Major'
            })
    
    # Special handling for event accessors (add/remove) - using DOTALL
    event_pattern = r'(add|remove)\s*\{.*?throw\s+new'
    for match in re.finditer(event_pattern, source, re.DOTALL | re.IGNORECASE):
        # Check for test context
        method_start = match.start()
        preceding_text = source[:method_start]
        lines_before = preceding_text.split('\n')[-10:]
        has_test_attribute = any(re.search(r'\[\s*(?:Test|Fact)\s*\]', line) for line in lines_before)
        
        if has_test_attribute:
            continue
        
        accessor_type = match.group(1)
        line_number = source[:match.start()].count('\n') + 1
        
        # Extract throw statement for display
        throw_match = re.search(r'throw\s+new[^;]*', match.group(0))
        display_value = throw_match.group(0) if throw_match else match.group(0)
        
        findings.append({
            'rule_id': 'exceptions_thrown_from_unexpected',
            'message': f'Exceptions should not be thrown from event {accessor_type} accessor',
            'node': f"EventAccessor.{accessor_type}",
            'file': filename,
            'property_path': ['source'],
            'value': display_value,
            'status': 'violation',
            'line': line_number,
            'severity': 'Major'
        })
    
    return findings


def check_exceptions_thrown_from_property_getter(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for exceptions_thrown_from_property rule.
    Detects exceptions thrown from property getters, excluding:
    - NotImplementedException, NotSupportedException, InvalidOperationException (allowed exceptions)
    - Property setters
    - Indexed properties (this[index])
    - Test methods
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Get the source code
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # First, find all property getter blocks
    property_getter_blocks = []
    getter_pattern = r'get\s*\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\}'
    
    for match in re.finditer(getter_pattern, source, re.DOTALL):
        getter_start = match.start()
        getter_content = match.group(1)
        
        # Check if this is within a test context
        preceding_text = source[:getter_start]
        lines_before = preceding_text.split('\n')[-20:]
        has_test_attribute = any(re.search(r'\[\s*(?:Test|Fact)\s*\]', line) for line in lines_before)
        
        if has_test_attribute:
            continue  # Skip test methods
        
        # Check for indexed properties
        property_context = preceding_text[-500:]
        if re.search(r'this\s*\[\s*[\w\s,<>\[\]]+\s*\]\s*\{', property_context, re.DOTALL):
            continue  # Skip indexed properties
        
        # Ensure this is a property, not a method
        property_signature = re.search(r'(?:public|private|protected|internal)?\s*(?:static\s+)?(?:virtual\s+)?(?:override\s+)?[\w\[\]<>,\s]+\s+(\w+)\s*\{', preceding_text[-200:])
        if not property_signature:
            continue
        
        property_name = property_signature.group(1)
        
        # Now find all throw statements within this getter block
        throw_pattern = r'throw\s+new\s+(\w+(?:Exception)?)'
        for throw_match in re.finditer(throw_pattern, getter_content, re.IGNORECASE):
            exception_type = throw_match.group(1)
            
            # Skip allowed exception types
            allowed_exceptions = ['NotImplementedException', 'NotSupportedException', 'InvalidOperationException']
            if exception_type in allowed_exceptions:
                continue
            
            # Calculate absolute position and line number
            absolute_position = getter_start + match.group(0).find(getter_content) + throw_match.start()
            line_number = source[:absolute_position].count('\n') + 1
            
            # Extract throw statement for display
            display_value = throw_match.group(0)
            
            findings.append({
                'rule_id': 'exceptions_thrown_from_property',
                'message': f'Property getter should not throw {exception_type} - convert to a method instead',
                'node': f"PropertyDeclaration.{property_name}",
                'file': filename,
                'property_path': ['source'],
                'value': display_value,
                'status': 'violation',
                'line': line_number,
                'severity': 'Major'
            })
    
    return findings


def check_exceptions_explicitly_rethrown(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for exceptions_explicitly_rethrown rule.
    Detects when caught exceptions are explicitly rethrown using 'throw exception;' 
    instead of using the bare 'throw;' statement which preserves the original stack trace.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Pattern to find catch blocks with variable names
    catch_pattern = r'catch\s*\(\s*(\w+(?:\.\w+)*)\s+(\w+)\s*\)'
    
    # Find all catch blocks
    catch_matches = list(re.finditer(catch_pattern, source, re.MULTILINE | re.DOTALL))
    
    for catch_match in catch_matches:
        exception_type = catch_match.group(1)
        variable_name = catch_match.group(2)
        catch_start = catch_match.end()
        
        # Find the opening brace of the catch block
        brace_count = 0
        block_start = -1
        for i in range(catch_start, len(source)):
            if source[i] == '{':
                if brace_count == 0:
                    block_start = i + 1
                brace_count += 1
            elif source[i] == '}':
                brace_count -= 1
                if brace_count == 0:
                    block_end = i
                    break
        
        if block_start == -1:
            continue
        
        # Extract the catch block content
        catch_block = source[block_start:block_end]
        
        # Look for explicit rethrows of the caught exception variable
        # Pattern: throw <variable_name>;
        rethrow_pattern = rf'\bthrow\s+{re.escape(variable_name)}\s*;'
        rethrow_matches = list(re.finditer(rethrow_pattern, catch_block))
        
        for rethrow_match in rethrow_matches:
            # Calculate absolute position in the source
            absolute_position = block_start + rethrow_match.start()
            line_number = source[:absolute_position].count('\n') + 1
            
            # Extract throw statement for display
            throw_statement = rethrow_match.group(0)
            
            findings.append({
                'rule_id': 'exceptions_explicitly_rethrown',
                'message': f'Use bare "throw;" instead of "throw {variable_name};" to preserve the original stack trace',
                'node': f"CatchClause.{exception_type}",
                'file': filename,
                'property_path': ['source'],
                'value': throw_statement.strip(),
                'status': 'violation',
                'line': line_number,
                'severity': 'Major'
            })
    
    return findings


def check_exceptions_created_without_being_thrown(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for exceptions_created_without_being rule.
    Detects when exceptions are created with 'new Exception()' but not thrown,
    assigned to variables, or returned from methods.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, 1):
        stripped_line = line.strip()
        
        # Skip empty lines and comments
        if not stripped_line or stripped_line.startswith('//') or stripped_line.startswith('/*'):
            continue
        
        # Look for 'new Exception' patterns
        exception_pattern = r'\bnew\s+\w*Exception\s*\([^)]*\)\s*;'
        exception_matches = list(re.finditer(exception_pattern, line))
        
        for match in exception_matches:
            exception_creation = match.group(0)
            
            # Check exclusion conditions
            # Skip if preceded by 'throw'
            if re.search(r'\bthrow\s+new\s+\w*Exception', line):
                continue
                
            # Skip if assigned to a variable (var, type, or field assignment)
            if re.search(r'(?:var\s+\w+|^\s*\w+(?:\.\w+)*\s*\w+|\w+)\s*=\s*.*new\s+\w*Exception', line):
                continue
                
            # Skip if used in return statement
            if re.search(r'\breturn\s+new\s+\w*Exception', line):
                continue
                
            # Skip if in ternary operator or conditional expression
            if re.search(r'\?\s*.*new\s+\w*Exception.*:', line) or re.search(r':\s*new\s+\w*Exception', line):
                continue
                
            # Skip if used in method parameter
            if re.search(r'\([^)]*new\s+\w*Exception.*\)', line):
                continue
                
            # Skip if in lambda expression
            if re.search(r'=>.*new\s+\w*Exception', line):
                continue
                
            # Skip if in array or collection initialization
            if re.search(r'[{\[,]\s*new\s+\w*Exception', line):
                continue
                
            # Skip if in property initialization
            if re.search(r'=\s*new\s+\w*Exception\s*\([^)]*\)\s*;?\s*$', line):
                continue
            
            # Skip if in test methods (check surrounding context for test attributes)
            is_in_test_method = False
            
            # Look backwards for test attributes directly above the current method
            for check_line_num in range(max(1, line_num - 5), line_num):
                if check_line_num <= len(lines):
                    check_line = lines[check_line_num - 1].strip()
                    if re.search(r'\[(Test|Fact)\]', check_line, re.IGNORECASE):
                        # Found test attribute, now verify it's followed by a method
                        for method_check in range(check_line_num, min(len(lines), check_line_num + 3)):
                            method_line = lines[method_check - 1].strip()
                            if re.search(r'^(public|private|protected)\s+\w+\s+\w+\s*\([^)]*\)\s*{?', method_line):
                                is_in_test_method = True
                                break
                        break
            
            if is_in_test_method:
                continue
            
            findings.append({
                'rule_id': 'exceptions_created_without_being',
                'message': 'Exception created but not thrown - use \'throw\' keyword or assign to variable',
                'node': f"MethodDeclaration",
                'file': filename,
                'property_path': ['source'],
                'value': exception_creation.strip(),
                'status': 'violation',
                'line': line_num,
                'severity': 'Major'
            })
    
    return findings


def check_exceptions_either_logged_or_rethrown(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for exceptions_either_logged_rethrown rule.
    Detects when exceptions are both logged (with exception object) and rethrown,
    which can cause duplicate logging.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Pattern to find catch blocks with variable names
    catch_pattern = r'catch\s*\(\s*(\w+(?:\.\w+)*)\s+(\w+)\s*\)'
    
    # Find all catch blocks
    catch_matches = list(re.finditer(catch_pattern, source, re.MULTILINE | re.DOTALL))
    
    for catch_match in catch_matches:
        exception_type = catch_match.group(1)
        variable_name = catch_match.group(2)
        catch_start = catch_match.end()
        
        # Find the opening brace of the catch block
        brace_count = 0
        block_start = -1
        for i in range(catch_start, len(source)):
            if source[i] == '{':
                if brace_count == 0:
                    block_start = i + 1
                brace_count += 1
            elif source[i] == '}':
                brace_count -= 1
                if brace_count == 0:
                    block_end = i
                    break
        
        if block_start == -1:
            continue
        
        # Extract the catch block content
        catch_block = source[block_start:block_end]
        
        # Check for logging with the exception variable
        # Look for various logging patterns that include the exception variable directly (not properties/methods)
        logging_patterns = [
            # Pattern for logging the exception object directly: Logger.Method(ex, ...) or Logger.Method(ex)
            rf'\b(?:Logger?|Debug|Trace|Console)\.(?:Log\w*|Write\w*|Error|Info|Warn\w*)\s*\(\s*{re.escape(variable_name)}\b(?:\s*[,)])',
            # Pattern for instance logger: _logger.LogMethod(ex, ...) or logger.LogMethod(ex, ...)
            rf'\b_?\w*[Ll]ogger\.(?:Log\w*)\s*\(\s*{re.escape(variable_name)}\b(?:\s*[,)])',
            # Pattern for static Logger class: Logger.Error(ex, ...)
            rf'\bLogger\.(?:Error|Info|Warn\w*|Debug|Write\w*)\s*\(\s*{re.escape(variable_name)}\b(?:\s*[,)])'
        ]
        
        has_logging = False
        for pattern in logging_patterns:
            if re.search(pattern, catch_block):
                has_logging = True
                break
        
        # Check for bare throw statement (rethrow)
        has_rethrow = bool(re.search(r'\bthrow\s*;', catch_block))
        
        if has_logging and has_rethrow:
            # Skip if in test methods (check surrounding context for test attributes)
            is_in_test_method = False
            
            # Look backwards for test attributes directly above the current method
            catch_line = source[:catch_match.start()].count('\n') + 1
            for check_line_num in range(max(1, catch_line - 15), catch_line):
                if check_line_num <= len(source.split('\n')):
                    lines = source.split('\n')
                    check_line = lines[check_line_num - 1].strip()
                    if re.search(r'\[(Test|Fact)\]', check_line, re.IGNORECASE):
                        # Found test attribute, now verify it's followed by a method
                        for method_check in range(check_line_num, min(len(lines), check_line_num + 3)):
                            if method_check - 1 < len(lines):
                                method_line = lines[method_check - 1].strip()
                                if re.search(r'^(public|private|protected)\s+\w+\s+\w+\s*\([^)]*\)\s*{?', method_line):
                                    is_in_test_method = True
                                    break
                        break
            
            if is_in_test_method:
                continue
            
            # Calculate absolute position in the source for the catch statement
            line_number = source[:catch_match.start()].count('\n') + 1
            
            findings.append({
                'rule_id': 'exceptions_either_logged_rethrown',
                'message': 'Exception is both logged and rethrown - this can cause duplicate logging',
                'node': f"CatchClause.{exception_type}",
                'file': filename,
                'property_path': ['source'],
                'value': f'catch ({exception_type} {variable_name}) - logged and rethrown',
                'status': 'violation',
                'line': line_number,
                'severity': 'Major'
            })
    
    return findings


def check_exception_types_public(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check that exception types are public.
    Custom exceptions should be public to allow proper exception handling across assemblies.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip empty lines and comments
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*'):
            continue
        
        # Look for exception class declarations that are not public
        if 'Exception' in line and 'class' in line and ':' in line:
            # Check if it's a class declaration ending with Exception
            class_match = re.search(r'(internal|private|protected)?\s*class\s+(\w*Exception)\s*:', line)
            if class_match:
                visibility = class_match.group(1)
                class_name = class_match.group(2)
                
                # If no visibility specified or not public, it's a violation
                if visibility and visibility != 'public':
                    findings.append({
                        'rule_id': 'exception_types_public',
                        'message': f'Exception class \'{class_name}\' should be public to allow proper exception handling across assemblies.',
                        'line': line_num,
                        'severity': 'Major',
                        'node': f'ClassDeclaration.{class_name}',
                        'status': 'violation',
                        'file': filename,
                        'property_path': ['source'],
                        'value': line_clean
                    })
    
    return findings
    """
    Custom logic for exception_types_public rule.
    Detects non-public exception classes that inherit from Exception, SystemException, or ApplicationException.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Pattern to find class declarations inheriting from Exception types
    class_pattern = r'(public\s+|internal\s+|private\s+|protected\s+)?(abstract\s+|sealed\s+)?class\s+(\w+)\s*:\s*(Exception|SystemException|ApplicationException)\b'
    
    class_matches = list(re.finditer(class_pattern, source, re.MULTILINE))
    
    for class_match in class_matches:
        access_modifier = class_match.group(1)  # public, internal, private, protected
        class_modifier = class_match.group(2)   # abstract, sealed
        class_name = class_match.group(3)       # class name
        exception_type = class_match.group(4)   # Exception type
        
        # Determine if the class is public
        is_public = access_modifier and access_modifier.strip() == 'public'
        
        # If no access modifier is specified, it defaults to internal (non-public)
        if not access_modifier:
            is_public = False
        
        # Only flag non-public exception classes
        if not is_public:
            # Skip if in test methods (check surrounding context for test attributes)
            is_in_test_method = False
            
            # Calculate line number for the class declaration
            line_number = source[:class_match.start()].count('\n') + 1
            
            # Look backwards for test attributes directly above the current method
            lines = source.split('\n')
            for check_line_num in range(max(1, line_number - 15), line_number):
                if check_line_num <= len(lines):
                    check_line = lines[check_line_num - 1].strip()
                    if re.search(r'\[(Test|Fact|Theory)\]', check_line, re.IGNORECASE):
                        # Found test attribute, now verify it's followed by a method
                        for method_check in range(check_line_num, min(len(lines), check_line_num + 10)):
                            if method_check - 1 < len(lines):
                                method_line = lines[method_check - 1].strip()
                                if re.search(r'^(public|private|protected)\s+\w+\s+\w+\s*\([^)]*\)\s*{?', method_line):
                                    is_in_test_method = True
                                    break
                        break
            
            if is_in_test_method:
                continue
            
            # Determine the actual access level for the message
            if access_modifier:
                access_level = access_modifier.strip()
            else:
                access_level = "internal (implicit)"
            
            findings.append({
                'rule_id': 'exception_types_public',
                'message': f'Exception type "{class_name}" should be public but is {access_level}',
                'node': f"ClassDeclaration.{class_name}",
                'file': filename,
                'property_path': ['source'],
                'value': f'{access_level} class {class_name} : {exception_type}',
                'status': 'violation',
                'line': line_number,
                'severity': 'Major'
            })
    
    return findings


def check_enumeration_type_names_avoid(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check that enumeration type names should avoid having Flags or Enum suffixes.
    
    The information that an enumeration type is actually an enumeration or a set of flags
    should not be duplicated in its name.
    
    Returns a list of violations where enum names end with 'Flags' or 'Enum' (case-insensitive).
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Pattern to find enum declarations with names ending in 'Flags' or 'Enum'
    # This matches: enum NameFlags, enum NameEnum, enum nameflags, enum nameenum, etc.
    enum_pattern = r'enum\s+(\w*(?:Flags|flags|Enum|enum))(?:\s|//[^\n]*\n|/\*.*?\*/)*\{'
    
    for match in re.finditer(enum_pattern, source, re.DOTALL):
        enum_name = match.group(1)
        
        # Skip if this appears to be in comments or test code
        full_match = match.group(0)
        line_start = source[:match.start()].count('\n') + 1
        
        # Get the line content to check for comment patterns
        lines = source.split('\n')
        if line_start <= len(lines):
            current_line = lines[line_start - 1]
            
            # Skip if line contains test-related comments
            if re.search(r'//.*test|//.*example', current_line, re.IGNORECASE):
                continue
        
        # Determine which suffix was found
        suffix = None
        if enum_name.lower().endswith('flags'):
            suffix = 'Flags'
        elif enum_name.lower().endswith('enum'):
            suffix = 'Enum'
        
        if suffix:
            message = f"Remove '{suffix}' suffix from enum type name '{enum_name}'"
            
            findings.append({
                'rule_id': 'enumeration_type_names_avoid',
                'message': message,
                'node': f"EnumDeclaration.{enum_name}",
                'file': filename,
                'property_path': ['source'],
                'value': enum_name,
                'status': 'violation',
                'line': line_start,
                'severity': 'Major'
            })
    
    return findings


def check_expressions_debugassert_produce_side(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for expressions_debugassert_produce_side rule.
    Checks that Debug.Assert expressions do not have side effects.
    Debug.Assert is removed in release builds, so side effects won't execute in production.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    # Try to get source code from multiple possible locations
    source = ast_tree.get('source', '')
    if not source:
        # Try reading the file directly
        try:
            with open(filename, 'r', encoding='utf-8') as f:
                source = f.read()
        except Exception:
            return findings
    
    if not source:
        return findings
    
    
    lines = source.split('\n')
    
    # Pattern to detect Debug.Assert calls with side effects - more specific
    side_effect_pattern = r'Debug\.Assert\([^)]*(?:(?:\w*\+\+)|(?:--\w*)|(?:\w+\+\+)|(?:\w+--)|(?:\w+\s*=[^=])|(?:\[[^\]]+\]\s*=)|(?:(?:Add|Remove|Insert|Delete|Update|Set|Clear|Enqueue|Dequeue|Push|Pop)\s*\())[^)]*\)'
    
    # Exclusion patterns for safe operations (these should not have any side effect patterns)
    exclusion_patterns = [
        r'\.Count\b',
        r'\.Length\b',
        r'\.Any\(',
        r'\.All\(',
        r'\.Contains\(',
        r'\.StartsWith\(',
        r'\.EndsWith\(',
        r'\.Equals\(',
        r'\.CompareTo\(',
        r'\.GetHashCode\(',
        r'\.ToString\(',
        r'\.IndexOf\(',
        r'\.Substring\(',
        r'\.ToUpper\(',
        r'\.ToLower\(',
        r'\.Trim\(',
        r'string\.IsNullOrEmpty',
        r'string\.IsNullOrWhiteSpace',
        r'Math\.',
        r'Convert\.',
        r'PureMethod\(',
        r'^//',
        r'^/\*',
        r'^///'
    ]
    
    for line_num, line in enumerate(lines, 1):
        # Skip comments
        stripped_line = line.strip()
        if stripped_line.startswith('//') or stripped_line.startswith('/*'):
            continue
        
        # Check for Debug.Assert with side effects
        if re.search(side_effect_pattern, line):
            # Check exclusion patterns  
            excluded = False
            for exclusion_pattern in exclusion_patterns:
                if re.search(exclusion_pattern, line):
                    excluded = True
                    break
            
            if not excluded:
                findings.append({
                    'rule_id': 'expressions_debugassert_produce_side',
                    'message': 'Pattern match',
                    'node': 'CallExpression.Assert',
                    'file': filename,
                    'property_path': ['source'],
                    'value': line.strip(),
                    'status': 'violation',
                    'line': line_num,
                    'severity': 'Major'
                })
    
    return findings


def _check_private_field_patterns(source_text):
    """Helper function: Check if source contains private field patterns that should be readonly"""
    import re
    lines = source_text.split('\n')
    
    for line in lines:
        line_stripped = line.strip()
        
        # Skip empty lines and comments
        if not line_stripped or line_stripped.startswith('//') or line_stripped.startswith('/*') or line_stripped.startswith('*') or line_stripped.startswith('///'):
            continue
            
        # Check for private field declarations
        if _is_private_field_needing_readonly(line_stripped):
            return True
            
    return False


def _is_private_field_needing_readonly(line):
    """Helper function: Check if a line contains a private field that should be readonly"""
    import re
    
    # Skip if already readonly
    if 'readonly' in line:
        return False
        
    # Skip properties (contains { or =>)
    if '{' in line or '=>' in line:
        return False
        
    # Skip if not private
    if not re.search(r'\bprivate\b', line):
        return False
        
    # Skip partial class declarations
    if 'partial' in line and 'class' in line:
        return False
        
    # Check for field declaration patterns
    # Matches: private <type> <name>; or private <type> <name> = <value>;
    patterns = [
        r'\bprivate\s+(?:static\s+)?(\w+|\w+<[^>]+>|\w+\[\])\s+\w+\s*;',  # private Type name;
        r'\bprivate\s+(?:static\s+)?(\w+|\w+<[^>]+>|\w+\[\])\s+\w+\s*=\s*[^;]+;'  # private Type name = value;
    ]
    
    for pattern in patterns:
        if re.search(pattern, line):
            return True
            
    return False


def _is_in_comment_or_string_fields_only(source, target_text):
    """Helper function: Check if target text is within comments or string literals"""
    lines = source.split('\n')
    for line in lines:
        if target_text in line:
            stripped = line.strip()
            # Skip comment lines
            if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*') or stripped.startswith('///'):
                continue
            # Skip if target is within string literals
            if ('"' in line and target_text in line):
                # Check if target is within quotes
                parts = line.split('"')
                for i in range(1, len(parts), 2):  # Check odd indices (inside quotes)
                    if target_text in parts[i]:
                        return True
            return False
    return False


def _line_has_attribute_above(lines, line_idx):
    """Helper function: Check if there's an attribute declaration above this line"""
    if line_idx == 0:
        return False
        
    # Check previous lines for attributes
    for i in range(line_idx - 1, max(-1, line_idx - 5), -1):
        prev_line = lines[i].strip()
        if not prev_line:
            continue
        if prev_line.startswith('[') and prev_line.endswith(']'):
            return True
        if prev_line and not prev_line.startswith('//'):
            break
    return False


def check_fields_only_assigned_constructor(ast_tree_or_node, filename=None):
    """
    Detect private fields that are only assigned in the constructor but not marked as readonly.
    These fields should be marked as readonly for better immutability.
    
    This function supports two calling conventions:
    1. check_fields_only_assigned_constructor(ast_tree, filename) - full tree analysis
    2. check_fields_only_assigned_constructor(node) - single node analysis (fallback)
    
    Should detect:
    - private int data = 0; // Only assigned in constructor, should be readonly
    - private List<string> items; // Only assigned in constructor, should be readonly
    - private DateTime createdAt; // Only assigned in constructor, should be readonly
    
    Should NOT detect:
    - private readonly int readonlyData; // Already readonly
    - private int modifiedField; // Modified after constructor
    - public int PublicField; // Not private
    - private int Property { get; set; } // Properties
    - [Attribute] private int attributedField; // Fields with attributes
    - // private int commentedField; // Commented out code
    """
    import re  # Ensure re module is available
    
    # Handle single-node calling convention (fallback mode)
    if filename is None and isinstance(ast_tree_or_node, dict) and 'source' in ast_tree_or_node:
        # This is a single node, analyze just this node
        node = ast_tree_or_node
        source = node.get('source', '')
        if not source:
            return False
            
        # Check for private field patterns that could be readonly
        return _check_private_field_patterns(source)
    
    # Handle full tree analysis (main mode)
    ast_tree = ast_tree_or_node
    if filename is None:
        filename = 'unknown'
    
    findings = []

    # Enhanced patterns to handle complex C# types including generics and initializers
    patterns = [
        r'\bprivate\s+(?:static\s+)?(\w+|\w+<[^>]+>|\w+\[\])\s+(\w+)\s*;',  # private Type name;
        r'\bprivate\s+(?:static\s+)?(\w+|\w+<[^>]+>|\w+\[\])\s+(\w+)\s*=\s*([^;]+);'  # private Type name = value;
    ]
    
    for node_type, nodes in ast_tree.items():
        if node_type in ["ClassDeclaration", "StructDeclaration"]:
            for node in nodes:
                source = node.get('source', '')
                if not source:
                    continue
                
                # Skip if this is within comments or strings
                if _is_in_comment_or_string_fields_only(source, 'private '):
                    continue
                
                start_line = node.get('start_line', 1)
                lines = source.split('\n')
                
                for line_idx, line in enumerate(lines):
                    line_stripped = line.strip()
                    
                    # Skip empty lines and comments
                    if not line_stripped or line_stripped.startswith('//') or line_stripped.startswith('/*') or line_stripped.startswith('*') or line_stripped.startswith('///'):
                        continue
                    
                    # Skip class/interface/struct/namespace declarations and braces
                    if (line_stripped.startswith('public class') or 
                        line_stripped.startswith('internal class') or
                        line_stripped.startswith('private class') or
                        line_stripped.startswith('protected class') or
                        line_stripped.startswith('public interface') or
                        line_stripped.startswith('public struct') or
                        line_stripped.startswith('namespace ') or
                        line_stripped.startswith('using ') or
                        line_stripped == '{' or 
                        line_stripped == '}' or
                        line_stripped.startswith('class ')):
                        continue
                    
                    # Skip if already readonly
                    if 'readonly' in line_stripped:
                        continue
                        
                    # Skip properties
                    if '{' in line_stripped or '=>' in line_stripped:
                        continue
                        
                    # Skip partial class declarations
                    if 'partial' in line_stripped and 'class' in line_stripped:
                        continue
                        
                    # Skip fields with attributes
                    if _line_has_attribute_above(lines, line_idx):
                        continue
                    
                    # Skip method declarations
                    if ('(' in line_stripped and ')' in line_stripped and 
                        not re.search(r'\bprivate\s+(?:static\s+)?(\w+|\w+<[^>]+>|\w+\[\])\s+\w+\s*[=;]', line_stripped)):
                        continue
                    
                    # Check each pattern
                    for pattern in patterns:
                        match = re.search(pattern, line_stripped)
                        if match:
                            field_type = match.group(1)
                            field_name = match.group(2)
                            initializer = match.group(3) if len(match.groups()) > 2 else None
                            
                            line_num = start_line + line_idx
                            
                            findings.append({
                                'rule_id': 'fields_that_are_only',
                                'message': f'Private field \'{field_name}\' is only assigned in constructor and should be marked as readonly.',
                                'file': filename,
                                'line': line_num,
                                'severity': 'Major',
                                'node': 'FieldDeclaration',
                                'status': 'violation',
                                'property_path': ['source'],
                                'value': line_stripped,
                                'context': {
                                    'field_name': field_name,
                                    'field_type': field_type,
                                    'has_initializer': bool(initializer and initializer.strip()),
                                    'suggested_fix': f'private readonly {field_type} {field_name}'
                                }
                            })
                            break  # Only match first pattern per line
    
    return findings

def check_floating_point_equality(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for floating_point_numbers_tested rule.
    Detects direct equality (== or !=) comparisons on floating point types (float, double, decimal).
    Tracks variable declarations to identify floating-point variables even when compared without literals.
    
    Should trigger on:
    - if (sum == g) where sum and g are floats/doubles
    - if (0.1f + 0.2f == 0.3f) - literal comparisons
    - while (floatX == floatY) - loop conditions
    - return test == 0.5f - return statements
    
    Should NOT trigger on:
    - Math.Abs(a - b) < epsilon - epsilon comparisons
    - Console.WriteLine($"{f} == {g}") - logging/display
    - // if (sum == g) - comments
    - Assert.AreEqual(a, b) - test assertions
    - Integer or string comparisons
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Track floating-point variables by name
    float_vars = set()
    float_type_pattern = re.compile(r'\b(float|double|decimal)\s+(\w+)\s*[=;,)]')
    
    # First pass: collect all float/double/decimal variable declarations
    for line in lines:
        # Skip comments
        line_stripped = line.strip()
        if line_stripped.startswith('//') or line_stripped.startswith('/*'):
            continue
        
        # Find variable declarations
        for match in float_type_pattern.finditer(line):
            var_name = match.group(2)
            float_vars.add(var_name)
    
    # Patterns for floating-point comparisons
    # Pattern 1: Floating-point literals with f, d, or m suffix
    literal_pattern = re.compile(r'(\d+\.\d+[fdm]?|\d+[fdm])\s*(==|!=)\s*\S+')
    literal_pattern_reverse = re.compile(r'\S+\s*(==|!=)\s*(\d+\.\d+[fdm]?|\d+[fdm])')
    
    # Exclusion patterns - these should NOT trigger
    exclude_patterns = [
        re.compile(r'Math\.Abs', re.IGNORECASE),  # Epsilon comparison
        re.compile(r'Console\.WriteLine|Console\.Write|Logger\.|Debug\.', re.IGNORECASE),  # Logging
        re.compile(r'^\s*//'),  # Line comment
        re.compile(r'/\*'),  # Block comment start
        re.compile(r'\[Test\]|\[Fact\]|Assert\.'),  # Unit test
        re.compile(r'ToString\s*\('),  # ToString conversion
        re.compile(r'\$"[^"]*(?:==|!=)[^"]*"'),  # String interpolation
        re.compile(r'"[^"]*(?:==|!=)[^"]*"'),  # String literal containing == or !=
        re.compile(r'string\.Format'),  # String formatting
    ]
    
    for line_num, line in enumerate(lines, 1):
        line_stripped = line.strip()
        
        # Skip empty lines
        if not line_stripped:
            continue
        
        # Check if line is excluded
        is_excluded = False
        for exclude_pat in exclude_patterns:
            if exclude_pat.search(line):
                is_excluded = True
                break
        
        if is_excluded:
            continue
        
        # Check if line has == or != comparison
        if '==' not in line and '!=' not in line:
            continue
        
        # Skip lines that are purely comments (after code)
        code_part = line.split('//')[0] if '//' in line else line
        if '==' not in code_part and '!=' not in code_part:
            continue
        
        # Check for floating-point literal comparisons
        has_float_literal = literal_pattern.search(code_part) or literal_pattern_reverse.search(code_part)
        
        # Check for comparison involving known float variables
        has_float_var_comparison = False
        comparison_match = re.search(r'(\w+)\s*(==|!=)\s*(\w+)', code_part)
        if comparison_match:
            left_var = comparison_match.group(1)
            right_var = comparison_match.group(3)
            if left_var in float_vars or right_var in float_vars:
                has_float_var_comparison = True
        
        # Check for comparison with literal on one side and variable on other
        var_literal_match = re.search(r'(\w+)\s*(==|!=)\s*(\d+\.\d+[fdm]?)', code_part)
        if var_literal_match:
            has_float_literal = True
        
        literal_var_match = re.search(r'(\d+\.\d+[fdm]?)\s*(==|!=)\s*(\w+)', code_part)
        if literal_var_match:
            has_float_literal = True
        
        if has_float_literal or has_float_var_comparison:
            findings.append({
                'rule_id': 'floating_point_numbers_tested',
                'message': 'Floating point numbers should not be tested for equality. Use epsilon-based comparison instead.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'node': 'BinaryExpression',
                'status': 'violation',
                'property_path': ['source'],
                'value': line_stripped[:100]
            })
    
    return findings


def check_forloop_conditions_true_least(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for forloop_conditions_true_least rule.
    Detects for loops where the initial condition is provably false.
    
    Should trigger on:
    - for (int i = 0; i < 0; i++) - 0 is not < 0
    - for (int i = 10; i < 5; i++) - 10 is not < 5
    - for (int i = 5; i > 10; i++) - 5 is not > 10
    - for (int i = 0; i > 5; i--) - 0 is not > 5
    
    Should NOT trigger on:
    - for (int i = 0; i < 10; i++) - valid loop
    - for (int i = 0; i < maxValue; i++) - variable condition
    - Comments containing for loops
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Pattern to match for loop with numeric initialization and condition
    # Captures: variable name, initial value, operator, limit value
    for_loop_pattern = re.compile(
        r'for\s*\(\s*(?:int|long|short|byte|uint|ulong|ushort)\s+(\w+)\s*=\s*(-?\d+)\s*;\s*\1\s*(<|>|<=|>=)\s*(-?\d+)\s*;',
        re.IGNORECASE
    )
    
    for line_num, line in enumerate(lines, 1):
        line_stripped = line.strip()
        
        # Skip empty lines
        if not line_stripped:
            continue
        
        # Skip comments
        if line_stripped.startswith('//') or line_stripped.startswith('/*'):
            continue
        
        # Get the code part before any inline comment
        code_part = line.split('//')[0] if '//' in line else line
        
        # Check for for loop pattern
        match = for_loop_pattern.search(code_part)
        if match:
            var_name = match.group(1)
            initial_value = int(match.group(2))
            operator = match.group(3)
            limit_value = int(match.group(4))
            
            # Evaluate if the condition is false from the start
            condition_false = False
            
            if operator == '<':
                # i < limit: false if initial >= limit
                condition_false = initial_value >= limit_value
            elif operator == '>':
                # i > limit: false if initial <= limit
                condition_false = initial_value <= limit_value
            elif operator == '<=':
                # i <= limit: false if initial > limit
                condition_false = initial_value > limit_value
            elif operator == '>=':
                # i >= limit: false if initial < limit
                condition_false = initial_value < limit_value
            
            if condition_false:
                findings.append({
                    'rule_id': 'forloop_conditions_true_least',
                    'message': f'For-loop condition is false from the start ({var_name} = {initial_value}; {var_name} {operator} {limit_value}). Loop will never execute.',
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'node': 'ForStatement',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': line_stripped[:100]
                })
    
    return findings


def check_generic_logger_injection_match(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check if ILogger<T> generic type parameter matches the enclosing class name.
    
    Noncompliant: ILogger<OtherClass> in MyClass
    Compliant: ILogger<MyClass> in MyClass
    """
    findings = []
    seen_findings = set()  # Deduplicate findings
    
    # Reserved words and common parsing artifacts to skip
    invalid_class_names = {'name', 'with', 'class', 'public', 'private', 'protected', 'internal', 
                           'static', 'abstract', 'sealed', 'partial', 'readonly', 'virtual', 'override'}
    
    # First pass: collect all valid class names in the file
    all_class_names = set()
    
    def collect_all_classes(node):
        if not isinstance(node, dict):
            return
        node_type = node.get('type') or node.get('node_type', '')
        if node_type == 'ClassDeclaration':
            class_name = node.get('name', '')
            if class_name and class_name.lower() not in invalid_class_names:
                all_class_names.add(class_name)
        # Recurse
        children = node.get('children', [])
        if isinstance(children, list):
            for child in children:
                collect_all_classes(child)
        for key, value in node.items():
            if key != 'children':
                if isinstance(value, dict):
                    collect_all_classes(value)
                elif isinstance(value, list):
                    for item in value:
                        if isinstance(item, dict):
                            collect_all_classes(item)
    
    collect_all_classes(ast_tree)
    
    def find_classes(node, parent_class=None):
        """Find violations - only report if logger type doesn't match the declared class."""
        if not isinstance(node, dict):
            return
        
        node_type = node.get('type') or node.get('node_type', '')
        
        if node_type == 'ClassDeclaration':
            class_name = node.get('name', '')
            source = node.get('source', '')
            start_line = node.get('start_line') or node.get('lineno') or 1
            
            if not class_name or class_name.lower() in invalid_class_names:
                children = node.get('children', [])
                if isinstance(children, list):
                    for child in children:
                        find_classes(child, parent_class)
                return
            
            if source:
                logger_pattern = r'ILogger<(\w+)>'
                
                lines = source.split('\n')
                for i, line in enumerate(lines):
                    line_num = start_line + i if isinstance(start_line, int) else i + 1
                    
                    stripped = line.strip()
                    if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
                        continue
                    
                    if '"' in line and 'ILogger<' in line:
                        before_logger = line.split('ILogger<')[0]
                        quote_count = before_logger.count('"') - before_logger.count('\\"')
                        if quote_count % 2 == 1:
                            continue
                    
                    for match in re.finditer(logger_pattern, line):
                        logger_type = match.group(1)
                        
                        if logger_type.lower() in invalid_class_names:
                            continue
                        
                        # Key fix: If the logger type matches the current class OR
                        # is another class in the file that matches the logger type, skip
                        # (handles nested classes where ILogger<InnerClass> in InnerClass is valid)
                        if logger_type == class_name:
                            continue  # Compliant - matches current class
                        
                        # For nested class case: if logger_type is a valid class in the file,
                        # only flag it if we can determine it's NOT in that class context
                        # Since the parser shows InnerClass as separate, if we're in OuterClass
                        # and find ILogger<InnerClass>, it might be in the nested InnerClass region
                        # So skip if logger_type is a known class (let InnerClass handle its own)
                        if logger_type in all_class_names:
                            # Check if this might be a nested class scenario
                            # If the source contains "class {logger_type}" declaration, skip this finding
                            # as it will be handled by that class's own processing
                            nested_class_pattern = rf'\bclass\s+{re.escape(logger_type)}\b'
                            if re.search(nested_class_pattern, source):
                                continue
                        
                        finding_key = (filename, line_num, logger_type, class_name)
                        if finding_key not in seen_findings:
                            seen_findings.add(finding_key)
                            findings.append({
                                'rule_id': 'generic_logger_injection_match',
                                'message': f'ILogger<{logger_type}> should be ILogger<{class_name}> to match enclosing type',
                                'file': filename,
                                'line': line_num,
                                'severity': 'Major',
                                'node': f'ClassDeclaration.{class_name}',
                                'status': 'violation',
                                'property_path': ['source'],
                                'value': line.strip()[:100]
                            })
        
        children = node.get('children', [])
        if isinstance(children, list):
            for child in children:
                find_classes(child, class_name if node_type == 'ClassDeclaration' else parent_class)
        
        for key, value in node.items():
            if key != 'children':
                if isinstance(value, dict):
                    find_classes(value, class_name if node_type == 'ClassDeclaration' else parent_class)
                elif isinstance(value, list):
                    for item in value:
                        if isinstance(item, dict):
                            find_classes(item, class_name if node_type == 'ClassDeclaration' else parent_class)
    
    find_classes(ast_tree)
    return findings


def check_generic_parameters_constrained_reference(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check if generic type parameters compared to null are constrained to reference types.
    
    Noncompliant: public void Method<T>(T param) { if (param == null) ... }
    Compliant: public void Method<T>(T param) where T : class { if (param == null) ... }
    
    Reference type constraints include:
    - where T : class
    - where T : SomeClass (any base class constraint)
    - where T : class, ISomeInterface
    """
    findings = []
    seen_findings = set()
    
    # Pattern to find where constraints - stops at next 'where' or '{' or newline
    where_constraint_pattern = r'where\s+(\w+)\s*:\s*([^{\n]+?)(?=\s+where\s|\s*\{|\s*$)'
    
    # Pattern to match null comparisons with a variable
    null_comparison_pattern = r'\b(\w+)\s*[!=]=\s*null\b|\bnull\s*[!=]=\s*(\w+)\b'
    
    def has_reference_constraint(type_param: str, constraints_text: str) -> bool:
        """Check if a type parameter has a reference type constraint."""
        where_matches = re.finditer(where_constraint_pattern, constraints_text)
        for match in where_matches:
            constrained_param = match.group(1)
            constraint_body = match.group(2).strip()
            
            if constrained_param == type_param:
                # Check for class constraint
                if 'class' in constraint_body:
                    return True
                if 'notnull' in constraint_body:
                    return True
                # Check for base class constraint (any capitalized type that's not 'struct' or 'new()')
                parts = [p.strip() for p in constraint_body.split(',')]
                for part in parts:
                    part = part.strip()
                    if part and part[0].isupper() and part not in ['struct'] and not part.startswith('new'):
                        # This is a base class or interface constraint
                        return True
        return False
    
    def extract_methods_from_source(source: str, base_line: int) -> List[Dict]:
        """Extract method declarations from class source code."""
        methods = []
        # Pattern to match method declarations with generic parameters
        # Matches: public void Method<T>(T param) or public T Method<T>(T param) etc.
        method_pattern = r'(?:public|private|protected|internal|static|virtual|override|async|sealed|\s)+\s*(?:[\w<>\[\]?,\s]+)\s+(\w+)\s*<([^>]+)>\s*\(([^)]*)\)'
        
        lines = source.split('\n')
        for i, line in enumerate(lines):
            stripped = line.strip()
            # Skip comments
            if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
                continue
            
            # Look for generic method declarations
            match = re.search(method_pattern, line)
            if match:
                method_name = match.group(1)
                type_params_str = match.group(2)
                params_str = match.group(3)
                
                type_params = [p.strip() for p in type_params_str.split(',')]
                
                # Extract method body to find constraints and null comparisons
                # Find the opening brace
                method_start = i
                method_source = ""
                brace_count = 0
                found_brace = False
                
                for j in range(i, len(lines)):
                    method_source += lines[j] + "\n"
                    for char in lines[j]:
                        if char == '{':
                            brace_count += 1
                            found_brace = True
                        elif char == '}':
                            brace_count -= 1
                    if found_brace and brace_count == 0:
                        break
                
                methods.append({
                    'name': method_name,
                    'type_params': type_params,
                    'params_str': params_str,
                    'source': method_source,
                    'line': base_line + i
                })
        
        return methods
    
    def get_param_names_with_types(params_str: str, type_params: List[str]) -> Dict[str, str]:
        """Get parameter names that use generic type parameters."""
        param_map = {}
        # Split by comma, handling nested generics
        params = []
        depth = 0
        current = ""
        for char in params_str:
            if char == '<':
                depth += 1
            elif char == '>':
                depth -= 1
            elif char == ',' and depth == 0:
                params.append(current.strip())
                current = ""
                continue
            current += char
        if current.strip():
            params.append(current.strip())
        
        for param in params:
            param = param.strip()
            if not param:
                continue
            # Parse "Type paramName" or "Type? paramName" etc.
            parts = param.split()
            if len(parts) >= 2:
                param_type = parts[-2].rstrip('?')
                param_name = parts[-1]
                # Check if param_type is one of the generic type params
                if param_type in type_params:
                    param_map[param_name] = param_type
        return param_map
    
    def analyze_class_node(node: Dict):
        """Analyze a class for unconstrained generic null comparisons."""
        if not isinstance(node, dict):
            return
        
        node_type = node.get('type') or node.get('node_type', '')
        source = node.get('source', '')
        class_name = node.get('name', '')
        start_line = node.get('start_line') or node.get('lineno') or 1
        
        if node_type == 'ClassDeclaration' and source:
            # Check for class-level generic parameters
            class_header_match = re.search(r'class\s+\w+\s*<([^>]+)>', source)
            class_type_params = []
            unconstrained_class_params = []
            
            if class_header_match:
                params_str = class_header_match.group(1)
                class_type_params = [p.strip() for p in params_str.split(',')]
                
                # Check class-level constraints
                class_header_end = source.find('{')
                if class_header_end != -1:
                    header = source[:class_header_end]
                    for tp in class_type_params:
                        if not has_reference_constraint(tp, header):
                            unconstrained_class_params.append(tp)
            
            # Track fields with unconstrained generic types
            field_type_map = {}
            if unconstrained_class_params:
                lines = source.split('\n')
                for i, line in enumerate(lines):
                    stripped = line.strip()
                    for tp in unconstrained_class_params:
                        # Match field declarations like: private T _value; or T _value;
                        field_pattern = rf'(?:private|public|protected|internal)?\s*(?:readonly\s+)?{re.escape(tp)}\s+(_?\w+)\s*[;=]'
                        field_match = re.search(field_pattern, stripped)
                        if field_match:
                            field_name = field_match.group(1)
                            field_type_map[field_name] = tp
            
            # Extract and analyze methods from class source
            methods = extract_methods_from_source(source, start_line)
            
            for method in methods:
                method_name = method['name']
                method_type_params = method['type_params']
                method_source = method['source']
                method_line = method['line']
                params_str = method['params_str']
                
                # Find constraints in method declaration
                # Look for where clauses between ) and {
                constraint_section = ""
                paren_close = method_source.find(')')
                brace_open = method_source.find('{')
                if paren_close != -1 and brace_open != -1 and brace_open > paren_close:
                    constraint_section = method_source[paren_close+1:brace_open]
                
                # Determine which method type params are unconstrained
                unconstrained_method_params = []
                for tp in method_type_params:
                    if not has_reference_constraint(tp, constraint_section):
                        unconstrained_method_params.append(tp)
                
                if not unconstrained_method_params:
                    continue
                
                # Get parameter names with unconstrained generic types
                param_map = get_param_names_with_types(params_str, unconstrained_method_params)
                
                if not param_map:
                    continue
                
                # Find null comparisons in method body
                method_lines = method_source.split('\n')
                for i, line in enumerate(method_lines):
                    line_num = method_line + i
                    
                    stripped = line.strip()
                    if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
                        continue
                    
                    # Remove string literals for checking
                    check_line = line
                    if '"' in line:
                        in_string = False
                        cleaned = ""
                        j = 0
                        while j < len(line):
                            if line[j] == '"' and (j == 0 or line[j-1] != '\\'):
                                in_string = not in_string
                            if not in_string:
                                cleaned += line[j]
                            j += 1
                        check_line = cleaned
                    
                    # Find null comparisons
                    for match in re.finditer(null_comparison_pattern, check_line):
                        var_name = match.group(1) or match.group(2)
                        
                        if var_name in param_map:
                            type_param = param_map[var_name]
                            finding_key = (filename, line_num, var_name, type_param)
                            if finding_key not in seen_findings:
                                seen_findings.add(finding_key)
                                findings.append({
                                    'rule_id': 'generic_parameters_constrained_reference',
                                    'message': f'Generic parameter \'{type_param}\' is not constrained to reference type, comparing \'{var_name}\' to null is misleading',
                                    'file': filename,
                                    'line': line_num,
                                    'severity': 'Major',
                                    'node': f'MethodDeclaration.{method_name}',
                                    'status': 'violation',
                                    'property_path': ['source'],
                                    'value': stripped[:100]
                                })
            
            # Check for non-generic methods that use class-level generic parameters
            if unconstrained_class_params:
                # Pattern to match non-generic method declarations (more flexible)
                non_generic_method_pattern = r'(?:public|private|protected|internal|static|virtual|override|async|sealed|\s)+\s*(?:void|[\w<>\[\]?,\s]+)\s+(\w+)\s*\(([^)]*)\)'
                
                lines = source.split('\n')
                for i, line in enumerate(lines):
                    # Look for method declarations that are NOT generic (no <T> before ()
                    # Method declarations contain parentheses and are followed by { (possibly on next line)
                    if '(' in line and ')' in line:
                        # Check it's not a generic method (no <T> between method name and ()
                        pre_paren = line.split('(')[0]
                        if '<' not in pre_paren.split()[-1] if pre_paren.split() else True:
                            match = re.search(non_generic_method_pattern, line)
                            if match:
                                method_name = match.group(1)
                                params_str = match.group(2)
                                
                                # Skip if method name is a keyword or common non-method patterns
                                if method_name in ['if', 'while', 'for', 'foreach', 'switch', 'catch', 'using', 'lock']:
                                    continue
                                
                                # Check if any parameter uses unconstrained class-level type params
                                method_param_map = get_param_names_with_types(params_str, unconstrained_class_params)
                            
                            if method_param_map:
                                # Extract method body
                                method_start = i
                                method_source = ""
                                brace_count = 0
                                found_brace = False
                                
                                for j in range(i, len(lines)):
                                    method_source += lines[j] + "\n"
                                    for char in lines[j]:
                                        if char == '{':
                                            brace_count += 1
                                            found_brace = True
                                        elif char == '}':
                                            brace_count -= 1
                                    if found_brace and brace_count == 0:
                                        break
                                
                                # Find null comparisons in method body
                                method_lines = method_source.split('\n')
                                for k, mline in enumerate(method_lines):
                                    line_num = start_line + i + k
                                    
                                    mstripped = mline.strip()
                                    if mstripped.startswith('//') or mstripped.startswith('/*') or mstripped.startswith('*'):
                                        continue
                                    
                                    # Remove string literals
                                    check_line = mline
                                    if '"' in mline:
                                        in_string = False
                                        cleaned = ""
                                        idx = 0
                                        while idx < len(mline):
                                            if mline[idx] == '"' and (idx == 0 or mline[idx-1] != '\\'):
                                                in_string = not in_string
                                            if not in_string:
                                                cleaned += mline[idx]
                                            idx += 1
                                        check_line = cleaned
                                    
                                    # Find null comparisons
                                    for nmatch in re.finditer(null_comparison_pattern, check_line):
                                        var_name = nmatch.group(1) or nmatch.group(2)
                                        
                                        if var_name in method_param_map:
                                            type_param = method_param_map[var_name]
                                            finding_key = (filename, line_num, var_name, type_param)
                                            if finding_key not in seen_findings:
                                                seen_findings.add(finding_key)
                                                findings.append({
                                                    'rule_id': 'generic_parameters_constrained_reference',
                                                    'message': f'Generic parameter \'{type_param}\' is not constrained to reference type, comparing \'{var_name}\' to null is misleading',
                                                    'file': filename,
                                                    'line': line_num,
                                                    'severity': 'Major',
                                                    'node': f'MethodDeclaration.{method_name}',
                                                    'status': 'violation',
                                                    'property_path': ['source'],
                                                    'value': mstripped[:100]
                                                })
            
            # Check for null comparisons on fields with unconstrained class-level generic types
            if field_type_map:
                lines = source.split('\n')
                for i, line in enumerate(lines):
                    line_num = start_line + i
                    stripped = line.strip()
                    
                    if stripped.startswith('//') or stripped.startswith('/*'):
                        continue
                    
                    for field_name, type_param in field_type_map.items():
                        null_check = rf'\b{re.escape(field_name)}\s*[!=]=\s*null\b|\bnull\s*[!=]=\s*{re.escape(field_name)}\b'
                        if re.search(null_check, line):
                            finding_key = (filename, line_num, field_name, type_param)
                            if finding_key not in seen_findings:
                                seen_findings.add(finding_key)
                                findings.append({
                                    'rule_id': 'generic_parameters_constrained_reference',
                                    'message': f'Generic parameter \'{type_param}\' is not constrained to reference type, comparing \'{field_name}\' to null is misleading',
                                    'file': filename,
                                    'line': line_num,
                                    'severity': 'Major',
                                    'node': f'ClassDeclaration.{class_name}',
                                    'status': 'violation',
                                    'property_path': ['source'],
                                    'value': stripped[:100]
                                })
        
        # Recurse to find nested classes
        children = node.get('children', [])
        if isinstance(children, list):
            for child in children:
                analyze_class_node(child)
        
        for key, value in node.items():
            if key != 'children':
                if isinstance(value, dict):
                    analyze_class_node(value)
                elif isinstance(value, list):
                    for item in value:
                        if isinstance(item, dict):
                            analyze_class_node(item)
    
    analyze_class_node(ast_tree)
    return findings


def check_generic_type_parameters_cocontravariant(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for generic_type_parameters_cocontravariant rule (RSPEC-3246).
    Detects generic interfaces and delegates that could use variance modifiers (in/out) but don't.
    
    Only interfaces and delegates support variance in C#. Classes/structs do not.
    
    - 'out T' (covariant): T is used only as return type / output
    - 'in T' (contravariant): T is used only as parameter / input
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    seen_findings = set()
    
    # Skip if in a comment or string context
    def is_in_comment_or_string(line_text, col_pos):
        # Check if position is in a string literal
        in_string = False
        escape_next = False
        for i, c in enumerate(line_text):
            if i >= col_pos:
                break
            if escape_next:
                escape_next = False
                continue
            if c == '\\':
                escape_next = True
                continue
            if c == '"':
                in_string = not in_string
        return in_string
    
    # Pattern to match interface or delegate declarations with generic parameters
    # This pattern captures:
    # - interface/delegate keyword
    # - the name
    # - the generic parameters
    interface_delegate_pattern = r'\b(interface|delegate)\s+(?:[\w<>]+\s+)?(\w+)\s*<([^>]+)>'
    
    # Pattern to check if a type parameter already has variance modifier
    variance_pattern = r'\b(in|out)\s+\w+'
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Skip comments
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
            continue
        
        # Skip string literals that contain the pattern
        if '"' in line and 'interface' in line.lower():
            # Check if 'interface' appears within a string
            quote_count = 0
            interface_in_string = False
            for i, char in enumerate(line):
                if char == '"' and (i == 0 or line[i-1] != '\\'):
                    quote_count += 1
                if quote_count % 2 == 1:  # Inside a string
                    if line[i:i+9].lower() == 'interface':
                        interface_in_string = True
                        break
            if interface_in_string:
                continue
        
        # Find interface or delegate declarations
        matches = list(re.finditer(interface_delegate_pattern, line, re.IGNORECASE))
        
        for match in matches:
            keyword = match.group(1).lower()  # 'interface' or 'delegate'
            name = match.group(2)
            generic_params = match.group(3)
            
            # Skip if this looks like it's inside a string
            match_start = match.start()
            if is_in_comment_or_string(line, match_start):
                continue
            
            # Parse the generic parameters
            # Split by comma, handling nested generics
            params = []
            depth = 0
            current_param = ""
            for char in generic_params:
                if char == '<':
                    depth += 1
                    current_param += char
                elif char == '>':
                    depth -= 1
                    current_param += char
                elif char == ',' and depth == 0:
                    params.append(current_param.strip())
                    current_param = ""
                else:
                    current_param += char
            if current_param.strip():
                params.append(current_param.strip())
            
            # Check each parameter for variance modifiers
            has_unmodified_params = False
            unmodified_params = []
            
            for param in params:
                param = param.strip()
                # Check if this parameter has 'in' or 'out' modifier
                if not re.match(r'^(in|out)\s+', param):
                    has_unmodified_params = True
                    # Extract just the type parameter name (handle constraints like "T where T : class")
                    param_name = param.split()[0] if param.split() else param
                    unmodified_params.append(param_name)
            
            if has_unmodified_params:
                finding_key = (filename, line_num, name)
                if finding_key not in seen_findings:
                    seen_findings.add(finding_key)
                    
                    param_list = ', '.join(unmodified_params)
                    message = f'Generic {keyword} \'{name}\' has type parameter(s) [{param_list}] that could potentially use variance modifiers (in/out)'
                    
                    findings.append({
                        'rule_id': 'generic_type_parameters_cocontravariant',
                        'message': message,
                        'file': filename,
                        'line': line_num,
                        'severity': 'Major',
                        'node': f'{keyword.capitalize()}Declaration.{name}',
                        'status': 'violation',
                        'property_path': ['source'],
                        'value': stripped[:100]
                    })
    
    return findings


def check_genericlist_instances_part_public(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for genericlist_instances_part_public rule (RSPEC-3956).
    Detects public APIs (methods/properties) that expose List<T> instead of interface types.
    
    List<T> is designed for performance, not inheritance, making it unsuitable for public APIs.
    Public members should return interface types (IEnumerable<T>, ICollection<T>, IList<T>, 
    or IReadOnlyCollection<T>) to allow implementation flexibility.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    seen_findings = set()
    
    # First pass: identify all class/struct/record declarations with their ranges
    class_pattern = re.compile(
        r'\b(public|internal|private|protected)?\s*'
        r'(?:(?:abstract|sealed|static|partial)\s+)*'
        r'(class|struct|record)\s+(\w+)'
    )
    
    # Build class info with start line and access modifier
    class_declarations = []  # List of (line_num, class_name, is_public, is_internal_or_private)
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        if stripped.startswith('//'):
            continue
        
        match = class_pattern.search(line)
        if match:
            access = match.group(1) or 'internal'
            class_name = match.group(3)
            is_public = access == 'public'
            is_internal_or_private = access in ('internal', 'private', 'protected')
            class_declarations.append((line_num, class_name, is_public, is_internal_or_private))
    
    # Pattern to detect public List<T> in method/property declarations
    public_list_pattern = re.compile(
        r'\bpublic\s+(?:(?:static|virtual|abstract|override|async|new|sealed|extern|unsafe)\s+)*'
        r'(?:(?:System\.Threading\.Tasks\.)?Task<\s*)?List<'
    )
    
    # Pattern to detect if List< appears in a string literal
    string_pattern = re.compile(r'"[^"]*List<[^"]*"')
    
    # Second pass: detect violations
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Skip comments
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
            continue
        
        # Skip lines that have List< inside a string literal
        if string_pattern.search(line):
            continue
        
        # Check for public List<T> pattern
        if not public_list_pattern.search(line):
            continue
        
        # Find which class this line belongs to
        # Find the most recent class declaration before this line
        containing_class = None
        for class_line, class_name, is_public, is_internal_or_private in reversed(class_declarations):
            if class_line < line_num:
                containing_class = (class_line, class_name, is_public, is_internal_or_private)
                break
        
        # Skip if we're in a non-public class (internal, private, or protected class)
        if containing_class and containing_class[3]:  # is_internal_or_private
            continue
        
        # Extract the member name
        member_name = "Unknown"
        
        # Method: public List<T> MethodName(
        method_match = re.search(r'List<[^>]+>\??\s+(\w+)\s*[\(<]', line)
        if method_match:
            member_name = method_match.group(1)
        else:
            # Property: public List<T> PropertyName { or =>
            prop_match = re.search(r'List<[^>]+>\??\s+(\w+)\s*[{=]', line)
            if prop_match:
                member_name = prop_match.group(1)
            else:
                # Indexer: public List<T> this[
                if 'this[' in line:
                    member_name = "Indexer"
        
        finding_key = (filename, line_num, member_name)
        if finding_key not in seen_findings:
            seen_findings.add(finding_key)
            
            # Determine if it's a method or property
            node_type = "MethodDeclaration" if '(' in line else "PropertyDeclaration"
            if 'this[' in line:
                node_type = "IndexerDeclaration"
            
            findings.append({
                'rule_id': 'genericlist_instances_part_public',
                'message': f'Public API member \'{member_name}\' returns List<T>. Consider using IEnumerable<T>, ICollection<T>, IList<T>, or IReadOnlyCollection<T> instead.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'node': f'{node_type}.{member_name}',
                'status': 'violation',
                'property_path': ['source'],
                'value': stripped[:100]
            })
    
    return findings


def check_generics_preferred_when_appropriate(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for generics_preferred_when_appropriate rule (RSPEC-4047).
    Detects methods with ref object parameters that should use generics instead.
    
    When a reference parameter (ref) is used, the passed argument type must exactly match
    the reference parameter type. Using generics (ref T) eliminates cumbersome down casting.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    seen_findings = set()
    
    # Pattern to detect ref object parameter (with optional nullable ?)
    ref_object_pattern = re.compile(r'\bref\s+object\??(?:\s+\w+|\s*[,)])')
    
    # Pattern to detect if we're inside a string literal
    string_pattern = re.compile(r'"[^"]*ref\s+object[^"]*"')
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Skip pure comment lines
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
            continue
        
        # Skip lines where ref object appears only in a string literal
        if string_pattern.search(line):
            # Check if there's also a real ref object outside strings
            line_without_strings = re.sub(r'"[^"]*"', '""', line)
            if not ref_object_pattern.search(line_without_strings):
                continue
        
        # Skip lines where ref object appears only in an inline comment
        code_part = line.split('//')[0]  # Get code before any inline comment
        
        # Check for ref object pattern in the code part only
        match = ref_object_pattern.search(code_part)
        if match:
            # Extract method/delegate name if possible
            member_name = 'Unknown'
            
            # Try to find method name
            method_match = re.search(r'\b(?:void|int|string|bool|object|Task|[\w<>]+)\s+(\w+)\s*[<(]', code_part)
            if method_match:
                member_name = method_match.group(1)
            
            # Try to find delegate name
            delegate_match = re.search(r'\bdelegate\s+\w+\s+(\w+)\s*\(', code_part)
            if delegate_match:
                member_name = delegate_match.group(1)
            
            # Determine if it's an interface method, delegate, or regular method
            if 'delegate' in code_part:
                node_type = 'DelegateDeclaration'
            elif 'interface' in stripped or (stripped.endswith(';') and '{' not in stripped and '(' in stripped):
                node_type = 'InterfaceMethodDeclaration'
            else:
                node_type = 'MethodDeclaration'
            
            finding_key = (line_num, member_name)
            if finding_key not in seen_findings:
                seen_findings.add(finding_key)
                findings.append({
                    'rule_id': 'generics_preferred_when_appropriate',
                    'message': f"Method '{member_name}' has a ref parameter of type object. Consider using a generic type parameter instead.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'node': f'{node_type}.{member_name}',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': stripped[:100]
                })
    
    return findings


def check_gethashcode_reference_mutable_fields(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for gethashcode_reference_mutable_fields rule (RSPEC-2328).
    Detects GetHashCode methods in classes that may reference mutable fields.
    
    Exceptions: struct, record struct, readonly struct (value types) should not trigger.
    Also excludes GetHashCode in classes where only readonly/const fields are used.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    seen_findings = set()
    
    # Track type declarations (class, struct, record) with their brace depths
    type_stack = []  # List of (type_kind, type_name, start_line, is_value_type)
    brace_depth = 0
    type_depths = []  # Stack of brace depths when each type started
    
    # First pass: identify all type declarations
    type_pattern = re.compile(
        r'\b(public|internal|private|protected)?\s*'
        r'(readonly\s+)?'
        r'(partial\s+)?'
        r'(struct|class|record\s+struct|record)\s+(\w+)'
    )
    
    # Pattern to detect GetHashCode override
    gethashcode_pattern = re.compile(r'\boverride\s+int\s+GetHashCode\s*\(\s*\)')
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Skip comments
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
            continue
        
        # Track braces for context
        open_braces = line.count('{')
        close_braces = line.count('}')
        
        # Check for type declarations before updating depth
        type_match = type_pattern.search(line)
        if type_match:
            readonly_mod = type_match.group(2)
            type_kind = type_match.group(4)  # class, struct, record, record struct
            type_name = type_match.group(5)
            
            # Determine if value type (struct, record struct, readonly struct)
            is_value_type = 'struct' in type_kind
            
            type_stack.append((type_kind, type_name, line_num, is_value_type))
            type_depths.append(brace_depth + open_braces)
        
        # Update brace depth
        brace_depth += open_braces - close_braces
        
        # Pop types when exiting their scope
        while type_depths and brace_depth < type_depths[-1]:
            type_depths.pop()
            if type_stack:
                type_stack.pop()
        
        # Check for GetHashCode override
        if gethashcode_pattern.search(line):
            # Determine the containing type
            if type_stack:
                containing_type = type_stack[-1]
                type_kind, type_name, _, is_value_type = containing_type
                
                # Skip if it's a value type (struct, record struct)
                if is_value_type:
                    continue
                
                # For classes, check if the GetHashCode uses mutable fields
                # Look at the method body for field/property access
                # This is a heuristic - we flag it if it accesses any identifier
                
                # Get the method body (simplified - look at next few lines until closing brace)
                method_body = []
                temp_depth = brace_depth
                found_opening = '{' in line
                if found_opening:
                    method_body.append(line)
                
                for next_line_num in range(line_num, min(line_num + 20, len(lines) + 1)):
                    next_line = lines[next_line_num - 1]
                    if next_line_num > line_num:
                        method_body.append(next_line)
                    temp_depth += next_line.count('{') - next_line.count('}')
                    if temp_depth <= brace_depth - 1 or ('}' in next_line and '=>' not in line):
                        break
                
                body_text = '\n'.join(method_body)
                
                # Check if body is just a constant return or base.GetHashCode()
                simple_patterns = [
                    r'return\s+\d+\s*;',  # return constant
                    r'return\s+base\.GetHashCode\(\)\s*;',  # return base.GetHashCode()
                    r'=>\s*\d+\s*;',  # expression body with constant
                    r'=>\s*base\.GetHashCode\(\)\s*;',  # expression body with base
                ]
                
                is_simple = any(re.search(p, body_text) for p in simple_patterns)
                if is_simple:
                    continue
                
                # Check if the class has any mutable fields/properties
                # This requires looking back at the class definition
                class_start = containing_type[2]
                class_body = '\n'.join(lines[class_start - 1:line_num])
                
                # Look for mutable indicators
                # 1. Auto-property with setter: { get; set; }
                has_mutable_auto_property = re.search(r'\{\s*get\s*;\s*set\s*;\s*\}', class_body)
                
                # 2. Init-only property: { get; init; }
                has_init_property = re.search(r'\{\s*get\s*;\s*init\s*;\s*\}', class_body)
                
                # 3. Property with explicit setter: set => or set { or set;
                has_explicit_setter = re.search(r'\bset\s*(=>|{|;)', class_body)
                
                # 4. Non-readonly field: public/private/internal/protected type name; (not readonly)
                # Match field declarations that don't have readonly/const before the type
                has_mutable_field = re.search(
                    r'^\s*(public|private|protected|internal)\s+(?!readonly\b)(?!const\b)(?!static\s+readonly\b)[\w<>\[\]?]+\s+\w+\s*[;=]',
                    class_body, 
                    re.MULTILINE
                )
                
                # 5. Check for explicit property setter blocks: set { _field = value; }
                has_property_setter_block = re.search(r'\bset\s*\{', class_body)
                
                # If has any mutable indicator, flag it
                if has_mutable_auto_property or has_init_property or has_mutable_field or has_property_setter_block:
                    finding_key = (line_num, type_name)
                    if finding_key not in seen_findings:
                        seen_findings.add(finding_key)
                        findings.append({
                            'rule_id': 'gethashcode_reference_mutable_fields',
                            'message': f"GetHashCode in '{type_name}' may reference mutable fields. Consider using only readonly fields in GetHashCode.",
                            'file': filename,
                            'line': line_num,
                            'severity': 'Major',
                            'node': f'MethodDeclaration.GetHashCode',
                            'status': 'violation',
                            'property_path': ['source'],
                            'value': stripped[:100]
                        })
    
    return findings


def check_getters_setters_access_expected(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for getters_setters_access_expected rule (RSPEC-4275).
    Detects properties where getter/setter access a different field than expected.
    
    This is typically a copy-paste error where:
    - Getter returns wrong field (e.g., property Y returns field x)
    - Setter assigns to wrong field (e.g., property X sets field y)
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    seen_findings = set()
    
    # First, collect all field declarations in the file
    # Pattern matches: private int x; or private string _name;
    field_pattern = re.compile(
        r'^\s*(?:private|protected|internal)\s+'
        r'(?:readonly\s+|static\s+|const\s+)?'
        r'[\w<>\[\]?]+\s+([_a-zA-Z][_a-zA-Z0-9]*)\s*[;=]'
    )
    
    # Collect all field names with their normalized versions
    all_fields = {}  # field_name -> normalized_name
    for line in lines:
        match = field_pattern.match(line)
        if match:
            field_name = match.group(1)
            if field_name not in ('value', 'get', 'set', 'this', 'base'):
                # Normalize: remove _ or m_ prefix and lowercase
                normalized = field_name.lower()
                if normalized.startswith('m_'):
                    normalized = normalized[2:]
                elif normalized.startswith('_'):
                    normalized = normalized[1:]
                all_fields[field_name] = normalized
    
    # Helper function to check if field matches property
    def field_matches_property(field_name, prop_name):
        """Check if field name corresponds to property name."""
        if field_name not in all_fields:
            return True  # Not a known field, don't flag
        norm_field = all_fields[field_name]
        norm_prop = prop_name.lower()
        # Check direct match or case-insensitive match
        return norm_field == norm_prop
    
    # Pattern to detect property declaration line
    # Matches: public int PropertyName or public virtual string Name
    # Allows trailing comments like // comment
    # Requires a type name (not class/struct/interface/enum/delegate) before property name
    property_decl_pattern = re.compile(
        r'^\s*(?:public|private|protected|internal)\s+'
        r'(?:static\s+|virtual\s+|override\s+|abstract\s+|sealed\s+)?'
        r'([\w<>\[\]?]+)\s+(\w+)\s*(?://.*)?$'
    )
    
    # Pattern for expression-bodied property: public int X => field;
    expr_property_pattern = re.compile(
        r'^\s*(?:public|private|protected|internal)\s+'
        r'(?:static\s+|virtual\s+|override\s+|abstract\s+|sealed\s+)?'
        r'[\w<>\[\]?]+\s+(\w+)\s*=>\s*(?:this\.)?([_a-zA-Z][_a-zA-Z0-9]*)'
    )
    
    # Patterns for getter/setter analysis
    getter_return_pattern = re.compile(r'\breturn\s+(?:this\.)?([_a-zA-Z][_a-zA-Z0-9]*)\s*[;.]')
    setter_assign_pattern = re.compile(r'(?:this\.)?([_a-zA-Z][_a-zA-Z0-9]*)\s*=\s*value\s*;')
    
    i = 0
    while i < len(lines):
        line = lines[i]
        stripped = line.strip()
        
        # Skip comments
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
            i += 1
            continue
        
        # Check for expression-bodied property first
        expr_match = expr_property_pattern.match(line)
        if expr_match:
            prop_name = expr_match.group(1)
            accessed_field = expr_match.group(2)
            prop_line = i + 1
            
            if accessed_field in all_fields and not field_matches_property(accessed_field, prop_name):
                finding_key = (prop_line, prop_name)
                if finding_key not in seen_findings:
                    seen_findings.add(finding_key)
                    findings.append({
                        'rule_id': 'getters_setters_access_expected',
                        'message': f"Property '{prop_name}' returns field '{accessed_field}' which doesn't match the property name.",
                        'file': filename,
                        'line': prop_line,
                        'severity': 'Major',
                        'node': f'PropertyDeclaration.{prop_name}',
                        'status': 'violation',
                        'property_path': ['source'],
                        'value': stripped[:100]
                    })
            i += 1
            continue
        
        # Check for block property declaration (property name on one line, { on next or same)
        prop_match = property_decl_pattern.match(line)
        if prop_match:
            type_name = prop_match.group(1)
            prop_name = prop_match.group(2)
            prop_line = i + 1
            
            # Skip type declarations (class, struct, interface, enum, delegate)
            if type_name in ('class', 'struct', 'interface', 'enum', 'delegate'):
                i += 1
                continue
            
            # Look for the property body starting with {
            body_start = i + 1
            if body_start < len(lines) and '{' in lines[body_start]:
                # Extract property body
                brace_depth = 0
                body_lines = []
                j = body_start
                while j < len(lines):
                    body_lines.append(lines[j])
                    brace_depth += lines[j].count('{') - lines[j].count('}')
                    if brace_depth == 0:
                        break
                    j += 1
                
                body_text = '\n'.join(body_lines)
                
                # Skip auto-properties: { get; set; } or { get; }
                if re.search(r'\{\s*get\s*;\s*(?:(?:private\s+)?set\s*;|init\s*;)?\s*\}', body_text):
                    i = j + 1
                    continue
                
                # Check getter - return statement
                getter_matches = getter_return_pattern.findall(body_text)
                for accessed_field in getter_matches:
                    if accessed_field in all_fields and not field_matches_property(accessed_field, prop_name):
                        finding_key = (prop_line, prop_name, 'getter')
                        if finding_key not in seen_findings:
                            seen_findings.add(finding_key)
                            findings.append({
                                'rule_id': 'getters_setters_access_expected',
                                'message': f"Property '{prop_name}' getter returns field '{accessed_field}' which doesn't match the property name.",
                                'file': filename,
                                'line': prop_line,
                                'severity': 'Major',
                                'node': f'PropertyDeclaration.{prop_name}',
                                'status': 'violation',
                                'property_path': ['source'],
                                'value': stripped[:100]
                            })
                            break
                
                # Check setter - assignment to field
                setter_matches = setter_assign_pattern.findall(body_text)
                for accessed_field in setter_matches:
                    if accessed_field in all_fields and not field_matches_property(accessed_field, prop_name):
                        finding_key = (prop_line, prop_name, 'setter')
                        if finding_key not in seen_findings:
                            seen_findings.add(finding_key)
                            findings.append({
                                'rule_id': 'getters_setters_access_expected',
                                'message': f"Property '{prop_name}' setter assigns to field '{accessed_field}' which doesn't match the property name.",
                                'file': filename,
                                'line': prop_line,
                                'severity': 'Major',
                                'node': f'PropertyDeclaration.{prop_name}',
                                'status': 'violation',
                                'property_path': ['source'],
                                'value': stripped[:100]
                            })
                            break
                
                i = j + 1
                continue
        
        i += 1
    
    return findings


def check_idisposable_without_suppress_finalize(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for idisposable_implemented_correctly rule.
    Checks that non-sealed classes implementing IDisposable call GC.SuppressFinalize(this).
    
    Returns findings for classes that:
    - Implement IDisposable
    - Are NOT sealed
    - Do NOT call GC.SuppressFinalize in the class body
    - Are NOT structs (value types don't need GC.SuppressFinalize)
    - Are NOT in test context
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Track class declarations and their body content
    i = 0
    while i < len(lines):
        line = lines[i]
        stripped = line.strip()
        
        # Skip comments
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
            i += 1
            continue
        
        # Look for class declarations implementing IDisposable
        # Pattern: class ClassName : IDisposable or class ClassName : BaseClass, IDisposable
        # Can have modifiers like public, internal, sealed, abstract, partial before class
        class_match = re.search(r'\b(class|struct|record)\s+(\w+)(?:<[^>]+>)?\s*:\s*(.+)', line)
        
        if class_match:
            class_type = class_match.group(1)  # class, struct, or record
            class_name = class_match.group(2)
            inheritance = class_match.group(3)
            
            # Check if implements IDisposable
            if 'IDisposable' not in inheritance:
                i += 1
                continue
            
            # Check if sealed (should be excluded)
            if 'sealed' in line.lower() or 'sealed' in lines[max(0, i-1)].lower():
                i += 1
                continue
            
            # Structs don't need GC.SuppressFinalize
            if class_type == 'struct':
                i += 1
                continue
            
            # Check if in test context
            if i > 0 and '[Test' in lines[i-1]:
                i += 1
                continue
            
            # Find the class body (from opening brace to closing brace)
            brace_count = 0
            class_start = i
            class_body = []
            found_opening = False
            
            j = i
            while j < len(lines):
                current_line = lines[j]
                
                for char in current_line:
                    if char == '{':
                        brace_count += 1
                        found_opening = True
                    elif char == '}':
                        brace_count -= 1
                
                if found_opening:
                    class_body.append(current_line)
                
                if found_opening and brace_count == 0:
                    break
                    
                j += 1
            
            # Check if the class body contains GC.SuppressFinalize call (not in comments)
            class_source = '\n'.join(class_body)
            
            # Remove single-line comments before checking
            class_source_no_comments = re.sub(r'//.*', '', class_source)
            # Remove multi-line comments
            class_source_no_comments = re.sub(r'/\*.*?\*/', '', class_source_no_comments, flags=re.DOTALL)
            
            has_suppress_finalize = bool(re.search(r'GC\.SuppressFinalize\s*\(|System\.GC\.SuppressFinalize\s*\(', class_source_no_comments))
            
            # If no GC.SuppressFinalize found, report violation
            if not has_suppress_finalize:
                findings.append({
                    'rule_id': 'idisposable_implemented_correctly',
                    'message': f"Class '{class_name}' implements IDisposable but does not call GC.SuppressFinalize(this)",
                    'file': filename,
                    'line': class_start + 1,  # 1-based line number
                    'severity': 'Major',
                    'node': f'ClassDeclaration.{class_name}',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': f'class {class_name} : IDisposable'
                })
            
            # Skip to end of class
            i = j + 1
            continue
        
        i += 1
    
    return findings


def check_idisposables_not_disposed(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for idisposables_disposed rule.
    Detects IDisposable objects created without proper disposal.
    
    Excludes:
    - Variables in using statements
    - Class-level fields
    - Variables that are returned (even on next line)
    - Test methods (checks for [Test], [Fact], [Theory] attributes)
    - Comments
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # IDisposable types to check
    disposable_types = ['Bitmap', 'StreamReader', 'FileStream', 'SqlConnection', 'HttpClient', 
                        'StreamWriter', 'BinaryReader', 'BinaryWriter', 'MemoryStream', 
                        'NetworkStream', 'WebClient', 'Socket']
    
    # Pattern to match variable assignments
    pattern = re.compile(r'var\s+(\w+)\s*=\s*new\s+(' + '|'.join(disposable_types) + r')\s*\(')
    
    # Track methods with test attributes
    in_test_method = False
    test_method_end_line = -1
    
    i = 0
    while i < len(lines):
        line = lines[i]
        stripped = line.strip()
        
        # Skip comments
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
            i += 1
            continue
        
        # Check for test attributes (look for them to mark test context)
        if re.search(r'\[(Test|Fact|Theory|TestMethod|TestCase)\]', stripped):
            # Find the end of this method
            in_test_method = True
            brace_count = 0
            found_opening = False
            j = i
            while j < len(lines):
                for char in lines[j]:
                    if char == '{':
                        brace_count += 1
                        found_opening = True
                    elif char == '}':
                        brace_count -= 1
                if found_opening and brace_count == 0:
                    test_method_end_line = j
                    break
                j += 1
            i += 1
            continue
        
        # Check if we've exited the test method
        if in_test_method and i > test_method_end_line:
            in_test_method = False
        
        # Skip if in test method context
        if in_test_method:
            i += 1
            continue
        
        # Check for using statement (both forms)
        if 'using' in stripped and ('using (' in stripped or 'using var' in stripped):
            i += 1
            continue
        
        # Check for class field declarations
        if re.search(r'^\s*(private|protected|public|internal)\s+\w+\s+\w+\s*=', line):
            i += 1
            continue
        
        # Check for pattern match
        match = pattern.search(line)
        if match:
            var_name = match.group(1)
            disposable_type = match.group(2)
            
            # Check if variable is returned within next 3 lines
            is_returned = False
            for j in range(i, min(i + 4, len(lines))):
                if re.search(r'return\s+' + var_name + r'\s*;', lines[j]):
                    is_returned = True
                    break
            
            if is_returned:
                i += 1
                continue
            
            # Check if this is inside a using block (look backwards)
            in_using_block = False
            for j in range(max(0, i - 5), i):
                if 'using (' in lines[j] or 'using var' in lines[j]:
                    in_using_block = True
                    break
            
            if in_using_block:
                i += 1
                continue
            
            # This is a violation
            findings.append({
                'rule_id': 'idisposables_disposed',
                'message': f"IDisposable '{var_name}' of type '{disposable_type}' is not disposed",
                'file': filename,
                'line': i + 1,  # 1-based line number
                'severity': 'Major',
                'node': f'Assignment.{var_name}',
                'status': 'violation',
                'property_path': ['source'],
                'value': f'var {var_name} = new {disposable_type}('
            })
        
        i += 1
    
    return findings


def check_if_else_if_without_else(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for if_else_if_constructs rule.
    Detects if-else if constructs that do NOT end with a final else clause.
    
    Rule: "if ... else if" constructs should end with "else" clauses
    
    Noncompliant:
        if (x == 0) { } else if (x == 1) { }  // Missing final else
    
    Compliant:
        if (x == 0) { } else if (x == 1) { } else { }  // Has final else
        if (x == 0) { } else { }  // Simple if-else, not if-else-if
        if (x == 0) { }  // Single if, not applicable
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    def find_matching_brace_end(start_line):
        """Find the line where the brace block ends."""
        brace_count = 0
        found_opening = False
        j = start_line
        
        while j < len(lines):
            line_content = lines[j]
            # Remove string literals to avoid counting braces in strings
            in_string = False
            for idx, char in enumerate(line_content):
                if char == '"' and (idx == 0 or line_content[idx-1] != '\\'):
                    in_string = not in_string
                if not in_string:
                    if char == '{':
                        brace_count += 1
                        found_opening = True
                    elif char == '}':
                        brace_count -= 1
            if found_opening and brace_count == 0:
                return j
            j += 1
        return len(lines) - 1
    
    def check_what_follows(after_line):
        """Check what follows after a closing brace - returns 'else_if', 'else', or 'other'."""
        k = after_line + 1
        while k < len(lines):
            next_line = lines[k].strip()
            
            # Skip empty lines
            if not next_line:
                k += 1
                continue
            
            # Skip single-line comments
            if next_line.startswith('//'):
                k += 1
                continue
            
            # Check if followed by else if
            if re.search(r'\belse\s+if\s*\(', next_line):
                return 'else_if', k
            
            # Check if followed by else (with or without brace on same line)
            if re.match(r'\s*else\s*(\{|$|//)', next_line) or next_line == 'else':
                return 'else', k
            
            # Something else follows - chain ended without else
            return 'other', k
        
        return 'other', len(lines)
    
    # Find all else if statements and track chains
    i = 0
    while i < len(lines):
        line = lines[i]
        stripped = line.strip()
        
        # Skip comments
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
            i += 1
            continue
        
        # Look for 'else if' pattern
        if re.search(r'\belse\s+if\s*\(', stripped):
            # Found an else if - find end of its block
            block_end = find_matching_brace_end(i)
            
            # Check what follows this else if block
            what_follows, _ = check_what_follows(block_end)
            
            if what_follows == 'else_if':
                # Chain continues, don't report yet - check the next else if
                pass
            elif what_follows == 'else':
                # Chain properly ends with else - compliant
                pass
            else:
                # Chain ends without else - violation!
                findings.append({
                    'rule_id': 'if_else_if_constructs',
                    'message': 'if-else if construct should end with else clause',
                    'file': filename,
                    'line': i + 1,  # Report on the else if line
                    'severity': 'Major',
                    'node': 'IfStatement.ElseIf',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': stripped[:80] if len(stripped) > 80 else stripped
                })
        
        i += 1
    
    return findings


def check_partial_methods_without_implementation(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for implementations_provided_partial_methods rule.
    Detects partial method declarations that lack implementations.
    
    A partial method declaration looks like: partial void MethodName();
    An implementation looks like: partial void MethodName() { ... }
    
    The rule should only flag declarations that have NO implementation in the file.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # First pass: collect all partial method declarations and implementations
    declarations = []  # List of (line_num, method_name)
    implementations = set()  # Set of method names that have implementations
    
    # Pattern for partial method declaration (ends with semicolon)
    decl_pattern = re.compile(r'partial\s+void\s+(\w+)\s*\([^)]*\)\s*;')
    
    # Pattern for partial method implementation on same line (has body with braces or expression body)
    impl_pattern_same_line = re.compile(r'partial\s+void\s+(\w+)\s*\([^)]*\)\s*(\{|=>)')
    
    # Pattern for partial method signature (to find implementations where { is on next line)
    # Allows for comment after the closing parenthesis
    impl_pattern_multi_line = re.compile(r'partial\s+void\s+(\w+)\s*\([^)]*\)\s*(//.*)?$')
    
    in_multiline_comment = False
    
    for i, line in enumerate(lines):
        stripped = line.strip()
        
        # Handle multi-line comments
        if '/*' in stripped:
            in_multiline_comment = True
        if '*/' in stripped:
            in_multiline_comment = False
            continue
        
        if in_multiline_comment:
            continue
        
        # Skip single-line comments (lines that are only comments)
        if stripped.startswith('//'):
            continue
        
        # Check for implementation on same line (more specific pattern)
        impl_match = impl_pattern_same_line.search(line)
        if impl_match:
            method_name = impl_match.group(1)
            implementations.add(method_name)
            continue
        
        # Skip if it's a declaration ending with semicolon
        if decl_pattern.search(line):
            decl_match = decl_pattern.search(line)
            if decl_match:
                method_name = decl_match.group(1)
                declarations.append((i + 1, method_name, stripped))
            continue
        
        # Check for implementation with { on next line
        impl_match_multi = impl_pattern_multi_line.search(stripped)
        if impl_match_multi:
            method_name = impl_match_multi.group(1)
            # Look at next non-empty, non-comment lines for opening brace
            for j in range(i + 1, min(i + 5, len(lines))):
                next_line = lines[j].strip()
                if not next_line:
                    continue
                if next_line.startswith('//'):
                    continue
                if next_line.startswith('{') or next_line == '{':
                    implementations.add(method_name)
                    break
                # If we find anything else, it's not an implementation
                break
    
    # Second pass: report declarations without implementations
    for line_num, method_name, line_content in declarations:
        if method_name not in implementations:
            findings.append({
                'rule_id': 'implementations_provided_partial_methods',
                'message': f"Partial method '{method_name}' has no implementation",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'node': f'MethodDeclaration.{method_name}',
                'status': 'violation',
                'property_path': ['source'],
                'value': f'partial void {method_name}();'
            })
    
    return findings


def check_os_commands_path_security(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects when OS commands are executed without specifying the full path.
    Security risk: PATH hijacking can occur if attackers place malicious executables
    in directories covered by PATH environment variable.
    
    Triggers on: Process.Start(), ProcessStartInfo.FileName assignments with relative paths
    Excludes: Comments, logging, full paths (with drive letters or /), configuration-based paths, test contexts
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Patterns for detecting process execution
    process_patterns = [
        # Process.Start("command") or Process.Start("command", "args")
        r'Process\.Start\s*\(\s*["\']([^"\'\\/:]+)["\']',
        # ProcessStartInfo("command") or FileName = "command"
        r'ProcessStartInfo\s*\(\s*["\']([^"\'\\/:]+)["\']',
        r'\.FileName\s*=\s*["\']([^"\'\\/:]+)["\']',
        # StartInfo.FileName = "command"
        r'StartInfo\.FileName\s*=\s*["\']([^"\'\\/:]+)["\']',
    ]
    
    # Exclusion patterns for individual lines
    exclude_patterns = [
        r'^\s*//',           # Line comments
        r'^\s*/\*',          # Block comment start
        r'Console\.',        # Console logging
        r'Logger\.',         # Logger calls
        r'Debug\.',          # Debug calls
        r'Trace\.',          # Trace calls
        r'Assert\.',         # Assertions
        r'@"[^"]*[/\\:]',    # Verbatim strings with paths
        r'"[^"]*[/\\:]',     # Strings with path separators (full paths)
        r'Environment\.GetFolderPath',  # Using system paths
        r'Path\.Combine',    # Path.Combine usage nearby
        r'AppSettings',      # Configuration
        r'Configuration',    # Configuration
    ]
    
    # Function to check if a line is in a test context
    def is_in_test_context(line_index):
        """Check if the current line is within a test method"""
        # Look backwards for test attributes (most reliable indicator)
        for i in range(max(0, line_index - 10), line_index + 1):
            prev_line = lines[i].strip()
            # Check for test attributes
            if re.search(r'\[Test\]|\[Fact\]|\[TestMethod\]|\[TestCase\]', prev_line, re.IGNORECASE):
                return True
        
        # Look for test method signatures with NUnit/xUnit patterns but exclude general methods
        for i in range(max(0, line_index - 8), line_index):
            prev_line = lines[i].strip()
            # Be very specific about test method patterns - avoid false positives
            if re.search(r'public\s+(void|async\s+Task)\s+(Test[A-Za-z]*|[A-Za-z]*Test)\s*\(\s*\)\s*$', prev_line, re.IGNORECASE):
                # Make sure it's actually a unit test method, not just a method with "Test" in the name
                # Look for test attributes within a few lines before the method
                for j in range(max(0, i - 5), i):
                    attr_line = lines[j].strip()
                    if re.search(r'\[Test\]|\[Fact\]|\[TestMethod\]', attr_line, re.IGNORECASE):
                        return True
                        
        return False
    
    for line_num, line in enumerate(lines, 1):
        # Skip exclusions - basic patterns
        should_exclude = False
        for exclude_pattern in exclude_patterns:
            if re.search(exclude_pattern, line, re.IGNORECASE):
                should_exclude = True
                break
        
        if should_exclude:
            continue
            
        # Skip if in test context
        if is_in_test_context(line_num - 1):  # Convert to 0-based index
            continue
        
        # Check for vulnerable patterns
        for pattern in process_patterns:
            matches = re.finditer(pattern, line)
            for match in matches:
                command = match.group(1)
                # Verify it's not a full path
                if not re.search(r'[/\\:]', command):
                    # It's a command without full path - vulnerable
                    findings.append({
                        'rule_id': 'searching_os_commands_path',
                        'message': f"OS command '{command}' executed without full path - vulnerable to PATH hijacking",
                        'file': filename,
                        'line': line_num,
                        'severity': 'Major',
                        'node': 'CallExpression.Process.Start',
                        'status': 'violation',
                        'property_path': ['source'],
                        'value': line.strip()
                    })
                    break  # One finding per line
    
    return findings


def check_commented_out_code(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects sections of code that have been commented out.
    Commented-out code creates maintenance burden and should be removed.
    
    Triggers on: Multiple consecutive commented lines containing code patterns
    Excludes: XML doc comments, TODO/FIXME comments, license headers, legitimate comments
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Patterns that indicate actual code (not comments)
    code_patterns = [
        r'^\s*//\s*\w+\s*\(',                    # //methodCall(
        r'^\s*//\s*\w+\s*=',                     # //variable =
        r'^\s*//\s*\w+\s*\.\w+',                 # //object.method
        r'^\s*//\s*return\s+',                   # //return
        r'^\s*//\s*if\s*\(',                     # //if (
        r'^\s*//\s*for\s*\(',                    # //for (
        r'^\s*//\s*foreach\s*\(',                # //foreach (
        r'^\s*//\s*while\s*\(',                  # //while (
        r'^\s*//\s*var\s+',                      # //var
        r'^\s*//\s*int\s+',                      # //int
        r'^\s*//\s*string\s+',                   # //string
        r'^\s*//\s*public\s+',                   # //public
        r'^\s*//\s*private\s+',                  # //private
        r'^\s*//\s*\{',                          # //{
        r'^\s*//\s*\}',                          # //}
        r'^\s*//\s*\w+;\s*$',                    # //statement;
    ]
    
    # Exclusion patterns (legitimate comments)
    exclude_patterns = [
        r'^\s*///\s',                            # XML doc comments
        r'^\s*//\s*TODO',                        # TODO comments
        r'^\s*//\s*FIXME',                       # FIXME comments
        r'^\s*//\s*NOTE',                        # NOTE comments
        r'^\s*//\s*HACK',                        # HACK comments
        r'^\s*//\s*BUG',                         # BUG comments
        r'^\s*//\s*Copyright',                   # License headers
        r'^\s*//\s*License',                     # License headers
        r'^\s*//\s*Author',                      # Author comments
        r'^\s*//\s*\*',                          # Decorative comments
        r'^\s*//\s*-+',                          # Separator comments
        r'^\s*//\s*=+',                          # Separator comments
        r'^\s*//\s*$',                           # Empty comments
        r'^\s*//\s*[A-Z][a-z]+\s+[a-z]+',        # Natural language sentences
    ]
    
    # Track consecutive commented code lines
    consecutive_code_comments = []
    
    for line_num, line in enumerate(lines, 1):
        # Check if line is a comment
        if not re.match(r'^\s*//', line):
            # Not a comment - if we had consecutive code comments, report them
            if len(consecutive_code_comments) >= 2:  # 2+ consecutive lines of commented code
                first_line = consecutive_code_comments[0]
                findings.append({
                    'rule_id': 'sections_code_commented_out',
                    'message': f"Commented-out code detected ({len(consecutive_code_comments)} lines). Remove commented code and use source control.",
                    'file': filename,
                    'line': first_line,
                    'severity': 'Major',
                    'node': 'Comment',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': f'{len(consecutive_code_comments)} consecutive lines of commented code'
                })
            consecutive_code_comments = []
            continue
        
        # Check for exclusions first
        is_excluded = False
        for exclude_pattern in exclude_patterns:
            if re.search(exclude_pattern, line, re.IGNORECASE):
                is_excluded = True
                break
        
        if is_excluded:
            if len(consecutive_code_comments) >= 2:
                first_line = consecutive_code_comments[0]
                findings.append({
                    'rule_id': 'sections_code_commented_out',
                    'message': f"Commented-out code detected ({len(consecutive_code_comments)} lines). Remove commented code and use source control.",
                    'file': filename,
                    'line': first_line,
                    'severity': 'Major',
                    'node': 'Comment',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': f'{len(consecutive_code_comments)} consecutive lines of commented code'
                })
            consecutive_code_comments = []
            continue
        
        # Check if it matches code patterns
        is_code = False
        for code_pattern in code_patterns:
            if re.search(code_pattern, line):
                is_code = True
                break
        
        if is_code:
            consecutive_code_comments.append(line_num)
        else:
            if len(consecutive_code_comments) >= 2:
                first_line = consecutive_code_comments[0]
                findings.append({
                    'rule_id': 'sections_code_commented_out',
                    'message': f"Commented-out code detected ({len(consecutive_code_comments)} lines). Remove commented code and use source control.",
                    'file': filename,
                    'line': first_line,
                    'severity': 'Major',
                    'node': 'Comment',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': f'{len(consecutive_code_comments)} consecutive lines of commented code'
                })
            consecutive_code_comments = []
    
    # Handle end of file
    if len(consecutive_code_comments) >= 2:
        first_line = consecutive_code_comments[0]
        findings.append({
            'rule_id': 'sections_code_commented_out',
            'message': f"Commented-out code detected ({len(consecutive_code_comments)} lines). Remove commented code and use source control.",
            'file': filename,
            'line': first_line,
            'severity': 'Major',
            'node': 'Comment',
            'status': 'violation',
            'property_path': ['source'],
            'value': f'{len(consecutive_code_comments)} consecutive lines of commented code'
        })
    
    return findings


def check_predictable_random_seed(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects Random class usage with predictable seeds.
    Cryptographic operations require unpredictable random numbers.
    
    Triggers on: new Random(constantValue), new Random((int)DateTime...)
    Excludes: Logging, unit tests, RandomNumberGenerator usage
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Patterns for detecting predictable random seeds
    vulnerable_patterns = [
        (r'new\s+Random\s*\(\s*(\d+)\s*\)', 'constant seed'),
        (r'new\s+Random\s*\(\s*\(int\)\s*DateTime\.', 'DateTime-based seed'),
        (r'new\s+Random\s*\(\s*DateTime\.[^)]*\.Ticks', 'DateTime.Ticks seed'),
        (r'new\s+Random\s*\(\s*Environment\.TickCount', 'TickCount seed'),
    ]
    
    # Exclusion patterns for individual lines
    exclude_patterns = [
        r'^\s*//',           # Comments
        r'Console\.',        # Logging
        r'Logger\.',         # Logging
        r'Debug\.',          # Debug
        r'Assert\.',         # Assertions
        r'RandomNumberGenerator',  # Secure random
        r'RNGCryptoServiceProvider',  # Secure random
        r'//.*new\s+Random',  # Commented code
    ]
    
    # Function to check if a line is in a test context
    def is_in_test_context(line_index):
        """Check if the current line is within a test method"""
        # Look backwards for test attributes
        for i in range(max(0, line_index - 10), line_index + 1):
            prev_line = lines[i].strip()
            # Check for test attributes
            if re.search(r'\[Test\]|\[Fact\]|\[TestMethod\]|\[TestCase\]', prev_line, re.IGNORECASE):
                return True
        
        # Look for test method signatures with test attributes validation
        for i in range(max(0, line_index - 8), line_index):
            prev_line = lines[i].strip()
            # Check for test method patterns
            if re.search(r'public\s+(void|async\s+Task)\s+(Test[A-Za-z]*|[A-Za-z]*Test)\s*\(\s*\)\s*$', prev_line, re.IGNORECASE):
                # Validate it's actually a test method by checking for test attributes
                for j in range(max(0, i - 5), i):
                    attr_line = lines[j].strip()
                    if re.search(r'\[Test\]|\[Fact\]|\[TestMethod\]', attr_line, re.IGNORECASE):
                        return True
                        
        return False
    
    for line_num, line in enumerate(lines, 1):
        # Skip exclusions - basic patterns
        should_exclude = False
        for exclude_pattern in exclude_patterns:
            if re.search(exclude_pattern, line, re.IGNORECASE):
                should_exclude = True
                break
        
        if should_exclude:
            continue
            
        # Skip if in test context
        if is_in_test_context(line_num - 1):  # Convert to 0-based index
            continue
        
        # Check for vulnerable patterns
        for pattern, seed_type in vulnerable_patterns:
            match = re.search(pattern, line)
            if match:
                findings.append({
                    'rule_id': 'secure_random_number_generators',
                    'message': f"Random number generator uses predictable seed ({seed_type}). Use RandomNumberGenerator for cryptographic operations.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'node': 'CallExpression.Random',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': line.strip()
                })
                break
    
    return findings


def check_sequential_duplicate_conditions(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects sequential if statements that check the same condition.
    This is either confusing or an error - should be combined or use different conditions.
    
    Triggers on: if(condition) {...} if(condition) {...} without reassignment
    Excludes: Reassignment between conditions, comments, logging, test contexts
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Function to check if a line is in a test context
    def is_in_test_context(line_index):
        """Check if the current line is within a test method"""
        # Look backwards for test attributes
        for i in range(max(0, line_index - 15), line_index + 1):
            prev_line = lines[i].strip()
            # Check for test attributes
            if re.search(r'\[Test\]|\[Fact\]|\[TestMethod\]|\[TestCase\]', prev_line, re.IGNORECASE):
                return True
        
        # Look for test method signatures with test attributes validation
        for i in range(max(0, line_index - 8), line_index):
            prev_line = lines[i].strip()
            # Check for test method patterns (more liberal - any method with test attributes)
            if re.search(r'public\s+(void|async\s+Task)\s+\w+\s*\(.*\)\s*$', prev_line, re.IGNORECASE):
                # Validate it's actually a test method by checking for test attributes
                for j in range(max(0, i - 8), i):
                    attr_line = lines[j].strip()
                    if re.search(r'\[Test\]|\[Fact\]|\[TestMethod\]|\[TestCase\]', attr_line, re.IGNORECASE):
                        return True
                        
        return False
    
    # Function to check if currently in a comment block
    def is_in_comment_block(line_index):
        """Check if the current line is within a multi-line comment block"""
        in_comment = False
        for i in range(0, line_index + 1):
            line = lines[i].strip()
            if '/*' in line and '*/' not in line:
                in_comment = True
            elif '*/' in line:
                in_comment = False
        return in_comment
    
    # Track previous condition and location
    prev_condition = None
    prev_line_num = None
    
    # Pattern to match if statements
    if_pattern = re.compile(r'if\s*\(\s*(.+?)\s*\)\s*$|if\s*\(\s*(.+?)\s*\)\s*\{')
    
    # Exclusion patterns for individual lines
    exclude_patterns = [
        r'^\s*//',           # Line comments
        r'^\s*/\*',          # Block comment start
        r'Console\.',        # Console logging
        r'Logger\.',         # Logger calls
        r'Debug\.',          # Debug calls
        r'Assert\.',         # Assertions
    ]
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Skip empty lines
        if not stripped:
            continue
            
        # Skip exclusions - basic patterns
        should_exclude = False
        for exclude_pattern in exclude_patterns:
            if re.search(exclude_pattern, stripped, re.IGNORECASE):
                should_exclude = True
                break
        
        if should_exclude:
            continue
            
        # Skip if in test context
        if is_in_test_context(line_num - 1):  # Convert to 0-based index
            continue
            
        # Skip if in comment block
        if is_in_comment_block(line_num - 1):  # Convert to 0-based index
            continue
        
        # Look for if statements
        match = if_pattern.search(stripped)
        if match:
            condition = match.group(1) or match.group(2)
            condition = condition.strip()
            
            # Check if it matches previous condition
            if prev_condition and condition == prev_condition:
                # Check if there's a reassignment between them
                has_reassignment = False
                
                # Look for assignment to variables in the condition between prev_line and current
                condition_vars = re.findall(r'\b([a-zA-Z_]\w*)\b', condition)
                for i in range(prev_line_num, line_num - 1):  # Between previous and current line
                    line_to_check = lines[i] if i < len(lines) else ""
                    for var in condition_vars:
                        if re.search(rf'\b{var}\s*=', line_to_check):
                            has_reassignment = True
                            break
                    if has_reassignment:
                        break
                
                if not has_reassignment:
                    findings.append({
                        'rule_id': 'sequential_tests_check_same',
                        'message': f"Sequential if statements check the same condition '{condition}'. Consider combining or using different conditions.",
                        'file': filename,
                        'line': line_num,
                        'severity': 'Major',
                        'node': 'IfStatement',
                        'status': 'violation',
                        'property_path': ['source'],
                        'value': stripped
                    })
            
            prev_condition = condition
            prev_line_num = line_num
    
    return findings


def check_serialization_constructor_security(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects serialization constructors without security attributes when other constructors have them.
    
    Triggers on: ISerializable class with secured regular constructor but unsecured serialization constructor
    Excludes: Comments, tests, classes without security on any constructor
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Find classes implementing ISerializable
    class_pattern = re.compile(r'class\s+(\w+)\s*:\s*[^{]*ISerializable[^{]*\{', re.MULTILINE)
    
    for class_match in class_pattern.finditer(source):
        class_name = class_match.group(1)
        class_start = class_match.end()
        
        # Find class end
        brace_count = 1
        class_end = class_start
        for i in range(class_start, len(source)):
            if source[i] == '{':
                brace_count += 1
            elif source[i] == '}':
                brace_count -= 1
                if brace_count == 0:
                    class_end = i
                    break
        
        class_body = source[class_start:class_end]
        
        # Check for SecurityPermission on any constructor
        has_secured_constructor = bool(re.search(r'\[SecurityPermission[^\]]*\]\s*\n?\s*public\s+' + class_name + r'\s*\(', class_body))
        
        if not has_secured_constructor:
            continue  # Rule only applies if there's a secured constructor
        
        # Check for serialization constructor (takes SerializationInfo, StreamingContext)
        serialization_ctor_pattern = re.compile(
            r'(?:\[SecurityPermission[^\]]*\]\s*\n?\s*)?(protected|private|public)?\s*' + 
            class_name + r'\s*\(\s*SerializationInfo\s+\w+\s*,\s*StreamingContext\s+\w+\s*\)'
        )
        
        serialization_match = serialization_ctor_pattern.search(class_body)
        if serialization_match:
            # Check if serialization constructor has SecurityPermission
            # Look for attribute before the constructor
            ctor_pos = serialization_match.start()
            preceding_content = class_body[max(0, ctor_pos-200):ctor_pos]
            
            if not re.search(r'\[SecurityPermission[^\]]*\]\s*$', preceding_content):
                # Find line number
                line_num = source[:class_match.start() + class_start + ctor_pos].count('\n') + 1
                
                findings.append({
                    'rule_id': 'serialization_constructors_secured',
                    'message': f"Serialization constructor in '{class_name}' is not secured but other constructors have security attributes.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'node': f'Constructor.{class_name}',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': serialization_match.group(0).strip()
                })
    
    return findings


def check_serialization_event_handler_signature(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects serialization event handlers with incorrect signatures.
    Event handlers must: be private, return void, take StreamingContext parameter.
    
    Triggers on: [OnSerializing], [OnSerialized], [OnDeserializing], [OnDeserialized] with wrong signature
    Excludes: Comments, tests
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Track attribute and method
    pending_attribute = None
    pending_line = None
    
    serialization_attrs = ['OnSerializing', 'OnSerialized', 'OnDeserializing', 'OnDeserialized']
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Skip comments
        if stripped.startswith('//') or stripped.startswith('/*'):
            continue
        
        # Check for serialization attributes
        for attr in serialization_attrs:
            if f'[{attr}]' in stripped or f'[{attr}Attribute]' in stripped:
                pending_attribute = attr
                pending_line = line_num
                break
        
        # Check for method after attribute
        if pending_attribute and re.search(r'\b(public|private|protected|internal)\b.*\(', stripped):
            # Validate signature
            issues = []
            
            # Check visibility (must be private)
            if not re.search(r'\bprivate\b', stripped):
                issues.append('must be private')
            
            # Check return type (must be void)
            if not re.search(r'\bvoid\b', stripped):
                issues.append('must return void')
            
            # Check parameter (must be StreamingContext)
            if not re.search(r'\(\s*StreamingContext\s+\w+\s*\)', stripped):
                issues.append('must take StreamingContext parameter')
            
            if issues:
                findings.append({
                    'rule_id': 'serialization_event_handlers_implemented',
                    'message': f"Serialization event handler with [{pending_attribute}] has incorrect signature: {', '.join(issues)}",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'node': 'MethodDeclaration',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': stripped
                })
            
            pending_attribute = None
            pending_line = None
    
    return findings


def check_ssl_certificate_validation_disabled(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects disabled SSL/TLS certificate validation.
    Disabling certificate validation exposes connections to MITM attacks.
    
    Triggers on: ServerCertificateValidationCallback = ... => true, always returns true
    Excludes: Comments, tests, proper validation logic (checking errors, cert properties)
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Patterns for disabled certificate validation
    vulnerable_patterns = [
        (r'ServerCertificateValidationCallback\s*=\s*\([^)]*\)\s*=>\s*true', 'Lambda always returns true'),
        (r'ServerCertificateValidationCallback\s*=\s*delegate\s*\{[^}]*return\s+true', 'Delegate always returns true'),
        (r'ServerCertificateCustomValidationCallback\s*=\s*\([^)]*\)\s*=>\s*true', 'Custom validation disabled'),
        (r'ServerCertificateCustomValidationCallback\s*=\s*HttpClientHandler\.DangerousAcceptAnyServerCertificateValidator', 'DangerousAcceptAny used'),
    ]
    
    # Exclusion patterns
    exclude_patterns = [
        r'^\s*//',           # Comments
        r'Console\.',        # Logging
        r'Logger\.',         # Logging
        r'\[Test',           # Tests
        r'\[Fact',           # xUnit
        r'SslPolicyErrors\.None',  # Proper validation
        r'\.Subject\.Contains',    # Certificate checking
        r'\.GetCertHashString',    # Thumbprint checking
        r'errors\s*==',            # Error checking
    ]
    
    for line_num, line in enumerate(lines, 1):
        # Skip exclusions
        should_exclude = False
        for exclude_pattern in exclude_patterns:
            if re.search(exclude_pattern, line, re.IGNORECASE):
                should_exclude = True
                break
        
        if should_exclude:
            continue
        
        # Check for vulnerable patterns
        for pattern, issue_type in vulnerable_patterns:
            if re.search(pattern, line, re.IGNORECASE):
                findings.append({
                    'rule_id': 'server_certificates_verified_during',
                    'message': f"SSL/TLS certificate validation is disabled: {issue_type}. This exposes connections to MITM attacks.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Critical',
                    'node': 'Assignment',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': line.strip()
                })
                break
    
    return findings


def check_ssrf_vulnerability(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects Server-Side Request Forgery (SSRF) vulnerabilities.
    User input used directly in HTTP requests can be exploited to access internal resources.
    
    Triggers on: HttpClient calls with user-controlled URLs without validation
    Excludes: Hard-coded URLs, validated URLs (allowlist, Uri checks), logging, tests
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Method parameter pattern (to identify user input)
    param_pattern = re.compile(r'(?:public|private|protected|internal)[^(]*\(([^)]*)\)')
    
    # Track method parameters (potential user input)
    method_params = set()
    current_method_start = 0
    
    for line_num, line in enumerate(lines, 1):
        # Extract method parameters
        param_match = param_pattern.search(line)
        if param_match:
            params = param_match.group(1)
            # Extract parameter names
            for param in params.split(','):
                parts = param.strip().split()
                if len(parts) >= 2:
                    method_params.add(parts[-1])
            current_method_start = line_num
    
    # Patterns for HTTP client calls with user input
    http_patterns = [
        r'GetStringAsync\s*\(\s*(\w+)\s*\)',
        r'GetAsync\s*\(\s*(\w+)\s*\)',
        r'PostAsync\s*\(\s*(\w+)',
        r'SendAsync\s*\([^)]*\s+(\w+)\s*\)',
        r'GetStringAsync\s*\(\s*\$"[^"]*\{(\w+)\}',
        r'GetAsync\s*\(\s*\$"[^"]*\{(\w+)\}',
    ]
    
    # Exclusion patterns
    exclude_patterns = [
        r'^\s*//',           # Comments
        r'Console\.',        # Logging
        r'Logger\.',         # Logging
        r'\[Test',           # Tests
        r'\[Fact',           # xUnit
        r'allowedDomains',   # Allowlist
        r'\.Contains\s*\(',  # Validation
        r'Uri\s+\w+\s*=\s*new\s+Uri',  # Uri validation
        r'TryGetValue',      # Dictionary lookup (allowlist)
    ]
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Skip exclusions
        should_exclude = False
        for exclude_pattern in exclude_patterns:
            if re.search(exclude_pattern, line, re.IGNORECASE):
                should_exclude = True
                break
        
        if should_exclude:
            continue
        
        # Check for HTTP patterns with variables
        for pattern in http_patterns:
            match = re.search(pattern, line)
            if match:
                var_name = match.group(1)
                # Check if variable is likely user input (method parameter)
                if var_name in method_params or var_name in ['url', 'uri', 'path', 'endpoint']:
                    # Check if there's validation nearby (within 10 lines before)
                    has_validation = False
                    for i in range(max(0, line_num - 11), line_num - 1):
                        check_line = lines[i] if i < len(lines) else ''
                        if any(re.search(p, check_line, re.IGNORECASE) for p in 
                               [r'allowedDomains', r'\.Contains', r'TryGetValue', r'if\s*\(']):
                            has_validation = True
                            break
                    
                    if not has_validation:
                        findings.append({
                            'rule_id': 'serverside_requests_vulnerable_forging',
                            'message': f"Potential SSRF vulnerability: user input '{var_name}' used in HTTP request without URL validation.",
                            'file': filename,
                            'line': line_num,
                            'severity': 'Critical',
                            'node': 'CallExpression.HttpClient',
                            'status': 'violation',
                            'property_path': ['source'],
                            'value': stripped
                        })
                        break
    
    return findings


def check_path_traversal_vulnerabilities(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects path traversal SSRF vulnerabilities in URL construction.
    User input in URL paths can be exploited to access unauthorized endpoints.
    
    Triggers on: URL construction with string interpolation/concatenation using user input
    Excludes: Path validation (..), Path.GetFileName, allowlists, logging, tests
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Track method parameters and variables
    param_pattern = re.compile(r'(?:public|private|protected|internal)[^(]*\(([^)]*)\)')
    method_params = set()
    
    for line in lines:
        param_match = param_pattern.search(line)
        if param_match:
            params = param_match.group(1)
            for param in params.split(','):
                parts = param.strip().split()
                if len(parts) >= 2:
                    method_params.add(parts[-1])
    
    # Patterns for URL construction with user input
    url_patterns = [
        (r'\$"[^"]*https?://[^"]*\{(\w+)\}[^"]*"', 'string interpolation'),
        (r'string\.Format\s*\(\s*"[^"]*https?://[^"]*"\s*,\s*(\w+)', 'String.Format'),
        (r'"https?://[^"]*"\s*\+\s*(\w+)', 'string concatenation'),
    ]
    
    # Exclusion patterns
    exclude_patterns = [
        r'^\s*//',           # Comments
        r'Console\.',        # Logging
        r'Logger\.',         # Logging
        r'Debug\.',          # Debug
        r'\[Test',           # Tests
        r'\[Fact',           # xUnit
        r'Path\.GetFileName',  # Sanitization
        r'Contains\s*\(\s*"\.\."',  # Traversal check
        r'TryGetValue',      # Allowlist
        r'allowedPaths',     # Allowlist
        r'allowedDocs',      # Allowlist
        r'ConfigurationManager',  # Config-based
    ]
    
    # HTTP client patterns (to confirm it's a request)
    http_client_patterns = [
        r'HttpClient',
        r'GetStringAsync',
        r'GetAsync',
        r'PostAsync',
        r'SendAsync',
        r'WebRequest',
    ]
    
    for line_num, line in enumerate(lines, 1):
        # Skip exclusions
        should_exclude = False
        for exclude_pattern in exclude_patterns:
            if re.search(exclude_pattern, line, re.IGNORECASE):
                should_exclude = True
                break
        
        if should_exclude:
            continue
        
        # Check for URL patterns with user input
        for pattern, pattern_type in url_patterns:
            match = re.search(pattern, line)
            if match:
                var_name = match.group(1)
                
                # Check if variable is user input (method param or common names)
                if var_name in method_params or var_name.lower() in ['path', 'filename', 'documentpath', 'userpath', 'segment', 'endpoint']:
                    # Check if there's path validation nearby (within 15 lines before)
                    has_validation = False
                    for i in range(max(0, line_num - 16), line_num):
                        check_line = lines[i] if i < len(lines) else ''
                        if re.search(r'Contains\s*\(\s*"\.\."', check_line) or \
                           re.search(r'Path\.GetFileName', check_line) or \
                           re.search(r'allowedPaths|allowedDocs|TryGetValue', check_line, re.IGNORECASE):
                            has_validation = True
                            break
                    
                    # Check if HTTP client is used nearby (within 5 lines)
                    has_http_client = False
                    for i in range(max(0, line_num - 3), min(len(lines), line_num + 5)):
                        check_line = lines[i] if i < len(lines) else ''
                        if any(re.search(p, check_line) for p in http_client_patterns):
                            has_http_client = True
                            break
                    
                    if not has_validation and has_http_client:
                        findings.append({
                            'rule_id': 'serverside_requests_vulnerable_traversing',
                            'message': f"Path traversal vulnerability: user input '{var_name}' used in URL construction via {pattern_type} without validation.",
                            'file': filename,
                            'line': line_num,
                            'severity': 'Critical',
                            'node': 'Assignment',
                            'status': 'violation',
                            'property_path': ['source'],
                            'value': line.strip()
                        })
                        break
    
    return findings


def check_servicecontract_operationcontract_correlation(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects [ServiceContract] classes/interfaces without any [OperationContract] methods.
    WCF services must have at least one operation defined.
    
    Triggers on: [ServiceContract] without [OperationContract] in same type
    Excludes: Comments, tests, types with at least one OperationContract
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Pattern to find ServiceContract attribute followed by class/interface
    service_contract_pattern = re.compile(
        r'\[ServiceContract[^\]]*\]\s*\n?\s*(public\s+)?(interface|class)\s+(\w+)',
        re.MULTILINE
    )
    
    for match in service_contract_pattern.finditer(source):
        type_kind = match.group(2)  # 'interface' or 'class'
        type_name = match.group(3)
        type_start = match.end()
        
        # Find type body
        brace_start = source.find('{', type_start)
        if brace_start == -1:
            continue
        
        # Find matching closing brace
        brace_count = 1
        type_end = brace_start + 1
        for i in range(brace_start + 1, len(source)):
            if source[i] == '{':
                brace_count += 1
            elif source[i] == '}':
                brace_count -= 1
                if brace_count == 0:
                    type_end = i
                    break
        
        type_body = source[brace_start:type_end]
        
        # Check for OperationContract in the type body
        if not re.search(r'\[OperationContract', type_body):
            # Calculate line number
            line_num = source[:match.start()].count('\n') + 1
            
            findings.append({
                'rule_id': 'servicecontract_operationcontract_attributes_preferred',
                'message': f"[ServiceContract] {type_kind} '{type_name}' has no [OperationContract] methods. Define at least one service operation.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'node': f'{type_kind.capitalize()}Declaration.{type_name}',
                'status': 'violation',
                'property_path': ['source'],
                'value': f'[ServiceContract] {type_kind} {type_name}'
            })
    
    return findings


def check_duplicate_conditional_branches(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for two_branches_conditional_structure rule.
    Detects when two branches in a conditional structure have exactly the same implementation.
    
    Analyzes:
    - if/else if/else chains with duplicate branches
    - switch statements with duplicate case blocks
    
    Excludes:
    - Empty branches or single-line trivial branches
    - Test files and test methods
    - Comments describing the pattern
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    # Helper to normalize code for comparison
    def normalize_code(code_block):
        """Normalize code block for comparison by removing whitespace and comments."""
        if not code_block:
            return ""
        # Remove single-line comments
        code = re.sub(r'//.*$', '', code_block, flags=re.MULTILINE)
        # Remove multi-line comments
        code = re.sub(r'/\*.*?\*/', '', code, flags=re.DOTALL)
        # Normalize whitespace
        code = re.sub(r'\s+', ' ', code).strip()
        return code
    
    # Helper to extract code block between braces
    def extract_brace_block(text, start_pos):
        """Extract the code block starting from an opening brace."""
        if start_pos >= len(text) or text[start_pos] != '{':
            return None, -1
        
        brace_count = 0
        block_start = start_pos
        
        for i in range(start_pos, len(text)):
            if text[i] == '{':
                brace_count += 1
            elif text[i] == '}':
                brace_count -= 1
                if brace_count == 0:
                    return text[block_start + 1:i], i
        return None, -1
    
    # Check for duplicate if-else branches
    # Pattern: else if (...) { ... } or else { ... }
    if_pattern = re.compile(
        r'(if|else\s+if|else)\s*(\([^)]*\))?\s*\{',
        re.MULTILINE | re.DOTALL
    )
    
    branches = []
    for match in if_pattern.finditer(source):
        branch_type = match.group(1).strip()
        condition = match.group(2) if match.group(2) else ""
        brace_start = match.end() - 1
        
        block, block_end = extract_brace_block(source, brace_start)
        if block is not None:
            line_num = source[:match.start()].count('\n') + 1
            branches.append({
                'type': branch_type,
                'condition': condition,
                'block': block,
                'normalized': normalize_code(block),
                'line': line_num,
                'end_pos': block_end
            })
    
    # Group branches by their if-chain (consecutive if/else if/else)
    if_chains = []
    current_chain = []
    
    for i, branch in enumerate(branches):
        if branch['type'] == 'if':
            if current_chain:
                if_chains.append(current_chain)
            current_chain = [branch]
        elif branch['type'] in ['else if', 'else']:
            current_chain.append(branch)
    
    if current_chain:
        if_chains.append(current_chain)
    
    # Check each chain for duplicates
    for chain in if_chains:
        if len(chain) < 2:
            continue
        
        seen_blocks = {}
        for branch in chain:
            normalized = branch['normalized']
            
            # Skip empty or trivial blocks
            if not normalized or len(normalized) < 10:
                continue
            
            if normalized in seen_blocks:
                first_branch = seen_blocks[normalized]
                findings.append({
                    'rule_id': 'two_branches_conditional_structure',
                    'message': f"Duplicate branch implementation found. This '{branch['type']}' branch has the same code as the branch at line {first_branch['line']}. Consider merging these conditions.",
                    'file': filename,
                    'line': branch['line'],
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': branch['block'][:100] + '...' if len(branch['block']) > 100 else branch['block'],
                    'node': f"ConditionalBranch.{branch['type']}",
                    'status': 'violation'
                })
            else:
                seen_blocks[normalized] = branch
    
    # Check for duplicate switch cases
    switch_pattern = re.compile(r'switch\s*\([^)]+\)\s*\{', re.MULTILINE)
    
    for switch_match in switch_pattern.finditer(source):
        switch_brace_start = switch_match.end() - 1
        switch_block, _ = extract_brace_block(source, switch_brace_start)
        
        if not switch_block:
            continue
        
        # Extract case blocks
        case_pattern = re.compile(r'case\s+[^:]+:', re.MULTILINE)
        cases = []
        
        case_matches = list(case_pattern.finditer(switch_block))
        for i, case_match in enumerate(case_matches):
            case_start = case_match.end()
            
            # Find end of this case (next case or end of switch)
            if i + 1 < len(case_matches):
                case_end = case_matches[i + 1].start()
            else:
                # Look for default or end of switch
                default_match = re.search(r'default\s*:', switch_block[case_start:])
                if default_match:
                    case_end = case_start + default_match.start()
                else:
                    case_end = len(switch_block)
            
            case_block = switch_block[case_start:case_end]
            case_line = source[:switch_match.start()].count('\n') + 1 + switch_block[:case_match.start()].count('\n')
            
            cases.append({
                'label': case_match.group().strip(),
                'block': case_block,
                'normalized': normalize_code(case_block),
                'line': case_line
            })
        
        # Check for duplicate cases
        seen_cases = {}
        for case in cases:
            normalized = case['normalized']
            
            # Skip empty or trivial cases
            if not normalized or normalized == 'break ;' or len(normalized) < 10:
                continue
            
            if normalized in seen_cases:
                first_case = seen_cases[normalized]
                findings.append({
                    'rule_id': 'two_branches_conditional_structure',
                    'message': f"Duplicate switch case implementation found. Case '{case['label']}' has the same code as '{first_case['label']}' at line {first_case['line']}. Consider combining these cases.",
                    'file': filename,
                    'line': case['line'],
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': case['block'][:100] + '...' if len(case['block']) > 100 else case['block'],
                    'node': f"SwitchCase.{case['label']}",
                    'status': 'violation'
                })
            else:
                seen_cases[normalized] = case
    
    return findings


def check_unsafe_deserialization(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for types_allowed_deserialized_restricted rule.
    Detects unsafe deserialization patterns that could lead to RCE.
    
    Detects:
    - BinaryFormatter.Deserialize (always unsafe)
    - SoapFormatter.Deserialize (always unsafe)
    - NetDataContractSerializer.Deserialize (always unsafe)
    - TypeNameHandling.All/Auto/Objects without SerializationBinder
    
    Excludes:
    - JsonConvert.DeserializeObject<T> with specific type
    - TypeNameHandling.None (default, safe)
    - When SerializationBinder is configured
    - Comments and test code
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    # Track which lines have been reported to avoid duplicates
    reported_lines = set()
    
    # Dangerous deserializer patterns
    dangerous_deserializers = [
        (r'new\s+BinaryFormatter\s*\(\s*\)', 'BinaryFormatter', 'BinaryFormatter is inherently unsafe and should not be used for deserialization'),
        (r'\.Deserialize\s*\([^)]*\)', 'Deserialize', None),  # Will check context
        (r'BinaryFormatter\s*\(\s*\)\s*\.Deserialize', 'BinaryFormatter.Deserialize', 'BinaryFormatter deserialization allows arbitrary type instantiation'),
        (r'SoapFormatter\s*\(\s*\)\s*\.Deserialize', 'SoapFormatter.Deserialize', 'SoapFormatter deserialization allows arbitrary type instantiation'),
        (r'NetDataContractSerializer\s*\(\s*\)\s*\.Deserialize', 'NetDataContractSerializer.Deserialize', 'NetDataContractSerializer allows arbitrary type instantiation'),
    ]
    
    # Check for BinaryFormatter, SoapFormatter, NetDataContractSerializer usage
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Check for dangerous deserializers
        for pattern, name, message in dangerous_deserializers:
            if re.search(pattern, line, re.IGNORECASE):
                # Skip if it's just a type reference in generic parameter
                if re.search(r'DeserializeObject<\w+>', line):
                    continue
                
                # Check if this is actually a dangerous call
                is_dangerous = False
                
                if 'BinaryFormatter' in line and '.Deserialize' in line:
                    is_dangerous = True
                    message = 'BinaryFormatter.Deserialize allows arbitrary type instantiation leading to RCE'
                elif 'SoapFormatter' in line and '.Deserialize' in line:
                    is_dangerous = True
                    message = 'SoapFormatter.Deserialize allows arbitrary type instantiation leading to RCE'
                elif 'NetDataContractSerializer' in line and '.Deserialize' in line:
                    is_dangerous = True
                    message = 'NetDataContractSerializer.Deserialize allows arbitrary type instantiation leading to RCE'
                elif 'new BinaryFormatter()' in line or 'new BinaryFormatter ()' in line:
                    is_dangerous = True
                    message = 'BinaryFormatter is obsolete and unsafe. Use a safer serializer.'
                elif 'new SoapFormatter()' in line or 'new SoapFormatter ()' in line:
                    is_dangerous = True
                    message = 'SoapFormatter is obsolete and unsafe. Use a safer serializer.'
                elif 'new NetDataContractSerializer()' in line:
                    is_dangerous = True
                    message = 'NetDataContractSerializer is unsafe without type restrictions.'
                
                if is_dangerous and line_num not in reported_lines:
                    reported_lines.add(line_num)
                    findings.append({
                        'rule_id': 'types_allowed_deserialized_restricted',
                        'message': message,
                        'file': filename,
                        'line': line_num,
                        'severity': 'Critical',
                        'property_path': ['source'],
                        'value': line_clean,
                        'node': f'CallExpression.{name}',
                        'status': 'violation'
                    })
                    break
    
    # Check for TypeNameHandling settings
    # Look for JsonSerializerSettings blocks
    settings_pattern = re.compile(
        r'(TypeNameHandling\s*=\s*TypeNameHandling\.(All|Auto|Objects|Arrays))',
        re.MULTILINE
    )
    
    for match in settings_pattern.finditer(source):
        line_num = source[:match.start()].count('\n') + 1
        
        if line_num in reported_lines:
            continue
        
        # Check if SerializationBinder is set in the same settings block
        # Look for SerializationBinder within ~10 lines before/after
        context_start = max(0, source.rfind('\n', 0, match.start() - 200))
        context_end = min(len(source), source.find(';', match.end()) + 100)
        context = source[context_start:context_end]
        
        # Check if there's a SerializationBinder
        has_binder = bool(re.search(r'SerializationBinder\s*=', context))
        
        # Check if line is a comment
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        type_handling = match.group(2)
        
        if not has_binder:
            reported_lines.add(line_num)
            findings.append({
                'rule_id': 'types_allowed_deserialized_restricted',
                'message': f'TypeNameHandling.{type_handling} allows arbitrary type instantiation. Use SerializationBinder to restrict allowed types or use TypeNameHandling.None.',
                'file': filename,
                'line': line_num,
                'severity': 'Critical',
                'property_path': ['source'],
                'value': match.group(0),
                'node': f'Assignment.TypeNameHandling.{type_handling}',
                'status': 'violation'
            })
    
    return findings


def check_too_many_generic_parameters(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for types_methods_avoid_having rule.
    Detects types and methods with too many generic type parameters.
    
    Default threshold: 2 (more than 2 generic parameters triggers a violation)
    
    Detects:
    - Classes/structs/interfaces with > 2 type parameters
    - Methods with > 2 type parameters
    
    Excludes:
    - Comments describing generic patterns
    - Test files
    - Standard library types in usage (Dictionary<K,V>, etc.)
    """
    findings = []
    threshold = 2  # Default threshold from SonarSource rule
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    reported_lines = set()
    
    # Pattern to match type declarations with generic parameters
    # Matches: class Name<T1, T2, ...>, interface Name<T1, T2, ...>, struct Name<T1, T2, ...>
    type_pattern = re.compile(
        r'\b(class|interface|struct)\s+(\w+)\s*<([^>]+)>',
        re.MULTILINE
    )
    
    for match in type_pattern.finditer(source):
        line_num = source[:match.start()].count('\n') + 1
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        type_kind = match.group(1)
        type_name = match.group(2)
        params_str = match.group(3)
        
        # Count type parameters (split by comma, handle constraints)
        params = [p.strip() for p in params_str.split(',')]
        param_count = len(params)
        
        if param_count > threshold and line_num not in reported_lines:
            reported_lines.add(line_num)
            findings.append({
                'rule_id': 'types_methods_avoid_having',
                'message': f"{type_kind.capitalize()} '{type_name}' has {param_count} generic parameters. Consider reducing to {threshold} or fewer for better readability.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': f'{type_kind} {type_name}<{params_str}>',
                'node': f'{type_kind.capitalize()}Declaration.{type_name}',
                'status': 'violation'
            })
    
    # Pattern to match method declarations with generic parameters
    # Matches: void MethodName<T1, T2, ...>( or TResult MethodName<T1, T2, ...>(
    method_pattern = re.compile(
        r'\b(?:public|private|protected|internal|static|virtual|override|abstract|\s)+\s+\w+(?:<[^>]+>)?\s+(\w+)\s*<([^>]+)>\s*\(',
        re.MULTILINE
    )
    
    for match in method_pattern.finditer(source):
        line_num = source[:match.start()].count('\n') + 1
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        if line_num in reported_lines:
            continue
        
        method_name = match.group(1)
        params_str = match.group(2)
        
        # Count type parameters
        params = [p.strip() for p in params_str.split(',')]
        param_count = len(params)
        
        if param_count > threshold:
            reported_lines.add(line_num)
            findings.append({
                'rule_id': 'types_methods_avoid_having',
                'message': f"Method '{method_name}' has {param_count} generic parameters. Consider reducing to {threshold} or fewer for better readability.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': f'{method_name}<{params_str}>',
                'node': f'MethodDeclaration.{method_name}',
                'status': 'violation'
            })
    
    return findings


def check_member_visibility_mismatch(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for types_avoid_having_members rule.
    Detects when a type has members with visibility higher than the type itself.
    
    Visibility hierarchy (from most to least restrictive):
    - private < internal < protected internal < protected < public
    
    For non-public types, public/protected members don't make sense.
    
    Excludes:
    - Interface members (implicitly public in interface context)
    - Test files
    - Comments
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    reported_lines = set()
    
    # Helper to get visibility level (higher number = more visible)
    def get_visibility_level(modifiers):
        if 'public' in modifiers:
            return 5
        if 'protected internal' in modifiers or 'internal protected' in modifiers:
            return 4
        if 'protected' in modifiers:
            return 3
        if 'internal' in modifiers:
            return 2
        if 'private' in modifiers:
            return 1
        return 2  # Default in C# is internal for top-level, private for nested
    
    # Helper to extract type body with its visibility
    def find_type_blocks(src):
        """Find all type declarations with their bodies and visibility."""
        type_pattern = re.compile(
            r'\b(public|internal|private|protected)?\s*(public|internal|private|protected)?\s*'
            r'(partial\s+)?(abstract\s+)?(sealed\s+)?(static\s+)?'
            r'(class|struct|record)\s+(\w+)',
            re.MULTILINE
        )
        
        type_blocks = []
        
        for match in type_pattern.finditer(src):
            # Get visibility from first few groups
            modifiers = ' '.join(filter(None, [match.group(1), match.group(2)]))
            if not modifiers:
                modifiers = 'internal'  # Default for top-level types
            
            type_kind = match.group(7)
            type_name = match.group(8)
            start_line = src[:match.start()].count('\n') + 1
            
            # Find the opening brace
            brace_pos = src.find('{', match.end())
            if brace_pos == -1:
                continue
            
            # Find matching closing brace
            brace_count = 1
            end_pos = brace_pos + 1
            while end_pos < len(src) and brace_count > 0:
                if src[end_pos] == '{':
                    brace_count += 1
                elif src[end_pos] == '}':
                    brace_count -= 1
                end_pos += 1
            
            body = src[brace_pos + 1:end_pos - 1]
            
            type_blocks.append({
                'modifiers': modifiers,
                'visibility': get_visibility_level(modifiers),
                'type_kind': type_kind,
                'type_name': type_name,
                'body': body,
                'start_line': start_line,
                'body_start': brace_pos + 1
            })
        
        return type_blocks
    
    type_blocks = find_type_blocks(source)
    
    # Member patterns
    member_patterns = [
        # Method declarations
        (r'\b(public|protected\s+internal|internal\s+protected|protected|internal|private)\s+.*?\s+(\w+)\s*\([^)]*\)\s*(?:\{|;|=>)', 'method'),
        # Property declarations
        (r'\b(public|protected\s+internal|internal\s+protected|protected|internal|private)\s+.*?\s+(\w+)\s*\{[^}]*(?:get|set)', 'property'),
        # Field declarations
        (r'\b(public|protected\s+internal|internal\s+protected|protected|internal|private)\s+(?:static\s+|readonly\s+|const\s+)*\w+\s+(\w+)\s*[;=]', 'field'),
    ]
    
    for type_block in type_blocks:
        type_visibility = type_block['visibility']
        type_modifiers = type_block['modifiers']
        
        # Skip public types - they can have any member visibility
        if type_visibility >= 5:
            continue
        
        body = type_block['body']
        body_start_pos = type_block['body_start']
        
        for pattern, member_kind in member_patterns:
            for match in re.finditer(pattern, body, re.MULTILINE):
                member_modifiers = match.group(1)
                member_name = match.group(2)
                member_visibility = get_visibility_level(member_modifiers)
                
                # Check if member visibility exceeds type visibility
                if member_visibility > type_visibility:
                    line_num = type_block['start_line'] + body[:match.start()].count('\n')
                    
                    # Skip if in comment
                    line_text = lines[line_num - 1] if line_num <= len(lines) else ''
                    if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
                        continue
                    
                    if line_num not in reported_lines:
                        reported_lines.add(line_num)
                        findings.append({
                            'rule_id': 'types_avoid_having_members',
                            'message': f"{member_modifiers.capitalize()} {member_kind} '{member_name}' in {type_modifiers} {type_block['type_kind']} '{type_block['type_name']}'. Member visibility ({member_modifiers}) is broader than type visibility ({type_modifiers}).",
                            'file': filename,
                            'line': line_num,
                            'severity': 'Major',
                            'property_path': ['source'],
                            'value': match.group(0)[:80],
                            'node': f"{member_kind.capitalize()}Declaration.{member_name}",
                            'status': 'violation'
                        })
    
    return findings


def check_types_outside_namespace(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for types_defined_named_namespaces rule.
    Detects types declared outside of any named namespace (in global namespace).
    
    Detects:
    - Classes, structs, interfaces, enums, records, delegates outside namespaces
    
    Excludes:
    - Types inside namespace { } blocks
    - Nested types inside other types
    - Comments and test code
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    reported_lines = set()
    
    # Find all namespace blocks with their ranges
    namespace_ranges = []
    namespace_pattern = re.compile(r'\bnamespace\s+([\w.]+)\s*\{', re.MULTILINE)
    
    for match in namespace_pattern.finditer(source):
        brace_start = match.end() - 1
        brace_count = 1
        end_pos = brace_start + 1
        
        while end_pos < len(source) and brace_count > 0:
            if source[end_pos] == '{':
                brace_count += 1
            elif source[end_pos] == '}':
                brace_count -= 1
            end_pos += 1
        
        namespace_ranges.append((brace_start, end_pos))
    
    # Also handle file-scoped namespaces: namespace X.Y;
    file_scoped_ns_pattern = re.compile(r'\bnamespace\s+([\w.]+)\s*;', re.MULTILINE)
    file_scoped_ns = file_scoped_ns_pattern.search(source)
    
    if file_scoped_ns:
        # File-scoped namespace covers everything after the declaration
        ns_end = file_scoped_ns.end()
        namespace_ranges.append((ns_end, len(source)))
    
    def is_inside_namespace(pos):
        """Check if position is inside any namespace block."""
        for start, end in namespace_ranges:
            if start < pos < end:
                return True
        return False
    
    def is_inside_type(pos, type_matches):
        """Check if position is inside another type (nested type)."""
        for tm in type_matches:
            if tm['body_start'] < pos < tm['body_end']:
                return True
        return False
    
    # Find all type declarations
    type_pattern = re.compile(
        r'\b(public|internal|private|protected)?\s*'
        r'(partial\s+)?(abstract\s+)?(sealed\s+)?(static\s+)?'
        r'(class|struct|interface|enum|record)\s+(\w+)',
        re.MULTILINE
    )
    
    type_matches = []
    
    for match in type_pattern.finditer(source):
        type_pos = match.start()
        line_num = source[:type_pos].count('\n') + 1
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        # Find body range for this type
        brace_pos = source.find('{', match.end())
        if brace_pos != -1:
            brace_count = 1
            end_pos = brace_pos + 1
            while end_pos < len(source) and brace_count > 0:
                if source[end_pos] == '{':
                    brace_count += 1
                elif source[end_pos] == '}':
                    brace_count -= 1
                end_pos += 1
            type_matches.append({
                'match': match,
                'body_start': brace_pos,
                'body_end': end_pos,
                'line_num': line_num
            })
        else:
            # Record types or other single-line declarations
            type_matches.append({
                'match': match,
                'body_start': match.end(),
                'body_end': source.find(';', match.end()) + 1 if source.find(';', match.end()) != -1 else match.end(),
                'line_num': line_num
            })
    
    # Check each type declaration
    for tm in type_matches:
        match = tm['match']
        type_pos = match.start()
        line_num = tm['line_num']
        
        type_kind = match.group(6)
        type_name = match.group(7)
        
        # Skip if inside a namespace
        if is_inside_namespace(type_pos):
            continue
        
        # Skip if it's a nested type (inside another type)
        if is_inside_type(type_pos, [t for t in type_matches if t != tm]):
            continue
        
        if line_num not in reported_lines:
            reported_lines.add(line_num)
            findings.append({
                'rule_id': 'types_defined_named_namespaces',
                'message': f"{type_kind.capitalize()} '{type_name}' is defined in the global namespace. Types should be defined in named namespaces to prevent name collisions.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': match.group(0),
                'node': f'{type_kind.capitalize()}Declaration.{type_name}',
                'status': 'violation'
            })
    
    # Check for delegates outside namespaces
    delegate_pattern = re.compile(
        r'\b(public|internal|private|protected)?\s*delegate\s+\w+\s+(\w+)\s*\(',
        re.MULTILINE
    )
    
    for match in delegate_pattern.finditer(source):
        delegate_pos = match.start()
        line_num = source[:delegate_pos].count('\n') + 1
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        # Skip if inside namespace
        if is_inside_namespace(delegate_pos):
            continue
        
        # Skip if inside a type
        if is_inside_type(delegate_pos, type_matches):
            continue
        
        delegate_name = match.group(2)
        
        if line_num not in reported_lines:
            reported_lines.add(line_num)
            findings.append({
                'rule_id': 'types_defined_named_namespaces',
                'message': f"Delegate '{delegate_name}' is defined in the global namespace. Types should be defined in named namespaces to prevent name collisions.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': match.group(0),
                'node': f'DelegateDeclaration.{delegate_name}',
                'status': 'violation'
            })
    
    return findings


def check_type_pascalcase_naming(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for types_named_pascalcase rule.
    Detects type names that don't follow PascalCase convention.
    
    PascalCase rules:
    - First letter must be uppercase
    - No underscores (except in test classes)
    - Two consecutive uppercase letters are allowed unless they form the full name
    
    Exceptions:
    - Types with [ComImport] or [InterfaceType] attributes
    - Test classes (can use underscores)
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    reported_lines = set()
    
    def is_valid_pascalcase(name, is_interface=False):
        """Check if a name follows PascalCase convention."""
        if not name or len(name) == 0:
            return False
        
        # For interfaces, must start with I followed by uppercase
        if is_interface:
            if not name.startswith('I') or len(name) < 2:
                return False
            if not name[1].isupper():
                return False
            # Check the rest without the I prefix
            name_to_check = name[1:]
        else:
            name_to_check = name
        
        # Must start with uppercase
        if not name_to_check[0].isupper():
            return False
        
        # Check for underscores
        if '_' in name:
            return False
        
        # Check for all uppercase (more than 2 chars)
        if len(name_to_check) > 2 and name_to_check.isupper():
            return False
        
        # Check for lowercase-only names
        if name_to_check.islower():
            return False
        
        return True
    
    # Type pattern to match class, struct, interface, enum, record declarations
    type_pattern = re.compile(
        r'\b(?:public|internal|private|protected)?\s*'
        r'(?:partial\s+)?(?:abstract\s+)?(?:sealed\s+)?(?:static\s+)?'
        r'(class|struct|interface|enum|record)\s+(\w+)',
        re.MULTILINE
    )
    
    for match in type_pattern.finditer(source):
        type_pos = match.start()
        line_num = source[:type_pos].count('\n') + 1
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        # Check for [ComImport] or [InterfaceType] attributes
        # Look at preceding lines for attributes
        attr_check_start = max(0, type_pos - 200)
        preceding_text = source[attr_check_start:type_pos]
        if '[ComImport]' in preceding_text or '[InterfaceType]' in preceding_text:
            continue
        
        type_kind = match.group(1)
        type_name = match.group(2)
        
        is_interface = type_kind == 'interface'
        
        if not is_valid_pascalcase(type_name, is_interface):
            if line_num not in reported_lines:
                reported_lines.add(line_num)
                
                # Determine the specific violation
                if is_interface and not type_name.startswith('I'):
                    reason = "Interface names should start with 'I' followed by PascalCase"
                elif '_' in type_name:
                    reason = "Type names should not contain underscores (use PascalCase)"
                elif type_name[0].islower():
                    reason = "Type names should start with an uppercase letter"
                elif len(type_name) > 2 and type_name.isupper():
                    reason = "Type names should be PascalCase, not ALL CAPS"
                else:
                    reason = "Type names should follow PascalCase convention"
                
                findings.append({
                    'rule_id': 'types_named_pascalcase',
                    'message': f"{type_kind.capitalize()} '{type_name}' is not named in PascalCase. {reason}.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': f'{type_kind} {type_name}',
                    'node': f'{type_kind.capitalize()}Declaration.{type_name}',
                    'status': 'violation'
                })
    
    return findings


def check_outdated_base_types(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for types_extend_outdated_base rule.
    Detects classes that extend obsolete .NET base types.
    
    Outdated base types:
    - ApplicationException -> use Exception instead
    - CollectionBase -> use Collection<T>
    - DictionaryBase -> use Dictionary<K,V>
    - ReadOnlyCollectionBase -> use ReadOnlyCollection<T>
    - XmlDocument (when extended for XML views)
    
    Excludes:
    - Comments and test code
    - Custom types with similar names
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    reported_lines = set()
    
    # Outdated base types and their modern replacements
    outdated_bases = {
        'ApplicationException': ('Exception', 'ApplicationException is obsolete since .NET 2.0. Use Exception or a more specific exception type.'),
        'System.ApplicationException': ('Exception', 'ApplicationException is obsolete since .NET 2.0. Use Exception or a more specific exception type.'),
        'CollectionBase': ('Collection<T>', 'CollectionBase is non-generic and obsolete. Use System.Collections.ObjectModel.Collection<T> instead.'),
        'System.Collections.CollectionBase': ('Collection<T>', 'CollectionBase is non-generic and obsolete. Use System.Collections.ObjectModel.Collection<T> instead.'),
        'DictionaryBase': ('Dictionary<TKey, TValue>', 'DictionaryBase is non-generic and obsolete. Use System.Collections.Generic.Dictionary<TKey, TValue> instead.'),
        'System.Collections.DictionaryBase': ('Dictionary<TKey, TValue>', 'DictionaryBase is non-generic and obsolete. Use System.Collections.Generic.Dictionary<TKey, TValue> instead.'),
        'ReadOnlyCollectionBase': ('ReadOnlyCollection<T>', 'ReadOnlyCollectionBase is non-generic and obsolete. Use System.Collections.ObjectModel.ReadOnlyCollection<T> instead.'),
        'System.Collections.ReadOnlyCollectionBase': ('ReadOnlyCollection<T>', 'ReadOnlyCollectionBase is non-generic and obsolete. Use System.Collections.ObjectModel.ReadOnlyCollection<T> instead.'),
        'XmlDocument': ('XDocument or XmlReader', 'Extending XmlDocument for creating XML views is not recommended. Consider using XDocument or XmlReader.'),
        'System.Xml.XmlDocument': ('XDocument or XmlReader', 'Extending XmlDocument for creating XML views is not recommended. Consider using XDocument or XmlReader.'),
    }
    
    # Pattern to match class declarations with inheritance
    class_pattern = re.compile(
        r'\b(?:public|internal|private|protected)?\s*'
        r'(?:partial\s+)?(?:abstract\s+)?(?:sealed\s+)?'
        r'class\s+(\w+)\s*:\s*([^{]+)',
        re.MULTILINE
    )
    
    for match in class_pattern.finditer(source):
        type_pos = match.start()
        line_num = source[:type_pos].count('\n') + 1
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        class_name = match.group(1)
        inheritance_part = match.group(2).strip()
        
        # Remove trailing comments from inheritance part
        inheritance_part = re.sub(r'//.*$', '', inheritance_part).strip()
        
        # Parse the inheritance list (base class and interfaces)
        # The base class is typically the first item before any comma or interface
        base_candidates = [b.strip() for b in inheritance_part.split(',')]
        
        for base_candidate in base_candidates:
            # Remove generic parameters for matching
            base_name = re.sub(r'<[^>]+>', '', base_candidate).strip()
            # Remove any remaining whitespace or newlines
            base_name = base_name.split()[0] if base_name.split() else ''
            
            # Check against outdated bases
            for outdated_base, (replacement, message) in outdated_bases.items():
                if base_name == outdated_base:
                    if line_num not in reported_lines:
                        reported_lines.add(line_num)
                        findings.append({
                            'rule_id': 'types_extend_outdated_base',
                            'message': f"Class '{class_name}' extends outdated base type '{base_name}'. {message}",
                            'file': filename,
                            'line': line_num,
                            'severity': 'Major',
                            'property_path': ['source'],
                            'value': f'class {class_name} : {base_name}',
                            'node': f'ClassDeclaration.{class_name}',
                            'status': 'violation'
                        })
                        break
    
    return findings


def check_recursive_type_inheritance(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for type_inheritance_recursive rule.
    Detects recursive type inheritance patterns (CRTP - Curiously Recurring Template Pattern).
    
    Detects patterns like:
    - class Node<T> where T : Node<T>
    - interface INode<T> where T : INode<T>
    
    These patterns can be confusing and should be avoided when simpler alternatives exist.
    
    Excludes:
    - Implementing standard interfaces like IComparable<T>, IEquatable<T>
    - Comments and test code
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    reported_lines = set()
    
    # Pattern to match type declarations with generic parameters and where constraints
    # Matches: class/interface/struct Name<T> where T : Name<T>
    recursive_pattern = re.compile(
        r'\b(class|interface|struct)\s+(\w+)\s*<([^>]+)>\s*'
        r'(?::\s*[^{]+?)?\s*'
        r'where\s+(\w+)\s*:\s*(\w+)\s*<\s*\4\s*>',
        re.MULTILINE | re.DOTALL
    )
    
    for match in recursive_pattern.finditer(source):
        type_pos = match.start()
        line_num = source[:type_pos].count('\n') + 1
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        type_kind = match.group(1)
        type_name = match.group(2)
        type_params = match.group(3)
        constrained_param = match.group(4)
        constraint_type = match.group(5)
        
        # Check if the constraint type is the declaring type itself
        if constraint_type == type_name:
            if line_num not in reported_lines:
                reported_lines.add(line_num)
                findings.append({
                    'rule_id': 'type_inheritance_recursive',
                    'message': f"{type_kind.capitalize()} '{type_name}' has a recursive type constraint 'where {constrained_param} : {constraint_type}<{constrained_param}>'. This pattern (CRTP) can be confusing. Consider using a non-recursive design.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': f'{type_kind} {type_name}<{type_params}> where {constrained_param} : {constraint_type}<{constrained_param}>',
                    'node': f'{type_kind.capitalize()}Declaration.{type_name}',
                    'status': 'violation'
                })
    
    # Also check for simpler recursive patterns without backreference
    # Pattern: class Name<T> ... where T : Name<T>
    simple_recursive_pattern = re.compile(
        r'\b(class|interface|struct)\s+(\w+)\s*<\s*(\w+)(?:\s*,\s*\w+)*\s*>\s*'
        r'[^{]*?'
        r'where\s+\3\s*:\s*\2\s*<',
        re.MULTILINE | re.DOTALL
    )
    
    for match in simple_recursive_pattern.finditer(source):
        type_pos = match.start()
        line_num = source[:type_pos].count('\n') + 1
        
        if line_num in reported_lines:
            continue
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        type_kind = match.group(1)
        type_name = match.group(2)
        type_param = match.group(3)
        
        reported_lines.add(line_num)
        findings.append({
            'rule_id': 'type_inheritance_recursive',
            'message': f"{type_kind.capitalize()} '{type_name}' has a recursive type constraint on '{type_param}'. This pattern (CRTP) can be confusing. Consider using a non-recursive design.",
            'file': filename,
            'line': line_num,
            'severity': 'Major',
            'property_path': ['source'],
            'value': f'{type_kind} {type_name}<{type_param}> where {type_param} : {type_name}<...>',
            'node': f'{type_kind.capitalize()}Declaration.{type_name}',
            'status': 'violation'
        })
    
    return findings


def check_type_names_match_namespaces(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for type_names_match_namespaces rule.
    Detects public type names that match well-known .NET Framework namespace names.
    
    This causes confusion and makes the library harder to use because developers
    may accidentally reference the wrong type or have to use fully qualified names.
    
    Excludes:
    - Private/internal types (less visible)
    - Comments and test code
    - Types with prefixes/suffixes that differentiate them
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    reported_lines = set()
    
    # Well-known .NET namespace names (case-insensitive)
    # These are common namespaces that should not be used as type names
    dotnet_namespaces = {
        'text', 'io', 'net', 'xml', 'data', 'drawing', 'media',
        'collections', 'threading', 'reflection', 'security',
        'diagnostics', 'configuration', 'resources', 'runtime',
        'componentmodel', 'web', 'windows', 'forms', 'linq',
        'tasks', 'serialization', 'globalization', 'interop',
        'numerics', 'management', 'messaging', 'servicemodel',
        'codedom', 'deployment', 'design', 'printing'
    }
    
    # Pattern to match public type declarations
    type_pattern = re.compile(
        r'\bpublic\s+'
        r'(?:partial\s+)?(?:abstract\s+)?(?:sealed\s+)?(?:static\s+)?'
        r'(class|struct|interface)\s+(\w+)',
        re.MULTILINE
    )
    
    for match in type_pattern.finditer(source):
        type_pos = match.start()
        line_num = source[:type_pos].count('\n') + 1
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        type_kind = match.group(1)
        type_name = match.group(2)
        
        # Check if type name matches a .NET namespace (case-insensitive)
        if type_name.lower() in dotnet_namespaces:
            if line_num not in reported_lines:
                reported_lines.add(line_num)
                findings.append({
                    'rule_id': 'type_names_match_namespaces',
                    'message': f"Public {type_kind} '{type_name}' has a name that matches a .NET namespace (System.{type_name}). This can cause confusion and name collisions. Consider using a more specific name.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': f'public {type_kind} {type_name}',
                    'node': f'{type_kind.capitalize()}Declaration.{type_name}',
                    'status': 'violation'
                })
    
    return findings


def check_type_examination_on_system_type(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for type_examined_systemtype_instances rule.
    Detects GetType() calls on System.Type variables and IsInstanceOfType() with Type arguments.
    
    These patterns produce predictable/useless results:
    - type.GetType() always returns System.RuntimeType
    - typeof(X).IsInstanceOfType(type) always returns false when type is a Type
    
    Excludes:
    - typeof(Type).GetType() - documented way to get RuntimeType instance
    - GetType() on regular objects (not Type variables)
    - IsInstanceOfType() with object arguments
    - Comments and test code
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip test files
    if '[Test]' in source or '[Fact]' in source or '[TestMethod]' in source:
        return findings
    
    reported_lines = set()
    
    # Track Type variables from method parameters and local declarations
    type_variables = set()
    
    # Find method parameters of type Type
    param_pattern = re.compile(r'\(\s*Type\s+(\w+)', re.MULTILINE)
    for match in param_pattern.finditer(source):
        type_variables.add(match.group(1))
    
    # Find local variables of type Type
    local_type_pattern = re.compile(r'Type\s+(\w+)\s*=', re.MULTILINE)
    for match in local_type_pattern.finditer(source):
        type_variables.add(match.group(1))
    
    # Pattern 1: GetType() called on a Type variable
    # e.g., type.GetType() or myType.GetType()
    for type_var in type_variables:
        gettype_pattern = re.compile(
            rf'\b{re.escape(type_var)}\.GetType\s*\(\s*\)',
            re.MULTILINE
        )
        
        for match in gettype_pattern.finditer(source):
            call_pos = match.start()
            line_num = source[:call_pos].count('\n') + 1
            
            # Skip comments
            line_text = lines[line_num - 1] if line_num <= len(lines) else ''
            if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
                continue
            
            # Skip the exception: typeof(Type).GetType()
            if 'typeof(Type)' in line_text:
                continue
            
            if line_num not in reported_lines:
                reported_lines.add(line_num)
                findings.append({
                    'rule_id': 'type_examined_systemtype_instances',
                    'message': f"Calling GetType() on Type variable '{type_var}' always returns System.RuntimeType. Use direct comparison instead: '{type_var} == typeof(SomeType)'.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': match.group(0),
                    'node': f'CallExpression.{type_var}.GetType',
                    'status': 'violation'
                })
    
    # Pattern 2: IsInstanceOfType() called with a Type variable argument
    # e.g., typeof(string).IsInstanceOfType(type)
    for type_var in type_variables:
        isinstanceof_pattern = re.compile(
            rf'typeof\s*\([^)]+\)\s*\.IsInstanceOfType\s*\(\s*{re.escape(type_var)}\s*\)',
            re.MULTILINE
        )
        
        for match in isinstanceof_pattern.finditer(source):
            call_pos = match.start()
            line_num = source[:call_pos].count('\n') + 1
            
            # Skip comments
            line_text = lines[line_num - 1] if line_num <= len(lines) else ''
            if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
                continue
            
            if line_num not in reported_lines:
                reported_lines.add(line_num)
                findings.append({
                    'rule_id': 'type_examined_systemtype_instances',
                    'message': f"IsInstanceOfType() with Type argument '{type_var}' always returns false. Use IsAssignableFrom() for type comparisons: 'typeof(X).IsAssignableFrom({type_var})'.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': match.group(0),
                    'node': f'CallExpression.IsInstanceOfType.{type_var}',
                    'status': 'violation'
                })
    
    # Pattern 3: Generic .GetType() on explicit Type cast or assignment
    # e.g., ((Type)x).GetType() or Type t = x; t.GetType();
    general_type_gettype = re.compile(
        r'\(\s*Type\s*\)\s*\w+\.GetType\s*\(\s*\)',
        re.MULTILINE
    )
    
    for match in general_type_gettype.finditer(source):
        call_pos = match.start()
        line_num = source[:call_pos].count('\n') + 1
        
        if line_num in reported_lines:
            continue
        
        # Skip comments
        line_text = lines[line_num - 1] if line_num <= len(lines) else ''
        if line_text.strip().startswith('//') or line_text.strip().startswith('/*'):
            continue
        
        reported_lines.add(line_num)
        findings.append({
            'rule_id': 'type_examined_systemtype_instances',
            'message': "Calling GetType() on a Type instance always returns System.RuntimeType. Use direct comparison instead.",
            'file': filename,
            'line': line_num,
            'severity': 'Major',
            'property_path': ['source'],
            'value': match.group(0),
            'node': 'CallExpression.Type.GetType',
            'status': 'violation'
        })
    
    return findings


def check_unassigned_members(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for unassigned_members_removed rule.
    Detects private fields and auto-properties that are never assigned a value.
    
    This function checks for:
    1. Private fields without initializers
    2. Private auto-properties without initializers
    3. Members not assigned in constructors or methods
    
    Exclusions:
    - Fields with dependency injection attributes ([Inject], [SerializeField], etc.)
    - Public/protected members (can be assigned externally)
    - Fields assigned anywhere in the class
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # DI and serialization attributes to exclude
    di_attributes = [
        'Inject', 'SerializeField', 'AutoWired', 'FromServices', 
        'Dependency', 'Import', 'Autowired', 'Required'
    ]
    
    # Track class boundaries
    classes = []
    brace_depth = 0
    current_class_start = None
    current_class_name = None
    
    for i, line in enumerate(lines):
        # Track class declarations
        class_match = re.search(r'\b(?:public|private|internal|protected)?\s*class\s+(\w+)', line)
        if class_match and '{' in line:
            current_class_name = class_match.group(1)
            current_class_start = i
        
        brace_depth += line.count('{') - line.count('}')
    
    # Find private fields without initializers
    # Pattern: private Type fieldName; (no = sign before ;)
    private_field_pattern = r'^\s*(private)\s+(\w+(?:<[^>]+>)?)\s+(\w+)\s*;'
    
    for i, line in enumerate(lines):
        line_num = i + 1
        line_clean = line.strip()
        
        # Skip comments
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Check for DI attributes on previous line(s)
        has_di_attribute = False
        for j in range(max(0, i - 3), i):
            prev_line = lines[j].strip()
            for attr in di_attributes:
                if f'[{attr}' in prev_line:
                    has_di_attribute = True
                    break
            if has_di_attribute:
                break
        
        if has_di_attribute:
            continue
        
        # Check for private field without initializer
        field_match = re.match(private_field_pattern, line)
        if field_match:
            visibility = field_match.group(1)
            field_type = field_match.group(2)
            field_name = field_match.group(3)
            
            # Check if this field is assigned anywhere in the file
            # Look for: fieldName = or this.fieldName =
            assignment_pattern = rf'\b{re.escape(field_name)}\s*='
            is_assigned = False
            
            for check_line in lines:
                if re.search(assignment_pattern, check_line):
                    is_assigned = True
                    break
            
            if not is_assigned:
                findings.append({
                    'rule_id': 'unassigned_members_removed',
                    'message': f"Private field '{field_name}' is never assigned and will always hold the default value. Remove it or initialize it.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': f'FieldDeclaration.{field_name}',
                    'status': 'violation'
                })
    
    # Find private auto-properties without initializers
    # Pattern: private Type PropertyName { get; set; } (no = before ;)
    auto_prop_pattern = r'^\s*(private)\s+(\w+(?:<[^>]+>)?)\s+(\w+)\s*\{\s*get\s*;\s*set\s*;\s*\}'
    
    for i, line in enumerate(lines):
        line_num = i + 1
        line_clean = line.strip()
        
        # Skip comments
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Check for DI attributes
        has_di_attribute = False
        for j in range(max(0, i - 3), i):
            prev_line = lines[j].strip()
            for attr in di_attributes:
                if f'[{attr}' in prev_line:
                    has_di_attribute = True
                    break
            if has_di_attribute:
                break
        
        if has_di_attribute:
            continue
        
        # Check for private auto-property without initializer
        prop_match = re.match(auto_prop_pattern, line)
        if prop_match:
            visibility = prop_match.group(1)
            prop_type = prop_match.group(2)
            prop_name = prop_match.group(3)
            
            # Check if this property is assigned anywhere
            assignment_pattern = rf'\b{re.escape(prop_name)}\s*='
            is_assigned = False
            
            for check_line in lines:
                if re.search(assignment_pattern, check_line):
                    is_assigned = True
                    break
            
            if not is_assigned:
                findings.append({
                    'rule_id': 'unassigned_members_removed',
                    'message': f"Private auto-property '{prop_name}' is never assigned and will always hold the default value. Remove it or initialize it.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': f'PropertyDeclaration.{prop_name}',
                    'status': 'violation'
                })
    
    return findings


def check_unchanged_variables_const(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for unchanged_variables_marked_as rule.
    Detects local variables that are assigned once and never modified, 
    which should be marked as const.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Const-compatible types
    const_types = ['int', 'string', 'double', 'float', 'long', 'short', 'byte', 
                   'bool', 'char', 'decimal', 'uint', 'ulong', 'ushort', 'sbyte']
    
    # Pattern for local variable declarations with literal values
    var_decl_pattern = r'^\s*(var|int|string|double|float|long|short|byte|bool|char|decimal)\s+(\w+)\s*=\s*([^;]+);'
    
    # Track variables
    declared_vars = {}
    
    for i, line in enumerate(lines):
        line_num = i + 1
        line_clean = line.strip()
        
        # Skip comments
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Skip if already const
        if 'const ' in line:
            continue
        
        match = re.match(var_decl_pattern, line)
        if match:
            var_type = match.group(1)
            var_name = match.group(2)
            init_value = match.group(3).strip()
            
            # Check if it's a literal value
            is_literal = (
                re.match(r'^[\d.]+[fdmlFDML]?$', init_value) or
                re.match(r'^"[^"]*"$', init_value) or
                re.match(r"^'.'$", init_value) or
                init_value in ['true', 'false']
            )
            
            is_const_type = var_type in const_types or var_type == 'var'
            
            if var_type == 'var' and is_literal:
                if re.match(r'^"[^"]*"$', init_value):
                    is_const_type = True
                elif re.match(r'^[\d.]+[fdmlFDML]?$', init_value):
                    is_const_type = True
                elif init_value in ['true', 'false']:
                    is_const_type = True
                else:
                    is_const_type = False
            
            if is_literal and is_const_type:
                declared_vars[var_name] = (line_num, var_type, line_clean)
    
    # Check if variables are modified
    for var_name, (decl_line, var_type, line_text) in declared_vars.items():
        is_modified = False
        
        for i, line in enumerate(lines):
            line_num = i + 1
            if line_num == decl_line:
                continue
            
            line_clean = line.strip()
            
            # Check for reassignment
            if re.search(rf'\b{re.escape(var_name)}\s*=(?!=)', line_clean):
                is_modified = True
                break
            
            # Compound assignment
            if re.search(rf'\b{re.escape(var_name)}\s*[+\-*/%&|^]=', line_clean):
                is_modified = True
                break
            
            # Increment/decrement
            if re.search(rf'\b{re.escape(var_name)}\s*\+\+|\+\+\s*{re.escape(var_name)}\b', line_clean):
                is_modified = True
                break
            if re.search(rf'\b{re.escape(var_name)}\s*--|\-\-\s*{re.escape(var_name)}\b', line_clean):
                is_modified = True
                break
            
            # ref/out parameter
            if re.search(rf'\b(ref|out)\s+{re.escape(var_name)}\b', line_clean):
                is_modified = True
                break
        
        if not is_modified:
            findings.append({
                'rule_id': 'unchanged_variables_marked_as',
                'message': f"Variable '{var_name}' is never modified and should be marked as const.",
                'file': filename,
                'line': decl_line,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_text,
                'node': f'VariableDeclaration.{var_name}',
                'status': 'violation'
            })
    
    return findings


def check_underscores_large_numbers(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for underscores_preferred_make_large rule.
    Detects large numeric literals without underscores for readability.
    
    Thresholds:
    - Decimal: 6+ digits
    - Binary: 9+ digits  
    - Hex: 9+ digits
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for i, line in enumerate(lines):
        line_num = i + 1
        line_clean = line.strip()
        
        # Skip comments
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Find decimal numbers (6+ digits without underscores)
        decimal_pattern = r'\b(\d{6,})[LlDdFfMm]?\b'
        for match in re.finditer(decimal_pattern, line):
            number = match.group(1)
            # Skip if it has underscores
            if '_' not in number:
                findings.append({
                    'rule_id': 'underscores_preferred_make_large',
                    'message': f"Large number '{number}' should use underscores for readability.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': 'NumericLiteral',
                    'status': 'violation'
                })
        
        # Find binary numbers (9+ digits without underscores)
        binary_pattern = r'0[bB]([01]{9,})'
        for match in re.finditer(binary_pattern, line):
            number = match.group(1)
            if '_' not in number:
                findings.append({
                    'rule_id': 'underscores_preferred_make_large',
                    'message': f"Large binary number '0b{number}' should use underscores for readability.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': 'NumericLiteral',
                    'status': 'violation'
                })
        
        # Find hex numbers (9+ hex digits without underscores)
        hex_pattern = r'0[xX]([0-9A-Fa-f]{9,})'
        for match in re.finditer(hex_pattern, line):
            number = match.group(1)
            if '_' not in number:
                findings.append({
                    'rule_id': 'underscores_preferred_make_large',
                    'message': f"Large hex number '0x{number}' should use underscores for readability.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': 'NumericLiteral',
                    'status': 'violation'
                })
    
    return findings


def check_unnecessary_bit_operations(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for unnecessary_bit_operations_performed rule.
    Detects bit operations with identity values:
    - x & -1 = x
    - x | 0 = x
    - x ^ 0 = x
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for i, line in enumerate(lines):
        line_num = i + 1
        line_clean = line.strip()
        
        # Skip comments
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Pattern: & -1 (AND with -1)
        if re.search(r'\w+\s*&\s*-1\b', line):
            findings.append({
                'rule_id': 'unnecessary_bit_operations_performed',
                'message': "Bitwise AND with -1 always returns the original value. Remove unnecessary operation.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_clean,
                'node': 'BinaryExpression.BitwiseAnd',
                'status': 'violation'
            })
        
        # Pattern: | 0 (OR with 0)
        if re.search(r'\w+\s*\|\s*0\b(?!x|X|b|B)', line):
            findings.append({
                'rule_id': 'unnecessary_bit_operations_performed',
                'message': "Bitwise OR with 0 always returns the original value. Remove unnecessary operation.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_clean,
                'node': 'BinaryExpression.BitwiseOr',
                'status': 'violation'
            })
        
        # Pattern: ^ 0 (XOR with 0)
        if re.search(r'\w+\s*\^\s*0\b(?!x|X|b|B)', line):
            findings.append({
                'rule_id': 'unnecessary_bit_operations_performed',
                'message': "Bitwise XOR with 0 always returns the original value. Remove unnecessary operation.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_clean,
                'node': 'BinaryExpression.BitwiseXor',
                'status': 'violation'
            })
    
    return findings


def check_unnecessary_math_comparisons(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for unnecessary_mathematical_comparisons_made rule.
    Detects comparisons that are always true or always false due to type ranges.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Type mismatches that produce always-true/false comparisons
    # float vs double.MaxValue
    # int vs long.MaxValue
    # byte vs int.MaxValue
    
    problematic_patterns = [
        (r'\bfloat\s+\w+.*?if\s*\(\s*\w+\s*(<=|<|>=|>)\s*double\.MaxValue\s*\)', 'float', 'double.MaxValue'),
        (r'if\s*\(\s*\w+\s*(<=|<)\s*double\.MaxValue\s*\)', 'smaller type', 'double.MaxValue'),
        (r'if\s*\(\s*\w+\s*(>=|>)\s*double\.MaxValue\s*\)', 'smaller type', 'double.MaxValue'),
        (r'if\s*\(\s*\w+\s*(<=|<)\s*long\.MaxValue\s*\)', 'smaller type', 'long.MaxValue'),
    ]
    
    for i, line in enumerate(lines):
        line_num = i + 1
        line_clean = line.strip()
        
        # Skip comments
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
        
        # Check for float compared to double.MaxValue
        if re.search(r'\b\w+\s*(<=|<|>=|>)\s*double\.MaxValue\b', line):
            # Look back to see if the variable is a float
            if any(re.search(r'\bfloat\s+\w+', lines[j]) for j in range(max(0, i-5), i+1)):
                findings.append({
                    'rule_id': 'unnecessary_mathematical_comparisons_made',
                    'message': "Comparison of float to double.MaxValue is always true or false. Remove unnecessary comparison.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': 'BinaryExpression.Comparison',
                    'status': 'violation'
                })
        
        # Check for int compared to long.MaxValue
        if re.search(r'\b\w+\s*(<=|<|>=|>)\s*long\.MaxValue\b', line):
            if any(re.search(r'\bint\s+\w+', lines[j]) for j in range(max(0, i-5), i+1)):
                findings.append({
                    'rule_id': 'unnecessary_mathematical_comparisons_made',
                    'message': "Comparison of int to long.MaxValue is always true or false. Remove unnecessary comparison.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': 'BinaryExpression.Comparison',
                    'status': 'violation'
                })
        
        # Check for byte compared to int.MaxValue
        if re.search(r'\b\w+\s*(<=|<|>=|>)\s*int\.MaxValue\b', line):
            if any(re.search(r'\bbyte\s+\w+', lines[j]) for j in range(max(0, i-5), i+1)):
                findings.append({
                    'rule_id': 'unnecessary_mathematical_comparisons_made',
                    'message': "Comparison of byte to int.MaxValue is always true or false. Remove unnecessary comparison.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': 'BinaryExpression.Comparison',
                    'status': 'violation'
                })
    
    return findings


def check_unnecessary_using(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for unnecessary_using_removed rule.
    Detects using directives for namespaces not referenced in the file.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Collect using directives
    using_directives = []
    code_start_line = 0
    
    for i, line in enumerate(lines):
        line_clean = line.strip()
        
        # Skip empty lines and comments
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*'):
            continue
        
        # Detect using directives
        using_match = re.match(r'^using\s+([\w.]+)\s*;', line_clean)
        if using_match:
            namespace = using_match.group(1)
            using_directives.append((i + 1, namespace, line_clean))
        elif not line_clean.startswith('using'):
            code_start_line = i
            break
    
    # Get code portion (after using directives)
    code_section = '\n'.join(lines[code_start_line:])
    
    # Common type-to-namespace mappings
    namespace_types = {
        'System': ['Console', 'Math', 'Environment', 'DateTime', 'TimeSpan', 'Guid', 'Exception', 'EventHandler', 'Action', 'Func'],
        'System.Collections.Generic': ['List', 'Dictionary', 'HashSet', 'Queue', 'Stack', 'IEnumerable', 'IList', 'IDictionary'],
        'System.Linq': ['Enumerable', 'Where', 'Select', 'First', 'Last', 'OrderBy', 'ToList', 'ToArray'],
        'System.Text': ['StringBuilder', 'Encoding', 'Regex'],
        'System.IO': ['File', 'Directory', 'Path', 'Stream', 'FileStream', 'StreamReader', 'StreamWriter'],
        'System.Threading': ['Thread', 'Task', 'Monitor', 'Mutex', 'Semaphore'],
        'System.Threading.Tasks': ['Task', 'Parallel'],
    }
    
    for line_num, namespace, using_line in using_directives:
        # Check if any types from this namespace are used
        is_used = False
        
        if namespace in namespace_types:
            for type_name in namespace_types[namespace]:
                # Check for type usage in code
                if re.search(rf'\b{type_name}\b', code_section):
                    is_used = True
                    break
        else:
            # For unknown namespaces, check for namespace prefix or last segment
            last_segment = namespace.split('.')[-1]
            if re.search(rf'\b{last_segment}\b', code_section):
                is_used = True
        
        if not is_used:
            findings.append({
                'rule_id': 'unnecessary_using_removed',
                'message': f"Using directive '{namespace}' is not used in this file. Remove unnecessary using.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': using_line,
                'node': f'UsingDirective.{namespace}',
                'status': 'violation'
            })
    
    return findings


def check_unread_private_fields(ast_tree, filename, **kwargs):
    """
    Detect private fields that are written but never read (dead stores).
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Strip comments from source for analysis
    def strip_comments(text):
        # Remove single-line comments
        text = re.sub(r'//.*$', '', text, flags=re.MULTILINE)
        # Remove multi-line comments
        text = re.sub(r'/\*.*?\*/', '', text, flags=re.DOTALL)
        return text
    
    # Find class boundaries and analyze each class separately
    class_pattern = r'(?:public\s+|internal\s+|sealed\s+|abstract\s+|partial\s+)*class\s+(\w+)'
    field_pattern = r'^\s*private\s+(?:readonly\s+)?(\w+(?:<[^>]+>)?)\s+(\w+)\s*[;=]'
    
    # Find all class start positions
    class_starts = []
    for i, line in enumerate(lines):
        match = re.search(class_pattern, line)
        if match:
            class_starts.append((i, match.group(1)))
    
    # For each class, find its end and analyze fields
    for idx, (class_start, class_name) in enumerate(class_starts):
        # Determine class end - either next class start or end of file
        if idx + 1 < len(class_starts):
            class_end = class_starts[idx + 1][0]
        else:
            class_end = len(lines)
        
        class_source = '\n'.join(lines[class_start:class_end])
        # Strip comments for analysis
        class_source_clean = strip_comments(class_source)
        class_lines = lines[class_start:class_end]
        
        # Find private fields in this class
        private_fields = []
        for j, line in enumerate(class_lines):
            field_match = re.match(field_pattern, line)
            if field_match:
                field_name = field_match.group(2)
                private_fields.append((class_start + j + 1, field_name, line.strip()))
        
        # Check each field for read usage within this class (using cleaned source)
        for line_num, field_name, field_decl in private_fields:
            is_read = False
            
            # Count all occurrences of field_name (in code, not comments)
            all_occurrences = len(re.findall(rf'\b{field_name}\b', class_source_clean))
            # Count write-only occurrences (field_name followed by assignment)
            write_occurrences = len(re.findall(rf'\b{field_name}\s*=(?!=)', class_source_clean))
            # Also count declarations
            decl_occurrences = len(re.findall(rf'private\s+\w+\s+{field_name}\s*[;=]', class_source_clean))
            
            # If field appears more times than writes + declarations, it's being read
            if all_occurrences > write_occurrences + decl_occurrences:
                is_read = True
            
            # Also check for lambda expressions that use the field
            if re.search(rf'=>\s*[^;]*\b{field_name}\b', class_source_clean):
                is_read = True
            
            # Check for use in operations
            if re.search(rf'[\+\-\*\/\%]\s*{field_name}\b', class_source_clean):
                is_read = True
            if re.search(rf'\b{field_name}\s*[\+\-\*\/\%]', class_source_clean):
                # Make sure it's not compound assignment
                if not re.search(rf'\b{field_name}\s*[\+\-\*\/\%]=', class_source_clean):
                    is_read = True
            
            if not is_read and write_occurrences > 0:
                findings.append({
                    'rule_id': 'unread_private_fields_removed',
                    'message': f"Private field '{field_name}' is written but never read. Remove this dead store.",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': field_decl,
                    'node': f'FieldDeclaration.{field_name}',
                    'status': 'violation'
                })
    
    return findings


def check_unused_assignments(ast_tree, filename, **kwargs):
    """
    Detect assignments where the value is immediately overwritten before being read.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Strip comments
    source_clean = re.sub(r'//.*$', '', source, flags=re.MULTILINE)
    source_clean = re.sub(r'/\*.*?\*/', '', source_clean, flags=re.DOTALL)
    
    lines = source_clean.split('\n')
    
    # Find assignments followed by reassignments to same variable
    # Pattern: var = value; ... var = value2; with no read of var between them
    decl_pattern = r'^\s*(?:var|int|string|bool|double|float|long|decimal|object|\w+)\s+(\w+)\s*=\s*(.+);'
    assign_pattern = r'^\s*(\w+)\s*=\s*(.+);'
    
    var_last_assign = {}  # var_name -> (line_num, line_text)
    
    for i, line in enumerate(lines):
        line_clean = line.strip()
        if not line_clean:
            continue
        
        # Check for declaration with assignment
        decl_match = re.match(decl_pattern, line)
        if decl_match:
            var_name = decl_match.group(1)
            var_last_assign[var_name] = (i + 1, line_clean)
            continue
        
        # Check for simple assignment
        assign_match = re.match(assign_pattern, line)
        if assign_match:
            var_name = assign_match.group(1)
            if var_name in var_last_assign:
                prev_line, prev_code = var_last_assign[var_name]
                # This is a reassignment - previous one was dead store
                findings.append({
                    'rule_id': 'unused_assignments_removed',
                    'message': f"Assignment to '{var_name}' on line {prev_line} is overwritten before being read.",
                    'file': filename,
                    'line': prev_line,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': prev_code,
                    'node': f'Assignment.{var_name}',
                    'status': 'violation'
                })
            var_last_assign[var_name] = (i + 1, line_clean)
            continue
        
        # Check if any tracked variable is used (read) on this line
        for var_name in list(var_last_assign.keys()):
            # Check if var is used (not as assignment target)
            if re.search(rf'\b{var_name}\b', line):
                # Check it's not just another assignment
                if not re.match(rf'^\s*{var_name}\s*=', line):
                    # Variable is read, so previous assignment was used
                    del var_last_assign[var_name]
    
    return findings


def check_unused_local_variables(ast_tree, filename, **kwargs):
    """
    Detect local variables that are declared but never used.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Strip comments
    source_clean = re.sub(r'//.*$', '', source, flags=re.MULTILINE)
    source_clean = re.sub(r'/\*.*?\*/', '', source_clean, flags=re.DOTALL)
    
    lines = source.split('\n')  # Keep original for line numbers
    lines_clean = source_clean.split('\n')  # Use cleaned for analysis
    
    # Pattern for local variable declarations
    decl_pattern = r'^\s*(?:var|int|string|bool|double|float|long|decimal|object|char|byte|short|uint|ulong|ushort|sbyte)\s+(\w+)\s*[=;]'
    
    # Find all local variable declarations
    local_vars = []
    for i, line in enumerate(lines):
        decl_match = re.match(decl_pattern, line)
        if decl_match:
            var_name = decl_match.group(1)
            local_vars.append((i + 1, var_name, line.strip()))
    
    # Check each local variable for usage in the cleaned source
    for line_num, var_name, decl_line in local_vars:
        # Count occurrences in cleaned source
        pattern = rf'\b{var_name}\b'
        matches = re.findall(pattern, source_clean)
        
        # If variable appears only once (its declaration), it's unused
        if len(matches) <= 1:
            findings.append({
                'rule_id': 'unused_local_variables_removed',
                'message': f"Local variable '{var_name}' is declared but never used.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': decl_line,
                'node': f'VariableDeclaration.{var_name}',
                'status': 'violation'
            })
    
    return findings


def check_unused_method_parameters(ast_tree, filename, **kwargs):
    """
    Detect method parameters that are never used in the method body.
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Strip comments
    source_clean = re.sub(r'//.*$', '', source, flags=re.MULTILINE)
    source_clean = re.sub(r'/\*.*?\*/', '', source_clean, flags=re.DOTALL)
    
    lines = source.split('\n')
    
    # Method pattern with parameters
    method_pattern = r'(?:public|private|protected|internal|static|\s)+[\w<>\[\]]+\s+(\w+)\s*\(([^)]+)\)'
    
    for i, line in enumerate(lines):
        # Skip override/virtual/abstract methods
        if re.search(r'\b(override|virtual|abstract)\b', line):
            continue
        
        method_match = re.search(method_pattern, line)
        if method_match:
            method_name = method_match.group(1)
            params_str = method_match.group(2)
            
            # Parse parameters
            params = []
            for param in params_str.split(','):
                param = param.strip()
                if param:
                    # Extract parameter name (last word)
                    parts = param.split()
                    if parts:
                        param_name = parts[-1]
                        params.append(param_name)
            
            if not params:
                continue
            
            # Find method body (from this line until we find matching closing brace)
            method_body_start = i
            brace_count = 0
            method_body_end = i
            
            for j in range(i, len(lines)):
                brace_count += lines[j].count('{') - lines[j].count('}')
                if brace_count > 0 or '{' in lines[j]:
                    method_body_end = j
                    if brace_count == 0 and j > i:
                        break
            
            method_body = '\n'.join(lines[i+1:method_body_end+1])
            # Strip comments from method body
            method_body_clean = re.sub(r'//.*$', '', method_body, flags=re.MULTILINE)
            method_body_clean = re.sub(r'/\*.*?\*/', '', method_body_clean, flags=re.DOTALL)
            
            # Check each parameter for usage
            for param_name in params:
                pattern = rf'\b{param_name}\b'
                if not re.search(pattern, method_body_clean):
                    findings.append({
                        'rule_id': 'unused_method_parameters_removed',
                        'message': f"Parameter '{param_name}' in method '{method_name}' is never used.",
                        'file': filename,
                        'line': i + 1,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': line.strip(),
                        'node': f'Parameter.{param_name}',
                        'status': 'violation'
                    })
    
    return findings


def check_method_overrides_change_parameter(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for method overrides that change parameter default values.
    
    This rule detects override methods that specify different default parameter values
    than the base class. This is problematic because the default value used depends on
    the static type of the variable, not the runtime type.
    
    Logic:
    1. Parse all classes and their inheritance hierarchy
    2. Find virtual/abstract methods with default parameters in base classes
    3. Find override methods with default parameters
    4. Compare the default values - only flag if they are DIFFERENT
    5. Exclude test classes and explicit interface implementations
    """
    findings = []
    
    source_code = ast_tree.get('source', '')
    if not source_code:
        return findings
    
    lines = source_code.split('\n')
    
    # Skip test files
    if re.search(r'\[Test(?:Fixture|Class)?\]|\[Fact\]|\[Theory\]', source_code):
        # Check if the entire file is a test file
        test_class_count = len(re.findall(r'\[Test(?:Fixture|Class)?\]', source_code))
        total_classes = len(re.findall(r'\b(?:class|struct)\s+\w+', source_code))
        if test_class_count > 0 and test_class_count >= total_classes * 0.5:
            return findings  # Skip if most classes are test classes
    
    # Data structure to store class info
    # class_info[class_name] = {'base_class': str, 'methods': {method_name: {param_name: default_value}}}
    class_info = {}
    
    # Pattern to match class declarations with inheritance
    class_pattern = re.compile(
        r'(?:public|private|protected|internal)?\s*(?:abstract|sealed|partial|static)?\s*'
        r'class\s+(\w+)\s*(?:<[^>]+>)?\s*(?::\s*([^{]+))?',
        re.MULTILINE
    )
    
    # Pattern to match virtual/abstract methods with default parameters
    virtual_method_pattern = re.compile(
        r'(?:public|protected|internal|private)?\s*(?:virtual|abstract)\s+\w+\s+(\w+)\s*\(([^)]*)\)',
        re.MULTILINE
    )
    
    # Pattern to match override methods with default parameters
    override_method_pattern = re.compile(
        r'(?:public|protected|internal|private)?\s*(?:sealed\s+)?override\s+\w+\s+(\w+)\s*\(([^)]*)\)',
        re.MULTILINE
    )
    
    # Pattern to extract parameters with defaults
    param_default_pattern = re.compile(
        r'(?:(?:\w+(?:<[^>]+>)?(?:\[\])?)\s+)?(\w+)\s*=\s*([^,\)]+)'
    )
    
    # First pass: collect class hierarchy and virtual/abstract method defaults
    current_class = None
    for i, line in enumerate(lines):
        # Skip comments
        stripped = line.strip()
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
            continue
        
        # Check for class declaration
        class_match = class_pattern.search(line)
        if class_match:
            class_name = class_match.group(1)
            base_classes = class_match.group(2)
            base_class = None
            if base_classes:
                # Parse base classes (first non-interface is likely the base class)
                bases = [b.strip() for b in base_classes.split(',')]
                for base in bases:
                    # Skip interfaces (typically start with I and uppercase second letter)
                    base_clean = base.split('<')[0].strip()
                    if not (base_clean.startswith('I') and len(base_clean) > 1 and base_clean[1].isupper()):
                        base_class = base_clean
                        break
            
            class_info[class_name] = {
                'base_class': base_class,
                'virtual_methods': {},
                'override_methods': {},
                'line': i + 1
            }
            current_class = class_name
        
        if current_class:
            # Check for virtual/abstract methods
            virtual_match = virtual_method_pattern.search(line)
            if virtual_match:
                method_name = virtual_match.group(1)
                params_str = virtual_match.group(2)
                
                # Extract parameters with defaults
                param_defaults = {}
                for param_match in param_default_pattern.finditer(params_str):
                    param_name = param_match.group(1)
                    default_value = param_match.group(2).strip()
                    param_defaults[param_name] = default_value
                
                if param_defaults:
                    class_info[current_class]['virtual_methods'][method_name] = param_defaults
            
            # Check for override methods
            override_match = override_method_pattern.search(line)
            if override_match:
                method_name = override_match.group(1)
                params_str = override_match.group(2)
                
                # Extract parameters with defaults
                param_defaults = {}
                for param_match in param_default_pattern.finditer(params_str):
                    param_name = param_match.group(1)
                    default_value = param_match.group(2).strip()
                    param_defaults[param_name] = default_value
                
                if param_defaults:
                    class_info[current_class]['override_methods'][method_name] = {
                        'params': param_defaults,
                        'line': i + 1,
                        'source': line.strip()
                    }
    
    # Helper function to find base method defaults through inheritance chain
    def find_base_method_defaults(class_name, method_name, visited=None):
        if visited is None:
            visited = set()
        
        if class_name in visited or class_name not in class_info:
            return None
        
        visited.add(class_name)
        info = class_info[class_name]
        
        # Check if this class has the virtual method
        if method_name in info['virtual_methods']:
            return info['virtual_methods'][method_name]
        
        # Check base class
        if info['base_class']:
            return find_base_method_defaults(info['base_class'], method_name, visited)
        
        return None
    
    # Second pass: compare override methods with base method defaults
    for class_name, info in class_info.items():
        # Skip if this class has test attributes
        class_line_idx = info['line'] - 1
        if class_line_idx > 0:
            # Check preceding lines for test attributes
            preceding_lines = '\n'.join(lines[max(0, class_line_idx - 3):class_line_idx])
            if re.search(r'\[Test(?:Fixture|Class)?\]|\[Fact\]|\[Theory\]', preceding_lines):
                continue
        
        for method_name, method_info in info['override_methods'].items():
            override_params = method_info['params']
            method_line = method_info['line']
            method_source = method_info['source']
            
            # Skip if this method has test attributes or Assert calls
            method_line_idx = method_line - 1
            # Check for test attributes on the method
            if method_line_idx > 0:
                preceding = lines[method_line_idx - 1] if method_line_idx > 0 else ''
                if re.search(r'\[Test\]|\[Fact\]|\[Theory\]', preceding):
                    continue
            
            # Check method body for Assert calls
            method_body_start = method_line_idx
            method_body_end = min(method_line_idx + 10, len(lines))
            method_body = '\n'.join(lines[method_body_start:method_body_end])
            if re.search(r'Assert\.', method_body):
                continue
            
            # Find base method defaults
            base_defaults = find_base_method_defaults(info['base_class'], method_name) if info['base_class'] else None
            
            # If we can't find base defaults, assume any override with defaults is a potential violation
            # (This is conservative - we flag when we can't verify the base)
            if base_defaults is None:
                # Only flag if we have override with defaults
                for param_name, override_default in override_params.items():
                    findings.append({
                        'rule_id': 'method_overrides_change_parameter',
                        'message': f"Override method '{method_name}' has default parameter '{param_name}={override_default}'. "
                                   f"Default values in overrides can cause confusion as they depend on the static type.",
                        'file': filename,
                        'line': method_line,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': method_source,
                        'node': f'ClassDeclaration.{class_name}',
                        'status': 'violation'
                    })
            else:
                # Compare defaults - only flag if they are DIFFERENT
                for param_name, override_default in override_params.items():
                    base_default = base_defaults.get(param_name)
                    
                    # Normalize values for comparison (strip quotes for strings)
                    def normalize_value(val):
                        if val is None:
                            return None
                        val = val.strip()
                        # Remove surrounding quotes for string comparison
                        if (val.startswith('"') and val.endswith('"')) or (val.startswith("'") and val.endswith("'")):
                            val = val[1:-1]
                        return val
                    
                    norm_override = normalize_value(override_default)
                    norm_base = normalize_value(base_default)
                    
                    # Only flag if values are different
                    if norm_base is not None and norm_override != norm_base:
                        findings.append({
                            'rule_id': 'method_overrides_change_parameter',
                            'message': f"Override method '{method_name}' changes default parameter '{param_name}' "
                                       f"from '{base_default}' to '{override_default}'. This can cause confusing behavior.",
                            'file': filename,
                            'line': method_line,
                            'severity': 'Major',
                            'property_path': ['source'],
                            'value': method_source,
                            'node': f'ClassDeclaration.{class_name}',
                            'status': 'violation'
                        })
                    elif norm_base is None and param_name not in base_defaults:
                        # Override adds a new default that doesn't exist in base
                        findings.append({
                            'rule_id': 'method_overrides_change_parameter',
                            'message': f"Override method '{method_name}' adds default parameter '{param_name}={override_default}' "
                                       f"that doesn't exist in the base method.",
                            'file': filename,
                            'line': method_line,
                            'severity': 'Major',
                            'property_path': ['source'],
                            'value': method_source,
                            'node': f'ClassDeclaration.{class_name}',
                            'status': 'violation'
                        })
    
    return findings


def check_method_overloads_default_parameter(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for method overloads where one with default parameters is hidden by another without defaults.
    
    This rule detects cases like:
        void Print(int number) { }
        void Print(int number, string delimiter = "\n") { }  // NONCOMPLIANT - default hidden
    
    The issue is that calling Print(1) will always call the first overload, making the default
    parameter in the second overload unreachable.
    """
    findings = []
    
    source_code = ast_tree.get('source', '')
    if not source_code:
        return findings
    
    lines = source_code.split('\n')
    
    # Pattern to match method declarations (simplified, more robust)
    method_pattern = re.compile(
        r'(?:public|private|protected|internal|static|virtual|abstract|override|sealed|async|\s)+'
        r'(\w+(?:<[^>]+>)?)\s+'  # Return type (group 1)
        r'(\w+)\s*'              # Method name (group 2)
        r'\(([^)]*)\)',          # Parameters (group 3)
    )
    
    # Pattern to extract parameter types and names
    param_pattern = re.compile(
        r'(?:(?:this|ref|out|in|params)\s+)?'  # Modifiers
        r'(\w+(?:<[^>]+>)?(?:\[\])?)\s+'        # Type (group 1)
        r'(\w+)'                                 # Name (group 2)
        r'(?:\s*=\s*([^,\)]+))?'                # Default value (group 3)
    )
    
    # Collect all classes with their line ranges
    class_info = []  # [(class_name, start_line, end_line, is_test)]
    
    class_starts = []
    for i, line in enumerate(lines):
        # Check for class declaration
        if re.search(r'\bclass\s+(\w+)', line):
            class_match = re.search(r'\bclass\s+(\w+)', line)
            if class_match:
                class_name = class_match.group(1)
                # Check if it's a test class
                is_test = False
                preceding = '\n'.join(lines[max(0, i-3):i+1])
                if re.search(r'\[TestFixture\]|\[TestClass\]|\[Fact\]|\[Theory\]', preceding):
                    is_test = True
                class_starts.append((class_name, i, is_test))
    
    # Find class end lines using brace matching
    for class_name, start_idx, is_test in class_starts:
        brace_count = 0
        started = False
        end_idx = start_idx
        
        for i in range(start_idx, len(lines)):
            line = lines[i]
            brace_count += line.count('{') - line.count('}')
            if '{' in line:
                started = True
            if started and brace_count <= 0:
                end_idx = i
                break
        
        class_info.append((class_name, start_idx, end_idx, is_test))
    
    # Process each class
    for class_name, start_idx, end_idx, is_test in class_info:
        if is_test:
            continue  # Skip test classes
        
        # Collect methods in this class
        methods = {}  # method_name -> [list of overloads]
        
        for i in range(start_idx, end_idx + 1):
            line = lines[i]
            stripped = line.strip()
            
            # Skip comments
            if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
                continue
            
            # Skip if line has test attributes
            if i > 0:
                prev_line = lines[i-1].strip()
                if re.search(r'\[Test\]|\[Fact\]|\[Theory\]', prev_line):
                    continue
            
            # Skip if line contains Assert (test context)
            if 'Assert.' in line:
                continue
            
            # Look for method declaration
            method_match = method_pattern.search(line)
            if method_match:
                return_type = method_match.group(1)
                method_name = method_match.group(2)
                params_str = method_match.group(3)
                
                # Skip if it's a class keyword line
                if 'class' in line:
                    continue
                
                # Skip constructors
                if return_type == class_name:
                    continue
                
                # Skip property accessors
                if method_name in ['get', 'set', 'add', 'remove']:
                    continue
                
                # Parse parameters
                params = []
                has_defaults = False
                
                for param_match in param_pattern.finditer(params_str):
                    param_type = param_match.group(1)
                    param_name = param_match.group(2)
                    default_value = param_match.group(3)
                    
                    params.append({
                        'type': param_type,
                        'name': param_name,
                        'has_default': default_value is not None,
                        'default': default_value.strip() if default_value else None
                    })
                    
                    if default_value is not None:
                        has_defaults = True
                
                # Store method
                if method_name not in methods:
                    methods[method_name] = []
                
                methods[method_name].append({
                    'line': i + 1,
                    'return_type': return_type,
                    'params': params,
                    'has_defaults': has_defaults,
                    'source': stripped
                })
        
        # Find overlapping overloads
        for method_name, overloads in methods.items():
            if len(overloads) < 2:
                continue
            
            # Separate overloads with and without defaults
            with_defaults = [o for o in overloads if o['has_defaults']]
            without_defaults = [o for o in overloads if not o['has_defaults']]
            
            if not with_defaults or not without_defaults:
                continue
            
            # Check each overload with defaults
            for default_overload in with_defaults:
                default_params = default_overload['params']
                
                # Find the index where defaults start
                first_default_idx = None
                for idx, param in enumerate(default_params):
                    if param['has_default']:
                        first_default_idx = idx
                        break
                
                if first_default_idx is None:
                    continue
                
                # Get the required (non-default) parameter signature
                required_params = default_params[:first_default_idx]
                required_signature = tuple(p['type'] for p in required_params)
                
                # Check if any overload without defaults matches this signature
                for simple_overload in without_defaults:
                    simple_params = simple_overload['params']
                    simple_signature = tuple(p['type'] for p in simple_params)
                    
                    # Check if the simple overload matches the required params exactly
                    if simple_signature == required_signature:
                        # Found a hiding situation!
                        default_param_names = [p['name'] + '=' + str(p['default']) 
                                              for p in default_params if p['has_default']]
                        
                        findings.append({
                            'rule_id': 'method_overloads_default_parameter',
                            'message': f"Method '{method_name}' overload with default parameter(s) "
                                       f"({', '.join(default_param_names)}) is hidden by simpler overload "
                                       f"at line {simple_overload['line']}.",
                            'file': filename,
                            'line': default_overload['line'],
                            'severity': 'Major',
                            'property_path': ['source'],
                            'value': default_overload['source'],
                            'node': f'ClassDeclaration.{class_name}',
                            'status': 'violation'
                        })
    
    return findings


def check_method_overloads_grouped_together(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check that method overloads are grouped together.
    
    This rule detects cases where overloaded methods are separated by other methods:
        void Process() { }
        void Execute() { }       // Different method separates overloads
        void Process(int x) { }  // NONCOMPLIANT - should be grouped with first Process
    
    Logic:
    1. Parse all methods within each class/interface
    2. Track the order of method declarations
    3. For each method name that appears multiple times (overloads)
    4. Check if all occurrences are consecutive
    5. Flag violations where overloads are not grouped
    """
    findings = []
    
    source_code = ast_tree.get('source', '')
    if not source_code:
        return findings
    
    lines = source_code.split('\n')
    
    # Pattern to match method declarations
    method_pattern = re.compile(
        r'(?:public|private|protected|internal|static|virtual|abstract|override|sealed|async|\s)+'
        r'(?:\w+(?:<[^>]+>)?)\s+'  # Return type
        r'(\w+)\s*'                # Method name (group 1)
        r'\([^)]*\)',              # Parameters
    )
    
    # Collect all classes/interfaces with their line ranges
    type_info = []  # [(type_name, type_kind, start_line, end_line, is_test)]
    
    type_starts = []
    for i, line in enumerate(lines):
        # Check for class/interface/struct declaration
        type_match = re.search(r'\b(class|interface|struct)\s+(\w+)', line)
        if type_match:
            type_kind = type_match.group(1)
            type_name = type_match.group(2)
            # Check if it's a test class
            is_test = False
            preceding = '\n'.join(lines[max(0, i-3):i+1])
            if re.search(r'\[TestFixture\]|\[TestClass\]|\[Fact\]|\[Theory\]', preceding):
                is_test = True
            type_starts.append((type_name, type_kind, i, is_test))
    
    # Find type end lines using brace matching
    for type_name, type_kind, start_idx, is_test in type_starts:
        brace_count = 0
        started = False
        end_idx = start_idx
        
        for i in range(start_idx, len(lines)):
            line = lines[i]
            brace_count += line.count('{') - line.count('}')
            if '{' in line:
                started = True
            if started and brace_count <= 0:
                end_idx = i
                break
        
        type_info.append((type_name, type_kind, start_idx, end_idx, is_test))
    
    # Process each type
    for type_name, type_kind, start_idx, end_idx, is_test in type_info:
        if is_test:
            continue  # Skip test classes
        
        # Collect methods in order of declaration
        method_order = []  # [(method_name, line_number, source)]
        
        for i in range(start_idx, end_idx + 1):
            line = lines[i]
            stripped = line.strip()
            
            # Skip comments
            if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
                continue
            
            # Skip if line has test attributes
            if i > 0:
                prev_line = lines[i-1].strip()
                if re.search(r'\[Test\]|\[Fact\]|\[Theory\]', prev_line):
                    continue
            
            # Skip lines that are class/interface declarations
            if re.search(r'\b(class|interface|struct)\s+\w+', line):
                continue
            
            # Look for method declaration
            method_match = method_pattern.search(line)
            if method_match:
                method_name = method_match.group(1)
                
                # Skip constructors (name matches type name)
                if method_name == type_name:
                    continue
                
                # Skip property accessors
                if method_name in ['get', 'set', 'add', 'remove']:
                    continue
                
                method_order.append((method_name, i + 1, stripped))
        
        # Find method names that have overloads
        method_counts = {}
        for method_name, line_num, source in method_order:
            if method_name not in method_counts:
                method_counts[method_name] = []
            method_counts[method_name].append((line_num, source))
        
        # Check each method with overloads
        for method_name, occurrences in method_counts.items():
            if len(occurrences) < 2:
                continue  # No overloads
            
            # Get the indices of this method in the method_order list
            indices = []
            for idx, (name, line_num, source) in enumerate(method_order):
                if name == method_name:
                    indices.append(idx)
            
            # Check if all indices are consecutive
            is_grouped = True
            for i in range(len(indices) - 1):
                if indices[i + 1] != indices[i] + 1:
                    is_grouped = False
                    break
            
            if not is_grouped:
                # Find the first non-grouped occurrence
                for i in range(len(indices) - 1):
                    if indices[i + 1] != indices[i] + 1:
                        # The overload at indices[i+1] is not grouped
                        violating_line = occurrences[i + 1][0]
                        violating_source = occurrences[i + 1][1]
                        first_line = occurrences[0][0]
                        
                        findings.append({
                            'rule_id': 'method_overloads_grouped_together',
                            'message': f"Method '{method_name}' overload at line {violating_line} "
                                       f"should be grouped with other overloads (first at line {first_line}).",
                            'file': filename,
                            'line': violating_line,
                            'severity': 'Major',
                            'property_path': ['source'],
                            'value': violating_source,
                            'node': f'ClassDeclaration.{type_name}',
                            'status': 'violation'
                        })
    
    return findings


def check_method_calls_resolve_ambiguously(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for method overloads where params and non-params versions could resolve ambiguously.
    
    This rule flags classes that have:
    1. A method with 'params' keyword for the last parameter
    2. Another overload of the same method with multiple regular parameters
    3. Where the parameter types could cause ambiguous resolution
    
    The key is that both overloads must have compatible types that could match the same call.
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Find all class/interface/struct declarations
    type_info = []  # [(type_name, type_kind, start_line, end_line, is_test)]
    type_starts = []
    
    for i, line in enumerate(lines):
        stripped = line.strip()
        
        # Check for class/interface/struct declaration
        match = re.search(r'(?:public|private|protected|internal|static|abstract|sealed|partial|\s)+\s*(class|interface|struct)\s+(\w+)', stripped)
        if match:
            type_kind = match.group(1)
            type_name = match.group(2)
            
            # Check if this is a test class - look back up to 5 lines for test attributes
            is_test = False
            for j in range(max(0, i - 5), i):
                if re.search(r'\[TestFixture\]|\[TestClass\]', lines[j]):
                    is_test = True
                    break
            
            type_starts.append((type_name, type_kind, i, is_test))
    
    # Find type end lines using brace matching
    for type_name, type_kind, start_idx, is_test in type_starts:
        brace_count = 0
        started = False
        end_idx = start_idx
        
        for i in range(start_idx, len(lines)):
            line = lines[i]
            brace_count += line.count('{') - line.count('}')
            if '{' in line:
                started = True
            if started and brace_count <= 0:
                end_idx = i
                break
        
        type_info.append((type_name, type_kind, start_idx, end_idx, is_test))
    
    # Process each type
    for type_name, type_kind, start_idx, end_idx, is_test in type_info:
        if is_test:
            continue  # Skip test classes
        
        # Also check if any method in the class has [Test], [Fact], [Theory] attribute
        # This catches classes where the test attribute is on methods, not the class
        class_source = '\n'.join(lines[start_idx:end_idx+1])
        if re.search(r'\[\s*(Test|Fact|Theory)\s*\]', class_source):
            continue  # Skip - contains test methods
        
        # Collect all method declarations
        methods = []  # [(method_name, line_num, has_params, params_element_type, param_types)]
        
        for i in range(start_idx, end_idx + 1):
            line = lines[i]
            stripped = line.strip()
            
            # Skip comments
            if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*'):
                continue
            
            # Match method declarations - look for method signature pattern
            # Methods can have zero or more modifiers, or none at all (default private)
            method_match = re.search(
                r'(?:(?:public|private|protected|internal|static|virtual|override|abstract|async|sealed)\s+)*'  # optional modifiers
                r'(\w+(?:<[^>]+>)?)\s+'  # return type (group 1)
                r'(\w+)\s*'  # method name (group 2)
                r'\(([^)]*)\)',  # parameters (group 3)
                stripped
            )
            
            if method_match:
                return_type = method_match.group(1)
                method_name = method_match.group(2)
                params_str = method_match.group(3).strip()
                
                # Skip constructors (method name matches class name)
                if method_name == type_name:
                    continue
                
                # Check if this method has params keyword
                has_params = 'params ' in params_str
                params_element_type = None
                param_types = []
                
                if has_params:
                    # Extract the element type of the params array
                    params_match = re.search(r'params\s+(\w+)\s*\[\]', params_str)
                    if params_match:
                        params_element_type = params_match.group(1)
                
                # Extract all parameter types
                if params_str:
                    # Split by comma but handle generic types
                    param_parts = []
                    depth = 0
                    current = ''
                    for c in params_str:
                        if c == '<':
                            depth += 1
                        elif c == '>':
                            depth -= 1
                        elif c == ',' and depth == 0:
                            param_parts.append(current.strip())
                            current = ''
                            continue
                        current += c
                    if current.strip():
                        param_parts.append(current.strip())
                    
                    for param in param_parts:
                        # Extract type from "type name" or "params type[] name"
                        param = param.strip()
                        if param.startswith('params '):
                            param = param[7:]  # Remove 'params '
                        
                        # Get just the type part (before the parameter name)
                        type_match = re.match(r'(\w+(?:<[^>]+>)?(?:\[\])?)\s+\w+', param)
                        if type_match:
                            param_types.append(type_match.group(1))
                
                methods.append((method_name, i + 1, has_params, params_element_type, param_types))
        
        # Group methods by name
        method_groups = {}
        for method_name, line_num, has_params, params_element_type, param_types in methods:
            if method_name not in method_groups:
                method_groups[method_name] = []
            method_groups[method_name].append((line_num, has_params, params_element_type, param_types))
        
        # Check each method group for ambiguous params/non-params combinations
        for method_name, overloads in method_groups.items():
            if len(overloads) < 2:
                continue
            
            # Find params versions and non-params versions
            params_versions = [(ln, et, pt) for ln, hp, et, pt in overloads if hp]
            non_params_versions = [(ln, pt) for ln, hp, et, pt in overloads if not hp]
            
            if not params_versions or not non_params_versions:
                continue  # Need both types for ambiguity
            
            # Check for ambiguity: non-params version with 2+ params after the fixed params
            for params_line, params_elem_type, params_param_types in params_versions:
                # Get number of fixed parameters before params (all but the last one)
                num_fixed = len(params_param_types) - 1 if params_param_types else 0
                
                for non_params_line, non_params_types in non_params_versions:
                    # Check if non-params version has more parameters than the fixed ones
                    if len(non_params_types) <= num_fixed:
                        continue  # Can't overlap - fewer params than fixed
                    
                    # Check if the fixed parameter types match (or are compatible)
                    fixed_match = True
                    for i in range(num_fixed):
                        if i < len(non_params_types):
                            # Types must be compatible (same type, or one is 'object')
                            type1 = params_param_types[i] if i < len(params_param_types) else None
                            type2 = non_params_types[i]
                            if type1 and type2:
                                if type1 != type2 and type1 != 'object' and type2 != 'object':
                                    fixed_match = False
                                    break
                    
                    if not fixed_match:
                        continue
                    
                    # Check if the remaining params can match the params array element type
                    # Types are ambiguous if params element type is compatible with remaining non-params types
                    remaining_types = non_params_types[num_fixed:]
                    
                    # Check compatibility
                    is_ambiguous = True
                    for rem_type in remaining_types:
                        # 'object' params can match anything
                        if params_elem_type == 'object':
                            continue  # Always compatible
                        # Same type is compatible
                        if rem_type == params_elem_type:
                            continue  # Compatible
                        # If remaining type is 'object', it's compatible with anything
                        if rem_type == 'object':
                            continue  # Compatible
                        # Different incompatible types - no ambiguity
                        is_ambiguous = False
                        break
                    
                    if is_ambiguous and len(remaining_types) >= 2:
                        # Found an ambiguous combination
                        findings.append({
                            'rule_id': 'method_calls_resolve_ambiguously',
                            'message': f"Method '{method_name}' has ambiguous overloads: "
                                       f"params version at line {params_line} and non-params version at line {non_params_line}.",
                            'file': filename,
                            'line': non_params_line,
                            'severity': 'Major',
                            'property_path': ['source'],
                            'value': lines[non_params_line - 1] if non_params_line <= len(lines) else '',
                            'node': f'ClassDeclaration.{type_name}',
                            'status': 'violation'
                        })
    
    return findings


def check_jwt_weak_signing(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for JWT tokens with weak or missing signatures.
    Detects:
    - SigningCredentials = null (no signature)
    - SecurityAlgorithms.None (no algorithm)
    - SecurityAlgorithms.HmacSha1 (weak algorithm)
    
    Excludes test methods and comments.
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    seen_violations = set()  # Track unique violations to avoid duplicates
    
    def collect_nodes(node, node_list):
        """Recursively collect all nodes"""
        node_list.append(node)
        if 'children' in node and node['children']:
            for child in node['children']:
                collect_nodes(child, node_list)
    
    all_nodes = []
    collect_nodes(ast_tree, all_nodes)
    
    # Weak/null signing patterns (including named parameter syntax with colon)
    weak_patterns = [
        (r'[Ss]igningCredentials\s*[=:]\s*null', 'SigningCredentials set to null - JWT will be unsigned'),
        (r'SecurityAlgorithms\.None\b', 'SecurityAlgorithms.None used - JWT will have no algorithm'),
        (r'SecurityAlgorithms\.HmacSha1\b', 'SecurityAlgorithms.HmacSha1 is a weak algorithm'),
    ]
    
    # Test attributes to exclude
    test_attributes = ['[Test]', '[Fact]', '[TestMethod]', '[Theory]', '[TestFixture]', '[TestClass]']
    
    for node in all_nodes:
        source = node.get('source', '')
        if not source:
            continue
        
        # Check MethodDeclaration nodes for method-level context
        if node.get('node_type') == 'MethodDeclaration':
            # Check if this method has test attributes
            has_test_attribute = any(attr in source for attr in test_attributes)
            if has_test_attribute:
                continue  # Skip test methods entirely
            
            method_name = node.get('name', 'unknown')
            base_line = node.get('lineno', 1)
            
            for pattern, message in weak_patterns:
                for match in re.finditer(pattern, source):
                    # Skip if in a comment
                    match_start = match.start()
                    line_start = source.rfind('\n', 0, match_start) + 1
                    line_content = source[line_start:match_start]
                    if '//' in line_content or line_content.strip().startswith('*'):
                        continue
                    
                    # Calculate line number
                    lines_before = source[:match_start].count('\n')
                    match_line = base_line + lines_before
                    
                    # Create unique key to avoid duplicates
                    violation_key = (match_line, pattern)
                    if violation_key in seen_violations:
                        continue
                    seen_violations.add(violation_key)
                    
                    findings.append({
                        'rule_id': 'jwt_signed_verified_strong',
                        'message': message,
                        'file': filename,
                        'line': match_line,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': match.group(0),
                        'node': f"MethodDeclaration.{method_name}",
                        'status': 'violation'
                    })
    
    return findings


def check_ldap_unauthenticated(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for LDAP connections that are not properly authenticated.
    Detects:
    - AuthenticationTypes.Anonymous
    - AuthenticationTypes.None
    - DirectoryEntry with only path (no credentials)
    
    Excludes test methods and comments.
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    seen_violations = set()  # Track unique violations to avoid duplicates
    
    def collect_nodes(node, node_list):
        """Recursively collect all nodes"""
        node_list.append(node)
        if 'children' in node and node['children']:
            for child in node['children']:
                collect_nodes(child, node_list)
    
    all_nodes = []
    collect_nodes(ast_tree, all_nodes)
    
    # Patterns for unauthenticated LDAP access
    unauthenticated_patterns = [
        (r'AuthenticationTypes\s*\.\s*Anonymous\b', 'LDAP connection using Anonymous authentication is insecure'),
        (r'AuthenticationTypes\s*\.\s*None\b', 'LDAP connection using None authentication is insecure'),
    ]
    
    # Pattern for DirectoryEntry without credentials - only path in constructor
    # Matches: new DirectoryEntry("...") or new DirectoryEntry(variable)
    # Does NOT match: new DirectoryEntry("...", user, pass) or new DirectoryEntry("...", user, pass, authType)
    directory_entry_no_creds_pattern = r'new\s+DirectoryEntry\s*\(\s*(?:"[^"]*"|[a-zA-Z_][a-zA-Z0-9_]*|\$"[^"]*")\s*\)'
    
    # Test attributes to exclude
    test_attributes = ['[Test]', '[Fact]', '[TestMethod]', '[Theory]', '[TestFixture]', '[TestClass]']
    
    for node in all_nodes:
        source = node.get('source', '')
        if not source:
            continue
        
        # Check MethodDeclaration nodes for method-level context
        if node.get('node_type') == 'MethodDeclaration':
            # Check if this method has test attributes
            has_test_attribute = any(attr in source for attr in test_attributes)
            if has_test_attribute:
                continue  # Skip test methods entirely
            
            method_name = node.get('name', 'unknown')
            base_line = node.get('lineno', 1)
            
            # Check for unauthenticated patterns
            for pattern, message in unauthenticated_patterns:
                for match in re.finditer(pattern, source):
                    # Skip if in a comment
                    match_start = match.start()
                    line_start = source.rfind('\n', 0, match_start) + 1
                    line_content = source[line_start:match_start]
                    if '//' in line_content or line_content.strip().startswith('*'):
                        continue
                    
                    # Calculate line number
                    lines_before = source[:match_start].count('\n')
                    match_line = base_line + lines_before
                    
                    # Create unique key to avoid duplicates
                    violation_key = (match_line, pattern)
                    if violation_key in seen_violations:
                        continue
                    seen_violations.add(violation_key)
                    
                    findings.append({
                        'rule_id': 'ldap_connections_authenticated',
                        'message': message,
                        'file': filename,
                        'line': match_line,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': match.group(0),
                        'node': f"MethodDeclaration.{method_name}",
                        'status': 'violation'
                    })
            
            # Check for DirectoryEntry without credentials
            for match in re.finditer(directory_entry_no_creds_pattern, source):
                match_start = match.start()
                
                # Skip if in a comment
                line_start = source.rfind('\n', 0, match_start) + 1
                line_content = source[line_start:match_start]
                if '//' in line_content or line_content.strip().startswith('*'):
                    continue
                
                # Calculate line number
                lines_before = source[:match_start].count('\n')
                match_line = base_line + lines_before
                
                # Create unique key to avoid duplicates
                violation_key = (match_line, 'DirectoryEntry_no_creds')
                if violation_key in seen_violations:
                    continue
                seen_violations.add(violation_key)
                
                findings.append({
                    'rule_id': 'ldap_connections_authenticated',
                    'message': 'DirectoryEntry created without credentials - LDAP connection may be unauthenticated',
                    'file': filename,
                    'line': match_line,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': match.group(0),
                    'node': f"MethodDeclaration.{method_name}",
                    'status': 'violation'
                })
    
    return findings


def check_lines_too_long(ast_tree: Dict, filename: str, max_length: int = 120) -> List[Dict]:
    """
    Check for lines that exceed the maximum length.
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        max_length: Maximum allowed line length (default: 120)
        
    Returns:
        List of violation findings
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, start=1):
        # Skip empty lines
        if not line.strip():
            continue
        
        # Skip using directives
        stripped = line.strip()
        if stripped.startswith('using ') and stripped.endswith(';'):
            continue
        
        # Skip comment lines (single-line, block, and XML documentation)
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*') or stripped.startswith('///'):
            continue
        
        # Skip lines that contain URLs (documentation)
        if 'http://' in line or 'https://' in line:
            continue
        
        # Check if line exceeds max length
        if len(line) > max_length:
            # Truncate value for display
            display_value = line.strip()[:80] + '...' if len(line.strip()) > 80 else line.strip()
            
            findings.append({
                'rule_id': 'lines_too_long',
                'message': f'Line exceeds {max_length} characters (length: {len(line)})',
                'file': filename,
                'line': line_num,
                'severity': 'Minor',
                'property_path': ['source'],
                'value': display_value,
                'node': f"Line.{line_num}",
                'status': 'violation'
            })
    
    return findings


def check_linq_expressions_simplified(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for LINQ expressions that can be simplified.
    Detects:
    - Where().Count() should be Count(predicate)
    - Select(x => x) is redundant identity projection
    - Where().Any() == false should use negation
    
    Excludes test methods and comments.
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    seen_violations = set()
    
    # Get full file source to check for test attributes context
    full_source = ast_tree.get('source', '')
    
    def collect_nodes(node, node_list):
        """Recursively collect all nodes"""
        node_list.append(node)
        if 'children' in node and node['children']:
            for child in node['children']:
                collect_nodes(child, node_list)
    
    all_nodes = []
    collect_nodes(ast_tree, all_nodes)
    
    # Patterns for simplifiable LINQ expressions
    linq_patterns = [
        (r'\.Where\s*\([^)]+\)\s*\.\s*Count\s*\(\s*\)', 'Where().Count() can be simplified to Count(predicate)'),
        (r'\.Select\s*\(\s*(\w+)\s*=>\s*\1\s*\)\s*\.\s*ToList\s*\(\s*\)', 'Select(x => x).ToList() is redundant - use ToList() directly'),
        (r'\.Where\s*\([^)]+\)\s*\.\s*Any\s*\(\s*\)\s*==\s*false', 'Where().Any() == false should use !Any() or !Where().Any()'),
    ]
    
    # Test attributes to exclude
    test_attributes = ['[Test]', '[Fact]', '[TestMethod]', '[Theory]', '[TestFixture]', '[TestClass]']
    
    # Test method name patterns
    test_method_patterns = ['Test_', 'test_', '_Test', 'Fact_', 'fact_', '_Fact', 'Should', 'When_', 'Given_']
    
    def is_test_method(method_name, line_num):
        """Check if a method is a test method by name or surrounding context"""
        # Check method name patterns
        if any(pattern in method_name for pattern in test_method_patterns):
            return True
        
        # Check for test attributes in lines before the method
        if full_source:
            lines = full_source.split('\n')
            # Check the 5 lines before the method start for test attributes
            start_check = max(0, line_num - 6)
            end_check = line_num
            for i in range(start_check, end_check):
                if i < len(lines):
                    line = lines[i]
                    if any(attr in line for attr in test_attributes):
                        return True
        return False
    
    for node in all_nodes:
        source = node.get('source', '')
        if not source:
            continue
        
        # Check MethodDeclaration nodes for method-level context
        if node.get('node_type') == 'MethodDeclaration':
            method_name = node.get('name', 'unknown')
            base_line = node.get('lineno', 1)
            
            # Check if this is a test method
            if is_test_method(method_name, base_line):
                continue  # Skip test methods entirely
            
            # Check if source contains test attributes
            if any(attr in source for attr in test_attributes):
                continue
            
            for pattern, message in linq_patterns:
                for match in re.finditer(pattern, source):
                    match_start = match.start()
                    
                    # Skip if in a comment
                    line_start = source.rfind('\n', 0, match_start) + 1
                    line_content = source[line_start:match_start]
                    if '//' in line_content or line_content.strip().startswith('*'):
                        continue
                    
                    # Calculate line number
                    lines_before = source[:match_start].count('\n')
                    match_line = base_line + lines_before
                    
                    # Create unique key to avoid duplicates
                    violation_key = (match_line, pattern)
                    if violation_key in seen_violations:
                        continue
                    seen_violations.add(violation_key)
                    
                    findings.append({
                        'rule_id': 'linq_expressions_simplified',
                        'message': message,
                        'file': filename,
                        'line': match_line,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': match.group(0),
                        'node': f"MethodDeclaration.{method_name}",
                        'status': 'violation'
                    })
    
    return findings


def check_literal_boolean_assertions(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for literal boolean values in assertions.
    Detects Assert.AreEqual(true/false, ...) which should use Assert.IsTrue/IsFalse.
    
    Handles both single-line and multi-line assertions.
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    seen_violations = set()
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Pattern for Assert.AreEqual with boolean literal as first parameter
    # Handles single-line and multi-line cases with DOTALL flag
    patterns = [
        (r'Assert\.AreEqual\s*\(\s*true\s*,', 'Assert.AreEqual(true, ...) should be replaced with Assert.IsTrue(...)'),
        (r'Assert\.AreEqual\s*\(\s*false\s*,', 'Assert.AreEqual(false, ...) should be replaced with Assert.IsFalse(...)'),
    ]
    
    lines = source.split('\n')
    
    for pattern, message in patterns:
        for match in re.finditer(pattern, source, re.MULTILINE | re.DOTALL):
            match_start = match.start()
            
            # Skip if in a comment
            line_start = source.rfind('\n', 0, match_start) + 1
            line_end = source.find('\n', match_start)
            if line_end == -1:
                line_end = len(source)
            line_content = source[line_start:line_end]
            
            # Check if line starts with comment
            stripped_line = line_content.strip()
            if stripped_line.startswith('//') or stripped_line.startswith('/*') or stripped_line.startswith('*'):
                continue
            
            # Check if the match is within a comment on the same line
            prefix = source[line_start:match_start]
            if '//' in prefix:
                continue
            
            # Calculate line number
            line_num = source[:match_start].count('\n') + 1
            
            # Create unique key to avoid duplicates
            violation_key = (line_num, pattern)
            if violation_key in seen_violations:
                continue
            seen_violations.add(violation_key)
            
            findings.append({
                'rule_id': 'literal_boolean_values_avoided',
                'message': message,
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': match.group(0).strip(),
                'node': f"TestAssertion",
                'status': 'violation'
            })
    
    return findings


def check_literal_suffixes_lowercase(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for lowercase literal suffixes that should be uppercase.
    Detects: l, f, d, m suffixes on numeric literals.
    Should use: L, F, D, M for clarity.
    
    Excludes comments and test methods.
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    seen_violations = set()
    
    # Get full file source
    full_source = ast_tree.get('source', '')
    if not full_source:
        return findings
    
    # Patterns for lowercase suffixes
    # Match: number followed by lowercase l, f, d, m (but not followed by uppercase letter)
    # This catches: 0l, 100l, 1.5f, 10.5m, 0x1Al, etc.
    patterns = [
        (r'\b\d+l\b', 'Use uppercase L suffix instead of lowercase l for long literals'),
        (r'\b0[xX][0-9A-Fa-f]+l\b', 'Use uppercase L suffix instead of lowercase l for hex long literals'),
        (r'\b\d+\.?\d*[eE]?[+-]?\d*f\b', 'Use uppercase F suffix instead of lowercase f for float literals'),
        (r'\b\d+\.?\d*[eE]?[+-]?\d*d\b', 'Use uppercase D suffix instead of lowercase d for double literals'),
        (r'\b\d+\.?\d*m\b', 'Use uppercase M suffix instead of lowercase m for decimal literals'),
        (r'\b\d+ul\b', 'Use uppercase UL suffix instead of lowercase ul for unsigned long literals'),
        (r'\b\d+lu\b', 'Use uppercase LU suffix instead of lowercase lu for long unsigned literals'),
    ]
    
    lines = full_source.split('\n')
    
    # Test attributes and patterns to exclude
    test_attributes = ['[Test]', '[Fact]', '[TestMethod]', '[Theory]', '[TestFixture]', '[TestClass]']
    test_method_patterns = ['Test_', 'test_', '_Test', 'Fact_', 'fact_', '_Fact', 'Should']
    
    def is_in_test_context(line_num):
        """Check if line is in a test method by looking at surrounding context"""
        # Check 10 lines before for test attributes
        start_check = max(0, line_num - 10)
        for i in range(start_check, line_num):
            if i < len(lines):
                line = lines[i]
                if any(attr in line for attr in test_attributes):
                    return True
        return False
    
    for line_num, line in enumerate(lines, start=1):
        # Skip comment lines
        stripped = line.strip()
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*') or stripped.startswith('///'):
            continue
        
        # Skip if in test context
        if is_in_test_context(line_num):
            continue
        
        # Skip logging statements
        if 'Console.' in line or 'Logger.' in line:
            continue
        
        # Skip string literals by removing them first
        # Simple approach: remove content between quotes
        line_no_strings = re.sub(r'"[^"]*"', '""', line)
        
        for pattern, message in patterns:
            for match in re.finditer(pattern, line_no_strings):
                # Skip if match is inside a comment on this line
                match_start = match.start()
                prefix = line_no_strings[:match_start]
                if '//' in prefix:
                    continue
                
                # Create unique key
                violation_key = (line_num, match.group(0))
                if violation_key in seen_violations:
                    continue
                seen_violations.add(violation_key)
                
                findings.append({
                    'rule_id': 'literal_suffixes_upper_case',
                    'message': message,
                    'file': filename,
                    'line': line_num,
                    'severity': 'Minor',
                    'property_path': ['source'],
                    'value': match.group(0),
                    'node': f"LiteralSuffix",
                    'status': 'violation'
                })
    
    return findings


def calculate_cyclomatic_complexity(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Calculate cyclomatic complexity for methods and properties.
    Complexity is calculated by counting decision points:
    - if, else if, else
    - while, for, foreach loops
    - switch cases
    - logical operators (&&, ||)
    - catch clauses
    - conditional operators (?:)
    
    Methods/properties with complexity > 10 are flagged as violations.
    
    Excludes:
    - Test methods ([Test], [Fact], etc.)
    - Generated code
    - Main entry point methods
    - Constructor methods
    - Dispose methods
    - Property getters/setters (simple ones)
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    max_complexity = 10  # Threshold from metadata
    
    # Get full source code
    full_source = ast_tree.get('source', '')
    if not full_source:
        return findings
    
    lines = full_source.split('\n')
    
    # Test attributes to exclude
    test_attributes = ['[Test]', '[Fact]', '[TestMethod]', '[Theory]', '[TestFixture]', '[TestClass]']
    
    def is_test_method(method_start_line):
        """Check if method is a test method by looking for attributes before it"""
        # Check up to 20 lines before method declaration
        start_check = max(0, method_start_line - 20)
        for i in range(start_check, method_start_line):
            if i < len(lines):
                line = lines[i]
                if any(attr in line for attr in test_attributes):
                    return True
        return False
    
    def is_excluded_method(method_name, method_source):
        """Check if method should be excluded"""
        # Exclude constructors
        if method_name in ['Main', 'Dispose', 'Finalize'] or method_name.startswith('ctor'):
            return True
        
        # Exclude simple property getters/setters
        if 'get;' in method_source and 'set;' in method_source:
            return True
        if method_source.strip() in ['get;', 'set;', '{ get; }', '{ set; }', '{ get; set; }']:
            return True
        
        return False
    
    def calculate_complexity(method_source):
        """Calculate cyclomatic complexity for a method"""
        complexity = 1  # Base complexity is 1
        
        # Count if statements (including else if)
        complexity += len(re.findall(r'\bif\s*\(', method_source))
        
        # Count else if (already counted as if, but we count else separately)
        # Count else (but not else if, as it's already counted)
        else_count = len(re.findall(r'\belse\s*(?!\s*if\b)', method_source))
        complexity += else_count
        
        # Count loops
        complexity += len(re.findall(r'\b(while|for|foreach)\s*\(', method_source))
        
        # Count switch cases (each case adds 1)
        switch_cases = re.findall(r'\bcase\s+', method_source)
        complexity += len(switch_cases)
        
        # Count logical operators (&&, ||) - each adds 1
        complexity += len(re.findall(r'\s+&&\s+', method_source))
        complexity += len(re.findall(r'\s+\|\|\s+', method_source))
        
        # Count catch clauses
        complexity += len(re.findall(r'\bcatch\s*\(', method_source))
        
        # Count conditional operators (?:)
        complexity += len(re.findall(r'\?[^:]*:', method_source))
        
        return complexity
    
    # Find all method and property declarations
    # Pattern for method declarations: access_modifier return_type MethodName(...)
    method_pattern = r'(?:public|private|protected|internal|static)\s+(?:async\s+)?(?:\w+\s+)*(\w+)\s*\([^)]*\)\s*{'
    property_pattern = r'(?:public|private|protected|internal|static)\s+(?:\w+\s+)*(\w+)\s*\{'
    
    # Find all methods
    for match in re.finditer(method_pattern, full_source, re.MULTILINE):
        method_name = match.group(1)
        method_start = match.start()
        method_line = full_source[:method_start].count('\n') + 1
        
        # Get method source by finding matching braces
        brace_count = 0
        method_end = method_start
        in_string = False
        escape_next = False
        
        for i in range(method_start, len(full_source)):
            char = full_source[i]
            
            if escape_next:
                escape_next = False
                continue
            
            if char == '\\':
                escape_next = True
                continue
            
            if char == '"' and not escape_next:
                in_string = not in_string
                continue
            
            if not in_string:
                if char == '{':
                    brace_count += 1
                elif char == '}':
                    brace_count -= 1
                    if brace_count == 0:
                        method_end = i + 1
                        break
        
        method_source = full_source[method_start:method_end]
        
        # Skip if test method or excluded
        if is_test_method(method_line) or is_excluded_method(method_name, method_source):
            continue
        
        # Calculate complexity
        complexity = calculate_complexity(method_source)
        
        if complexity > max_complexity:
            findings.append({
                'rule_id': 'methods_properties_too_complex',
                'message': f'Method "{method_name}" has cyclomatic complexity of {complexity}, which exceeds the threshold of {max_complexity}. Consider refactoring to reduce complexity.',
                'file': filename,
                'line': method_line,
                'severity': 'Major',
                'property_path': ['source'],
                'value': method_name,
                'node': f'MethodDeclaration.{method_name}',
                'status': 'violation'
            })
    
    # Find all properties with complex getters/setters
    for match in re.finditer(property_pattern, full_source, re.MULTILINE):
        property_name = match.group(1)
        property_start = match.start()
        property_line = full_source[:property_start].count('\n') + 1
        
        # Get property source
        brace_count = 0
        property_end = property_start
        in_string = False
        escape_next = False
        
        for i in range(property_start, len(full_source)):
            char = full_source[i]
            
            if escape_next:
                escape_next = False
                continue
            
            if char == '\\':
                escape_next = True
                continue
            
            if char == '"' and not escape_next:
                in_string = not in_string
                continue
            
            if not in_string:
                if char == '{':
                    brace_count += 1
                elif char == '}':
                    brace_count -= 1
                    if brace_count == 0:
                        property_end = i + 1
                        break
        
        property_source = full_source[property_start:property_end]
        
        # Skip simple properties
        if is_excluded_method(property_name, property_source):
            continue
        
        # Calculate complexity
        complexity = calculate_complexity(property_source)
        
        if complexity > max_complexity:
            findings.append({
                'rule_id': 'methods_properties_too_complex',
                'message': f'Property "{property_name}" has cyclomatic complexity of {complexity}, which exceeds the threshold of {max_complexity}. Consider refactoring to reduce complexity.',
                'file': filename,
                'line': property_line,
                'severity': 'Major',
                'property_path': ['source'],
                'value': property_name,
                'node': f'PropertyDeclaration.{property_name}',
                'status': 'violation'
            })
    
    return findings


def check_dispose_method_implements_idisposable(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check that methods named "Dispose" properly implement IDisposable.Dispose.
    
    This rule ensures that methods named 'Dispose' are only used for proper IDisposable 
    implementation to prevent confusion and maintain the dispose pattern convention.
    
    Should trigger on:
    - Public/protected/internal Dispose methods in classes that don't implement IDisposable
    - Non-static Dispose methods that aren't part of IDisposable pattern
    
    Should NOT trigger on:
    - Classes that implement IDisposable (directly or through inheritance)
    - Static Dispose utility methods
    - Private Dispose helper methods
    - Override methods inheriting dispose pattern
    - Abstract Dispose methods in base classes
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    
    # Get full source code
    full_source = ast_tree.get('source', '')
    if not full_source:
        return findings
    
    lines = full_source.split('\n')
    
    def find_class_for_method(method_start_pos):
        """Find the class declaration that contains this method"""
        # Look backwards from method position to find the containing class
        source_before = full_source[:method_start_pos]
        
        # Find the last class declaration before this method
        class_pattern = r'\b(?:public|private|protected|internal|abstract|sealed|static)?\s*(?:partial\s+)?class\s+(\w+)(?:\s*:\s*([^{]+))?\s*\{'
        
        matches = list(re.finditer(class_pattern, source_before, re.MULTILINE))
        if not matches:
            return None, None
        
        # Get the last (most recent) class before the method
        last_class = matches[-1]
        class_name = last_class.group(1)
        inheritance = last_class.group(2) if last_class.group(2) else ""
        
        return class_name, inheritance.strip()
    
    def class_implements_idisposable(class_name, inheritance):
        """Check if class implements IDisposable"""
        if not inheritance:
            return False
        
        # Check for IDisposable in inheritance list
        # Handle both direct implementation and inheritance
        idisposable_patterns = [
            r'\bIDisposable\b',
            r':\s*IDisposable\b',
            r',\s*IDisposable\b'
        ]
        
        for pattern in idisposable_patterns:
            if re.search(pattern, inheritance):
                return True
        
        # Check if inheriting from a class that might implement IDisposable
        # This is a simple check - in practice, you'd need full type resolution
        if 'Disposable' in inheritance or 'Dispose' in inheritance:
            # Could be inheriting from a disposable base class
            return True
        
        return False
    
    def is_static_method(method_source):
        """Check if method is static"""
        return 'static' in method_source.split('{')[0]
    
    def is_private_method(method_source):
        """Check if method is private"""
        method_declaration = method_source.split('{')[0]
        return 'private' in method_declaration and 'public' not in method_declaration and 'protected' not in method_declaration and 'internal' not in method_declaration
    
    def is_override_method(method_source):
        """Check if method is override"""
        method_declaration = method_source.split('{')[0]
        return 'override' in method_declaration
    
    def is_abstract_method(method_source):
        """Check if method is abstract"""
        method_declaration = method_source.split('{')[0]
        return 'abstract' in method_declaration
    
    # Find all Dispose method declarations
    # Pattern: access_modifier return_type? Dispose(parameters)
    # More flexible pattern that handles various method signatures
    # Match: public/protected/internal void Dispose() or public void Dispose()
    dispose_pattern = r'\b(public|protected|internal)\s+(?:static\s+)?(?:virtual\s+)?(?:override\s+)?(?:abstract\s+)?(?:async\s+)?void\s+Dispose\s*\([^)]*\)'
    
    for match in re.finditer(dispose_pattern, full_source, re.MULTILINE):
        method_start = match.start()
        method_line = full_source[:method_start].count('\n') + 1
        
        # Find the opening brace (might be on same line or next line)
        brace_start = method_start
        while brace_start < len(full_source) and full_source[brace_start] != '{':
            brace_start += 1
        
        if brace_start >= len(full_source):
            continue  # No opening brace found
        
        # Get method source by finding matching braces
        brace_count = 0
        method_end = brace_start
        in_string = False
        escape_next = False
        
        for i in range(brace_start, len(full_source)):
            char = full_source[i]
            
            if escape_next:
                escape_next = False
                continue
            
            if char == '\\':
                escape_next = True
                continue
            
            if char == '"' and not escape_next:
                in_string = not in_string
                continue
            
            if not in_string:
                if char == '{':
                    brace_count += 1
                elif char == '}':
                    brace_count -= 1
                    if brace_count == 0:
                        method_end = i + 1
                        break
        
        if brace_count != 0:
            continue  # Unmatched braces, skip
        
        method_source = full_source[method_start:method_end]
        
        # Skip static methods (utility methods)
        if is_static_method(method_source):
            continue
        
        # Skip private methods (helper methods)
        if is_private_method(method_source):
            continue
        
        # Skip override methods (inheriting dispose pattern)
        if is_override_method(method_source):
            continue
        
        # Skip abstract methods (base class pattern)
        if is_abstract_method(method_source):
            continue
        
        # Find the containing class
        class_name, inheritance = find_class_for_method(method_start)
        
        if not class_name:
            # Can't determine class context, skip
            continue
        
        # Check if class implements IDisposable
        if class_implements_idisposable(class_name, inheritance):
            # Class implements IDisposable, this is compliant
            continue
        
        # This is a violation: Dispose method in class that doesn't implement IDisposable
        findings.append({
            'rule_id': 'methods_named_dispose_implement',
            'message': f'Method "Dispose" in class "{class_name}" should implement IDisposable.Dispose. Classes with Dispose methods must implement IDisposable to follow the dispose pattern convention.',
            'file': filename,
            'line': method_line,
            'severity': 'Major',
            'property_path': ['source'],
            'value': 'Dispose',
            'node': f'MethodDeclaration.Dispose',
            'status': 'violation'
        })
    
    return findings


def check_methods_avoid_identical_implementations(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for methods with identical implementations.
    
    This rule detects methods with identical implementations that indicate code duplication.
    It compares normalized method bodies to find exact duplicates that should be refactored
    into common methods or helper functions.
    
    Should trigger on:
    - Methods with identical multi-line implementations
    - Methods with same logic but different parameter names
    - Methods returning same complex calculations
    - Methods with duplicate business logic
    
    Should NOT trigger on:
    - Override methods (required to implement same pattern)
    - Interface implementations
    - Virtual/abstract methods
    - External methods (extern keyword)
    - Test methods ([Test], [Fact], etc.)
    - Simple getters/setters (single line returns)
    - Methods with bodies under 10 characters
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    
    # Get full source code
    full_source = ast_tree.get('source', '')
    if not full_source:
        return findings
    
    lines = full_source.split('\n')
    
    def normalize_method_body(body):
        """Normalize method body by removing whitespace, comments, and parameter name differences"""
        # Remove single-line comments
        normalized = re.sub(r'//.*$', '', body, flags=re.MULTILINE)
        # Remove multi-line comments
        normalized = re.sub(r'/\*.*?\*/', '', normalized, flags=re.DOTALL)
        # Remove all whitespace
        normalized = re.sub(r'\s+', '', normalized)
        # Remove parameter names from method calls (normalize variable names)
        # This is a simple approach - in practice, you'd want more sophisticated normalization
        return normalized
    
    def extract_method_body(method_source):
        """Extract just the method body (content between braces)"""
        # Find first opening brace
        brace_start = method_source.find('{')
        if brace_start == -1:
            return ""
        
        # Find matching closing brace
        brace_count = 0
        in_string = False
        escape_next = False
        
        for i in range(brace_start, len(method_source)):
            char = method_source[i]
            
            if escape_next:
                escape_next = False
                continue
            
            if char == '\\':
                escape_next = True
                continue
            
            if char == '"' and not escape_next:
                in_string = not in_string
                continue
            
            if not in_string:
                if char == '{':
                    brace_count += 1
                elif char == '}':
                    brace_count -= 1
                    if brace_count == 0:
                        # Extract body content (excluding the braces)
                        return method_source[brace_start + 1:i]
        
        return ""
    
    def is_excluded_method(method_source, method_name):
        """Check if method should be excluded from duplicate detection"""
        method_declaration = method_source.split('{')[0] if '{' in method_source else method_source
        
        # Exclude override methods
        if 'override' in method_declaration:
            return True
        
        # Exclude virtual/abstract methods
        if 'virtual' in method_declaration or 'abstract' in method_declaration:
            return True
        
        # Exclude extern methods
        if 'extern' in method_declaration:
            return True
        
        # Exclude test methods (check for attributes before method)
        method_start_line = full_source.find(method_declaration)
        if method_start_line > 0:
            # Check 20 lines before for test attributes
            source_before = full_source[:method_start_line]
            lines_before = source_before.split('\n')
            for line in lines_before[-20:]:
                if any(attr in line for attr in ['[Test]', '[Fact]', '[TestMethod]', '[Theory]']):
                    return True
        
        # Exclude simple getters/setters (single line returns)
        body = extract_method_body(method_source)
        normalized_body = normalize_method_body(body)
        # If body is very short (under 10 chars after normalization), likely a simple getter/setter
        if len(normalized_body) < 10:
            return True
        
        return False
    
    # Find all method declarations
    # Pattern: access_modifier return_type MethodName(parameters)
    method_pattern = r'\b(public|protected|internal|private)\s+(?:static\s+)?(?:virtual\s+)?(?:override\s+)?(?:abstract\s+)?(?:async\s+)?(?:\w+\s+)+(\w+)\s*\([^)]*\)\s*'
    
    methods = []
    
    for match in re.finditer(method_pattern, full_source, re.MULTILINE):
        method_name = match.group(2)
        method_start = match.start()
        method_line = full_source[:method_start].count('\n') + 1
        
        # Get method source by finding matching braces
        brace_start = method_start
        while brace_start < len(full_source) and full_source[brace_start] != '{':
            brace_start += 1
        
        if brace_start >= len(full_source):
            continue  # No opening brace found
        
        # Get method source by finding matching braces
        brace_count = 0
        method_end = brace_start
        in_string = False
        escape_next = False
        
        for i in range(brace_start, len(full_source)):
            char = full_source[i]
            
            if escape_next:
                escape_next = False
                continue
            
            if char == '\\':
                escape_next = True
                continue
            
            if char == '"' and not escape_next:
                in_string = not in_string
                continue
            
            if not in_string:
                if char == '{':
                    brace_count += 1
                elif char == '}':
                    brace_count -= 1
                    if brace_count == 0:
                        method_end = i + 1
                        break
        
        if brace_count != 0:
            continue  # Unmatched braces, skip
        
        method_source = full_source[method_start:method_end]
        
        # Skip excluded methods
        if is_excluded_method(method_source, method_name):
            continue
        
        # Extract and normalize method body
        method_body = extract_method_body(method_source)
        normalized_body = normalize_method_body(method_body)
        
        # Skip if body is too short
        if len(normalized_body) < 10:
            continue
        
        methods.append({
            'name': method_name,
            'source': method_source,
            'body': method_body,
            'normalized_body': normalized_body,
            'line': method_line
        })
    
    # Compare all methods to find duplicates
    seen_bodies = {}
    for i, method1 in enumerate(methods):
        normalized = method1['normalized_body']
        
        # Check if we've seen this normalized body before
        if normalized in seen_bodies:
            # Found a duplicate
            original_method = seen_bodies[normalized]
            
            # Report both methods (original and duplicate)
            if original_method['line'] not in [f['line'] for f in findings if f.get('value') == original_method['name']]:
                findings.append({
                    'rule_id': 'methods_avoid_having_identical',
                    'message': f'Method "{original_method["name"]}" has an identical implementation to another method. Consider refactoring to eliminate duplication.',
                    'file': filename,
                    'line': original_method['line'],
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': original_method['name'],
                    'node': f'MethodDeclaration.{original_method["name"]}',
                    'status': 'violation'
                })
            
            findings.append({
                'rule_id': 'methods_avoid_having_identical',
                'message': f'Method "{method1["name"]}" has an identical implementation to method "{original_method["name"]}" (line {original_method["line"]}). Consider refactoring to eliminate duplication.',
                'file': filename,
                'line': method1['line'],
                'severity': 'Major',
                'property_path': ['source'],
                'value': method1['name'],
                'node': f'MethodDeclaration.{method1["name"]}',
                'status': 'violation'
            })
        else:
            # First time seeing this body, store it
            seen_bodies[normalized] = method1
    
    return findings


def check_methods_avoid_too_many_parameters(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for methods and constructors that have too many parameters.
    
    Methods with a long parameter list (>6) are difficult to use because maintainers
    must figure out the role of each parameter and keep track of their position.
    
    Should trigger on:
    - Methods with more than 6 parameters
    - Constructors with more than 6 parameters
    
    Should NOT trigger on:
    - Methods with 6 or fewer parameters
    - Override methods (may need to match base signature)
    - Interface implementations (must match interface)
    - Event handlers (standard signature)
    - Main method (standard signature)
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    max_parameters = 6  # Threshold: more than 6 parameters is too many
    
    # Get full source code
    full_source = ast_tree.get('source', '')
    if not full_source:
        return findings
    
    def count_parameters(parameter_list):
        """Count the number of parameters in a parameter list string"""
        if not parameter_list or parameter_list.strip() == '':
            return 0
        
        # Remove comments
        param_list = re.sub(r'//.*$', '', parameter_list, flags=re.MULTILINE)
        param_list = re.sub(r'/\*.*?\*/', '', param_list, flags=re.DOTALL)
        
        # Split by comma, but be careful with generic types and nested parentheses
        # Simple approach: count commas + 1, but need to handle generics and nested structures
        param_count = 0
        depth = 0  # Track nesting depth for generics < >
        paren_depth = 0  # Track parentheses depth
        bracket_depth = 0  # Track bracket depth []
        in_string = False
        escape_next = False
        
        i = 0
        while i < len(param_list):
            char = param_list[i]
            
            if escape_next:
                escape_next = False
                i += 1
                continue
            
            if char == '\\':
                escape_next = True
                i += 1
                continue
            
            if char == '"' and not escape_next:
                in_string = not in_string
                i += 1
                continue
            
            if not in_string:
                if char == '<':
                    depth += 1
                elif char == '>':
                    depth -= 1
                elif char == '(':
                    paren_depth += 1
                elif char == ')':
                    paren_depth -= 1
                elif char == '[':
                    bracket_depth += 1
                elif char == ']':
                    bracket_depth -= 1
                elif char == ',' and depth == 0 and paren_depth == 0 and bracket_depth == 0:
                    param_count += 1
            
            i += 1
        
        # Number of parameters = number of commas + 1 (if not empty)
        if param_list.strip():
            return param_count + 1
        return 0
    
    def is_excluded_method(method_declaration, method_name):
        """Check if method should be excluded from parameter count check"""
        # Exclude Main method (standard signature)
        if method_name == 'Main' and 'static' in method_declaration:
            return True
        
        # Exclude override methods (may need to match base signature)
        if 'override' in method_declaration:
            return True
        
        # Exclude interface implementations (check for explicit interface implementation)
        if '.' in method_name or 'interface' in method_declaration.lower():
            return True
        
        # Exclude event handlers (standard signature pattern)
        if 'EventHandler' in method_declaration or 'EventArgs' in method_declaration:
            return True
        
        return False
    
    # Find all method declarations
    # Pattern: access_modifier return_type? MethodName(parameters)
    method_pattern = r'\b(public|protected|internal|private)\s+(?:static\s+)?(?:virtual\s+)?(?:override\s+)?(?:abstract\s+)?(?:async\s+)?(?:\w+\s+)*(\w+)\s*\(([^)]*)\)'
    
    for match in re.finditer(method_pattern, full_source, re.MULTILINE):
        method_name = match.group(2)
        parameter_list = match.group(3)
        method_start = match.start()
        method_line = full_source[:method_start].count('\n') + 1
        
        # Get method declaration for exclusion checks
        method_declaration = full_source[method_start:method_start + 200]  # Get first 200 chars
        
        # Skip excluded methods
        if is_excluded_method(method_declaration, method_name):
            continue
        
        # Count parameters
        param_count = count_parameters(parameter_list)
        
        if param_count > max_parameters:
            findings.append({
                'rule_id': 'methods_avoid_having_too',
                'message': f'Method "{method_name}" has {param_count} parameters, which exceeds the recommended maximum of {max_parameters}. Consider refactoring to use parameter objects or split into smaller methods.',
                'file': filename,
                'line': method_line,
                'severity': 'Major',
                'property_path': ['source'],
                'value': method_name,
                'node': f'MethodDeclaration.{method_name}',
                'status': 'violation'
            })
    
    # Find all constructor declarations
    # Pattern: access_modifier ClassName(parameters)
    constructor_pattern = r'\b(public|protected|internal|private)\s+(\w+)\s*\(([^)]*)\)'
    
    for match in re.finditer(constructor_pattern, full_source, re.MULTILINE):
        class_name = match.group(2)
        parameter_list = match.group(3)
        constructor_start = match.start()
        constructor_line = full_source[:constructor_start].count('\n') + 1
        
        # Count parameters
        param_count = count_parameters(parameter_list)
        
        if param_count > max_parameters:
            findings.append({
                'rule_id': 'methods_avoid_having_too',
                'message': f'Constructor "{class_name}" has {param_count} parameters, which exceeds the recommended maximum of {max_parameters}. Consider refactoring to use parameter objects or builder pattern.',
                'file': filename,
                'line': constructor_line,
                'severity': 'Major',
                'property_path': ['source'],
                'value': class_name,
                'node': f'ConstructorDeclaration.{class_name}',
                'status': 'violation'
            })
    
    return findings


def check_methods_named_according_their_synchro(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check that methods are named according to their synchronicity.
    
    According to the Task-based Asynchronous Pattern (TAP):
    - Methods returning Task or Task<T> should use the "Async" suffix
    - Methods that do not return Task should NOT have an "Async" suffix
    
    Should trigger on:
    - Methods returning Task/Task<T> without "Async" suffix
    - Methods with "Async" suffix that don't return Task/Task<T>
    
    Should NOT trigger on:
    - Methods returning Task/Task<T> with "Async" suffix (compliant)
    - Methods not returning Task without "Async" suffix (compliant)
    - Override methods (may need to match base signature)
    - Interface implementations (must match interface)
    - Event handlers
    - Test methods
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    
    # Get full source code
    full_source = ast_tree.get('source', '')
    if not full_source:
        return findings
    
    def returns_task(return_type):
        """Check if return type is Task or Task<T>"""
        if not return_type:
            return False
        
        # Normalize return type (remove whitespace)
        normalized = re.sub(r'\s+', '', return_type)
        
        # Check for Task or Task<T>
        # Pattern: Task or Task<...>
        task_patterns = [
            r'^Task$',
            r'^Task<',
            r'^System\.Threading\.Tasks\.Task$',
            r'^System\.Threading\.Tasks\.Task<',
            r'^global::System\.Threading\.Tasks\.Task$',
            r'^global::System\.Threading\.Tasks\.Task<'
        ]
        
        for pattern in task_patterns:
            if re.match(pattern, normalized):
                return True
        
        return False
    
    def has_async_suffix(method_name):
        """Check if method name ends with Async"""
        return method_name.endswith("Async") or method_name.endswith("async")
    
    def is_excluded_method(method_declaration, method_name):
        """Check if method should be excluded from naming check"""
        # Exclude override methods (may need to match base signature)
        if 'override' in method_declaration:
            return True
        
        # Exclude interface implementations (check for explicit interface implementation)
        if '.' in method_name or 'interface' in method_declaration.lower():
            return True
        
        # Exclude event handlers
        if 'EventHandler' in method_declaration or 'EventArgs' in method_declaration:
            return True
        
        # Exclude test methods (check for attributes before method)
        method_start_pos = full_source.find(method_declaration[:50])  # Find method start
        if method_start_pos > 0:
            source_before = full_source[:method_start_pos]
            lines_before = source_before.split('\n')
            for line in lines_before[-20:]:
                if any(attr in line for attr in ['[Test]', '[Fact]', '[TestMethod]', '[Theory]']):
                    return True
        
        return False
    
    # Find all method declarations
    # Pattern: access_modifier return_type MethodName(parameters)
    # More flexible pattern to capture return type and method name
    method_pattern = r'\b(public|protected|internal|private)\s+(?:static\s+)?(?:virtual\s+)?(?:override\s+)?(?:abstract\s+)?(?:async\s+)?(\w+(?:<[^>]+>)?(?:\s*\.\s*\w+(?:<[^>]+>)?)*)\s+(\w+)\s*\([^)]*\)'
    
    for match in re.finditer(method_pattern, full_source, re.MULTILINE):
        return_type = match.group(2)
        method_name = match.group(3)
        method_start = match.start()
        method_line = full_source[:method_start].count('\n') + 1
        
        # Get method declaration for exclusion checks
        method_declaration = full_source[method_start:method_start + 300]  # Get first 300 chars
        
        # Skip excluded methods
        if is_excluded_method(method_declaration, method_name):
            continue
        
        # Check if method returns Task
        returns_task_type = returns_task(return_type)
        
        # Check if method has Async suffix
        has_async = has_async_suffix(method_name)
        
        # Violation 1: Returns Task but missing Async suffix
        if returns_task_type and not has_async:
            findings.append({
                'rule_id': 'methods_named_according_their',
                'message': f'Method "{method_name}" returns Task or Task<T> but is missing the "Async" suffix. According to TAP, async methods should be named with the "Async" suffix.',
                'file': filename,
                'line': method_line,
                'severity': 'Major',
                'property_path': ['source'],
                'value': method_name,
                'node': f'MethodDeclaration.{method_name}',
                'status': 'violation'
            })
        
        # Violation 2: Has Async suffix but doesn't return Task
        if has_async and not returns_task_type:
            findings.append({
                'rule_id': 'methods_named_according_their',
                'message': f'Method "{method_name}" has the "Async" suffix but does not return Task or Task<T>. Methods that do not return Task should not have the "Async" suffix.',
                'file': filename,
                'line': method_line,
                'severity': 'Major',
                'property_path': ['source'],
                'value': method_name,
                'node': f'MethodDeclaration.{method_name}',
                'status': 'violation'
            })
    
    return findings


def check_methods_should_not_be_empty(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for empty methods that have no meaningful implementation.
    
    An empty method is generally considered bad practice and can lead to confusion,
    readability, and maintenance issues. Empty methods bring no functionality and
    are misleading to others.
    
    Should trigger on:
    - Methods with empty bodies (only braces)
    - Methods with only comments
    - Methods with only whitespace
    
    Should NOT trigger on:
    - Abstract methods (no body)
    - Methods that throw exceptions (NotImplementedException, etc.)
    - Methods that call base implementations
    - Methods with actual implementation
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    
    # Get full source code
    full_source = ast_tree.get('source', '')
    if not full_source:
        return findings
    
    def is_empty_body(body):
        """Check if method body is empty (only whitespace/comments)"""
        if not body:
            return True
        
        # Remove all comments
        # Remove single-line comments
        body_no_comments = re.sub(r'//.*$', '', body, flags=re.MULTILINE)
        # Remove multi-line comments
        body_no_comments = re.sub(r'/\*.*?\*/', '', body_no_comments, flags=re.DOTALL)
        # Remove XML documentation comments
        body_no_comments = re.sub(r'///.*$', '', body_no_comments, flags=re.MULTILINE)
        
        # Remove all whitespace
        body_clean = re.sub(r'\s+', '', body_no_comments)
        
        # If only braces remain or nothing, it's empty
        return body_clean == '' or body_clean == '{}'
    
    def has_meaningful_content(body):
        """Check if body has meaningful content (not just comments)"""
        if not body:
            return False
        
        # Remove comments
        body_no_comments = re.sub(r'//.*$', '', body, flags=re.MULTILINE)
        body_no_comments = re.sub(r'/\*.*?\*/', '', body_no_comments, flags=re.DOTALL)
        body_no_comments = re.sub(r'///.*$', '', body_no_comments, flags=re.MULTILINE)
        
        # Remove whitespace
        body_clean = re.sub(r'\s+', '', body_no_comments)
        
        # Check for meaningful content
        # Exclude just braces
        if body_clean == '' or body_clean == '{}':
            return False
        
        # Check for common patterns that indicate non-empty methods
        meaningful_patterns = [
            r'throw\s+',
            r'return\s+',
            r'base\.',
            r'Console\.',
            r'System\.',
            r'await\s+',
            r'if\s*\(',
            r'for\s*\(',
            r'while\s*\(',
            r'foreach\s*\(',
            r'=\s*[^;]+;',  # Assignment
            r'\.\w+\s*\(',  # Method call
        ]
        
        for pattern in meaningful_patterns:
            if re.search(pattern, body_clean):
                return True
        
        return False
    
    def is_abstract_method(method_declaration):
        """Check if method is abstract (no body)"""
        return 'abstract' in method_declaration and '{' not in method_declaration.split('abstract')[1].split(';')[0]
    
    # Find all method declarations
    # Pattern: access_modifier return_type MethodName(parameters) { body }
    method_pattern = r'\b(public|protected|internal|private)\s+(?:static\s+)?(?:virtual\s+)?(?:override\s+)?(?:abstract\s+)?(?:async\s+)?(?:\w+\s+)*(\w+)\s*\([^)]*\)\s*\{'
    
    for match in re.finditer(method_pattern, full_source, re.MULTILINE):
        method_name = match.group(2)
        method_start = match.start()
        method_line = full_source[:method_start].count('\n') + 1
        
        # Get method declaration for exclusion checks
        method_declaration = full_source[method_start:method_start + 200]
        
        # Skip abstract methods (they don't have bodies)
        if is_abstract_method(method_declaration):
            continue
        
        # Find the opening brace
        brace_start = method_start
        while brace_start < len(full_source) and full_source[brace_start] != '{':
            brace_start += 1
        
        if brace_start >= len(full_source):
            continue  # No opening brace found
        
        # Get method body by finding matching braces
        brace_count = 0
        method_end = brace_start
        in_string = False
        escape_next = False
        
        for i in range(brace_start, len(full_source)):
            char = full_source[i]
            
            if escape_next:
                escape_next = False
                continue
            
            if char == '\\':
                escape_next = True
                continue
            
            if char == '"' and not escape_next:
                in_string = not in_string
                continue
            
            if not in_string:
                if char == '{':
                    brace_count += 1
                elif char == '}':
                    brace_count -= 1
                    if brace_count == 0:
                        method_end = i + 1
                        break
        
        if brace_count != 0:
            continue  # Unmatched braces, skip
        
        # Extract method body (content between braces)
        method_body = full_source[brace_start + 1:method_end - 1]
        
        # Check if body is empty
        if is_empty_body(method_body) and not has_meaningful_content(method_body):
            findings.append({
                'rule_id': 'methods_empty',
                'message': f'Method "{method_name}" is empty and has no meaningful implementation. Empty methods are misleading and should either be removed, throw NotImplementedException, or provide actual implementation.',
                'file': filename,
                'line': method_line,
                'severity': 'Major',
                'property_path': ['source'],
                'value': method_name,
                'node': f'MethodDeclaration.{method_name}',
                'status': 'violation'
            })
    
    return findings


def check_methods_should_not_return_constants(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for methods that only return constant values instead of having actual logic.
    
    There's no point in forcing the overhead of a method call for a method that always
    returns the same constant value. Even worse, the fact that a method call must be
    made will likely mislead developers who call the method thinking that something
    more is done. Declare a constant instead.
    
    This rule raises an issue on methods that contain only one statement: the return
    of a constant value.
    
    Should trigger on:
    - Methods with only a single return statement returning a literal constant
    - Methods returning numeric literals, string literals, boolean literals, null, etc.
    
    Should NOT trigger on:
    - Methods with multiple statements
    - Methods returning computed values (expressions)
    - Methods returning field/property values
    - Methods returning method call results
    - Abstract methods
    - Override methods (may need to match base signature)
    
    Args:
        ast_tree: Full AST tree
        filename: Source file name
        
    Returns:
        List of violation findings
    """
    findings = []
    
    # Get full source code
    full_source = ast_tree.get('source', '')
    if not full_source:
        return findings
    
    def is_constant_value(return_value):
        """Check if return value is a constant literal"""
        if not return_value:
            return False
        
        # Remove whitespace
        value = return_value.strip()
        
        # Check for literal constants
        # Numeric literals
        if re.match(r'^-?\d+(\.\d+)?([eE][+-]?\d+)?[fFdDmMlL]?$', value):
            return True
        
        # String literals
        if re.match(r'^@"[^"]*"$', value) or re.match(r'^"[^"]*"$', value):
            return True
        
        # Character literals
        if re.match(r"^'[^']*'$", value):
            return True
        
        # Boolean literals
        if value in ['true', 'false', 'True', 'False']:
            return True
        
        # Null literal
        if value in ['null', 'Null']:
            return True
        
        # Default keyword
        if value == 'default':
            return True
        
        return False
    
    def is_single_return_constant(method_body):
        """Check if method body contains only a single return statement with a constant"""
        if not method_body:
            return False, None
        
        # Remove comments
        body_no_comments = re.sub(r'//.*$', '', method_body, flags=re.MULTILINE)
        body_no_comments = re.sub(r'/\*.*?\*/', '', body_no_comments, flags=re.DOTALL)
        body_no_comments = re.sub(r'///.*$', '', body_no_comments, flags=re.MULTILINE)
        
        # Remove whitespace
        body_clean = re.sub(r'\s+', ' ', body_no_comments).strip()
        
        # Check for single return statement pattern: return <constant>;
        # Pattern: return <value>;
        return_pattern = r'^return\s+([^;]+);\s*$'
        match = re.match(return_pattern, body_clean, re.IGNORECASE)
        
        if match:
            return_value = match.group(1).strip()
            # Check if it's a constant
            if is_constant_value(return_value):
                return True, return_value
        
        return False, None
    
    def is_excluded_method(method_declaration, method_name):
        """Check if method should be excluded from constant return check"""
        # Exclude abstract methods (no body)
        if 'abstract' in method_declaration and '{' not in method_declaration.split('abstract')[1].split(';')[0]:
            return True
        
        # Exclude override methods (may need to match base signature)
        if 'override' in method_declaration:
            return True
        
        # Exclude interface implementations (check for explicit interface implementation)
        if '.' in method_name or 'interface' in method_declaration.lower():
            return True
        
        return False
    
    # Find all method declarations
    # Pattern: access_modifier return_type MethodName(parameters) { body }
    method_pattern = r'\b(public|protected|internal|private)\s+(?:static\s+)?(?:virtual\s+)?(?:override\s+)?(?:abstract\s+)?(?:async\s+)?(?:\w+\s+)*(\w+)\s*\([^)]*\)\s*\{'
    
    for match in re.finditer(method_pattern, full_source, re.MULTILINE):
        method_name = match.group(2)
        method_start = match.start()
        method_line = full_source[:method_start].count('\n') + 1
        
        # Get method declaration for exclusion checks
        method_declaration = full_source[method_start:method_start + 200]
        
        # Skip excluded methods
        if is_excluded_method(method_declaration, method_name):
            continue
        
        # Find the opening brace
        brace_start = method_start
        while brace_start < len(full_source) and full_source[brace_start] != '{':
            brace_start += 1
        
        if brace_start >= len(full_source):
            continue  # No opening brace found
        
        # Get method body by finding matching braces
        brace_count = 0
        method_end = brace_start
        in_string = False
        escape_next = False
        
        for i in range(brace_start, len(full_source)):
            char = full_source[i]
            
            if escape_next:
                escape_next = False
                continue
            
            if char == '\\':
                escape_next = True
                continue
            
            if char == '"' and not escape_next:
                in_string = not in_string
                continue
            
            if not in_string:
                if char == '{':
                    brace_count += 1
                elif char == '}':
                    brace_count -= 1
                    if brace_count == 0:
                        method_end = i + 1
                        break
        
        if brace_count != 0:
            continue  # Unmatched braces, skip
        
        # Extract method body (content between braces)
        method_body = full_source[brace_start + 1:method_end - 1]
        
        # Check if method only returns a constant
        is_constant, constant_value = is_single_return_constant(method_body)
        
        if is_constant:
            findings.append({
                'rule_id': 'methods_return_constants',
                'message': f'Method "{method_name}" only returns a constant value ({constant_value}). Consider declaring a constant instead of using a method.',
                'file': filename,
                'line': method_line,
                'severity': 'Major',
                'property_path': ['source'],
                'value': method_name,
                'node': f'MethodDeclaration.{method_name}',
                'status': 'violation'
            })
    
    return findings


def check_nameof_preferred(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for hardcoded parameter names in strings that should use nameof().
    
    This rule detects when a string literal in a throw statement contains the name
    of one of the method parameters. Instead of hardcoding the parameter name,
    nameof() should be used.
    
    Noncompliant:
        throw new ArgumentException("Bad argument", "someParameter");
        throw new Exception("anotherParam should not be null");
    
    Compliant:
        throw new ArgumentException("Bad argument", nameof(someParameter));
        throw new Exception($"{nameof(anotherParam)} should not be null");
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    source_clean = re.sub(r'//.*$', '', source, flags=re.MULTILINE)
    source_clean = re.sub(r'/\*.*?\*/', '', source_clean, flags=re.DOTALL)
    
    # Pattern to match method declarations with parameters
    # Matches: [modifiers] return_type method_name(parameters)
    method_pattern = r'(?:public|private|protected|internal|static|async|virtual|override|abstract|\s)*[\w<>\[\],\s]+\s+(\w+)\s*\(([^)]*)\)'
    
    i = 0
    while i < len(lines):
        line = lines[i]
        line_clean = line.strip()
        
        # Skip test methods and attributes
        if re.search(r'\[(?:Test|Fact|TestMethod|Theory|DataTestMethod)\]', line_clean, re.IGNORECASE):
            i += 1
            continue
        
        # Check for method declaration
        method_match = re.search(method_pattern, line_clean)
        if method_match:
            method_name = method_match.group(1)
            params_str = method_match.group(2).strip()
            
            # Extract parameter names
            param_names = []
            if params_str:
                for param in params_str.split(','):
                    param = param.strip()
                    if param:
                        # Extract parameter name (last identifier before optional default value)
                        # Handle: type name, type name = value, ref/out type name, etc.
                        param_parts = re.split(r'\s*=\s*', param)[0]  # Remove default value
                        param_parts = re.split(r'\s+', param_parts.strip())
                        # Find the last word that looks like an identifier
                        for part in reversed(param_parts):
                            if re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', part) and part not in ['ref', 'out', 'in', 'params']:
                                param_names.append(part)
                                break
            
            if not param_names:
                i += 1
                continue
            
            # Find method body - track braces to find the end
            brace_count = 0
            method_start_line = i
            method_body_start_line = i
            in_method = False
            
            # Find opening brace and method end
            for j in range(i, len(lines)):
                current_line = lines[j]
                brace_count += current_line.count('{') - current_line.count('}')
                
                if '{' in current_line and not in_method:
                    in_method = True
                    method_body_start_line = j
                
                if in_method and brace_count == 0 and j > i:
                    method_end_line = j
                    break
            else:
                # Method body not found or incomplete
                i += 1
                continue
            
            # Get method body lines (from opening brace to closing brace)
            method_body_lines = lines[method_body_start_line:method_end_line + 1]
            method_body = '\n'.join(method_body_lines)
            method_body_clean = re.sub(r'//.*$', '', method_body, flags=re.MULTILINE)
            method_body_clean = re.sub(r'/\*.*?\*/', '', method_body_clean, flags=re.DOTALL)
            
            # Check for throw statements with string literals containing parameter names
            # Pattern to match throw statements - matches Exception or *Exception
            throw_pattern = r'throw\s+new\s+(?:\w+)?Exception\s*\([^)]*\)'
            
            for throw_match in re.finditer(throw_pattern, method_body_clean, re.IGNORECASE):
                throw_statement = throw_match.group(0)
                throw_start_in_body = throw_match.start()
                
                # Skip if nameof() is already used
                if 'nameof(' in throw_statement:
                    continue
                
                # Skip if using string interpolation with nameof
                if '$"' in throw_statement and 'nameof(' in throw_statement:
                    continue
                
                # Extract string literals from the throw statement
                # Match quoted strings: "..." or '...'
                string_literal_pattern = r'["\']([^"\']*)["\']'
                
                for str_match in re.finditer(string_literal_pattern, throw_statement):
                    string_content = str_match.group(1)
                    
                    # Check if any parameter name appears in the string literal
                    for param_name in param_names:
                        # Check if parameter name appears in the string (as whole word or part of string)
                        if param_name in string_content:
                            # Calculate line number: count newlines from method_body_start_line
                            lines_before_throw = method_body_clean[:throw_start_in_body].count('\n')
                            throw_line = method_body_start_line + lines_before_throw + 1
                            
                            # Get the actual line for context
                            if throw_line <= len(lines):
                                actual_line = lines[throw_line - 1].strip()
                            else:
                                actual_line = throw_statement
                            
                            findings.append({
                                'rule_id': 'nameof_preferred',
                                'message': f'Parameter name "{param_name}" is hardcoded in string literal. Use nameof({param_name}) instead.',
                                'file': filename,
                                'line': throw_line,
                                'severity': 'Major',
                                'property_path': ['source'],
                                'value': actual_line,
                                'node': f'MethodDeclaration.{method_name}',
                                'status': 'violation'
                            })
                            break  # Only report once per throw statement per parameter
        
        i += 1
    
    return findings


def check_namespaces_should_not_be_empty(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for empty namespaces that contain no meaningful content.
    
    This rule detects namespaces that are empty or contain only whitespace/comments.
    Empty namespaces clutter a project and should be removed.
    
    Noncompliant:
        namespace MyEmptyNamespace { }
        namespace Company.Product.EmptyModule { // No content }
    
    Compliant:
        namespace Company.Product.Services {
            public class UserService { }
        }
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    source_clean = re.sub(r'//.*$', '', source, flags=re.MULTILINE)
    source_clean = re.sub(r'/\*.*?\*/', '', source_clean, flags=re.DOTALL)
    
    # Pattern to match namespace declarations (namespace can be on same line or next line)
    # Match: namespace Name or namespace Name { (but not in comments)
    namespace_pattern = r'^\s*namespace\s+([\w\.]+)(?:\s*\{)?\s*$'
    
    i = 0
    while i < len(lines):
        line = lines[i]
        line_clean = line.strip()
        
        # Skip comment lines
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            i += 1
            continue
        
        # Check for namespace declaration (must be at start of line or after whitespace)
        namespace_match = re.search(namespace_pattern, line_clean)
        if namespace_match:
            namespace_name = namespace_match.group(1)
            namespace_start_line = i
            
            # Find the namespace body - track braces to find the end
            brace_count = 0
            namespace_body_lines = []
            in_namespace = False
            opening_brace_line = i
            
            # Find opening brace (could be on same line or next line)
            for j in range(i, len(lines)):
                current_line = lines[j]
                brace_count += current_line.count('{') - current_line.count('}')
                
                if '{' in current_line and not in_namespace:
                    in_namespace = True
                    opening_brace_line = j
                
                if in_namespace:
                    namespace_body_lines.append(current_line)
                
                if in_namespace and brace_count == 0 and j > i:
                    namespace_end_line = j
                    break
            else:
                # Namespace body not found or incomplete
                i += 1
                continue
            
            # Get namespace body (content between braces)
            namespace_body = '\n'.join(namespace_body_lines)
            # Extract content between the first { and last }
            first_brace = namespace_body.find('{')
            last_brace = namespace_body.rfind('}')
            
            if first_brace != -1 and last_brace != -1 and last_brace > first_brace:
                namespace_body = namespace_body[first_brace + 1:last_brace]
            else:
                # Fallback: try to remove braces
                namespace_body = namespace_body.strip()
                if namespace_body.startswith('{'):
                    namespace_body = namespace_body[1:]
                if namespace_body.endswith('}'):
                    namespace_body = namespace_body[:-1]
            
            # Clean the body: remove comments and whitespace
            namespace_body_clean = re.sub(r'//.*$', '', namespace_body, flags=re.MULTILINE)
            namespace_body_clean = re.sub(r'/\*.*?\*/', '', namespace_body_clean, flags=re.DOTALL)
            namespace_body_clean = namespace_body_clean.strip()
            
            # Check if namespace is empty (only whitespace/comments)
            if not namespace_body_clean or namespace_body_clean.isspace():
                # Check if there are nested namespaces (they might be empty too, but we'll report the outer one)
                # For now, report this namespace as empty
                findings.append({
                    'rule_id': 'namespaces_empty',
                    'message': f'Namespace "{namespace_name}" is empty and should be removed.',
                    'file': filename,
                    'line': namespace_start_line + 1,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': f'NamespaceDeclaration.{namespace_name}',
                    'status': 'violation'
                })
            else:
                # Check for nested empty namespaces within this namespace
                # Look for nested namespace declarations in the body
                nested_ns_pattern = r'namespace\s+([\w\.]+)\s*\{'
                for nested_match in re.finditer(nested_ns_pattern, namespace_body_clean):
                    nested_ns_name = nested_match.group(1)
                    nested_start = nested_match.start()
                    
                    # Find the nested namespace body
                    nested_brace_count = 0
                    nested_in_ns = False
                    nested_body_start = nested_start
                    
                    for k in range(nested_start, len(namespace_body_clean)):
                        char = namespace_body_clean[k]
                        if char == '{':
                            nested_brace_count += 1
                            nested_in_ns = True
                        elif char == '}':
                            nested_brace_count -= 1
                            if nested_in_ns and nested_brace_count == 0:
                                nested_body_end = k
                                nested_body = namespace_body_clean[nested_body_start + nested_match.end() - nested_match.start():nested_body_end]
                                
                                # Clean nested body
                                nested_body_clean = re.sub(r'//.*$', '', nested_body, flags=re.MULTILINE)
                                nested_body_clean = re.sub(r'/\*.*?\*/', '', nested_body_clean, flags=re.DOTALL)
                                nested_body_clean = nested_body_clean.strip()
                                
                                # Check if nested namespace is empty
                                if not nested_body_clean or nested_body_clean.isspace():
                                    # Calculate line number for nested namespace
                                    # Count lines from the start of the outer namespace body to the nested namespace
                                    lines_before_nested = namespace_body[:nested_start].count('\n')
                                    # Add the opening brace line of the outer namespace
                                    nested_ns_line = opening_brace_line + lines_before_nested + 1
                                    
                                    findings.append({
                                        'rule_id': 'namespaces_empty',
                                        'message': f'Nested namespace "{nested_ns_name}" is empty and should be removed.',
                                        'file': filename,
                                        'line': nested_ns_line,
                                        'severity': 'Major',
                                        'property_path': ['source'],
                                        'value': nested_match.group(0),
                                        'node': f'NamespaceDeclaration.{nested_ns_name}',
                                        'status': 'violation'
                                    })
                                break
        
        i += 1
    
    return findings


def check_new_guid_should_be_avoided(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for new Guid() usage that should be replaced with Guid.Empty or Guid.NewGuid().
    
    This rule detects parameterless instantiation of the Guid struct, which is ambiguous
    about the intent. Instead, use:
    - Guid.Empty for an empty GUID
    - Guid.NewGuid() for a randomly-generated GUID
    - new Guid(...) with parameters for specific initialization
    
    Noncompliant:
        var g1 = new Guid();
        Guid g2 = new();
        var g3 = default(Guid);
        Guid g4 = default;
    
    Compliant:
        var g1 = Guid.NewGuid();
        var g2 = Guid.Empty;
        var g3 = new Guid(bytes);
        var g4 = new Guid("12345678-1234-5678-9012-123456789012");
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Pattern 1: new Guid() - parameterless instantiation
    pattern1 = r'new\s+Guid\s*\(\s*\)'
    
    # Pattern 2: new() with Guid type (target-typed new) - Guid g = new();
    pattern2 = r'Guid\s+\w+\s*=\s*new\s*\(\s*\)'
    
    # Pattern 3: default(Guid) - default expression
    pattern3 = r'default\s*\(\s*Guid\s*\)'
    
    # Pattern 4: default with Guid type (default literal) - Guid g = default;
    pattern4 = r'Guid\s+\w+\s*=\s*default\s*;'
    
    i = 0
    while i < len(lines):
        line = lines[i]
        line_clean = line.strip()
        line_num = i + 1
        
        # Skip empty lines
        if not line_clean:
            i += 1
            continue
        
        # Skip lines that are ONLY comments (no code before the comment)
        # Check if line starts with // or /* after optional whitespace
        if re.match(r'^\s*(//|/\*|\*)', line):
            i += 1
            continue
        
        # Remove comments from line for checking compliant patterns
        # Remove // comments
        line_without_comments = re.sub(r'//.*$', '', line)
        # Remove /* */ comments
        line_without_comments = re.sub(r'/\*.*?\*/', '', line_without_comments, flags=re.DOTALL)
        
        # Skip if line contains Guid.NewGuid() or Guid.Empty in actual code (compliant)
        if 'Guid.NewGuid()' in line_without_comments or 'Guid.Empty' in line_without_comments:
            i += 1
            continue
        
        # Skip if line contains new Guid(...) with parameters in actual code (compliant)
        if re.search(r'new\s+Guid\s*\([^)]+\)', line_without_comments):
            i += 1
            continue
        
        # Check for pattern 1: new Guid() - must be in the line
        if re.search(pattern1, line):
            findings.append({
                'rule_id': 'new_guid_avoided',
                'message': 'Parameterless Guid instantiation is ambiguous. Use Guid.Empty for empty GUID or Guid.NewGuid() for random GUID.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_clean,
                'node': 'ObjectCreationExpression.Guid',
                'status': 'violation'
            })
        
        # Check for pattern 2: Guid g = new();
        if re.search(pattern2, line):
            findings.append({
                'rule_id': 'new_guid_avoided',
                'message': 'Target-typed new() with Guid is ambiguous. Use Guid.Empty for empty GUID or Guid.NewGuid() for random GUID.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_clean,
                'node': 'ObjectCreationExpression.Guid',
                'status': 'violation'
            })
        
        # Check for pattern 3: default(Guid)
        if re.search(pattern3, line):
            findings.append({
                'rule_id': 'new_guid_avoided',
                'message': 'default(Guid) is ambiguous. Use Guid.Empty for empty GUID or Guid.NewGuid() for random GUID.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_clean,
                'node': 'DefaultExpression.Guid',
                'status': 'violation'
            })
        
        # Check for pattern 4: Guid g = default;
        if re.search(pattern4, line):
            findings.append({
                'rule_id': 'new_guid_avoided',
                'message': 'default literal with Guid is ambiguous. Use Guid.Empty for empty GUID or Guid.NewGuid() for random GUID.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_clean,
                'node': 'DefaultExpression.Guid',
                'status': 'violation'
            })
        
        i += 1
    
    return findings


def check_non_abstract_attributes_should_be_sealed(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Check for non-abstract attribute classes that should be sealed.
    
    This rule detects classes that inherit from System.Attribute, are not abstract,
    and are not sealed. Sealing attributes improves performance by eliminating
    the search through the inheritance hierarchy when retrieving custom attributes.
    
    Noncompliant:
        public class MyAttribute : Attribute { }  // Not sealed
        internal class InternalAttribute : Attribute { }  // Not sealed
    
    Compliant:
        public sealed class MyAttribute : Attribute { }  // Sealed
        public abstract class BaseAttribute : Attribute { }  // Abstract (doesn't need sealing)
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    source_clean = re.sub(r'//.*$', '', source, flags=re.MULTILINE)
    source_clean = re.sub(r'/\*.*?\*/', '', source_clean, flags=re.DOTALL)
    
    # Pattern to match class declarations that inherit from Attribute
    # Matches: [modifiers] class ClassName : Attribute or class ClassName : SomeBase, Attribute
    class_pattern = r'(?:public|private|protected|internal|abstract|sealed|static|\s)*class\s+(\w+)\s*[:\s].*?Attribute\b'
    
    i = 0
    while i < len(lines):
        line = lines[i]
        line_clean = line.strip()
        
        # Skip comment lines
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            i += 1
            continue
        
        # Check for class declaration inheriting from Attribute
        class_match = re.search(class_pattern, line_clean, re.IGNORECASE)
        if class_match:
            class_name = class_match.group(1)
            class_start_line = i
            
            # Check if class is abstract (abstract classes don't need to be sealed)
            if re.search(r'\babstract\s+class\b', line_clean, re.IGNORECASE):
                i += 1
                continue
            
            # Check if class is sealed (compliant)
            if re.search(r'\bsealed\s+class\b', line_clean, re.IGNORECASE):
                i += 1
                continue
            
            # Check if it actually inherits from Attribute (not just contains "Attribute" in name)
            # Need to verify ": Attribute" is in the inheritance list
            if not re.search(r':\s*[^:]*\bAttribute\b', line_clean):
                # Might be multi-line inheritance, check next few lines
                inheritance_found = False
                for j in range(i, min(i + 5, len(lines))):
                    combined_line = ' '.join(lines[i:j+1])
                    if re.search(r':\s*[^:]*\bAttribute\b', combined_line):
                        inheritance_found = True
                        break
                
                if not inheritance_found:
                    i += 1
                    continue
            
            # Found a non-abstract, non-sealed attribute class - flag it
            findings.append({
                'rule_id': 'nonabstract_attributes_sealed',
                'message': f'Non-abstract attribute class "{class_name}" should be sealed for better performance.',
                'file': filename,
                'line': class_start_line + 1,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_clean,
                'node': f'ClassDeclaration.{class_name}',
                'status': 'violation'
            })
        
        i += 1
    
    return findings


