def partcreationpolicy_without_export(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects classes with [PartCreationPolicy] attribute but missing [Export] attribute.
    Flags only those classes.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    # Traverse all class declarations
    def visit(node):
        if not isinstance(node, dict):
            return
        if node.get('node_type') == 'ClassDeclaration':
            source = node.get('source', '')
            # Find all attribute lines before the class declaration
            attr_lines = []
            for line in source.splitlines():
                line_strip = line.strip()
                if line_strip.startswith('[') and line_strip.endswith(']'):
                    attr_lines.append(line_strip)
                elif line_strip.startswith('public class') or line_strip.startswith('internal class') or line_strip.startswith('class'):
                    break
            has_partcreation = any('PartCreationPolicy' in l for l in attr_lines)
            has_export = any('Export' in l for l in attr_lines)
            if has_partcreation and not has_export:
                findings.append({
                    'rule_id': 'partcreationpolicyattribute_preferred_exportattribute',
                    'message': 'Class uses PartCreationPolicyAttribute but is missing ExportAttribute.',
                    'node': 'ClassDeclaration.' + node.get('name', ''),
                    'file': filename,
                    'property_path': ['source'],
                    'value': source,
                    'status': 'violation',
                    'line': node.get('lineno', 1),
                    'severity': 'Major'
                })
        for key in ['body', 'children']:
            if key in node and isinstance(node[key], list):
                for child in node[key]:
                    visit(child)
    visit(ast_tree)
    return findings

def check_overflow_checking_disabled_enumerablesum(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects .Sum() calls inside unchecked blocks (even if on separate lines), unless inside try-catch.
    """
    findings = []
    if not isinstance(ast_tree, dict):
        return findings
    source = ast_tree.get('source', '')
    if not source:
        return findings
    lines = source.split('\n')
    inside_unchecked = False
    inside_try = False
    brace_depth = 0
    for idx, line in enumerate(lines, 1):
        # Enter unchecked block
        if not inside_unchecked and re.search(r'unchecked\s*{', line):
            inside_unchecked = True
            brace_depth = line.count('{') - line.count('}')
            if brace_depth < 1:
                brace_depth = 1
            continue
        if inside_unchecked:
            # Track try block inside unchecked
            if re.search(r'try\s*{', line):
                inside_try = True
            if re.search(r'\.Sum\s*\(', line) and not inside_try:
                findings.append({
                    'rule_id': 'overflow_checking_disabled_enumerablesum',
                    'message': 'Sum() call in unchecked context - Sum always executes in checked context making unchecked misleading',
                    'file': filename,
                    'line': idx,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line.strip(),
                    'node': 'MethodDeclaration',
                    'status': 'violation',
                })
            brace_depth += line.count('{') - line.count('}')
            if '}' in line and inside_try:
                inside_try = False
            if brace_depth <= 0:
                inside_unchecked = False
    return findings
    """
    Check for bitwise operations on enum values where the enum type lacks [Flags] attribute.
    
    This rule detects bitwise operations (|, &, ^) on enum values in method bodies,
    but only flags enums that don't have the [Flags] attribute.
    
    Noncompliant:
        enum Permissions { Read = 1, Write = 2 }
        var result = Permissions.Read | Permissions.Write;  // Noncompliant
    
    Compliant:
        [Flags]
        enum Permissions { Read = 1, Write = 2 }
        var result = Permissions.Read | Permissions.Write;  // Compliant
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    source_clean = re.sub(r'//.*$', '', source, flags=re.MULTILINE)
    source_clean = re.sub(r'/\*.*?\*/', '', source_clean, flags=re.DOTALL)
    
    # First, find all enum declarations and check which ones have [Flags]
    flags_enums = set()
    enum_pattern = r'\[Flags\]\s*enum\s+(\w+)'
    
    for match in re.finditer(enum_pattern, source_clean, re.IGNORECASE):
        enum_name = match.group(1)
        flags_enums.add(enum_name)
    
    # Also handle multi-line [Flags] attribute
    # Pattern: [Flags] on one line, enum on next line
    flags_attr_pattern = r'\[Flags\]'
    enum_decl_pattern = r'enum\s+(\w+)'
    
    # Find all [Flags] attributes and their positions
    flags_positions = []
    for match in re.finditer(flags_attr_pattern, source_clean, re.IGNORECASE):
        flags_positions.append(match.end())
    
    # Find all enum declarations
    for enum_match in re.finditer(enum_decl_pattern, source_clean, re.IGNORECASE):
        enum_name = enum_match.group(1)
        enum_start = enum_match.start()
        
        # Check if there's a [Flags] attribute before this enum (within reasonable distance)
        for flags_pos in flags_positions:
            # Check if [Flags] is before this enum and not too far (within 10 lines)
            if flags_pos < enum_start:
                # Count lines between [Flags] and enum
                text_between = source_clean[flags_pos:enum_start]
                lines_between = text_between.count('\n')
                if lines_between <= 3:  # Allow up to 3 lines between [Flags] and enum
                    flags_enums.add(enum_name)
                    break
    
    # Now find bitwise operations on enum values
    # Pattern: Type.Member | Type.Member, Type.Member & Type.Member, Type.Member ^ Type.Member
    bitwise_pattern = r'\b(\w+)\.(\w+)\s*([|&^])\s*(\w+)\.(\w+)\b'
    
    i = 0
    while i < len(lines):
        line = lines[i]
        line_clean = line.strip()
        
        # Skip comment lines
        if line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            i += 1
            continue
        
        # Skip test methods
        if re.search(r'\[(?:Test|Fact|TestMethod|Theory|DataTestMethod)\]', line_clean, re.IGNORECASE):
            i += 1
            continue
        
        # Check for bitwise operations on enum values
        for match in re.finditer(bitwise_pattern, line_clean):
            enum_type1 = match.group(1)
            member1 = match.group(2)
            operator = match.group(3)
            enum_type2 = match.group(4)
            member2 = match.group(5)
            
            # Both sides should be the same enum type for this to be a valid enum bitwise operation
            if enum_type1 == enum_type2:
                enum_type = enum_type1
                
                # Check if this enum has [Flags] attribute
                if enum_type not in flags_enums:
                    # This is a non-Flags enum used in bitwise operation - flag it
                    findings.append({
                        'rule_id': 'nonflags_enums_avoided_bitwise',
                        'message': f'Bitwise operation ({operator}) on enum "{enum_type}" which lacks [Flags] attribute. Add [Flags] attribute to the enum or avoid bitwise operations.',
                        'file': filename,
                        'line': i + 1,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': line_clean,
                        'node': f'MethodDeclaration.unknown',
                        'status': 'violation'
                    })
        
        i += 1
    
    return findings


def check_linkedlist_first_last_violations(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Precisely detects First() and Last() extension method calls on LinkedList<T> objects.
    Uses method-scoped variable tracking to avoid false positives on other collection types.
    """
    findings = []
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    # Remove comments and strings to avoid false positives
    import re
    
    # Remove single-line comments
    cleaned_source = re.sub(r'//.*?$', '', source, flags=re.MULTILINE)
    # Remove multi-line comments
    cleaned_source = re.sub(r'/\*.*?\*/', '', cleaned_source, flags=re.DOTALL)
    # Remove string literals
    cleaned_source = re.sub(r'"[^"]*"', '', cleaned_source)
    cleaned_source = re.sub(r"'[^']*'", '', cleaned_source)
    
    lines = cleaned_source.split('\n')
    
    # Track method boundaries and variables per method
    current_method_vars = {}  # {variable_name: line_number}
    brace_depth = 0
    in_method = False
    method_start_brace_depth = 0
    
    for i, line in enumerate(lines):
        line_clean = line.strip()
        if not line_clean:
            continue
        
        # Count braces to track scope depth
        brace_depth += line_clean.count('{') - line_clean.count('}')
        
        # Detect method start
        if re.search(r'\b(?:public|private|protected|internal|static).*?\s+\w+\s*\([^)]*\)\s*\{?', line_clean):
            in_method = True
            method_start_brace_depth = brace_depth
            current_method_vars = {}  # Reset variables for new method
            continue
        
        # Detect method end (when we return to the same brace depth as method start - 1)
        if in_method and brace_depth < method_start_brace_depth:
            in_method = False
            current_method_vars = {}
            continue
        
        # Only process lines within methods
        if not in_method:
            continue
        
        # Look for LinkedList variable declarations within current method
        # Pattern 1: LinkedList<Type> varName = new LinkedList<Type>();
        match1 = re.search(r'LinkedList<[^>]+>\s+(\w+)\s*=\s*new\s+LinkedList<[^>]+>', line_clean)
        if match1:
            var_name = match1.group(1)
            current_method_vars[var_name] = i + 1
            continue
            
        # Pattern 2: var varName = new LinkedList<Type>();
        match2 = re.search(r'\bvar\s+(\w+)\s*=\s*new\s+LinkedList<[^>]+>', line_clean)
        if match2:
            var_name = match2.group(1)
            current_method_vars[var_name] = i + 1
            continue
            
        # Pattern 3: Assignment to existing var (only within same method)
        match3 = re.search(r'^[^=]*(\w+)\s*=\s*new\s+LinkedList<[^>]+>', line_clean)
        if match3:
            var_name = match3.group(1)
            current_method_vars[var_name] = i + 1
            continue
        
        # Look for First()/Last() calls on variables declared as LinkedList in current method
        first_last_matches = re.finditer(r'(\w+)\s*\.\s*(First|Last)\s*\(', line_clean)
        for match in first_last_matches:
            var_name = match.group(1)
            method_name = match.group(2)
            
            # Check if this variable is a LinkedList within current method scope
            if var_name in current_method_vars:
                findings.append({
                    'rule_id': 'first_last_properties_linkedlist',
                    'message': f'Use .{method_name} property instead of .{method_name}() method on LinkedList<T> for better performance',
                    'file': filename,
                    'line': i + 1,
                    'severity': 'Major',
                    'property_path': ['source'],
                    'value': line_clean,
                    'node': f'MethodDeclaration.unknown',
                    'status': 'violation'
                })
    
    return findings

def check_firstsingle_violations(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects FirstOrDefault() or SingleOrDefault() calls on collections that are known to be non-empty.
    
    This custom function provides precise detection by tracking variable declarations
    with non-empty collection initializations and identifying when those variables
    call FirstOrDefault() or SingleOrDefault().
    """
    import re
    
    if not filename:
        filename = 'unknown'
    
    findings = []
    
    def is_in_comment_or_string(line, text):
        """Check if text is within comments or string literals"""
        stripped = line.strip()
        # Skip comment lines
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*') or stripped.startswith('///'):
            return True
        # Check if target is within string literals
        if '"' in line and text in line:
            # Check if target is within quotes
            parts = line.split('"')
            for i in range(1, len(parts), 2):  # Check odd indices (inside quotes)
                if text in parts[i]:
                    return True
        return False
    
    def detect_non_empty_collections(source):
        """
        Detect variable declarations with non-empty collection initializations.
        Returns dict of {variable_name: line_number}
        """
        non_empty_vars = {}
        lines = source.split('\n')
        
        # Patterns for non-empty collection declarations
        patterns = [
            # Array literals with elements: new[] { ... }, new int[] { ... }
            r'(?:var|[\w<>\[\]]+)\s+(\w+)\s*=\s*new\s*(?:\w*\[\s*\])?\s*\{\s*([^}]+)\s*\}',
            # List/collection initializations with elements: new List<T> { ... }
            r'(?:var|[\w<>\[\]]+)\s+(\w+)\s*=\s*new\s+(?:\w+<[^>]+>|\w+)\s*\(\s*\)\s*\{\s*([^}]+)\s*\}',
            # Explicit type array initializations: new int[] { ... }
            r'(?:var|[\w<>\[\]]+)\s+(\w+)\s*=\s*new\s+\w+\[\s*\]\s*\{\s*([^}]+)\s*\}',
            # HashSet/Dictionary initializations: new HashSet<T> { ... }, new Dictionary<T,U> { ... }
            r'(?:var|[\w<>\[\]]+)\s+(\w+)\s*=\s*new\s+(?:HashSet|Dictionary)<[^>]+>\s*(?:\(\s*\))?\s*\{\s*([^}]+)\s*\}',
        ]
        
        for i, line in enumerate(lines, 1):
            if is_in_comment_or_string(line, 'new'):
                continue
            
            for pattern in patterns:
                matches = re.finditer(pattern, line)
                for match in matches:
                    var_name = match.group(1)
                    init_content = match.group(2).strip()
                    
                    # Skip if initialization is empty (just whitespace/comments)
                    if not init_content or init_content.isspace():
                        continue
                    
                    # Skip empty array literals
                    if not init_content or init_content.strip() == '':
                        continue
                        
                    # Track this as non-empty variable
                    non_empty_vars[var_name] = i
        
        return non_empty_vars
    
    def find_firstordefault_calls(source, non_empty_vars):
        """
        Find FirstOrDefault() or SingleOrDefault() calls on tracked non-empty variables.
        """
        violations = []
        lines = source.split('\n')
        
        for i, line in enumerate(lines, 1):
            if is_in_comment_or_string(line, 'FirstOrDefault') and is_in_comment_or_string(line, 'SingleOrDefault'):
                continue
            
            # Pattern for variable.FirstOrDefault() or variable.SingleOrDefault()
            firstordefault_pattern = r'(\w+)\s*\.\s*(FirstOrDefault|SingleOrDefault)\s*\('
            matches = re.finditer(firstordefault_pattern, line)
            
            for match in matches:
                var_name = match.group(1)
                method_name = match.group(2)
                
                # Check if this variable is tracked as non-empty
                if var_name in non_empty_vars:
                    violations.append({
                        'line': i,
                        'variable': var_name,
                        'method': method_name,
                        'declared_line': non_empty_vars[var_name],
                        'full_line': line.strip()
                    })
        
        return violations
    
    def process_node(node, base_line=0):
        """Process an AST node and its children recursively"""
        if not isinstance(node, dict):
            return
        
        # Process method declarations
        if node.get('node_type') == 'MethodDeclaration':
            source = node.get('source', '')
            if source:
                method_line = node.get('lineno', 1) + base_line
                
                # Track non-empty collections within this method scope
                non_empty_vars = detect_non_empty_collections(source)
                
                # Find FirstOrDefault/SingleOrDefault violations
                violations = find_firstordefault_calls(source, non_empty_vars)
                
                # Create findings for each violation
                for violation in violations:
                    findings.append({
                        'rule_id': 'firstsingle_preferred_instead_firstordefaultsingleordefault',
                        'message': f"'{violation['method']}()' should not be used on '{violation['variable']}' which is known to be non-empty. Use '{violation['method'].replace('OrDefault', '')}()' instead for better code clarity and intent.",
                        'file': filename,
                        'line': method_line + violation['line'] - 1,
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': violation['full_line'],
                        'node': f'MethodDeclaration.{violation["variable"]}.{violation["method"]}',
                        'status': 'violation'
                    })
        
        # Process children
        children = node.get('children', [])
        if isinstance(children, list):
            for child in children:
                process_node(child, base_line)
    
    # Handle different AST structures
    if isinstance(ast_tree, dict):
        if 'node_type' in ast_tree:
            # Single root node structure
            process_node(ast_tree, 0)
        else:
            # Multi-node structure (legacy)
            for node_type, nodes in ast_tree.items():
                if node_type == "MethodDeclaration" and isinstance(nodes, list):
                    for node in nodes:
                        source = node.get('source', '')
                        if source:
                            start_line = node.get('start_line', 1)
                            
                            # Track non-empty collections within this method scope
                            non_empty_vars = detect_non_empty_collections(source)
                            
                            # Find FirstOrDefault/SingleOrDefault violations
                            violations = find_firstordefault_calls(source, non_empty_vars)
                            
                            # Create findings for each violation
                            for violation in violations:
                                findings.append({
                                    'rule_id': 'firstsingle_preferred_instead_firstordefaultsingleordefault',
                                    'message': f"'{violation['method']}()' should not be used on '{violation['variable']}' which is known to be non-empty. Use '{violation['method'].replace('OrDefault', '')}()' instead for better code clarity and intent.",
                                    'file': filename,
                                    'line': start_line + violation['line'] - 1,
                                    'severity': 'Major',
                                    'property_path': ['source'],
                                    'value': violation['full_line'],
                                    'node': f'MethodDeclaration.{violation["variable"]}.{violation["method"]}',
                                    'status': 'violation'
                                })
    
    return findings

def check_flags_enum_explicitly_initialize(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects Flags enums where members after the first three are not explicitly initialized to powers of two.
    
    The first three members (0, 1, 2) naturally match powers of two, so they don't need explicit initialization.
    We check for [Flags] attribute and enum definitions with 4+ members where later members lack explicit values.
    """
    import re
    
    if not filename:
        filename = 'unknown'
    
    findings = []
    
    def is_in_comment_or_string(line, text):
        """Check if text is within comments or string literals"""
        stripped = line.strip()
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*') or stripped.startswith('///'):
            return True
        if '"' in line and text in line:
            parts = line.split('"')
            for i in range(1, len(parts), 2):
                if text in parts[i]:
                    return True
        return False
    
    def find_flags_enums(source):
        """Find all Flags enum declarations and analyze their member initialization"""
        violations = []
        lines = source.split('\n')
        
        i = 0
        while i < len(lines):
            line = lines[i].strip()
            
            # Skip comments and strings
            if is_in_comment_or_string(lines[i], 'Flags'):
                i += 1
                continue
            
            # Look for [Flags] attribute
            if re.match(r'^\s*\[\s*Flags\s*\]', line):
                # Look for enum declaration on next few lines
                enum_line_idx = None
                enum_name = None
                
                for j in range(i + 1, min(i + 4, len(lines))):
                    enum_match = re.match(r'^\s*(?:public\s+|private\s+|internal\s+)?enum\s+(\w+)', lines[j].strip())
                    if enum_match:
                        enum_line_idx = j
                        enum_name = enum_match.group(1)
                        break
                
                if enum_line_idx is not None:
                    # Parse enum members
                    members = []
                    brace_count = 0
                    member_started = False
                    
                    for k in range(enum_line_idx, len(lines)):
                        current_line = lines[k].strip()
                        
                        # Track braces
                        brace_count += current_line.count('{')
                        brace_count -= current_line.count('}')
                        
                        if '{' in current_line:
                            member_started = True
                            # Check if there are members on the same line
                            after_brace = current_line.split('{', 1)
                            if len(after_brace) > 1 and after_brace[1].strip():
                                member_line = after_brace[1].strip()
                                if not is_in_comment_or_string(lines[k], member_line):
                                    members.append((k + 1, member_line))
                        elif member_started and brace_count > 0:
                            # Inside enum body
                            if current_line and not current_line.startswith('//') and current_line != '}':
                                if not is_in_comment_or_string(lines[k], current_line):
                                    members.append((k + 1, current_line))
                        elif brace_count == 0 and member_started:
                            # End of enum
                            break
                    
                    # Analyze members for missing explicit initialization
                    if len(members) > 3:  # Only check if more than 3 members
                        for idx, (line_num, member_text) in enumerate(members):
                            if idx >= 3:  # Check members after first 3
                                # Remove trailing comma and comments
                                clean_member = re.sub(r'\s*,?\s*//.*$', '', member_text).strip()
                                clean_member = clean_member.rstrip(',').strip()
                                
                                # Check if member has explicit initialization
                                if '=' not in clean_member:
                                    violations.append({
                                        'line': line_num,
                                        'enum_name': enum_name,
                                        'member_name': clean_member,
                                        'member_index': idx,
                                        'full_line': member_text.strip()
                                    })
                    
                    i = enum_line_idx + 1
                else:
                    i += 1
            else:
                i += 1
        
        return violations
    
    # Handle different AST structures
    if isinstance(ast_tree, dict):
        if 'node_type' in ast_tree:
            # Single root node structure - work with full source
            source = ast_tree.get('source', '')
            if source:
                violations = find_flags_enums(source)
                for violation in violations:
                    findings.append({
                        'rule_id': 'flags_enumerations_explicitly_initialize',
                        'message': f"Member '{violation['member_name']}' in Flags enum '{violation['enum_name']}' should be explicitly initialized. Members after the first three must use powers of two (e.g., = 4, = 8, = 16).",
                        'file': filename,
                        'line': violation['line'],
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': violation['full_line'],
                        'node': f'EnumDeclaration.{violation["enum_name"]}.{violation["member_name"]}',
                        'status': 'violation'
                    })
        else:
            # Multi-node structure (legacy) - check all content
            source = ast_tree.get('source', '')
            if source:
                violations = find_flags_enums(source)
                for violation in violations:
                    findings.append({
                        'rule_id': 'flags_enumerations_explicitly_initialize',
                        'message': f"Member '{violation['member_name']}' in Flags enum '{violation['enum_name']}' should be explicitly initialized. Members after the first three must use powers of two (e.g., = 4, = 8, = 16).",
                        'file': filename,
                        'line': violation['line'],
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': violation['full_line'],
                        'node': f'EnumDeclaration.{violation["enum_name"]}.{violation["member_name"]}',
                        'status': 'violation'
                    })
    
    return findings

def check_flags_enum_zero_value_member_named_none(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects Flags enums where zero-value members are not named 'None'.
    
    According to best practices, Flags enums should have their zero-value member named 'None'
    to clearly indicate the absence of any flags.
    """
    import re
    
    if not filename:
        filename = 'unknown'
    
    findings = []
    
    def is_in_comment_or_string(line, text):
        """Check if text is within comments or string literals"""
        stripped = line.strip()
        if stripped.startswith('//') or stripped.startswith('/*') or stripped.startswith('*') or stripped.startswith('///'):
            return True
        if '"' in line and text in line:
            parts = line.split('"')
            for i in range(1, len(parts), 2):
                if text in parts[i]:
                    return True
        return False
    
    def find_flags_enums_zero_value_violations(source):
        """Find Flags enums with zero-value members not named 'None'"""
        violations = []
        lines = source.split('\n')
        
        i = 0
        while i < len(lines):
            line = lines[i].strip()
            
            # Skip comments and strings
            if is_in_comment_or_string(lines[i], 'Flags'):
                i += 1
                continue
            
            # Look for [Flags] attribute
            if re.match(r'^\s*\[\s*Flags\s*\]', line):
                # Look for enum declaration on next few lines
                enum_line_idx = None
                enum_name = None
                
                for j in range(i + 1, min(i + 4, len(lines))):
                    enum_match = re.match(r'^\s*(?:public\s+|private\s+|internal\s+)?enum\s+(\w+)', lines[j].strip())
                    if enum_match:
                        enum_line_idx = j
                        enum_name = enum_match.group(1)
                        break
                
                if enum_line_idx is not None:
                    # Parse enum members to find zero-value members
                    members = []
                    brace_count = 0
                    member_started = False
                    
                    for k in range(enum_line_idx, len(lines)):
                        current_line = lines[k].strip()
                        
                        # Track braces
                        brace_count += current_line.count('{')
                        brace_count -= current_line.count('}')
                        
                        if '{' in current_line:
                            member_started = True
                            # Check if there are members on the same line
                            after_brace = current_line.split('{', 1)
                            if len(after_brace) > 1 and after_brace[1].strip():
                                member_line = after_brace[1].strip()
                                if not is_in_comment_or_string(lines[k], member_line):
                                    members.append((k + 1, member_line))
                        elif member_started and brace_count > 0:
                            # Inside enum body
                            if current_line and not current_line.startswith('//') and current_line != '}':
                                if not is_in_comment_or_string(lines[k], current_line):
                                    members.append((k + 1, current_line))
                        elif brace_count == 0 and member_started:
                            # End of enum
                            break
                    
                    # Check for zero-value members not named 'None'
                    for line_num, member_text in members:
                        # Remove trailing comma and comments
                        clean_member = re.sub(r'\s*,?\s*//.*$', '', member_text).strip()
                        clean_member = clean_member.rstrip(',').strip()
                        
                        # Check for explicit zero value assignment
                        zero_value_patterns = [
                            r'^(\w+)\s*=\s*0\s*$',           # Name = 0
                            r'^(\w+)\s*=\s*0x0\s*$',        # Name = 0x0  
                            r'^(\w+)\s*=\s*0b0+\s*$',       # Name = 0b0, 0b00, etc.
                        ]
                        
                        for pattern in zero_value_patterns:
                            match = re.match(pattern, clean_member)
                            if match:
                                member_name = match.group(1)
                                if member_name.lower() != 'none':
                                    violations.append({
                                        'line': line_num,
                                        'enum_name': enum_name,
                                        'member_name': member_name,
                                        'full_line': member_text.strip()
                                    })
                                break
                        
                        # Check for implicit zero value (first member without assignment)
                        # Only check if it's the first member and has no explicit assignment
                        if '=' not in clean_member and members.index((line_num, member_text)) == 0:
                            member_name = clean_member
                            if member_name.lower() != 'none' and member_name:
                                violations.append({
                                    'line': line_num,
                                    'enum_name': enum_name,
                                    'member_name': member_name,
                                    'full_line': member_text.strip(),
                                    'implicit_zero': True
                                })
                    
                    i = enum_line_idx + 1
                else:
                    i += 1
            else:
                i += 1
        
        return violations
    
    # Handle different AST structures
    if isinstance(ast_tree, dict):
        if 'node_type' in ast_tree:
            # Single root node structure - work with full source
            source = ast_tree.get('source', '')
            if source:
                violations = find_flags_enums_zero_value_violations(source)
                for violation in violations:
                    implicit_note = " (implicit zero value)" if violation.get('implicit_zero') else ""
                    findings.append({
                        'rule_id': 'flags_enumerations_zerovalue_members',
                        'message': f"Zero-value member '{violation['member_name']}' in Flags enum '{violation['enum_name']}' should be named 'None'{implicit_note}. This improves code clarity and follows .NET conventions.",
                        'file': filename,
                        'line': violation['line'],
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': violation['full_line'],
                        'node': f'EnumDeclaration.{violation["enum_name"]}.{violation["member_name"]}',
                        'status': 'violation'
                    })
        else:
            # Multi-node structure (legacy) - check all content
            source = ast_tree.get('source', '')
            if source:
                violations = find_flags_enums_zero_value_violations(source)
                for violation in violations:
                    implicit_note = " (implicit zero value)" if violation.get('implicit_zero') else ""
                    findings.append({
                        'rule_id': 'flags_enumerations_zerovalue_members',
                        'message': f"Zero-value member '{violation['member_name']}' in Flags enum '{violation['enum_name']}' should be named 'None'{implicit_note}. This improves code clarity and follows .NET conventions.",
                        'file': filename,
                        'line': violation['line'],
                        'severity': 'Major',
                        'property_path': ['source'],
                        'value': violation['full_line'],
                        'node': f'EnumDeclaration.{violation["enum_name"]}.{violation["member_name"]}',
                        'status': 'violation'
                    })
    
    return findings


def check_equals_override_comparison(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects when == operator is used after Equals method has been overridden.
    When Equals is overridden, == may not use the custom equality logic.
    
    Triggers on: Classes with override bool Equals(...) that later use == operator
    Excludes: Logging, unit tests, comments, built-in types, .Equals() calls
    """
    findings = []
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Function to check if a line is in a test context
    def is_in_test_context(line_index):
        """Check if the current line is within a test method"""
        # Look backwards for test attributes
        for i in range(max(0, line_index - 15), line_index + 1):
            prev_line = lines[i].strip()
            # Check for test attributes
            if re.search(r'\[Test\]|\[Fact\]|\[TestMethod\]|\[TestCase\]', prev_line, re.IGNORECASE):
                return True
        
        # Look for test method signatures with test attributes validation
        for i in range(max(0, line_index - 8), line_index):
            prev_line = lines[i].strip()
            # Check for test method patterns
            if re.search(r'public\s+(void|async\s+Task)\s+\w+\s*\(.*\)\s*$', prev_line, re.IGNORECASE):
                # Validate it's actually a test method by checking for test attributes
                for j in range(max(0, i - 8), i):
                    attr_line = lines[j].strip()
                    if re.search(r'\[Test\]|\[Fact\]|\[TestMethod\]|\[TestCase\]', attr_line, re.IGNORECASE):
                        return True
                        
        return False
    
    # Function to check if currently in a comment block
    def is_in_comment_block(line_index):
        """Check if the current line is within a multi-line comment block"""
        in_comment = False
        for i in range(0, line_index + 1):
            line = lines[i].strip()
            if '/*' in line and '*/' not in line:
                in_comment = True
            elif '*/' in line:
                in_comment = False
        return in_comment
    
    # Find all classes that override Equals method
    equals_overriding_classes = set()
    
    # Pattern to match class declarations
    class_pattern = re.compile(r'class\s+(\w+)')
    # Pattern to match Equals override
    equals_override_pattern = re.compile(r'override\s+bool\s+Equals\s*\(')
    
    current_class = None
    brace_depth = 0
    in_class = False
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Track brace depth
        brace_depth += stripped.count('{') - stripped.count('}')
        
        # Check for class declaration
        class_match = class_pattern.search(stripped)
        if class_match and not in_class:
            current_class = class_match.group(1)
            in_class = True
        
        # Check if we're exiting the class
        if in_class and brace_depth <= 0:
            in_class = False
            current_class = None
        
        # Check for Equals override within a class
        if in_class and current_class and equals_override_pattern.search(stripped):
            equals_overriding_classes.add(current_class)
    
    # Now find == operator usage in classes that override Equals
    if not equals_overriding_classes:
        return findings
    
    # Exclusion patterns for individual lines
    exclude_patterns = [
        r'^\s*//',           # Line comments
        r'Console\.',        # Console logging
        r'Logger\.',         # Logger calls
        r'Debug\.',          # Debug calls
        r'Assert\.',         # Assertions
        r'\.Equals\(',       # .Equals() method calls - compliant
    ]
    
    # Function to check if currently in Equals method
    def is_in_equals_method(line_index):
        """Check if the current line is within an Equals method override"""
        # Look backwards for Equals method signature
        for i in range(max(0, line_index - 10), line_index):
            prev_line = lines[i].strip()
            if re.search(r'override\s+bool\s+Equals\s*\(', prev_line):
                return True
        return False
    
    # Pattern to match == or != operator usage between custom objects (not built-ins)
    equality_pattern = re.compile(r'\b([a-zA-Z_]\w*)\s*(==|!=)\s*([a-zA-Z_]\w*)\b')
    
    # Additional patterns for assignment and other contexts
    assignment_equality_pattern = re.compile(r'=\s*([a-zA-Z_]\w*)\s*(==|!=)\s*([a-zA-Z_]\w*)')
    
    # Track current class context for == usage
    current_class = None
    brace_depth = 0
    in_class = False
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Skip empty lines
        if not stripped:
            continue
            
        # Skip exclusions - basic patterns
        should_exclude = False
        for exclude_pattern in exclude_patterns:
            if re.search(exclude_pattern, stripped, re.IGNORECASE):
                should_exclude = True
                break
        
        if should_exclude:
            continue
            
        # Skip if in test context
        if is_in_test_context(line_num - 1):  # Convert to 0-based index
            continue
            
        # Skip if in comment block
        if is_in_comment_block(line_num - 1):  # Convert to 0-based index
            continue
            
        # Skip if in Equals method itself
        if is_in_equals_method(line_num - 1):  # Convert to 0-based index
            continue
        
        # Track brace depth
        brace_depth += stripped.count('{') - stripped.count('}')
        
        # Check for class declaration
        class_match = class_pattern.search(stripped)
        if class_match and not in_class:
            current_class = class_match.group(1)
            in_class = True
        
        # Check if we're exiting the class
        if in_class and brace_depth <= 0:
            in_class = False
            current_class = None
        
        # Check for == or != operator usage in classes that override Equals
        if (in_class and current_class and 
            current_class in equals_overriding_classes and
            ('==' in stripped or '!=' in stripped)):
            
            # Extract the operator used
            operator = '==' if '==' in stripped else '!='
            
            # Skip built-in type comparisons and literal values
            if (re.search(r'\b(null|true|false|\d+)\b.*' + operator, stripped, re.IGNORECASE) or
                re.search(r'\b(string|int|bool|DateTime|decimal|float|double)\b', stripped, re.IGNORECASE)):
                continue
            
            findings.append({
                'rule_id': 'avoided_when_equals_is',
                'message': f"Avoid using {operator} operator in class '{current_class}' that overrides Equals. Use .Equals() method for proper comparison.",
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'node': f'BinaryExpression.{operator}',
                'status': 'violation',
                'property_path': ['source'],
                'value': stripped
            })
    
    return findings

# Custom function for string.IsNullOrEmpty rule
def check_stringisnullorempty_preferred(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Detects patterns where string.Equals() is used to check for empty strings instead of string.IsNullOrEmpty().
    Looks for: "".Equals(...), .Equals(""), .Equals(string.Empty)
    """
    findings = []
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        
        # Skip empty lines and comments
        if not stripped or stripped.startswith('//') or stripped.startswith('/*'):
            continue
        
        # Skip test context
        if any(marker in line for marker in ['[Test', '[Fact', '[Theory', 'Assert.']):
            continue
            
        # Skip logging and debug statements
        if any(marker in line for marker in ['Console.', 'Debug.', 'Logger.', 'Log.']):
            continue
            
        # Skip string formatting
        if any(marker in line for marker in ['$"', 'string.Format', '"{0}"']):
            continue
        
        # Check for problematic patterns
        patterns = [
            (r'""\s*\.\s*Equals\s*\(', 'empty string literal calling Equals'),
            (r'\.\s*Equals\s*\(\s*""\s*\)', 'calling Equals with empty string'),
            (r'\.\s*Equals\s*\(\s*string\.Empty\s*\)', 'calling Equals with string.Empty'),
            (r'string\.Empty\s*\.\s*Equals\s*\(', 'string.Empty calling Equals'),
        ]
        
        for pattern, description in patterns:
            if re.search(pattern, line, re.IGNORECASE):
                # Additional exclusions for legitimate use cases
                if any(exclude in line.lower() for exclude in [
                    'tostring()', 'getstring', 'format(', 'interpolation',
                    'debug', 'console', 'logger', 'log.', 'trace'
                ]):
                    continue
                
                findings.append({
                    'rule_id': 'stringisnullorempty_preferred',
                    'message': f"Use string.IsNullOrEmpty() instead of .Equals(\"\") or .Equals(string.Empty) ({description})",
                    'file': filename,
                    'line': line_num,
                    'severity': 'Major',
                    'node': 'CallExpression.Equals',
                    'status': 'violation',
                    'property_path': ['source'],
                    'value': stripped
                })
                break  # Only report one violation per line
    
    return findings


def check_switch_statements_include_at_least_3_cases(ast_tree: Dict, filename: str) -> List[Dict]:
    """
    Custom logic for switch_statements_include_least rule.
    Checks that switch statements have at least 3 case clauses.
    Switch statements with fewer than 3 cases should use if-else or ternary operators instead.
    
    Compliant: switch with 3+ cases, if-else statements, ternary operators
    Non-compliant: switch with only 1-2 cases
    """
    findings = []
    
    if not isinstance(ast_tree, dict):
        return findings
    
    source = ast_tree.get('source', '')
    if not source:
        return findings
    
    lines = source.split('\n')
    
    # Skip files that are primarily tests or logging
    is_test_file = any(pattern in source.lower() for pattern in ['[test]', '[fact]', '[testcase]', 'assert.', 'nunit', 'xunit', 'mstest'])
    if is_test_file:
        return findings
    
    # Find all switch statements
    for line_num, line in enumerate(lines, 1):
        line_clean = line.strip()
        
        # Skip comments and empty lines
        if not line_clean or line_clean.startswith('//') or line_clean.startswith('/*') or line_clean.startswith('*'):
            continue
            
        # Skip lines with logging
        if any(log_pattern in line for log_pattern in ['Console.', 'Logger.', 'Debug.', 'Trace.', 'Log.']):
            continue
        
        # Look for switch statement start - handle both same line and next line braces
        switch_match = re.search(r'\bswitch\s*\([^)]+\)', line)
        if not switch_match:
            continue
        
        # Check if the opening brace is on the same line or next line
        switch_start_line = line_num - 1  # 0-based index
        has_opening_brace = '{' in line
        
        if not has_opening_brace and switch_start_line + 1 < len(lines):
            # Check next line for opening brace
            next_line = lines[switch_start_line + 1].strip()
            if next_line.startswith('{'):
                has_opening_brace = True
                switch_start_line += 1  # Start extraction from the brace line
        
        if not has_opening_brace:
            continue  # Not a complete switch statement
        
        # Extract the complete switch statement by finding matching braces
        switch_content = _extract_switch_block(lines, switch_start_line)
        
        if not switch_content:
            continue
        
        # Count case clauses in the switch block
        case_count = _count_case_clauses(switch_content)
        
        # Check if this is a switch expression (=> syntax) - these are different
        if '=>' in switch_content:
            continue  # Skip switch expressions for now as they have different rules
        
        # Only flag if there are fewer than 3 cases
        if case_count < 3:
            finding = {
                'rule_id': 'switch_statements_include_least',
                'message': f'Switch statement has only {case_count} case clause(s). Use if-else or ternary operator for fewer than 3 cases.',
                'file': filename,
                'line': line_num,
                'severity': 'Major',
                'property_path': ['source'],
                'value': line_clean,
                'node': 'SwitchStatement',
                'status': 'violation'
            }
            findings.append(finding)
    
    return findings


def _extract_switch_block(lines: List[str], start_line_idx: int) -> str:
    """
    Extract the complete switch block starting from the given line.
    Returns the switch block content including nested braces.
    """
    if start_line_idx >= len(lines):
        return ""
    
    # Find the opening brace
    content = lines[start_line_idx]
    if '{' not in content:
        return ""
    
    brace_count = content.count('{') - content.count('}')
    switch_block = content
    
    # Continue reading lines until we find the matching closing brace
    line_idx = start_line_idx + 1
    while brace_count > 0 and line_idx < len(lines):
        line = lines[line_idx]
        switch_block += '\n' + line
        brace_count += line.count('{') - line.count('}')
        line_idx += 1
    
    return switch_block


def _count_case_clauses(switch_content: str) -> int:
    """
    Count the number of case clauses in a switch statement.
    Includes both 'case' and 'default' clauses.
    """
    # Remove comments to avoid false matches
    content = re.sub(r'//.*$', '', switch_content, flags=re.MULTILINE)
    content = re.sub(r'/\*.*?\*/', '', content, flags=re.DOTALL)
    
    # Count case labels (case X: or default:)
    case_pattern = r'\b(?:case\s+[^:]+|default)\s*:'
    case_matches = re.findall(case_pattern, content, re.MULTILINE | re.DOTALL)
    
    return len(case_matches)